// ── Lazy resource loader ──────────────────────────────────────
const _resLoading = {};
const _resLoaded = new Set();
function _loadScript(src) {
  if (_resLoaded.has(src)) return Promise.resolve();
  if (_resLoading[src]) return _resLoading[src];
  _resLoading[src] = new Promise((res, rej) => {
    const s = document.createElement('script'); s.src = src;
    s.onload = () => { _resLoaded.add(src); delete _resLoading[src]; res(); };
    s.onerror = () => { delete _resLoading[src]; rej(new Error('Failed: ' + src)); };
    document.head.appendChild(s);
  });
  return _resLoading[src];
}
function _loadCss(href) {
  if (document.querySelector(`link[href="${href}"]`)) return;
  const l = document.createElement('link'); l.rel = 'stylesheet'; l.href = href;
  document.head.appendChild(l);
}

// Archive API throttle — max 1 request per 600ms, in-memory cache keyed by URL
const _archCache={};
const _archQ=[];let _archRunning=false;
function _archFetch(url){
  if(_archCache[url])return Promise.resolve(_archCache[url]);
  return new Promise((res,rej)=>{
    _archQ.push({url,res,rej});
    if(!_archRunning)_archDrain();
  });
}
function _archDrain(){
  if(!_archQ.length){_archRunning=false;return;}
  _archRunning=true;
  const{url,res,rej}=_archQ.shift();
  fetch(url).then(r=>r.json()).then(d=>{_archCache[url]=d;res(d);}).catch(rej).finally(()=>setTimeout(_archDrain,650));
}

// ── Theme ─────────────────────────────────────────────────
const isDark = () => document.documentElement.dataset.theme === 'dark';
let _lastTemp = null; // remember temp so theme toggle can re-colour it
function setTheme(t){
  document.documentElement.dataset.theme = t;
  document.getElementById('theme-btn').textContent = t === 'dark' ? '☀️' : '🌙';
  try { localStorage.setItem('wx-theme', t); } catch(e){}
  updatePhotoBackground(null);
  if(_lastTemp !== null){
    const el = document.getElementById('temp-val');
    if(el) el.style.color = tempColor(_lastTemp);
  }
  if(_tempData.length) drawTempChart(_tempData);
  if(_rainData.length) drawRainChart(_rainData);
  const mc = document.getElementById('mesh-canvas');
  if(mc) mc.style.opacity = t === 'dark' ? '1' : '0.35';
}
function toggleTheme(){ setTheme(isDark() ? 'light' : 'dark'); }
document.getElementById('theme-btn').addEventListener('click', toggleTheme);
(function initTheme(){
  document.documentElement.dataset.theme='dark';
  try{localStorage.removeItem('wx-theme');}catch(e){}
})();

// ── Chart colour helpers ──────────────────────────────────
const CC = {
  get grid()     { return isDark() ? 'rgba(255,255,255,.05)' : 'rgba(0,0,0,.10)'; },
  get label()    { return isDark() ? 'rgba(255,255,255,.28)' : 'rgba(0,0,0,.60)'; },
  get now()      { return isDark() ? 'rgba(255,255,255,.2)'  : 'rgba(0,0,0,.35)'; },
  get tempLine() { return isDark() ? '#4d9ff8' : '#1d4ed8'; },
  get tempFill() { return isDark() ? 'rgba(77,159,248,.18)'  : 'rgba(29,78,216,.15)'; },
  get rainBar()  { return isDark() ? '#60a5fa' : '#2563eb'; },
  get tipDot()   { return isDark() ? '#4d9ff8' : '#1d4ed8'; },
  get noData()   { return isDark() ? 'rgba(255,255,255,.15)' : 'rgba(0,0,0,.35)'; },
};

// ── Utilities ─────────────────────────────────────────────
function fmt(v,d=1){return(v==null||v==='')?'—':Number(v).toFixed(d);}
function set(id,v){const e=document.getElementById(id);if(e)e.textContent=v;}
function windDir(deg){const d=['S','SSV','SV','VSV','V','VJV','JV','JJV','J','JJZ','JZ','ZJZ','Z','ZSZ','SZ','SSZ'];return d[Math.round(deg/22.5)%16];}
function uvLabel(u){if(u<=2)return'Nizek';if(u<=5)return'Zmeren';if(u<=7)return'Visok';if(u<=10)return'Zelo visok';return'Ekstremni';}
function solarLabel(w){if(!w&&w!==0)return'—';if(w<20)return'Noč/temno';if(w<100)return'Oblačno';if(w<300)return'Delno oblačno';if(w<600)return'Pretežno sončno';return'Jasno sončno';}
function dewLabel(d){if(d<5)return'Zelo suho';if(d<10)return'Suho';if(d<15)return'Prijetno';if(d<20)return'Rahlo vlažno';return'Soparno';}

function tempColor(t){
  if(isDark()){
    // Bright, saturated colours — all high contrast on dark navy
    if(t<0)  return '#bae6fd';  // bright sky blue
    if(t<8)  return '#67e8f9';  // bright cyan
    if(t<15) return '#6ee7b7';  // bright mint
    if(t<22) return '#f1f5f9';  // bright white
    if(t<28) return '#fcd34d';  // bright amber
    if(t<35) return '#fb923c';  // bright orange
    return '#f87171';
  } else {
    if(t<0)  return '#1d4ed8';
    if(t<8)  return '#0369a1';
    if(t<15) return '#0f766e';
    if(t<22) return '#0f172a';
    if(t<28) return '#b45309';
    if(t<35) return '#c2410c';
    return '#dc2626';
  }
}
function feelsStyle(t){
  if(isDark()){
    if(t<0)  return{label:'Zmrzuje',   c:'#93c5fd',bg:'rgba(147,197,253,.1)',b:'rgba(147,197,253,.25)'};
    if(t<8)  return{label:'Mrzlo',       c:'#7dd3fc',bg:'rgba(125,211,252,.1)',b:'rgba(125,211,252,.25)'};
    if(t<15) return{label:'Hladno',       c:'#6ee7b7',bg:'rgba(110,231,183,.1)',b:'rgba(110,231,183,.25)'};
    if(t<22) return{label:'Prijetno',c:'#34d399',bg:'rgba(52,211,153,.1)', b:'rgba(52,211,153,.25)'};
    if(t<28) return{label:'Toplo',       c:'#fcd34d',bg:'rgba(252,211,77,.1)', b:'rgba(252,211,77,.25)'};
    return         {label:'Vroče',        c:'#f87171',bg:'rgba(248,113,113,.1)',b:'rgba(248,113,113,.25)'};
  } else {
    if(t<0)  return{label:'Zmrzuje',   c:'#1d4ed8',bg:'rgba(29,78,216,.08)', b:'rgba(29,78,216,.2)'};
    if(t<8)  return{label:'Mrzlo',       c:'#0369a1',bg:'rgba(3,105,161,.08)', b:'rgba(3,105,161,.2)'};
    if(t<15) return{label:'Hladno',       c:'#0f766e',bg:'rgba(15,118,110,.08)',b:'rgba(15,118,110,.2)'};
    if(t<22) return{label:'Prijetno',c:'#059669',bg:'rgba(5,150,105,.08)', b:'rgba(5,150,105,.2)'};
    if(t<28) return{label:'Toplo',       c:'#b45309',bg:'rgba(180,83,9,.08)',  b:'rgba(180,83,9,.2)'};
    return         {label:'Vroče',        c:'#dc2626',bg:'rgba(220,38,38,.08)', b:'rgba(220,38,38,.2)'};
  }
}
function beaufort(kmh){const s=[[1,'0','Tišina'],[5,'1','Tih zrak'],[11,'2','Lahek vetrič'],[19,'3','Blagi vetrič'],[28,'4','Zmerni vetrič'],[38,'5','Svež veter'],[49,'6','Močan veter'],[61,'7','Skoraj vihar'],[74,'8','Vihar'],[88,'9','Močan vihar'],[102,'10','Nevihta'],[117,'11','Silovit vihar'],[999,'12','Orkan']];for(const[mx,n,name]of s)if(kmh<=mx)return{n,name};return{n:'12',name:'Hurricane'};}
function countUp(id,target,dec,unitHTML,dur){
  const el=document.getElementById(id);if(!el||isNaN(Number(target)))return;
  const uHTML=unitHTML||'',t0=performance.now();
  const step=(now)=>{const p=Math.min((now-t0)/dur,1),ease=1-Math.pow(1-p,3);el.innerHTML=(Number(target)*ease).toFixed(dec)+uHTML;if(p<1)requestAnimationFrame(step);};
  requestAnimationFrame(step);
}

// ── Condition & icons ─────────────────────────────────────
function getCondition(obs){
  const pr=obs.metric.precipRate||0,sr=obs.metric.solarRadiation||obs.solarRadiation||0;
  const h=new Date().getHours(),night=h<5||h>22;
  if(pr>7)   return{icon:'⛈',label:'Močan dež'};if(pr>2.5)return{icon:'🌧',label:'Dež'};
  if(pr>0)   return{icon:'🌦',label:'Rahel dež'};if(night&&sr<10)return{icon:'🌙',label:'Jasna noč'};
  if(night)  return{icon:'☁',label:'Oblačna noč'};if(sr>700)return{icon:'☀',label:'Jasno sončno'};
  if(sr>300) return{icon:'🌤',label:'Pretežno sončno'};if(sr>80)return{icon:'⛅',label:'Delno oblačno'};
  if(sr>10)  return{icon:'🌥',label:'Pretežno oblačno'};return{icon:'☁',label:'Oblačno'};
}
