function weatherIcon(label){
  // Use _wxCond (set by updateBgFromObs) for special conditions
  const wc=typeof _wxCond==='string'?_wxCond:'';
  if(wc==='snow')        return iconSnow();
  if(wc==='fog')         return iconFog();
  if(wc==='hot')         return iconHot();
  if(wc==='storm')       return iconStorm();
  if(wc==='heavy_rain')  return iconHeavyRain();
  if(wc==='rain')        return iconRain();
  if(wc==='night')       return iconNight();
  if(wc==='cloudy')      return iconCloudy();
  if(wc==='sunny')       return iconSunny();
  const m={'Jasno sončno':iconSunny,'Pretežno sončno':iconPartlyCloudy,'Delno oblačno':iconPartlyCloudy,'Pretežno oblačno':iconCloudy,'Oblačno':iconCloudy,'Rahel dež':iconRain,'Dež':iconRain,'Močan dež':iconHeavyRain,'Jasna noč':iconNight,'Oblačna noč':iconNightCloudy,'Meglena noč':iconNightCloudy};
  return(m[label]||iconCloudy)();
}

// ── Sunrise / sunset ──────────────────────────────────────
function sunTimes(lat,lon,date){
  const rad=Math.PI/180,deg=180/Math.PI;
  const start=new Date(date.getFullYear(),0,0),doy=Math.floor((date-start)/864e5);
  const leap=(date.getFullYear()%4===0&&(date.getFullYear()%100!==0||date.getFullYear()%400===0));
  const g=2*Math.PI/(leap?366:365)*(doy-1);
  const eqtime=229.18*(0.000075+0.001868*Math.cos(g)-0.032077*Math.sin(g)-0.014615*Math.cos(2*g)-0.04089*Math.sin(2*g));
  const decl=0.006918-0.399912*Math.cos(g)+0.070257*Math.sin(g)-0.006758*Math.cos(2*g)+0.000907*Math.sin(2*g)-0.002697*Math.cos(3*g)+0.00148*Math.sin(3*g);
  const cosHA=(Math.cos(90.833*rad)-(Math.sin(lat*rad)*Math.sin(decl)))/(Math.cos(lat*rad)*Math.cos(decl));
  if(Math.abs(cosHA)>1)return null;
  const ha=deg*Math.acos(cosHA),noon=720-4*lon-eqtime;
  return{sunrise:new Date(Date.UTC(date.getFullYear(),date.getMonth(),date.getDate(),0,Math.round(noon-4*ha))),sunset:new Date(Date.UTC(date.getFullYear(),date.getMonth(),date.getDate(),0,Math.round(noon+4*ha)))};
}
function fmtTime(d){return d.toLocaleTimeString([],{hour:'2-digit',minute:'2-digit'});}
function updateSunArc(lat,lon){
  const now=new Date(),st=sunTimes(lat,lon,now);if(!st)return;
  set('sunrise-time',fmtTime(st.sunrise));set('sunset-time',fmtTime(st.sunset));
  const dur=st.sunset-st.sunrise,dh=Math.floor(dur/36e5),dm=Math.floor((dur%36e5)/6e4);
  set('daylen',dh+'h '+(dm<10?'0':'')+dm+'m');
  const t=Math.max(0,Math.min(1,(now-st.sunrise)/(st.sunset-st.sunrise)));
  const cx=130,cy=125,r=115,theta=Math.PI*(1-t),sx=cx+r*Math.cos(theta),sy=cy-r*Math.sin(theta);
  const sd=document.getElementById('sun-dot'),sh=document.getElementById('sun-halo'),sp=document.getElementById('sun-progress');
  if(sd){sd.setAttribute('cx',sx);sd.setAttribute('cy',sy);sd.setAttribute('opacity',t>0&&t<1?'1':'0.3');}
  if(sh){sh.setAttribute('cx',sx);sh.setAttribute('cy',sy);sh.setAttribute('opacity','0.5');}
  if(sp){const lg=t>0.5?1:0;sp.setAttribute('d',t>=0.99?'M 15 125 A 115 115 0 0 1 245 125':t<=0.01?'M 15 125':'M 15 125 A 115 115 0 '+lg+' 1 '+sx.toFixed(1)+' '+sy.toFixed(1));}
  const sr=document.getElementById('sr-label'),ss=document.getElementById('ss-label');
  if(sr)sr.textContent=fmtTime(st.sunrise);if(ss)ss.textContent=fmtTime(st.sunset);
}

// ── Background effects ────────────────────────────────────
function setBgEffect(type){
  const bg=document.getElementById('bg');bg.querySelectorAll('.rain-drop,.star').forEach(e=>e.remove());
  if(type==='rain'){for(let i=0;i<60;i++){const d=document.createElement('div');d.className='rain-drop';d.style.cssText='left:'+Math.random()*110+'%;height:'+(12+Math.random()*18)+'px;animation-delay:'+(-Math.random()*2)+'s;animation-duration:'+(0.5+Math.random()*0.4)+'s;opacity:'+(0.25+Math.random()*0.25);bg.appendChild(d);}}
  else if(type==='night'){for(let i=0;i<100;i++){const s=document.createElement('div');s.className='star';const sz=.5+Math.random()*2;s.style.cssText='left:'+Math.random()*100+'%;top:'+Math.random()*65+'%;width:'+sz+'px;height:'+sz+'px;animation-delay:'+Math.random()*4+'s;animation-duration:'+(2+Math.random()*3)+'s';bg.appendChild(s);}}
}

// ── Pressure arc ──────────────────────────────────────────
function updatePressureArc(p){
  const t=Math.max(0,Math.min(1,(p-970)/80));
  const cx=65,cy=62,r=52,theta=Math.PI*(1-t),x=cx+r*Math.cos(theta),y=cy-r*Math.sin(theta);
  const dot=document.getElementById('p-dot');if(dot){dot.setAttribute('cx',x.toFixed(1));dot.setAttribute('cy',y.toFixed(1));}
}

// ── Charts ────────────────────────────────────────────────
function smoothPath(pts){if(pts.length<2)return'';let d='M '+pts[0].x+' '+pts[0].y;for(let i=1;i<pts.length;i++){const p0=pts[i-2]||pts[0],p1=pts[i-1],p2=pts[i],p3=pts[i+1]||p2;const c1x=p1.x+(p2.x-p0.x)/6,c1y=p1.y+(p2.y-p0.y)/6,c2x=p2.x-(p3.x-p1.x)/6,c2y=p2.y-(p3.y-p1.y)/6;d+=' C '+c1x.toFixed(1)+','+c1y.toFixed(1)+' '+c2x.toFixed(1)+','+c2y.toFixed(1)+' '+p2.x.toFixed(1)+','+p2.y.toFixed(1);}return d;}
function mkSVG(parent,tag,attrs){const el=document.createElementNS('http://www.w3.org/2000/svg',tag);for(const[k,v]of Object.entries(attrs))el.setAttribute(k,v);parent.appendChild(el);return el;}
function mouseToSVGX(svg,evt){const r=svg.getBoundingClientRect(),vb=svg.viewBox.baseVal;return(evt.clientX-r.left)/r.width*vb.width;}
// Attach mouse + touch scrubbing to a chart SVG. onMove(svgX,clientX,clientY) updates the
// crosshair/tooltip; onLeave hides it. Touch drag scrubs values (preventDefault stops page scroll).
function attachScrub(svg,onMove,onLeave){
  const xFromClient=cx=>{const r=svg.getBoundingClientRect(),vb=svg.viewBox.baseVal;return(cx-r.left)/r.width*vb.width;};
  svg.addEventListener('mousemove',e=>onMove(xFromClient(e.clientX),e.clientX,e.clientY));
  svg.addEventListener('mouseleave',onLeave);
  svg.addEventListener('touchstart',e=>{const t=e.touches[0];onMove(xFromClient(t.clientX),t.clientX,t.clientY);},{passive:true});
  svg.addEventListener('touchmove',e=>{const t=e.touches[0];onMove(xFromClient(t.clientX),t.clientX,t.clientY);},{passive:true});
  svg.addEventListener('touchend',onLeave);
  svg.addEventListener('touchcancel',onLeave);
}

let _tempData=[],_rainData=[],_hourlyObs=[],_forecastHours=[];
let _sliderActive=false,_liveTemp=null,_liveTempColor='',_liveIconHtml='';
function drawTempChart(data){
  const svg=document.getElementById('temp-svg');if(!svg||!data.length)return;
  svg.innerHTML='';_tempData=data;
  const VW=880,VH=200,pad={t:25,r:20,b:42,l:46},cw=VW-pad.l-pad.r,ch=VH-pad.t-pad.b;
  const temps=data.map(d=>d.temp),mn=Math.min(...temps),mx=Math.max(...temps),yMin=mn-1,yMax=mx+1;
  const xS=i=>pad.l+i/(data.length-1)*cw,yS=v=>pad.t+(1-(v-yMin)/(yMax-yMin))*ch;

  // Temperature-mapped gradient stops (horizontal, by position)
  const step=Math.max(1,Math.floor(data.length/24));
  let lineStops='',fillStops='';
  for(let i=0;i<data.length;i+=step){
    const pct=((i/(data.length-1))*100).toFixed(1)+'%';
    const c=tempColor(data[i].temp);
    lineStops+=`<stop offset="${pct}" stop-color="${c}" stop-opacity="0.9"/>`;
    fillStops+=`<stop offset="${pct}" stop-color="${c}" stop-opacity="0.18"/>`;
  }
  const lastC=tempColor(data[data.length-1].temp);
  lineStops+=`<stop offset="100%" stop-color="${lastC}" stop-opacity="0.9"/>`;
  fillStops+=`<stop offset="100%" stop-color="${lastC}" stop-opacity="0.18"/>`;

  const defs=mkSVG(svg,'defs',{});
  defs.innerHTML=
    `<linearGradient id="tl" x1="0" y1="0" x2="1" y2="0">${lineStops}</linearGradient>`+
    `<linearGradient id="tf" x1="0" y1="0" x2="1" y2="0">${fillStops}</linearGradient>`+
    `<linearGradient id="tfv" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="white" stop-opacity="1"/><stop offset="100%" stop-color="white" stop-opacity="0"/></linearGradient>`+
    `<mask id="tfm"><rect x="${pad.l}" y="${pad.t}" width="${cw}" height="${ch}" fill="url(#tfv)"/></mask>`+
    `<filter id="lg"><feGaussianBlur stdDeviation="1.5" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter>`;

  // Grid
  for(let i=0;i<=5;i++){const y=pad.t+i/5*ch,val=yMax-(i/5*(yMax-yMin));
    mkSVG(svg,'line',{x1:pad.l,x2:VW-pad.r,y1:y,y2:y,stroke:CC.grid,'stroke-width':'1','stroke-dasharray':'4,4'});
    const t=mkSVG(svg,'text',{x:pad.l-6,y:y+4,'text-anchor':'end','font-size':'9',fill:CC.label,'font-family':'JetBrains Mono,monospace'});
    t.textContent=val.toFixed(1)+'°';}
  data.forEach((d,i)=>{if(d.time.getHours()%4===0){const h=d.time.getHours(),t=mkSVG(svg,'text',{x:xS(i),y:VH-4,'text-anchor':'middle','font-size':'9',fill:CC.label,'font-family':'JetBrains Mono,monospace'});t.textContent=(h<10?'0':'')+h+':00';}});

  const pts=data.map((d,i)=>({x:xS(i),y:yS(d.temp)})),lp=smoothPath(pts);

  // Gradient fill area (masked to fade at top)
  const fillPath=mkSVG(svg,'path',{d:lp+' L '+xS(data.length-1)+','+(VH-pad.b)+' L '+xS(0)+','+(VH-pad.b)+' Z',fill:'url(#tf)',mask:'url(#tfm)',opacity:'0.7'});

  // Animated temperature line
  const linePath=mkSVG(svg,'path',{d:lp,fill:'none',stroke:'url(#tl)','stroke-width':'2.8',filter:'url(#lg)','stroke-linecap':'round','stroke-linejoin':'round'});
  try{
    const len=Math.ceil(linePath.getTotalLength());
    linePath.style.strokeDasharray=len;
    linePath.style.strokeDashoffset=len;
    linePath.style.transition='stroke-dashoffset 1.5s cubic-bezier(.4,0,.2,1)';
    requestAnimationFrame(()=>requestAnimationFrame(()=>{linePath.style.strokeDashoffset='0';}));
  }catch(e){}

  // Now line
  const now=new Date(),f0=data[0].time,fl=data[data.length-1].time,nt=(now-f0)/(fl-f0);
  if(nt>=0&&nt<=1){const nx=pad.l+nt*cw;
    mkSVG(svg,'line',{x1:nx,x2:nx,y1:pad.t,y2:VH-pad.b,stroke:CC.now,'stroke-width':'1','stroke-dasharray':'4,3'});
    const nl=mkSVG(svg,'text',{x:nx+4,y:pad.t+10,'font-size':'8',fill:CC.now,'font-family':'JetBrains Mono,monospace'});
    nl.textContent='zdaj';}

  const tipDot=mkSVG(svg,'circle',{cx:0,cy:0,r:'5',fill:CC.tipDot,stroke:'white','stroke-width':'2',opacity:'0',style:'pointer-events:none'});
  const tipLine=mkSVG(svg,'line',{x1:0,x2:0,y1:pad.t,y2:VH-pad.b,stroke:CC.now,'stroke-width':'1','stroke-dasharray':'3,2',opacity:'0',style:'pointer-events:none'});
  mkSVG(svg,'rect',{x:pad.l,y:pad.t,width:cw,height:ch,fill:'transparent'});
  const tip=document.getElementById('chart-tip');
  attachScrub(svg,(sx,clientX,clientY)=>{if(!_tempData.length)return;const idx=Math.max(0,Math.min(_tempData.length-1,Math.round((sx-pad.l)/cw*(_tempData.length-1))));const d=_tempData[idx];if(!d)return;const px=xS(idx),py=yS(d.temp);tipDot.setAttribute('cx',px);tipDot.setAttribute('cy',py);tipDot.setAttribute('opacity','1');tipDot.setAttribute('fill',tempColor(d.temp));tipLine.setAttribute('x1',px);tipLine.setAttribute('x2',px);tipLine.setAttribute('opacity','1');tip.innerHTML='<span style="color:'+tempColor(d.temp)+';font-weight:600">'+d.temp.toFixed(1)+'°C</span>&ensp;'+d.time.toLocaleTimeString([],{hour:'2-digit',minute:'2-digit'});tip.style.opacity='1';tip.style.left=Math.min(clientX+14,window.innerWidth-120)+'px';tip.style.top=Math.max(8,clientY-28)+'px';},()=>{tipDot.setAttribute('opacity','0');tipLine.setAttribute('opacity','0');tip.style.opacity='0';});
  set('temp-range',fmt(mn,1)+'° – '+fmt(mx,1)+'°C');
}
function drawRainChart(data){
  const svg=document.getElementById('rain-svg');if(!svg||!data.length)return;
  svg.innerHTML='';_rainData=data;
  const VW=880,VH=150,pad={t:15,r:20,b:42,l:46},cw=VW-pad.l-pad.r,ch=VH-pad.t-pad.b;
  const maxR=Math.max(...data.map(d=>d.rain),.5),total=data.reduce((a,b)=>a+b.rain,0);
  const defs=mkSVG(svg,'defs',{});
  defs.innerHTML=
    `<linearGradient id="rg" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="${CC.rainBar}" stop-opacity="0.85"/><stop offset="100%" stop-color="${CC.rainBar}" stop-opacity="0.12"/></linearGradient>`+
    `<filter id="rblur"><feGaussianBlur stdDeviation="0.8"/></filter>`;
  for(let i=0;i<=3;i++){const y=pad.t+i/3*ch,val=maxR*(1-i/3);
    mkSVG(svg,'line',{x1:pad.l,x2:VW-pad.r,y1:y,y2:y,stroke:CC.grid,'stroke-width':'1','stroke-dasharray':'4,4'});
    if(val>0){const t=mkSVG(svg,'text',{x:pad.l-5,y:y+4,'text-anchor':'end','font-size':'9',fill:CC.label,'font-family':'JetBrains Mono,monospace'});t.textContent=val.toFixed(1);}}
  const bw=Math.max(3,(cw/data.length)*.72),xS=i=>pad.l+i/data.length*cw;
  const tipDot=mkSVG(svg,'circle',{cx:0,cy:0,r:'4',fill:CC.rainBar,stroke:'white','stroke-width':'1.5',opacity:'0',style:'pointer-events:none'});
  const tipLine=mkSVG(svg,'line',{x1:0,x2:0,y1:pad.t,y2:VH-pad.b,stroke:CC.now,'stroke-width':'1','stroke-dasharray':'3,2',opacity:'0',style:'pointer-events:none'});
  data.forEach((d,i)=>{
    const x=xS(i),h=(d.rain/maxR)*ch;
    if(d.rain>0){
      // Main bar
      const bar=mkSVG(svg,'rect',{x:(x-bw/2).toFixed(1),y:(pad.t+ch-h).toFixed(1),width:bw.toFixed(1),height:h.toFixed(1),fill:'url(#rg)',rx:'3'});
      // Subtle top glow line
      mkSVG(svg,'rect',{x:(x-bw/2).toFixed(1),y:(pad.t+ch-h).toFixed(1),width:bw.toFixed(1),height:'2',fill:CC.rainBar,rx:'1',opacity:'0.6'});
    }
    if(d.time.getHours()%4===0){const hr=d.time.getHours(),t=mkSVG(svg,'text',{x:x,y:VH-4,'text-anchor':'middle','font-size':'9',fill:CC.label,'font-family':'JetBrains Mono,monospace'});t.textContent=(hr<10?'0':'')+hr+':00';}
  });
  if(total<.1){const t=mkSVG(svg,'text',{x:VW/2,y:VH/2,'text-anchor':'middle','font-size':'12',fill:CC.noData,'font-family':'Inter,sans-serif'});t.textContent='Ni padavin v zadnjih 24 urah';}
  mkSVG(svg,'rect',{x:pad.l,y:pad.t,width:cw,height:ch,fill:'transparent'});
  const tip=document.getElementById('chart-tip');
  attachScrub(svg,(sx,clientX,clientY)=>{if(!_rainData.length)return;const idx=Math.max(0,Math.min(_rainData.length-1,Math.round((sx-pad.l)/cw*(_rainData.length-1))));const d=_rainData[idx];if(!d)return;const px=xS(idx),py=pad.t+ch-(d.rain/maxR)*ch;tipDot.setAttribute('cx',px);tipDot.setAttribute('cy',Math.max(pad.t+4,py));tipDot.setAttribute('opacity','1');tipLine.setAttribute('x1',px);tipLine.setAttribute('x2',px);tipLine.setAttribute('opacity','1');tip.innerHTML='<span style="color:'+CC.rainBar+';font-weight:600">'+d.rain.toFixed(2)+' mm</span>&ensp;'+d.time.toLocaleTimeString([],{hour:'2-digit',minute:'2-digit'});tip.style.opacity='1';tip.style.left=Math.min(clientX+14,window.innerWidth-120)+'px';tip.style.top=Math.max(8,clientY-28)+'px';},()=>{tipDot.setAttribute('opacity','0');tipLine.setAttribute('opacity','0');tip.style.opacity='0';});
  set('rain-range','Skupaj: '+total.toFixed(1)+' mm');
}

