function buildDailySummaries(observations){
  const byDay={};
  observations.forEach(o=>{
    const day=o.obsTimeLocal.slice(0,10);
    if(!byDay[day]) byDay[day]={date:day,highs:[],lows:[],temps:[],rains:[],winds:[],gusts:[],hums:[]};
    const m=o.metric;
    // Daily max/min come from each hour's own high/low — using the hourly
    // average smooths the peak away (npr. 36,2° se prikaže kot 35,4°).
    if(m.tempHigh!=null)       byDay[day].highs.push(m.tempHigh);
    else if(m.tempAvg!=null)   byDay[day].highs.push(m.tempAvg);
    if(m.tempLow!=null)        byDay[day].lows.push(m.tempLow);
    else if(m.tempAvg!=null)   byDay[day].lows.push(m.tempAvg);
    if(m.tempAvg!=null)        byDay[day].temps.push(m.tempAvg);
    if(m.precipTotal!=null)    byDay[day].rains.push(m.precipTotal);
    if(m.windspeedAvg!=null)   byDay[day].winds.push(m.windspeedAvg);
    if(m.windspeedHigh!=null)  byDay[day].gusts.push(m.windspeedHigh);
    if(m.humidityAvg!=null)    byDay[day].hums.push(m.humidityAvg);
  });
  return Object.values(byDay)
    .map(d=>({
      obsTimeLocal:d.date,
      metric:{
        tempHigh:      d.highs.length ? Math.max(...d.highs) : null,
        tempLow:       d.lows.length ? Math.min(...d.lows) : null,
        tempAvg:       d.temps.length ? d.temps.reduce((a,b)=>a+b,0)/d.temps.length : null,
        precipTotal:   d.rains.length ? Math.max(...d.rains) : 0,
        windspeedAvg:  d.winds.length ? d.winds.reduce((a,b)=>a+b,0)/d.winds.length : null,
        windspeedHigh: d.gusts.length ? Math.max(...d.gusts) : null,
        humidityAvg:   d.hums.length  ? Math.round(d.hums.reduce((a,b)=>a+b,0)/d.hums.length) : null,
      }
    }))
    .sort((a,b)=>a.obsTimeLocal.localeCompare(b.obsTimeLocal));
}

function applyHourly(observations){
  const raw=observations.slice(-24);
  drawTempChart(raw.map(o=>({time:new Date(o.obsTimeLocal.replace(' ','T')),temp:o.metric.tempAvg??o.metric.temp??0})));
  drawRainChart(raw.map((o,i,arr)=>{
    const curr=o.metric.precipTotal??0;
    if(i===0) return{time:new Date(o.obsTimeLocal.replace(' ','T')),rain:0};
    const prevDay=arr[i-1].obsTimeLocal.slice(0,10),currDay=o.obsTimeLocal.slice(0,10);
    const inc=currDay!==prevDay?curr:Math.max(0,curr-(arr[i-1].metric.precipTotal??0));
    return{time:new Date(o.obsTimeLocal.replace(' ','T')),rain:inc};
  }));
  applyDayStats(observations);applyPressureTrend(observations);
  drawWindRose(observations);drawWindTrend(observations);drawWindDist(observations);applyYesterdayDelta(observations);
  drawHourlyProfile(observations);
  _hourlyObs=observations;
  _autoInitAI();
  _histCache['7']=buildDailySummaries(observations);   // always build, never just delete
  saveToLocalHistory(_histCache['7']);
  fetchForecastTrust();
  if(_lastBriefObs)renderWeatherMemory(_lastBriefObs);
  renderStormAutopsy();
  refreshInsights();
  if(histTabActive()&&_currentPeriod==='7') applyHistory(_histCache['7']);
}

// ── Forecast ──────────────────────────────────────────────
// ── 5-day forecast — Open-Meteo (brez API ključa) ────────
// ── Station On This Day ───────────────────────────────────
function metricToCondition(m){
  if(!m) return{emoji:'—',desc:'Ni podatkov'};
  const r=m.precipTotal||0, t=m.tempAvg??m.tempHigh??0, w=m.windspeedHigh||0;
  if(t<=0&&r>0)  return{emoji:'❄️',desc:'Sneg/slana'};
  if(t<=0)       return{emoji:'🌡',desc:'Zmrzuje'};
  if(r>15)       return{emoji:'⛈', desc:'Močan dež'};
  if(r>5)        return{emoji:'🌧', desc:'Dežen dan'};
  if(r>1)        return{emoji:'🌦', desc:'Plohe'};
  if(r>0)        return{emoji:'🌦', desc:'Rahel dež'};
  if(w>50)       return{emoji:'🌬', desc:'Viharno'};
  if(t>30)       return{emoji:'🌡', desc:'Vročinski val'};
  if(t>24)       return{emoji:'☀️', desc:'Vroče'};
  if(t>18)       return{emoji:'🌤', desc:'Sončno'};
  if(t>12)       return{emoji:'⛅', desc:'Prijetno'};
  return                {emoji:'🌥', desc:'Hladno'};
}

function getStationOnThisDay(){
  try{
    const stored=JSON.parse(localStorage.getItem(LS_KEY)||'{}');
    const today=new Date();
    const mm=String(today.getMonth()+1).padStart(2,'0');
    const dd=String(today.getDate()).padStart(2,'0');
    const yy=today.getFullYear();
    return [1,2,3,4,5].map(n=>{
      const yr=yy-n, key=yr+'-'+mm+'-'+dd;
      return{year:yr,date:key,metric:stored[key]||null};
    });
  }catch(e){return[];}
}

// Klimatologija za današnji koledarski datum (±okno dni) iz celotne shrambe.
function getDayClimatology(){
  try{
    const stored=JSON.parse(localStorage.getItem(LS_KEY)||'{}');
    const doy=d=>Math.floor((d-new Date(d.getFullYear(),0,0))/86400000);
    const target=doy(new Date());
    const WIN=3;
    let sumHi=0,nHi=0,sumLo=0,nLo=0,sumAvg=0,nAvg=0;
    let recHi=null,recLo=null,wettest=null;
    const years=new Set();
    for(const k in stored){
      const p=k.split('-');
      if(p.length!==3)continue;
      const dt=new Date(+p[0],+p[1]-1,+p[2]);
      if(isNaN(dt))continue;
      let diff=Math.abs(doy(dt)-target);
      if(diff>182)diff=365-diff;           // ovoj čez konec leta
      if(diff>WIN)continue;
      const m=stored[k];if(!m)continue;
      const yr=+p[0];
      if(m.tempHigh!=null){sumHi+=m.tempHigh;nHi++;years.add(yr);if(!recHi||m.tempHigh>recHi.v)recHi={v:m.tempHigh,year:yr};}
      if(m.tempLow!=null){sumLo+=m.tempLow;nLo++;if(!recLo||m.tempLow<recLo.v)recLo={v:m.tempLow,year:yr};}
      if(m.tempAvg!=null){sumAvg+=m.tempAvg;nAvg++;}
      if(m.precipTotal>0&&(!wettest||m.precipTotal>wettest.v))wettest={v:m.precipTotal,year:yr};
    }
    if(nHi<3&&nLo<3)return null;
    return{
      meanHigh:nHi?sumHi/nHi:null,
      meanLow:nLo?sumLo/nLo:null,
      meanAvg:nAvg?sumAvg/nAvg:null,
      years:years.size,
      recHigh:recHi,recLow:recLo,wettest,window:WIN
    };
  }catch(e){return null;}
}

function applyDayClimatology(){
  const el=document.getElementById('otd-station-clim');
  if(!el)return;
  const clim=getDayClimatology();
  if(!clim){el.innerHTML='';el.style.display='none';return;}
  el.style.display='';
  const dstr=new Date().toLocaleDateString('sl',{day:'numeric',month:'short'});
  const f1=v=>v==null?'—':v.toFixed(1).replace('.',',');
  let html='';
  html+='<div class="otd-clim-row"><span class="otd-clim-lbl">Normala za '+dstr+'</span>'+
        '<span class="otd-clim-val"><strong style="color:#f87171">'+f1(clim.meanHigh)+'°</strong> / <strong style="color:var(--blue)">'+f1(clim.meanLow)+'°</strong>'+
        ' <span class="otd-clim-n">('+clim.years+' let)</span></span></div>';
  if(clim.recHigh||clim.recLow){
    html+='<div class="otd-clim-row"><span class="otd-clim-lbl">Rekord</span><span class="otd-clim-val">';
    if(clim.recHigh)html+='🔥 <strong style="color:var(--red)">'+f1(clim.recHigh.v)+'°</strong> ('+clim.recHigh.year+')';
    if(clim.recHigh&&clim.recLow)html+=' · ';
    if(clim.recLow)html+='❄️ <strong style="color:var(--blue)">'+f1(clim.recLow.v)+'°</strong> ('+clim.recLow.year+')';
    html+='</span></div>';
  }
  if(typeof _liveTemp==='number'&&isFinite(_liveTemp)&&clim.meanAvg!=null){
    const an=_liveTemp-clim.meanAvg;
    const col=Math.abs(an)<1?'var(--muted)':an>0?'var(--red)':'var(--blue)';
    const word=Math.abs(an)<1?'blizu dnevnega povprečja':an>0?'nad dnevnim povprečjem':'pod dnevnim povprečjem';
    html+='<div class="otd-clim-row otd-clim-anom"><span class="otd-clim-lbl">Zdaj '+f1(_liveTemp)+'°</span>'+
          '<span class="otd-clim-val" style="color:'+col+'"><strong>'+(an>=0?'+':'−')+f1(Math.abs(an))+'°</strong> '+word+' za ta datum</span></div>';
  }
  el.innerHTML=html;
}

function applyStationOnThisDay(){
  const grid=document.getElementById('otd-station-grid');
  if(!grid){applyDayClimatology();return;}
  const today=new Date();
  const titleEl=document.getElementById('otd-station-title');
  if(titleEl)titleEl.textContent='📡 '+today.toLocaleDateString('sl',{day:'numeric',month:'long'})+' — postaja IREICA1';
  const results=getStationOnThisDay();
  grid.innerHTML='';
  results.forEach(r=>{
    const item=document.createElement('div');item.className='otd-item';
    if(!r.metric){
      item.innerHTML='<div class="otd-year">'+r.year+'</div><div class="otd-emoji" style="font-size:1.1rem;color:var(--muted)">—</div><div class="otd-desc" style="font-size:.72rem">Ni podatkov</div>';
    }else{
      const c=metricToCondition(r.metric);
      item.innerHTML=
        '<div class="otd-year">'+r.year+'</div>'+
        '<div class="otd-emoji">'+c.emoji+'</div>'+
        '<div class="otd-desc">'+c.desc+'</div>'+
        '<div class="otd-temps"><span class="th">'+(r.metric.tempHigh!=null?r.metric.tempHigh.toFixed(1):'—')+'°</span><span style="color:var(--muted)">/</span><span class="tl">'+(r.metric.tempLow!=null?r.metric.tempLow.toFixed(1):'—')+'°</span></div>'+
        (r.metric.precipTotal>0?'<div class="otd-rain">🌧 '+r.metric.precipTotal.toFixed(1)+' mm</div>':'')+
        (r.metric.windspeedHigh!=null?'<div class="otd-wind">💨 '+r.metric.windspeedHigh.toFixed(1)+' km/h</div>':'');
    }
    grid.appendChild(item);
  });
  const filled=results.filter(r=>r.metric).length;
  const src=document.getElementById('otd-station-source');
  if(src)src.textContent=filled>0?filled+'/5 let podatkov':'Shramba prazna — zbira se z obiski';
  applyDayClimatology();
}

