function wmoInfo(code){
  if(code==null)return{emoji:'❓',desc:'Neznano'};
  if(code===0)  return{emoji:'☀️',desc:'Jasno'};
  if(code<=2)   return{emoji:'🌤',desc:'Pretežno sončno'};
  if(code<=3)   return{emoji:'⛅',desc:'Delno oblačno'};
  if(code<=9)   return{emoji:'🌫',desc:'Oblačno'};
  if(code<=19)  return{emoji:'🌦',desc:'Plohe'};
  if(code<=29)  return{emoji:'⛈',desc:'Nevihte'};
  if(code<=39)  return{emoji:'🌬',desc:'Prah/pesek'};
  if(code<=49)  return{emoji:'🌫',desc:'Megla'};
  if(code<=59)  return{emoji:'🌦',desc:'Rosenje'};
  if(code<=69)  return{emoji:'🌧',desc:'Dež'};
  if(code<=79)  return{emoji:'❄️',desc:'Sneg'};
  if(code<=84)  return{emoji:'🌦',desc:'Dežne plohe'};
  if(code<=90)  return{emoji:'🌨',desc:'Snežne plohe'};
  if(code<=99)  return{emoji:'⛈',desc:'Nevihta'};
  return{emoji:'❓',desc:'Neznano'};
}

