let _galleryPhotos = [];
let _galleryLoaded = false;
let _lbIdx = 0;
let _galleryPendingFile = null;

function galleryOpenPicker(){
  const inp = document.createElement('input');
  inp.type = 'file';
  inp.accept = 'image/*';
  inp.onchange = () => { if(inp.files[0]) galleryFileSelected(inp.files[0]); };
  inp.click();
}

function initGallery(){
  if(!_galleryLoaded){ _galleryLoaded=true; loadGallery(); }
  const drop = document.getElementById('gallery-drop');
  if(drop && !drop._ddSetup){
    drop._ddSetup = true;
    drop.addEventListener('dragover', e=>{ e.preventDefault(); drop.classList.add('drag-over'); });
    drop.addEventListener('dragleave', ()=>drop.classList.remove('drag-over'));
    drop.addEventListener('drop', e=>{ e.preventDefault(); drop.classList.remove('drag-over'); const f=e.dataTransfer.files[0]; if(f)galleryFileSelected(f); });
  }
}

async function loadGallery(){
  const grid = document.getElementById('gallery-grid');
  const cnt = document.getElementById('gallery-count');
  try {
    const res = await fetch(PROXY+'/gallery?category=general', { cache:'no-cache' });
    const data = await res.json();
    _galleryPhotos = data.photos || [];
    if(cnt) cnt.textContent = _galleryPhotos.length ? _galleryPhotos.length+' fotografij' : '';
    renderGallery();
  } catch(e){
    if(grid) grid.innerHTML='<div class="gallery-empty"><div class="gallery-empty-icon">⚠️</div><div class="gallery-empty-text">Napaka pri nalaganju fotografij.</div></div>';
  }
}

function renderGallery(){
  const grid = document.getElementById('gallery-grid');
  if(!grid) return;
  if(!_galleryPhotos.length){
    grid.innerHTML='<div class="gallery-empty"><div class="gallery-empty-icon">📷</div><div class="gallery-empty-text">Še ni fotografij. Bodi prvi!</div></div>';
    return;
  }
  grid.innerHTML = _galleryPhotos.map((p,i)=>{
    const imgUrl = PROXY+'/gallery/img/'+encodeURIComponent(p.key);
    const date = p.uploadedAt ? new Date(p.uploadedAt).toLocaleDateString('sl-SI',{day:'numeric',month:'long',year:'numeric'}) : '';
    const author = p.author && p.author!=='Anonimno' ? p.author : '';
    const meta = [date, author].filter(Boolean).join(' · ');
    return `<div class="gallery-card" onclick="openGalleryLightbox(${i})">
      <img src="${imgUrl}" alt="${p.title||''}" loading="lazy">
      <div class="gallery-card-overlay">
        <div class="gallery-card-title">${p.title||'Brez naslova'}</div>
        ${meta?`<div class="gallery-card-meta">${meta}</div>`:''}
      </div>
      <button class="gallery-card-del" title="Izbriši" onclick="event.stopPropagation();galleryDelete(${i})">✕</button>
    </div>`;
  }).join('');
}

function galleryFileSelected(file){
  if(!file) return;
  if(!file.type.startsWith('image/')){
    showToast('Prosimo naložite sliko (JPEG, PNG, WebP).');
    return;
  }
  _galleryPendingFile = file;
  const reader = new FileReader();
  reader.onload = e => {
    const img = document.getElementById('gallery-preview-img');
    if(img) img.src = e.target.result;
  };
  reader.readAsDataURL(file);
  const chip = document.getElementById('gallery-weather-chip-val');
  const t = document.getElementById('temp-val')?.textContent?.trim();
  const cond = document.getElementById('cond-label')?.textContent?.trim();
  if(chip) chip.textContent = [t ? t+'°C' : '', cond].filter(Boolean).join(' · ') || 'ni podatkov';
  document.getElementById('gallery-upload-modal')?.classList.add('open');
  // file input is dynamic, no need to reset
}

function closeGalleryUploadModal(){
  document.getElementById('gallery-upload-modal')?.classList.remove('open');
  _galleryPendingFile = null;
}

async function gallerySubmitUpload(){
  if(!_galleryPendingFile) return;
  const btn = document.getElementById('gallery-submit-btn');
  const prog = document.getElementById('gallery-progress');
  const fill = document.getElementById('gallery-progress-fill');
  btn.disabled = true;
  btn.textContent = 'Nalagam…';
  if(prog){ prog.style.display='block'; fill.style.width='30%'; }
  const fd = new FormData();
  fd.append('photo', _galleryPendingFile);
  fd.append('title',   document.getElementById('gallery-title')?.value?.trim() || '');
  fd.append('caption', document.getElementById('gallery-caption')?.value?.trim() || '');
  fd.append('author',  document.getElementById('gallery-author')?.value?.trim() || 'Anonimno');
  const chip = document.getElementById('gallery-weather-chip-val')?.textContent || '';
  fd.append('weather', chip);
  try {
    if(fill) fill.style.width='65%';
    const res = await fetch(PROXY+'/gallery/upload', { method:'POST', body:fd });
    const data = await res.json();
    if(!res.ok || !data.ok) throw new Error(data.error || 'Napaka pri nalaganju');
    if(fill) fill.style.width='100%';
    // Optimistic update — dodamo sliko direktno brez re-fetcha (nič ne flicera)
    _galleryPhotos.unshift({
      key: data.key,
      uploaded: new Date().toISOString(),
      uploadedAt: new Date().toISOString(),
      contentType: _galleryPendingFile.type,
      title:   fd.get('title')   || '',
      caption: fd.get('caption') || '',
      author:  fd.get('author')  || 'Anonimno',
      weather: chip
    });
    closeGalleryUploadModal();
    showToast('Fotografija uspešno naložena! 📸');
    const _cnt = document.getElementById('gallery-count');
    if(_cnt) _cnt.textContent = _galleryPhotos.length+' fotografij';
    requestAnimationFrame(renderGallery);
    ['gallery-title','gallery-caption','gallery-author'].forEach(id=>{ const el=document.getElementById(id); if(el)el.value=''; });
  } catch(e){
    showToast('Napaka: '+e.message);
  } finally {
    btn.disabled = false;
    btn.textContent = '⬆ Naloži fotografijo';
    if(prog) setTimeout(()=>{ prog.style.display='none'; fill.style.width='0%'; }, 800);
  }
}

async function galleryDelete(idx){
  const photo = _galleryPhotos[idx];
  if(!photo) return;
  if(!confirm('Izbriši to fotografijo?')) return;
  let pwd = sessionStorage.getItem('_galAdminPwd');
  if(!pwd){
    pwd = prompt('Geslo za brisanje:');
    if(!pwd) return;
  }
  try {
    const res = await fetch(PROXY+'/gallery/delete/'+encodeURIComponent(photo.key), {
      method:'DELETE',
      headers:{ 'Authorization': 'Bearer '+pwd }
    });
    if(res.status === 401){
      sessionStorage.removeItem('_galAdminPwd');
      showToast('Napačno geslo.');
      return;
    }
    sessionStorage.setItem('_galAdminPwd', pwd);
    showToast('Fotografija izbrisana.');
    _galleryPhotos.splice(idx, 1);
    const _cnt2 = document.getElementById('gallery-count');
    if(_cnt2) _cnt2.textContent = _galleryPhotos.length ? _galleryPhotos.length+' fotografij' : '';
    renderGallery();
  } catch(e){
    showToast('Napaka pri brisanju.');
  }
}

function openGalleryLightbox(idx){
  _lbIdx = idx;
  _renderLightbox();
  document.getElementById('gallery-lightbox')?.classList.add('open');
  document.addEventListener('keydown', _lbKeyHandler);
}

function _renderLightbox(){
  const p = _galleryPhotos[_lbIdx];
  if(!p) return;
  const img = document.getElementById('gallery-lb-img');
  const info = document.getElementById('gallery-lb-info');
  if(img) img.src = PROXY+'/gallery/img/'+encodeURIComponent(p.key);
  if(info){
    const date = p.uploadedAt ? new Date(p.uploadedAt).toLocaleDateString('sl-SI',{day:'numeric',month:'long',year:'numeric'}) : '';
    const author = p.author && p.author!=='Anonimno' ? p.author : '';
    const meta = [date, author, p.weather].filter(Boolean).join(' · ');
    info.innerHTML = `
      <div class="gallery-lb-title">${p.title||'Brez naslova'}</div>
      ${meta?`<div class="gallery-lb-meta">${meta}</div>`:''}
      ${p.caption?`<div class="gallery-lb-caption">${p.caption}</div>`:''}
    `;
  }
  const prev = document.getElementById('gallery-lb-prev');
  const next = document.getElementById('gallery-lb-next');
  if(prev) prev.style.display = _lbIdx > 0 ? 'flex' : 'none';
  if(next) next.style.display = _lbIdx < _galleryPhotos.length-1 ? 'flex' : 'none';
}

function closeGalleryLightbox(e){
  if(e && e.target !== document.getElementById('gallery-lightbox') && !e.target.classList.contains('gallery-lb-close')) return;
  document.getElementById('gallery-lightbox')?.classList.remove('open');
  document.removeEventListener('keydown', _lbKeyHandler);
}

function galleryLbNav(dir){
  _lbIdx = Math.max(0, Math.min(_galleryPhotos.length-1, _lbIdx+dir));
  _renderLightbox();
}

function _lbKeyHandler(e){
  if(e.key==='ArrowLeft') galleryLbNav(-1);
  else if(e.key==='ArrowRight') galleryLbNav(1);
  else if(e.key==='Escape'){ document.getElementById('gallery-lightbox')?.classList.remove('open'); document.removeEventListener('keydown',_lbKeyHandler); }
}

