// ── CSV / history file import ─────────────────────────────
let _importParsed=[];

function openImport(){
  const m=document.getElementById('import-modal');if(m)m.style.display='flex';
  document.getElementById('import-preview').style.display='none';
  document.getElementById('import-confirm-btn').style.display='none';
  const fi=document.getElementById('import-file-input');if(fi)fi.value='';
  _importParsed=[];
}
function closeImport(){
  const m=document.getElementById('import-modal');if(m)m.style.display='none';
}
function handleImportDrop(e){
  e.preventDefault();
  document.getElementById('import-dropzone').style.borderColor='var(--border)';
  const file=e.dataTransfer?.files?.[0];if(file)parseImportFile(file);
}
function handleImportFile(input){
  const file=input.files?.[0];if(file)parseImportFile(file);
}

function parseImportFile(file){
  const reader=new FileReader();
  reader.onload=e=>{
    try{
      const text=e.target.result;
      const rows=text.trim().split('\n').filter(l=>l.trim()&&!l.startsWith('#'));
      if(!rows.length)throw new Error('Prazna datoteka');
      // Auto-detect format
      const header=rows[0].toLowerCase();
      let parsed=[];
      if(header.includes('date') && (header.includes('temphigh')||header.includes('maxtempm')||header.includes('max temp'))){
        parsed=parseWUcsv(rows);
      } else if(file.name.toLowerCase().includes('dayfile')||rows[0].match(/^\d{2}\/\d{2}\/\d{4}/)){
        parsed=parseCumulusDayfile(rows);
      } else if(header.includes('date')||header.includes('datum')){
        parsed=parseGenericCsv(rows);
      } else {
        parsed=parseCumulusDayfile(rows); // try anyway
      }
      _importParsed=parsed.filter(d=>d&&d.obsTimeLocal&&d.metric.tempHigh!=null);
      showImportPreview(_importParsed,file.name);
    }catch(err){
      const pv=document.getElementById('import-preview');
      if(pv){pv.style.display='block';pv.innerHTML='<span style="color:var(--red)">Napaka: '+err.message+'</span>';}
    }
  };
  reader.readAsText(file,'utf-8');
}

function _col(row,headers,...names){
  for(const n of names){const i=headers.indexOf(n);if(i>=0&&row[i]!=null&&row[i]!=='')return row[i];}
  return null;
}
function _pf(v){const n=parseFloat(v);return isNaN(n)?null:n;}
function _isoDate(str){
  if(!str)return null;
  str=str.trim();
  // YYYY-MM-DD
  if(str.match(/^\d{4}-\d{2}-\d{2}/))return str.slice(0,10);
  // DD/MM/YYYY (Cumulus)
  const dm=str.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})/);
  if(dm)return dm[3]+'-'+dm[2].padStart(2,'0')+'-'+dm[1].padStart(2,'0');
  // MM/DD/YYYY (US)
  const us=str.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})/);
  if(us)return us[3]+'-'+us[1].padStart(2,'0')+'-'+us[2].padStart(2,'0');
  // Timestamp
  const d=new Date(str);if(!isNaN(d))return d.toISOString().slice(0,10);
  return null;
}

function parseWUcsv(rows){
  const sep=rows[0].includes(';')?';':',';
  const headers=rows[0].split(sep).map(h=>h.trim().replace(/"/g,'').toLowerCase());
  return rows.slice(1).map(line=>{
    const row=line.split(sep).map(c=>c.trim().replace(/"/g,''));
    const date=_isoDate(_col(row,headers,'date','time','datetime','datum'));
    if(!date)return null;
    return{obsTimeLocal:date,metric:{
      tempHigh:   _pf(_col(row,headers,'temphigh','maxtempm','max temp (°c)','max temp','high temp (°c)','high temperature','tmax')),
      tempLow:    _pf(_col(row,headers,'templow','mintempm','min temp (°c)','min temp','low temp (°c)','low temperature','tmin')),
      tempAvg:    _pf(_col(row,headers,'tempavg','meantempm','avg temp (°c)','mean temp','avg temp','tavg')),
      precipTotal:_pf(_col(row,headers,'precipitation','precip','precipm','precipitation (mm)','rain (mm)','rainfall','rain_mm','totalprecip')),
      windspeedHigh:_pf(_col(row,headers,'windhigh','maxwindspeedm','max wind speed (km/h)','wind high','max wind','gust')),
      windspeedAvg: _pf(_col(row,headers,'windavg','meanwindspeedm','avg wind speed (km/h)','wind avg','mean wind')),
      humidityAvg:  _pf(_col(row,headers,'humidityavg','meandewpointm','humidity','avg humidity','hum avg')),
      _source:'import',
    }};
  });
}

function parseCumulusDayfile(rows){
  // Cumulus MX dayfile.txt: DD/MM/YYYY,highgust,bearinghighgust,...many cols
  // Col 0=date, 2=hightemp, 3=lowtemp, 8=totalprecip, 1=highgust, 12=avgtemp, 18=avgwind
  return rows.map(line=>{
    const sep=line.includes(';')?';':',';
    const c=line.split(sep).map(x=>x.trim());
    const date=_isoDate(c[0]);
    if(!date)return null;
    const tempH=_pf(c[2]),tempL=_pf(c[3]);
    return{obsTimeLocal:date,metric:{
      tempHigh:   tempH,
      tempLow:    tempL,
      tempAvg:    _pf(c[12])??((tempH!=null&&tempL!=null)?(tempH+tempL)/2:null),
      precipTotal:_pf(c[8]),
      windspeedHigh:_pf(c[1]),
      windspeedAvg: _pf(c[18]),
      humidityAvg:  _pf(c[34])??null,
      _source:'import',
    }};
  });
}

function parseGenericCsv(rows){
  const sep=rows[0].includes(';')?';':',';
  const headers=rows[0].split(sep).map(h=>h.trim().replace(/"/g,'').toLowerCase());
  return rows.slice(1).map(line=>{
    const row=line.split(sep).map(c=>c.trim().replace(/"/g,''));
    const date=_isoDate(row[0]);if(!date)return null;
    const tempH=_pf(_col(row,headers,'max','tmax','temp_max','high','maxtemp')??row[1]);
    const tempL=_pf(_col(row,headers,'min','tmin','temp_min','low','mintemp')??row[2]);
    return{obsTimeLocal:date,metric:{
      tempHigh:   tempH,
      tempLow:    tempL,
      tempAvg:    _pf(_col(row,headers,'avg','tavg','mean'))??(tempH!=null&&tempL!=null?(tempH+tempL)/2:null),
      precipTotal:_pf(_col(row,headers,'rain','precip','precipitation','padavine')??row[3]),
      windspeedHigh:_pf(_col(row,headers,'gust','windmax','wind_max')),
      windspeedAvg: _pf(_col(row,headers,'windavg','wind_avg','wind')),
      humidityAvg:  _pf(_col(row,headers,'humidity','hum','vlaga')),
      _source:'import',
    }};
  });
}

function showImportPreview(parsed,filename){
  const pv=document.getElementById('import-preview');
  const btn=document.getElementById('import-confirm-btn');
  if(!pv)return;
  pv.style.display='block';
  if(!parsed.length){
    pv.innerHTML='<span style="color:var(--amber)">⚠️ Ni prebranih vrstic. Preveri format datoteke.</span>';
    if(btn)btn.style.display='none';
    return;
  }
  const sorted=[...parsed].sort((a,b)=>a.obsTimeLocal.localeCompare(b.obsTimeLocal));
  const from=sorted[0].obsTimeLocal,to=sorted[sorted.length-1].obsTimeLocal;
  const stored=JSON.parse(localStorage.getItem(LS_KEY)||'{}');
  const overlap=parsed.filter(d=>stored[d.obsTimeLocal]).length;
  pv.innerHTML=
    '<div style="background:var(--fc-bg);border:1px solid var(--fc-border);border-radius:10px;padding:.85rem;line-height:1.8">'
    +'<div>📄 <b>'+filename+'</b></div>'
    +'<div>📅 Obseg: <b>'+from+'</b> → <b>'+to+'</b></div>'
    +'<div>📊 Prebranih dni: <b>'+parsed.length+'</b></div>'
    +(overlap?'<div>⚠️ Prekrivanje: <b>'+overlap+' dni</b> bo prepisanih</div>':'')
    +'</div>';
  if(btn)btn.style.display='block';
}

function confirmImport(){
  if(!_importParsed.length)return;
  try{
    const stored=JSON.parse(localStorage.getItem(LS_KEY)||'{}');
    _importParsed.forEach(d=>{stored[d.obsTimeLocal]=d.metric;});
    // Trim to 6 years
    const cutoff=new Date(Date.now()-6*365*24*3600*1000).toISOString().slice(0,10);
    Object.keys(stored).forEach(k=>{if(k<cutoff)delete stored[k];});
    localStorage.setItem(LS_KEY,JSON.stringify(stored));
    closeImport();
    // Invalidate cache and refresh
    Object.keys(_histCache).forEach(k=>delete _histCache[k]);
    switchPeriod(_currentPeriod);
    applyMonthlySummary();applyYearRecords();applyStationOnThisDay();applyPheno();refreshInsights();refreshClimate();refreshLife();
    // Success toast
    const t=document.getElementById('toast');
    if(t){t.textContent='✅ Uvoženih '+_importParsed.length+' dni podatkov';t.classList.add('show');setTimeout(()=>t.classList.remove('show'),3500);}
  }catch(e){
    alert('Napaka pri shranjevanju: '+e.message);
  }
}


// ── Auto-load history file from GitHub ───────────────────
const HISTORY_FILE='./history.json';

async function autoLoadHistoryFile(){
  try{
    const res=await fetch(HISTORY_FILE+'?_='+Math.floor(Date.now()/3600000));
    if(!res.ok)return;
    const raw=await res.json();
    const parsed=parseHistoryJson(raw);
    if(!parsed.length)return;
    const stored=JSON.parse(localStorage.getItem(LS_KEY)||'{}');
    let added=0;
    parsed.forEach(d=>{if(d.obsTimeLocal&&!stored[d.obsTimeLocal]){stored[d.obsTimeLocal]=d.metric;added++;}});
    if(added>0){
      localStorage.setItem(LS_KEY,JSON.stringify(stored));
      Object.keys(_histCache).forEach(k=>delete _histCache[k]);
      applyMonthlySummary();applyYearRecords();applyStationOnThisDay();applyPheno();refreshInsights();refreshClimate();refreshLife();renderPastDays();
      if(histTabActive())switchPeriod(_currentPeriod);
      const t=document.getElementById('toast');
      if(t){t.textContent='📂 history.json: uvoženih '+added+' novih dni';t.classList.add('show');setTimeout(()=>t.classList.remove('show'),4000);}
    }
  }catch(e){console.warn('[history.json]',e.message);}
}

// ── Zadnjih 7 dni strip ──────────────────────────────────
const _PD_LAT=46.325779, _PD_LON=14.921137;
const _PD_DAYS=['Ned','Pon','Tor','Sre','Čet','Pet','Sob'];
const _PD_DAYS_FULL=['Nedelja','Ponedeljek','Torek','Sreda','Četrtek','Petek','Sobota'];
let _pdActiveDate=null;

function renderPastDays(){
  const wrap=document.getElementById('past-days-scroll');
  if(!wrap)return;
  const stored=JSON.parse(localStorage.getItem(LS_KEY)||'{}');
  const today=new Date(); today.setHours(0,0,0,0);
  const days=[];
  for(let i=7;i>=1;i--){
    const d=new Date(today); d.setDate(d.getDate()-i);
    const key=_localDateStr(d); // local date — toISOString() would shift back a day in UTC+ timezones
    if(stored[key]) days.push({date:key,data:stored[key]});
  }
  if(!days.length){
    wrap.innerHTML='<div style="color:var(--muted);font-size:.78rem;padding:.5rem 0">Ni zadostnih podatkov v zgodovini.</div>';
    return;
  }
  const maxHigh=Math.max(...days.map(d=>d.data.tempHigh??-99));
  const maxRain=Math.max(...days.map(d=>d.data.precipTotal??0));
  const maxWind=Math.max(...days.map(d=>d.data.windspeedHigh??0));
  const globalLow=Math.min(...days.map(d=>d.data.tempLow??99));
  const globalHigh=Math.max(...days.map(d=>d.data.tempHigh??-99));
  const tempRange=Math.max(1,globalHigh-globalLow);
  wrap.innerHTML=days.map(d=>{
    const dt=new Date(d.date+'T12:00:00');
    const dn=_PD_DAYS[dt.getDay()];
    const dm=dt.getDate()+'. '+(dt.getMonth()+1)+'.';
    const{tempHigh:h,tempLow:l,precipTotal:r,windspeedHigh:w}=d.data;
    const isHot=(h!=null&&h===maxHigh&&maxHigh>-99);
    const isWet=(r!=null&&r===maxRain&&maxRain>0);
    const isWindy=(w!=null&&w===maxWind&&maxWind>0&&!isHot&&!isWet);
    const barLeft=Math.round(((l??globalLow)-globalLow)/tempRange*100);
    const barW=Math.max(8,Math.round(((h??globalHigh)-(l??globalLow))/tempRange*100));
    const badge=isHot?'🌡':isWet?'💧':isWindy?'💨':'';
    return`<div class="pd-card${isHot?' pd-hot':''}${isWet?' pd-wet':''}${isWindy?' pd-windy':''}" data-date="${d.date}" onclick="togglePdDetail('${d.date}',this)">
      ${badge?`<span class="pd-badge">${badge}</span>`:''}
      <div class="pd-day">${dn}</div>
      <div class="pd-date">${dm}</div>
      <div class="pd-temp-high">${h!=null?h.toFixed(1):'—'}°</div>
      <div class="pd-temp-low">${l!=null?l.toFixed(1):'—'}°</div>
      <div class="pd-bar-wrap"><div class="pd-bar" style="left:${barLeft}%;width:${barW}%"></div></div>
      <div class="pd-meta">
        <span>${r!=null&&r>0?'💧 '+r.toFixed(1)+' mm':'<span style="opacity:.3">💧 —</span>'}</span>
        <span>${w!=null&&w>0?'💨 '+Math.round(w)+' km/h':'<span style="opacity:.3">💨 —</span>'}</span>
      </div>
    </div>`;
  }).join('');
}

async function togglePdDetail(date,el){
  const panel=document.getElementById('pd-detail');
  if(_pdActiveDate===date){
    panel.classList.remove('open');
    document.querySelectorAll('.pd-card').forEach(c=>c.classList.remove('active'));
    _pdActiveDate=null;
    return;
  }
  _pdActiveDate=date;
  document.querySelectorAll('.pd-card').forEach(c=>c.classList.remove('active'));
  el.classList.add('active');
  panel.classList.add('open');
  panel.innerHTML='<div class="pd-detail-loading">Nalaganje urnih podatkov…</div>';
  const dt=new Date(date+'T12:00:00');
  const title=`${_PD_DAYS_FULL[dt.getDay()]}, ${dt.getDate()}. ${dt.getMonth()+1}. ${dt.getFullYear()}`;
  try{
    const url=`https://archive-api.open-meteo.com/v1/archive?latitude=${_PD_LAT}&longitude=${_PD_LON}&start_date=${date}&end_date=${date}&hourly=temperature_2m,precipitation,windspeed_10m&timezone=Europe%2FBerlin&wind_speed_unit=kmh`;
    const res=await fetch(url);
    const j=await res.json();
    const hrs=j.hourly.time.map(t=>t.slice(11,16));
    const temps=j.hourly.temperature_2m;
    const prec=j.hourly.precipitation;
    const wind=j.hourly.windspeed_10m;
    const validTemps=temps.filter(x=>x!=null);
    const tMin=Math.min(...validTemps), tMax=Math.max(...validTemps);
    const tRange=Math.max(0.5,tMax-tMin);
    const totalRain=prec.reduce((a,b)=>(a||0)+(b||0),0);
    const maxWindVal=Math.max(...wind.filter(x=>x!=null));
    // SVG
    const W=400,H=100,px=8,py=10;
    const n=hrs.length;
    const pts=temps.map((t,i)=>t!=null?[px+(i/(n-1))*(W-px*2),H-py-((t-tMin)/tRange)*(H-py*2)]:null).filter(Boolean);
    const polyline=pts.map(([x,y])=>`${x.toFixed(1)},${y.toFixed(1)}`).join(' ');
    const maxPrec=Math.max(...prec.filter(x=>x!=null),0.1);
    const rainBars=prec.map((p,i)=>{
      if(!p||p<=0)return'';
      const bw=Math.max(3,(W-px*2)/n*0.7);
      const x=px+(i/(n-1))*(W-px*2)-bw/2;
      const bh=(p/maxPrec)*(H-py*2)*0.35;
      return`<rect x="${x.toFixed(1)}" y="${(H-py-bh).toFixed(1)}" width="${bw.toFixed(1)}" height="${bh.toFixed(1)}" fill="rgba(96,165,250,.4)" rx="1"/>`;
    }).join('');
    // x labels every 6h
    const xlbls=[0,6,12,18].map(h=>{
      const idx=hrs.findIndex(t=>t===`${String(h).padStart(2,'0')}:00`);
      if(idx<0)return'';
      const x=px+(idx/(n-1))*(W-px*2);
      return`<text x="${x.toFixed(1)}" y="${H-1}" font-size="7.5" fill="var(--muted)" text-anchor="middle">${hrs[idx]}</text>`;
    }).join('');
    // y labels
    const ylbls=[tMin,tMax].map(t=>{
      const y=H-py-((t-tMin)/tRange)*(H-py*2);
      return`<text x="${(W-2).toFixed(1)}" y="${(y+3).toFixed(1)}" font-size="7" fill="var(--muted)" text-anchor="end">${t.toFixed(1)}°</text>`;
    }).join('');
    panel.innerHTML=`
      <div class="pd-detail-hdr">
        <span class="pd-detail-title">📅 ${title}</span>
        <button class="pd-detail-close" onclick="closePdDetail()">✕</button>
      </div>
      <svg class="pd-detail-svg" viewBox="0 0 ${W} ${H}">
        ${rainBars}
        <polyline points="${polyline}" fill="none" stroke="var(--amber)" stroke-width="2" stroke-linejoin="round" stroke-linecap="round"/>
        ${xlbls}${ylbls}
      </svg>
      <div class="pd-detail-stats">
        <span>🌡 Najvišja <b>${tMax.toFixed(1)} °C</b></span>
        <span>❄ Najnižja <b>${tMin.toFixed(1)} °C</b></span>
        <span>💧 Padavine <b>${totalRain.toFixed(1)} mm</b></span>
        <span>💨 Max veter <b>${maxWindVal.toFixed(0)} km/h</b></span>
      </div>`;
  }catch(e){
    panel.innerHTML='<div class="pd-detail-loading" style="color:var(--red)">Napaka pri nalaganju podatkov za ta dan.</div>';
  }
}
function closePdDetail(){
  document.getElementById('pd-detail').classList.remove('open');
  document.querySelectorAll('.pd-card').forEach(c=>c.classList.remove('active'));
  _pdActiveDate=null;
}

function parseHistoryJson(raw){
  // Format 1: {\"YYYY-MM-DD\":{tempHigh,...}} — naš LS format
  if(raw&&typeof raw==='object'&&!Array.isArray(raw)){
    const first=Object.values(raw)[0];
    if(first&&(first.tempHigh!=null||first.tempLow!=null||first.precipTotal!=null)){
      return Object.entries(raw)
        .filter(([k])=>k.match(/^\d{4}-\d{2}-\d{2}$/))
        .map(([k,v])=>({obsTimeLocal:k,metric:v}));
    }
  }
  // Format 2: [{obsTimeLocal, metric}]
  if(Array.isArray(raw)&&raw[0]?.obsTimeLocal){
    return raw.map(d=>({obsTimeLocal:d.obsTimeLocal?.slice(0,10),metric:d.metric??d})).filter(d=>d.obsTimeLocal);
  }
  // Format 3: [{date, tempHigh, tempLow, ...}]
  if(Array.isArray(raw)){
    return raw.map(d=>{
      const date=(d.date||d.datum||d.day||d.time||'').slice(0,10);
      if(!date.match(/^\d{4}-\d{2}-\d{2}$/))return null;
      return{obsTimeLocal:date,metric:{
        tempHigh:    d.tempHigh??d.maxTemp??d.tmax??null,
        tempLow:     d.tempLow??d.minTemp??d.tmin??null,
        tempAvg:     d.tempAvg??d.avgTemp??d.tavg??null,
        precipTotal: d.precipTotal??d.rain??d.precip??0,
        windspeedHigh:d.windspeedHigh??d.gustHigh??d.maxWind??null,
        windspeedAvg: d.windspeedAvg??d.windAvg??null,
        humidityAvg:  d.humidityAvg??d.humidity??null,
      }};
    }).filter(d=>d&&d.obsTimeLocal);
  }
  return[];
}

function getPeriodRange(period){
  const now=new Date();
  const pad=n=>String(n).padStart(2,'0');
  const fd=d=>d.getFullYear()+'-'+pad(d.getMonth()+1)+'-'+pad(d.getDate());
  const end=fd(now);
  if(period==='30')   return{start:fd(new Date(now-30*864e5)),end};
  if(period==='year') return{start:now.getFullYear()+'-01-01',end};
  if(period==='5year')return{start:(now.getFullYear()-5)+'-01-01',end};
  return null;
}
async function fetchArchiveHistory(period){
  const r=getPeriodRange(period);
  const url='https://archive-api.open-meteo.com/v1/archive'
    +'?latitude='+LAT+'&longitude='+LON
    +'&start_date='+r.start+'&end_date='+r.end
    +'&daily=temperature_2m_max,temperature_2m_min,precipitation_sum,'
    +'wind_speed_10m_max,wind_speed_10m_mean,relative_humidity_2m_mean'
    +'&timezone=Europe%2FLjubljana';
  // Route through the throttled/cached archive queue to avoid Open-Meteo
  // "Too many concurrent requests" (429), which previously made the 5-year
  // fetch fail and silently fall back to recent-only localStorage data.
  let data=null,lastErr=null;
  for(let attempt=0;attempt<3;attempt++){
    try{
      data=await _archFetch(url);
      if(data?.daily?.time?.length)break;
      lastErr=new Error(data?.reason||'Ni podatkov');
    }catch(e){lastErr=e;}
    delete _archCache[url]; // bust cached error so the retry actually refetches
    data=null;
    await new Promise(res=>setTimeout(res,800*(attempt+1)));
  }
  const d=data?.daily;
  if(!d?.time?.length) throw lastErr||new Error('Ni podatkov');
  // Merge with localStorage station data where available.
  // Only let stored data override ERA5 when it carries an explicit station/import tag.
  // Data saved by buildDailySummaries (recent hourly obs) has no _source and must NOT
  // replace ERA5 archive values, because ERA5 and station peaks are not comparable
  // (ERA5 grid averages run ~2-4°C below actual station highs, so allowing the override
  // makes a recent warm day beat genuinely hotter historical dates).
  const stored=JSON.parse(localStorage.getItem(LS_KEY)||'{}');
  const result=d.time.map((date,i)=>{
    const raw=stored[date];
    const st=(raw?._source==='postaja'||raw?._source==='import')?raw:null;
    const era5Hi=d.temperature_2m_max?.[i];
    return{
      obsTimeLocal:date,
      metric:{
        tempHigh:   st?.tempHigh   ?? era5Hi  ?? null,
        tempLow:    st?.tempLow    ?? d.temperature_2m_min?.[i]  ?? null,
        tempAvg:    st?.tempAvg    ?? (era5Hi!=null&&d.temperature_2m_min?.[i]!=null
                                       ?(era5Hi+d.temperature_2m_min[i])/2:null),
        precipTotal:st?.precipTotal?? d.precipitation_sum?.[i]  ?? 0,
        windspeedHigh:st?.windspeedHigh??d.wind_speed_10m_max?.[i]  ?? null,
        windspeedAvg: st?.windspeedAvg ??d.wind_speed_10m_mean?.[i] ?? null,
        humidityAvg:  st?.humidityAvg  ??d.relative_humidity_2m_mean?.[i]??null,
        _source: st?'postaja':'ERA5',
      }
    };
  }).filter(s=>s.metric.tempHigh!=null);
  // Include station data from localStorage for dates after the ERA5 archive cutoff
  // (very recent days that Open-Meteo hasn't processed yet).
  const lastArchiveDate=d.time.length?d.time[d.time.length-1]:'';
  const seen=new Set(result.map(s=>s.obsTimeLocal));
  Object.entries(stored)
    .filter(([k])=>k>lastArchiveDate&&k>=r.start&&k<=r.end&&!seen.has(k))
    .filter(([,m])=>m.tempHigh!=null)
    .forEach(([k,m])=>result.push({obsTimeLocal:k,metric:{...m,_source:m._source||'postaja'}}));
  return result;
}

async function switchPeriod(period){
  _currentPeriod=period;
  setPeriodBtns(period,false);
  const infoEl=document.getElementById('hist-accum-info');if(infoEl)infoEl.textContent='';

  if(period==='7'){ showHistory7(); return; }

  // Use cache if fresh (<10 min)
  if(_histCache[period]?.data&&Date.now()-_histCache[period].ts<600000){
    applyHistory(_histCache[period].data);
    _showArchiveNote(period,_histCache[period].stationDays);
    return;
  }

  showHistLoading(); setPeriodBtns(period,true);
  try{
    const summaries=await fetchArchiveHistory(period);
    const stationDays=summaries.filter(s=>s.metric._source==='postaja').length;
    _histCache[period]={data:summaries,ts:Date.now(),stationDays};
    saveToLocalHistory(summaries.filter(s=>s.metric._source==='postaja')); // only actual station data
    applyHistory(summaries);
    _showArchiveNote(period,stationDays,summaries.length);
  }catch(e){
    console.warn('Archive fetch failed:',e);
    // Final fallback: localStorage only — note this covers only locally
    // accumulated days, so records (e.g. max temp) may be incomplete.
    const stored=getLocalHistory(period);
    if(stored.length){
      applyHistory(stored);
      const el=document.getElementById('hist-accum-info');
      if(el)el.textContent='⚠️ Arhiv ni dosegljiv — prikazani so le lokalno shranjeni dnevi ('+stored.length+'). Rekordi so lahko nepopolni.';
      else updateAccumInfo(stored.length,localHistoryDays());
    }else{
      showHistErr('Napaka pri nalaganju: '+e.message);
    }
  }finally{
    setPeriodBtns(period,false);
  }
}

function _showArchiveNote(period,stationDays,total){
  let el=document.getElementById('hist-accum-info');
  if(!el){
    el=document.createElement('div');el.id='hist-accum-info';
    el.style.cssText='font-size:.76rem;color:var(--muted);margin-bottom:.75rem;font-family:"JetBrains Mono",monospace';
    const pn=document.querySelector('.period-nav');if(pn)pn.after(el);
  }
  const src=stationDays>0
    ?'🛰 ERA5 + 📡 '+stationDays+' dni postaje IREICA1'
    :'🛰 ERA5 reanaliza (Open-Meteo)';
  el.textContent=src+(total?' · '+total+' dni':'');
}


async function fetchHistory(){
  // Now handled by switchPeriod — kept for backwards compatibility
  switchPeriod('7');
}
function fmtHistDate(s){
  const d=new Date(s.slice(0,10)+'T12:00:00');
  return d.toLocaleDateString('sl',{day:'numeric',month:'short',year:'numeric'});
}
function fmtHistDateShort(s){
  const d=new Date(s.slice(0,10)+'T12:00:00');
  return d.toLocaleDateString('sl',{day:'numeric',month:'numeric'});
}

function applyHistory(summaries){
  if(!summaries||!summaries.length){
    showHistErr('Ni podatkov za izbrano obdobje');return;
  }
  const sorted=[...summaries].sort((a,b)=>a.obsTimeLocal.localeCompare(b.obsTimeLocal));
  let maxT={v:-Infinity,d:''},minT={v:Infinity,d:''},maxR={v:-Infinity,d:''},maxW={v:-Infinity,d:''},maxG={v:-Infinity,d:''};
  sorted.forEach(s=>{
    const m=s.metric,dt=fmtHistDate(s.obsTimeLocal);
    if((m.tempHigh??-999)>maxT.v)    {maxT={v:m.tempHigh,d:dt};}
    if((m.tempLow??999)<minT.v)      {minT={v:m.tempLow, d:dt};}
    if((m.precipTotal??0)>maxR.v)    {maxR={v:m.precipTotal,d:dt};}
    if((m.windspeedAvg??0)>maxW.v)   {maxW={v:m.windspeedAvg,d:dt};}
    if((m.windspeedHigh??0)>maxG.v)  {maxG={v:m.windspeedHigh,d:dt};}
  });
  const su=(id,val,unit)=>{const e=document.getElementById(id);if(e)e.innerHTML=val+'<span class="unit"> '+unit+'</span>';};
  su('rec-temp-high',fmt(maxT.v,1),'°C'); set('rec-temp-high-date',maxT.d);
  su('rec-temp-low', fmt(minT.v,1),'°C'); set('rec-temp-low-date', minT.d);
  su('rec-rain',     fmt(maxR.v,1),' mm');set('rec-rain-date',     maxR.d);
  su('rec-wind',     fmt(maxW.v,1),' km/h');set('rec-wind-date',   maxW.d);
  su('rec-gust',     fmt(maxG.v,1),' km/h');set('rec-gust-date',   maxG.d);

  drawHistTempChart(sorted);
  drawHistRainChart(sorted);

  const u='<span style="font-size:.74rem;color:var(--muted);margin-left:1px">';
  const tbody=document.getElementById('history-tbody');
  if(!tbody)return;
  // Batch all rows into one HTML string + single innerHTML set instead of
  // one createElement+appendChild per row — on the 5-year view that's
  // 1800+ individual DOM insertions, each triggering incremental reflow.
  const rowsHtml=[...sorted].reverse().map(s=>{
    const m=s.metric;
    return '<tr>'+
      '<td>'+fmtHistDate(s.obsTimeLocal)+'</td>'+
      '<td class="td-high">'+fmt(m.tempHigh,1)+u+'°C</span></td>'+
      '<td class="td-low">'+fmt(m.tempLow,1)+u+'°C</span></td>'+
      '<td>'+fmt(m.tempAvg,1)+u+'°C</span></td>'+
      '<td class="td-rain">'+fmt(m.precipTotal,1)+u+'mm</span></td>'+
      '<td>'+fmt(m.windspeedAvg,1)+u+'km/h</span></td>'+
      '<td style="color:var(--purple)">'+fmt(m.windspeedHigh,1)+u+'km/h</span></td>'+
      '<td>'+fmt(m.humidityAvg,0)+u+'%</span></td>'+
    '</tr>';
  }).join('');
  tbody.innerHTML=rowsHtml;
}

function showHistErr(msg){
  const tbody=document.getElementById('history-tbody');
  if(tbody)tbody.innerHTML='<tr><td colspan="8" style="text-align:center;color:var(--red);padding:2rem">'+msg+'</td></tr>';
}

function drawHistTempChart(data){
  const svg=document.getElementById('hist-temp-svg');if(!svg||!data.length)return;
  svg.innerHTML='';
  const VW=880,VH=200,pad={t:30,r:20,b:42,l:46};
  const cw=VW-pad.l-pad.r,ch=VH-pad.t-pad.b;
  const allT=[...data.map(d=>d.metric.tempHigh??0),...data.map(d=>d.metric.tempLow??0)];
  const mn=Math.min(...allT)-1,mx=Math.max(...allT)+1;
  const xS=i=>pad.l+i/(data.length-1)*cw,yS=v=>pad.t+(1-(v-mn)/(mx-mn))*ch;

  for(let i=0;i<=4;i++){
    const y=pad.t+i/4*ch,val=mx-(i/4*(mx-mn));
    mkSVG(svg,'line',{x1:pad.l,x2:VW-pad.r,y1:y,y2:y,stroke:CC.grid,'stroke-width':'1'});
    const t=mkSVG(svg,'text',{x:pad.l-6,y:y+4,'text-anchor':'end','font-size':'9',fill:CC.label,'font-family':'JetBrains Mono,monospace'});
    t.textContent=val.toFixed(0)+'°';
  }
  // Batch per-point date labels into a fragment — on the 5-year view this
  // is ~360 elements; appending each straight to the live svg one at a
  // time triggers incremental reflow (same fix as the history table).
  const dateLabelFrag=document.createDocumentFragment();
  data.forEach((d,i)=>{
    if(i%5===0||i===data.length-1){
      const t=mkSVG(dateLabelFrag,'text',{x:xS(i),y:VH-4,'text-anchor':'middle','font-size':'9',fill:CC.label,'font-family':'JetBrains Mono,monospace'});
      t.textContent=fmtHistDateShort(d.obsTimeLocal);
    }
  });
  svg.appendChild(dateLabelFrag);

  const defs=mkSVG(svg,'defs',{});
  defs.innerHTML=
    '<linearGradient id="hgh" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="#f87171" stop-opacity="0.22"/><stop offset="100%" stop-color="#f87171" stop-opacity="0"/></linearGradient>'+
    '<linearGradient id="hgl" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="'+CC.tempLine+'" stop-opacity="0.15"/><stop offset="100%" stop-color="'+CC.tempLine+'" stop-opacity="0"/></linearGradient>';

  const hPts=data.map((d,i)=>({x:xS(i),y:yS(d.metric.tempHigh??mn)}));
  const lPts=data.map((d,i)=>({x:xS(i),y:yS(d.metric.tempLow??mn)}));
  const hP=smoothPath(hPts),lP=smoothPath(lPts);
  const base=' L '+xS(data.length-1)+','+(VH-pad.b)+' L '+xS(0)+','+(VH-pad.b)+' Z';

  mkSVG(svg,'path',{d:hP+base,fill:'url(#hgh)'});
  mkSVG(svg,'path',{d:lP+base,fill:'url(#hgl)'});
  mkSVG(svg,'path',{d:hP,fill:'none',stroke:'#f87171','stroke-width':'2','stroke-linecap':'round'});
  mkSVG(svg,'path',{d:lP,fill:'none',stroke:CC.tempLine,'stroke-width':'2','stroke-linecap':'round'});

  // Legend
  [{c:'#f87171',l:'Maks'},{c:CC.tempLine,l:'Min'}].forEach(({c,l},i)=>{
    const lx=VW-pad.r-(i===0?105:55);
    mkSVG(svg,'line',{x1:lx,x2:lx+12,y1:pad.t-8,y2:pad.t-8,stroke:c,'stroke-width':'2.5','stroke-linecap':'round'});
    const t=mkSVG(svg,'text',{x:lx+16,y:pad.t-4,'font-size':'9',fill:CC.label,'font-family':'JetBrains Mono,monospace'});t.textContent=l;
  });

  const highs=data.map(d=>d.metric.tempHigh??-999),lows=data.map(d=>d.metric.tempLow??999);
  set('hist-temp-range','Min '+fmt(Math.min(...lows),1)+'° / Maks '+fmt(Math.max(...highs),1)+'°C');

  // Interactive crosshair
  const tipLine=mkSVG(svg,'line',{x1:0,x2:0,y1:pad.t,y2:VH-pad.b,stroke:CC.now,'stroke-width':'1','stroke-dasharray':'3,2',opacity:'0',style:'pointer-events:none'});
  const dotH=mkSVG(svg,'circle',{cx:0,cy:0,r:'4',fill:'#f87171',stroke:'white','stroke-width':'1.5',opacity:'0',style:'pointer-events:none'});
  const dotL=mkSVG(svg,'circle',{cx:0,cy:0,r:'4',fill:CC.tempLine,stroke:'white','stroke-width':'1.5',opacity:'0',style:'pointer-events:none'});
  mkSVG(svg,'rect',{x:pad.l,y:pad.t,width:cw,height:ch,fill:'transparent'});
  const tip=document.getElementById('chart-tip');
  attachScrub(svg,(sx,clientX,clientY)=>{const idx=Math.max(0,Math.min(data.length-1,Math.round((sx-pad.l)/cw*(data.length-1))));const d=data[idx];if(!d)return;const hi=d.metric.tempHigh,lo=d.metric.tempLow,px=xS(idx);tipLine.setAttribute('x1',px);tipLine.setAttribute('x2',px);tipLine.setAttribute('opacity','1');if(hi!=null){dotH.setAttribute('cx',px);dotH.setAttribute('cy',yS(hi));dotH.setAttribute('opacity','1');}else dotH.setAttribute('opacity','0');if(lo!=null){dotL.setAttribute('cx',px);dotL.setAttribute('cy',yS(lo));dotL.setAttribute('opacity','1');}else dotL.setAttribute('opacity','0');tip.innerHTML='<span style="color:#f87171;font-weight:600">'+(hi!=null?hi.toFixed(1):'—')+'°</span> / <span style="color:'+CC.tempLine+';font-weight:600">'+(lo!=null?lo.toFixed(1):'—')+'°</span>&ensp;'+fmtHistDateShort(d.obsTimeLocal);tip.style.opacity='1';tip.style.left=Math.min(clientX+14,window.innerWidth-140)+'px';tip.style.top=Math.max(8,clientY-28)+'px';},()=>{tipLine.setAttribute('opacity','0');dotH.setAttribute('opacity','0');dotL.setAttribute('opacity','0');tip.style.opacity='0';});
}

function drawHistRainChart(data){
  const svg=document.getElementById('hist-rain-svg');if(!svg||!data.length)return;
  svg.innerHTML='';
  const VW=880,VH=150,pad={t:15,r:20,b:42,l:46};
  const cw=VW-pad.l-pad.r,ch=VH-pad.t-pad.b;
  const rains=data.map(d=>d.metric.precipTotal??0);
  const maxR=Math.max(...rains,0.5),total=rains.reduce((a,b)=>a+b,0);

  const defs=mkSVG(svg,'defs',{});
  defs.innerHTML='<linearGradient id="hrg" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="'+CC.rainBar+'" stop-opacity="0.8"/><stop offset="100%" stop-color="'+CC.rainBar+'" stop-opacity="0.15"/></linearGradient>';

  for(let i=0;i<=3;i++){
    const y=pad.t+i/3*ch,val=maxR*(1-i/3);
    mkSVG(svg,'line',{x1:pad.l,x2:VW-pad.r,y1:y,y2:y,stroke:CC.grid,'stroke-width':'1'});
    if(val>0){const t=mkSVG(svg,'text',{x:pad.l-5,y:y+4,'text-anchor':'end','font-size':'9',fill:CC.label,'font-family':'JetBrains Mono,monospace'});t.textContent=val.toFixed(1);}
  }

  const bw=Math.max(1.5,(cw/data.length)*0.7);
  const xS=i=>pad.l+i/data.length*cw;
  // Batch bars + date labels into a fragment — on the 5-year view this is
  // up to ~1800 rects; appending each straight to the live svg one at a
  // time triggers incremental reflow (same fix as the history table).
  const barFrag=document.createDocumentFragment();
  data.forEach((d,i)=>{
    const r=d.metric.precipTotal??0,x=xS(i),h=(r/maxR)*ch;
    if(r>0)mkSVG(barFrag,'rect',{x:(x-bw/2).toFixed(1),y:(pad.t+ch-h).toFixed(1),width:bw.toFixed(1),height:h.toFixed(1),fill:'url(#hrg)',rx:'2'});
    if(i%5===0||i===data.length-1){
      const t=mkSVG(barFrag,'text',{x:x,y:VH-4,'text-anchor':'middle','font-size':'9',fill:CC.label,'font-family':'JetBrains Mono,monospace'});
      t.textContent=fmtHistDateShort(d.obsTimeLocal);
    }
  });
  svg.appendChild(barFrag);
  if(total<0.1){const t=mkSVG(svg,'text',{x:VW/2,y:VH/2,'text-anchor':'middle','font-size':'12',fill:CC.noData,'font-family':'Inter,sans-serif'});t.textContent='Ni padavin v izbranem obdobju';}
  set('hist-rain-range','Skupaj: '+fmt(total,1)+' mm');

  // Interactive crosshair
  const tipLine=mkSVG(svg,'line',{x1:0,x2:0,y1:pad.t,y2:VH-pad.b,stroke:CC.now,'stroke-width':'1','stroke-dasharray':'3,2',opacity:'0',style:'pointer-events:none'});
  const tipDot=mkSVG(svg,'circle',{cx:0,cy:0,r:'4',fill:CC.rainBar,stroke:'white','stroke-width':'1.5',opacity:'0',style:'pointer-events:none'});
  mkSVG(svg,'rect',{x:pad.l,y:pad.t,width:cw,height:ch,fill:'transparent'});
  const tip=document.getElementById('chart-tip');
  attachScrub(svg,(sx,clientX,clientY)=>{const idx=Math.max(0,Math.min(data.length-1,Math.round((sx-pad.l)/cw*(data.length-1))));const d=data[idx];if(!d)return;const r=d.metric.precipTotal??0,px=xS(idx),py=pad.t+ch-(r/maxR)*ch;tipLine.setAttribute('x1',px);tipLine.setAttribute('x2',px);tipLine.setAttribute('opacity','1');tipDot.setAttribute('cx',px);tipDot.setAttribute('cy',Math.max(pad.t+4,py));tipDot.setAttribute('opacity','1');tip.innerHTML='<span style="color:'+CC.rainBar+';font-weight:600">'+r.toFixed(1)+' mm</span>&ensp;'+fmtHistDateShort(d.obsTimeLocal);tip.style.opacity='1';tip.style.left=Math.min(clientX+14,window.innerWidth-120)+'px';tip.style.top=Math.max(8,clientY-28)+'px';},()=>{tipLine.setAttribute('opacity','0');tipDot.setAttribute('opacity','0');tip.style.opacity='0';});
}


function setFavicon(emoji){
  try{
    const c=document.createElement('canvas');c.width=64;c.height=64;
    const ctx=c.getContext('2d');ctx.font='52px serif';ctx.textAlign='center';
    ctx.fillText(emoji,32,52);
    let lnk=document.querySelector("link[rel~='icon']");
    if(!lnk){lnk=document.createElement('link');lnk.rel='icon';document.head.appendChild(lnk);}
    lnk.href=c.toDataURL();
  }catch(e){}
}

// ── Toast ─────────────────────────────────────────────────
function showToast(msg,dur){
  const t=document.getElementById('toast');if(!t)return;
  t.textContent=msg;t.classList.add('show');
  setTimeout(()=>t.classList.remove('show'),dur||2600);
}

// ── Share ─────────────────────────────────────────────────
function shareWeather(){
  const g=id=>document.getElementById(id)?.textContent||'—';
  const cond=g('cond-label'),hum=g('hs-humidity').replace(/\D/g,'');
  const wSpd=g('wind-speed').replace(/[^0-9.]/g,''),wDir=g('wind-dir-lbl').split('·')[0].trim();
  const rain=g('rain-total'),high=g('day-high'),low=g('day-low');
  const temp=_lastTemp!=null?_lastTemp.toFixed(1)+'°C':'—';
  const txt=`🌤 Vreme – Rečica ob Savinji\n🌡 ${temp} — ${cond}\n💧 Vlažnost: ${hum} %  |  Rosišče: ${g('dewpt-hero')}°C\n💨 Veter: ${wDir} ${wSpd} km/h\n🌧 Padavine danes: ${rain} mm\n📈 Maks: ${high}°C  |  Min: ${low}°C\n\n📡 Postaja IREICA1 · Rečica ob Savinji`;
  if(navigator.share){navigator.share({title:'Meteorec — Rečica ob Savinji',text:txt}).catch(()=>{});}
  else{navigator.clipboard.writeText(txt).then(()=>showToast('✓ Kopirano v odložišče!')).catch(()=>showToast('Deljenje ni podprto'));}
}

// ── Countdown ─────────────────────────────────────────────
let _nextRefresh=Date.now()+5*60*1000;
function updateCountdown(){
  const elapsed=Date.now()-(_nextRefresh-5*60*1000);
  const pct=Math.min(100,(elapsed/(5*60*1000))*100);
  const bar=document.getElementById('countdown-fill');if(bar)bar.style.width=pct+'%';
}
setInterval(updateCountdown,1000);updateCountdown();

// ── Yesterday delta ───────────────────────────────────────
function applyYesterdayDelta(observations){
  const target=new Date(Date.now()-24*3600*1000);
  let closest=null,minDiff=Infinity;
  observations.forEach(o=>{const t=new Date(o.obsTimeLocal.replace(' ','T'));const df=Math.abs(t-target);if(df<minDiff){minDiff=df;closest=o;}});
  if(!closest||_lastTemp===null)return;
  const ty=closest.metric?.tempAvg??closest.metric?.temp;if(ty==null)return;
  const d=_lastTemp-ty,sign=d>0?'+':'';
  const word=d>0.5?'topleje kot včeraj':d<-0.5?'hladneje kot včeraj':'podobno kot včeraj';
  const col=d>0.5?'var(--red)':d<-0.5?'var(--blue)':'var(--muted)';
  const el=document.getElementById('yesterday-delta');
  if(el)el.innerHTML=`<span class="dv" style="color:${col}">${sign}${d.toFixed(1)}°C</span> <span style="color:var(--muted)">${word}</span>`;
}

function drawWindTrend(observations){
  const svg=document.getElementById('wind-trend-svg');if(!svg)return;
  // Build daily max gust from observations
  const byDay={};
  observations.forEach(o=>{
    const day=o.obsTimeLocal.slice(0,10);
    const sp=o.metric?.windspeedHigh??o.metric?.windSpeed??0;
    if(!byDay[day]||sp>byDay[day].max) byDay[day]={day,max:sp,avg:o.metric?.windspeedAvg??0};
  });
  const days=Object.values(byDay).sort((a,b)=>a.day.localeCompare(b.day)).slice(-7);
  if(!days.length)return;
  svg.innerHTML='';
  const VW=220,VH=90,pad={t:10,r:8,b:28,l:8};
  const cw=VW-pad.l-pad.r,ch=VH-pad.t-pad.b;
  const maxV=Math.max(...days.map(d=>d.max),5);
  const bw=Math.max(4,(cw/days.length)*0.55);
  const mk=(tag,attrs)=>{const e=document.createElementNS('http://www.w3.org/2000/svg',tag);Object.entries(attrs).forEach(([k,v])=>e.setAttribute(k,v));svg.appendChild(e);return e;};
  // Grid lines
  [0.5,1].forEach(f=>{const y=pad.t+ch*(1-f);mk('line',{x1:pad.l,x2:VW-pad.r,y1:y,y2:y,stroke:CC.grid,'stroke-width':'1'});});
  days.forEach((d,i)=>{
    const x=pad.l+i/(days.length)*cw+(cw/days.length-bw)/2+bw/2;
    const h=Math.max(3,(d.max/maxV)*ch);
    const col=d.max<10?'#60a5fa':d.max<30?'#4d9ff8':'#a78bfa';
    mk('rect',{x:(x-bw/2).toFixed(1),y:(pad.t+ch-h).toFixed(1),width:bw.toFixed(1),height:h.toFixed(1),fill:col,rx:'2',opacity:'.85'});
    // Value label on top
    if(d.max>0){const t=mk('text',{x:x.toFixed(1),y:(pad.t+ch-h-3).toFixed(1),'text-anchor':'middle','font-size':'7',fill:CC.label,'font-family':'JetBrains Mono,monospace'});t.textContent=d.max.toFixed(0);}
    // Day label
    const date=new Date(d.day+'T12:00:00');
    const lbl=date.toLocaleDateString('sl',{weekday:'short'}).slice(0,2);
    const t2=mk('text',{x:x.toFixed(1),y:VH-10,'text-anchor':'middle','font-size':'8',fill:CC.label,'font-family':'JetBrains Mono,monospace'});
    t2.textContent=lbl;
  });
}

function drawWindDist(observations){
  const el=document.getElementById('wind-dist');if(!el)return;
  const total=observations.length||1;
  const calm=observations.filter(o=>(o.metric?.windspeedAvg??0)<2).length;
  const light=observations.filter(o=>{const s=o.metric?.windspeedAvg??0;return s>=2&&s<10;}).length;
  const mod=observations.filter(o=>{const s=o.metric?.windspeedAvg??0;return s>=10&&s<30;}).length;
  const strong=observations.filter(o=>(o.metric?.windspeedAvg??0)>=30).length;
  const cats=[
    {lbl:'Mirno (<2)',  n:calm,  col:'var(--muted)'},
    {lbl:'Lahek (2–10)',n:light, col:'#60a5fa'},
    {lbl:'Zmeren (10–30)',n:mod, col:'#4d9ff8'},
    {lbl:'Močan (>30)', n:strong,col:'#a78bfa'},
  ];
  el.innerHTML='';
  cats.forEach(c=>{
    const pct=Math.round(c.n/total*100);
    const row=document.createElement('div');
    row.style.cssText='display:flex;align-items:center;gap:.4rem;font-size:.74rem';
    row.innerHTML=
      '<div style="width:60px;color:var(--muted);flex-shrink:0">'+c.lbl+'</div>'+
      '<div style="flex:1;height:5px;background:var(--rain-track);border-radius:3px;overflow:hidden">'+
        '<div style="height:100%;width:'+pct+'%;background:'+c.col+';border-radius:3px;transition:width .8s ease"></div>'+
      '</div>'+
      '<div style="width:28px;text-align:right;font-family:JetBrains Mono,monospace;color:var(--muted)">'+pct+'%</div>';
    el.appendChild(row);
  });
}


function drawWindRose(observations){
  const svg=document.getElementById('wind-rose-svg');if(!svg)return;
  const dirs=new Array(8).fill(0),spds=new Array(8).fill(0);
  observations.forEach(o=>{
    const d=o.winddirAvg??o.winddir;
    if(d==null)return;
    const sp=o.metric?.windspeedAvg??o.metric?.windSpeed??0;
    const sec=Math.round(d/45)%8;dirs[sec]++;spds[sec]+=sp;
  });
  const total=dirs.reduce((a,b)=>a+b,0);

  // Fall back to XLSX climatology if recent data is too sparse (<24 readings)
  let usingClimo=false;
  if(total<24&&typeof XLSX_WIND!=='undefined'){
    usingClimo=true;
    // XLSX order: N,NE,E,SE,S,SW,W,NW → map to our index (0=N)
    const order=['N','NE','E','SE','S','SW','W','NW'];
    order.forEach((d,i)=>{
      const w=XLSX_WIND.find(x=>x.dir===d);
      dirs[i]=w?w.pct:0; spds[i]=(w?w.avg:0)*(w?w.pct:0);
    });
  }

  const maxF=Math.max(...dirs)||1;
  svg.innerHTML='';
  const cx=75,cy=75,maxR=50;
  const labels=['S','SV','V','JV','J','JZ','Z','SZ'];

  // Grid rings + radial guides
  [.33,.66,1].forEach(r=>mkSVG(svg,'circle',{cx,cy,r:(maxR*r).toFixed(1),fill:'none',stroke:CC.grid,'stroke-width':'1'}));
  for(let i=0;i<8;i++){
    const a=(i*45-90)*Math.PI/180;
    mkSVG(svg,'line',{x1:cx,y1:cy,x2:(cx+maxR*Math.cos(a)).toFixed(1),y2:(cy+maxR*Math.sin(a)).toFixed(1),stroke:CC.grid,'stroke-width':'.5',opacity:'.5'});
  }

  // Current wind direction (highlight)
  const curDir=_lastBriefObs?.winddir??_lastBriefObs?.metric?.winddir;
  const curSec=curDir!=null?Math.round(curDir/45)%8:-1;

  // Filled petals (wedges)
  const half=20*Math.PI/180; // petal half-width in radians
  dirs.forEach((cnt,i)=>{
    if(cnt===0)return;
    const len=(cnt/maxF)*maxR*.92;
    const avgSp=cnt>0?spds[i]/cnt:0;
    const color=avgSp<10?'#60a5fa':avgSp<30?'#4d9ff8':'#a78bfa';
    const a=(i*45-90)*Math.PI/180;
    const tipX=cx+len*Math.cos(a),tipY=cy+len*Math.sin(a);
    const baseR=len*0.18;
    const lX=cx+baseR*Math.cos(a-half),lY=cy+baseR*Math.sin(a-half);
    const rX=cx+baseR*Math.cos(a+half),rY=cy+baseR*Math.sin(a+half);
    const isCur=i===curSec;
    mkSVG(svg,'path',{
      d:`M${cx},${cy} L${lX.toFixed(1)},${lY.toFixed(1)} L${tipX.toFixed(1)},${tipY.toFixed(1)} L${rX.toFixed(1)},${rY.toFixed(1)} Z`,
      fill:color,opacity:isCur?'.95':'.62',
      stroke:isCur?'var(--text)':'none','stroke-width':isCur?'1':'0'
    });
  });

  // Direction labels
  labels.forEach((lbl,i)=>{
    const a=(i*45-90)*Math.PI/180,lr=maxR+12;
    const isCard=i%2===0; // N,E,S,W bigger
    const t=mkSVG(svg,'text',{x:(cx+lr*Math.cos(a)).toFixed(1),y:(cy+lr*Math.sin(a)).toFixed(1),'text-anchor':'middle','dominant-baseline':'central','font-size':isCard?'8.5':'7',fill:i===curSec?'var(--text)':CC.label,'font-family':'JetBrains Mono,monospace','font-weight':isCard?'600':'400'});
    t.textContent=lbl;
  });
  mkSVG(svg,'circle',{cx,cy,r:'2.5',fill:'var(--muted)'});

  // Stats
  const dom=dirs.indexOf(maxF);
  const domPct=usingClimo?Math.round(dirs[dom]):Math.round(dirs[dom]/total*100);
  const calm=usingClimo?null:Math.round(observations.filter(o=>(o.metric?.windspeedAvg??o.metric?.windSpeed??0)<2).length/(observations.length||1)*100);
  const el=document.getElementById('wind-rose-stats');
  if(el){
    el.innerHTML=`Prevladujoča smer: <strong style="color:var(--text)">${labels[dom]}</strong> (${domPct}% časa)`
      +(calm!=null?`<br>Mirno: ${calm}% časa`:'')
      +(usingClimo?`<br><span style="font-size:.64rem;opacity:.8">📊 Klimatologija 2019–2026 (premalo svežih meritev)</span>`:'');
  }

  // Update card title to reflect data source
  const titleEl=svg.closest('.wind-rose-card')?.querySelector('.clabel');
  if(titleEl)titleEl.innerHTML=usingClimo?'🌹 Roža vetrov — klimatologija':'🌹 Roža vetrov — zadnjih 7 dni';
}

// ══════════════════════════════════════════════════════════
// ── RainViewer animirani radar ────────────────────────────
// ══════════════════════════════════════════════════════════
let _radarMap=null,_radarFrames=[],_radarIdx=0,_radarTimer=null,_radarLayers={},_radarPlaying=true,_radarHost='';

async function initRadarMap(){
  if(_radarMap)return;
  if(typeof L==='undefined'){
    _loadCss('https://unpkg.com/leaflet@1.9.4/dist/leaflet.css');
    await _loadScript('https://unpkg.com/leaflet@1.9.4/dist/leaflet.js');
  }
  const mapEl=document.getElementById('radar-map');if(!mapEl)return;

  _radarMap=L.map('radar-map',{zoomControl:true,attributionControl:false,minZoom:4,maxZoom:10}).setView([LAT,LON],7);

  // Base tiles — theme-aware
  const dark=isDark();
  const baseUrl=dark
    ? 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png'
    : 'https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png';
  L.tileLayer(baseUrl,{maxZoom:10,maxNativeZoom:19,subdomains:'abcd'}).addTo(_radarMap);

  // Station marker
  L.circleMarker([LAT,LON],{radius:6,color:'#2563eb',fillColor:'#4d9ff8',fillOpacity:.9,weight:2}).addTo(_radarMap).bindPopup('IREICA1 · Rečica ob Savinji');

  await loadRadarFrames();
}

async function loadRadarFrames(){
  try{
    const res=await fetch('https://api.rainviewer.com/public/weather-maps.json');
    const data=await res.json();
    _radarHost=data.host;
    const past=(data.radar?.past||[]).map(f=>({...f,kind:'past'}));
    const now=(data.radar?.nowcast||[]).map(f=>({...f,kind:'nowcast'}));
    _radarFrames=[...past,...now];
    if(!_radarFrames.length)return;
    _radarIdx=past.length-1; // start at "now"
    showRadarFrame(_radarIdx);
    if(_radarPlaying)startRadarAnim();
  }catch(e){console.warn('RainViewer:',e);
    const t=document.getElementById('radar-time');if(t)t.textContent='Radar ni dosegljiv';
  }
}

function showRadarFrame(i){
  if(!_radarFrames[i]||!_radarMap)return;
  const f=_radarFrames[i];
  // Lazy-create layer
  if(!_radarLayers[f.path]){
    const color=isDark()?2:4; // 2=universal blue, 4=TWC for light
    const url=`${_radarHost}${f.path}/256/{z}/{x}/{y}/${color}/1_1.png`;
    _radarLayers[f.path]=L.tileLayer(url,{opacity:0,tileSize:256,maxNativeZoom:8,maxZoom:10,errorTileUrl:'data:image/gif;base64,R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBRAA7'});
    _radarLayers[f.path].addTo(_radarMap);
  }
  // Fade: hide others, show this
  Object.entries(_radarLayers).forEach(([p,layer])=>{
    layer.setOpacity(p===f.path?0.72:0);
  });
  // Update UI
  const dt=new Date(f.time*1000);
  const tEl=document.getElementById('radar-time');
  if(tEl)tEl.innerHTML=dt.toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'})+
    (f.kind==='nowcast'?' <span class="radar-fc-badge">napoved</span>':i===_radarFrames.filter(x=>x.kind==='past').length-1?' <span class="radar-now-badge">zdaj</span>':'');
  const fill=document.getElementById('radar-track-fill');
  if(fill)fill.style.width=((i+1)/_radarFrames.length*100)+'%';
}

function startRadarAnim(){
  clearInterval(_radarTimer);
  _radarTimer=setInterval(()=>{
    _radarIdx=(_radarIdx+1)%_radarFrames.length;
    showRadarFrame(_radarIdx);
  },700);
}

function toggleRadarPlay(){
  _radarPlaying=!_radarPlaying;
  const btn=document.getElementById('radar-play');
  if(_radarPlaying){startRadarAnim();if(btn)btn.textContent='⏸ Pavza';}
  else{clearInterval(_radarTimer);if(btn)btn.textContent='▶ Predvajaj';}
}

function radarSeek(e){
  const track=document.getElementById('radar-track');if(!track||!_radarFrames.length)return;
  const rect=track.getBoundingClientRect();
  const pct=(e.clientX-rect.left)/rect.width;
  _radarIdx=Math.max(0,Math.min(_radarFrames.length-1,Math.floor(pct*_radarFrames.length)));
  showRadarFrame(_radarIdx);
  _radarPlaying=false;clearInterval(_radarTimer);
  const btn=document.getElementById('radar-play');if(btn)btn.textContent='▶ Predvajaj';
}

// ══════════════════════════════════════════════════════════
// ── Pelod in alergeni (Open-Meteo CAMS) ───────────────────
// ══════════════════════════════════════════════════════════
const POLLEN_TYPES=[
  {key:'alder_pollen',   icon:'🌳',name:'Jelša',  low:5,  mod:25, high:50},
  {key:'birch_pollen',   icon:'🌲',name:'Breza',  low:5,  mod:25, high:90},
  {key:'grass_pollen',   icon:'🌾',name:'Trave',  low:5,  mod:20, high:50},
  {key:'mugwort_pollen', icon:'🌿',name:'Pelin',  low:5,  mod:15, high:50},
  {key:'ragweed_pollen', icon:'🪴',name:'Ambrozija',low:5,mod:15, high:50},
];

async function fetchPollen(){
  const grid=document.getElementById('pollen-grid');
  const sub=document.getElementById('pollen-sub');
  if(!grid)return;
  try{
    const params=POLLEN_TYPES.map(p=>p.key).join(',');
    const url=`https://air-quality-api.open-meteo.com/v1/air-quality?latitude=${LAT}&longitude=${LON}&hourly=${params}&timezone=Europe%2FLjubljana&forecast_days=1`;
    const data=await _archFetch(url);
    const h=data.hourly;
    if(!h){grid.innerHTML='<div style="color:var(--muted);font-size:.74rem">Podatki o pelodu niso dosegljivi za to lokacijo.</div>';return;}

    const hourNow=new Date().getHours();
    const items=POLLEN_TYPES.map(p=>{
      const arr=h[p.key]||[];
      const val=arr[hourNow]??arr.find(v=>v!=null)??null;
      return {...p,val};
    }).filter(p=>p.val!=null);

    if(!items.length){grid.innerHTML='<div style="color:var(--muted);font-size:.74rem">Trenutno ni zaznanega peloda (izven sezone).</div>';if(sub)sub.textContent='Zunaj pelodne sezone';return;}

    const levelOf=(p)=>{
      if(p.val<p.low)return{txt:'nizko',bg:'rgba(74,222,128,.15)',c:'var(--green)'};
      if(p.val<p.mod)return{txt:'zmerno',bg:'rgba(251,191,36,.15)',c:'var(--amber)'};
      if(p.val<p.high)return{txt:'visoko',bg:'rgba(249,115,22,.15)',c:'#ea580c'};
      return{txt:'zelo viš.',bg:'rgba(248,113,113,.18)',c:'var(--red)'};
    };

    grid.innerHTML=items.map(p=>{
      const lv=levelOf(p);
      return `<div class="pollen-item">
        <div class="pollen-icon">${p.icon}</div>
        <div class="pollen-name">${p.name}</div>
        <div class="pollen-val" style="color:${lv.c}">${Math.round(p.val)}</div>
        <div class="pollen-level" style="background:${lv.bg};color:${lv.c}">${lv.txt}</div>
      </div>`;
    }).join('');

    const worst=items.reduce((a,b)=>b.val>a.val?b:a);
    const wl=levelOf(worst);
    if(sub)sub.innerHTML=`Najvišje: <strong style="color:${wl.c}">${worst.name} (${wl.txt})</strong> · enote grains/m³`;
  }catch(e){
    grid.innerHTML='<div style="color:var(--muted);font-size:.74rem">Pelod ni dosegljiv.</div>';
    console.warn('Pollen:',e);
  }
}

// ══════════════════════════════════════════════════════════
// ── Reka Savinja — pretok (Open-Meteo Flood / GloFAS) ────
// ══════════════════════════════════════════════════════════
async function fetchFlood(){
  const el=document.getElementById('flood-content');if(!el)return;
  try{
    const url=`https://flood-api.open-meteo.com/v1/flood?latitude=${LAT}&longitude=${LON}&daily=river_discharge,river_discharge_mean,river_discharge_max&forecast_days=7`;
    const data=await _archFetch(url);
    const d=data.daily;
    if(!d||!d.river_discharge){el.innerHTML='<div style="color:var(--muted);font-size:.78rem">Podatki o pretoku niso dosegljivi.</div>';return;}

    const discharge=d.river_discharge.filter(v=>v!=null);
    const today=discharge[0];
    const mean=d.river_discharge_mean?.[0]??(discharge.reduce((a,b)=>a+b,0)/discharge.length);
    const max7=Math.max(...discharge);
    const ratio=mean>0?today/mean:1;

    // Status by ratio to typical
    let status,col,icon;
    if(ratio<0.6){status='Nizek pretok';col='var(--amber)';icon='🏜';}
    else if(ratio<1.5){status='Normalen pretok';col='var(--green)';icon='🌊';}
    else if(ratio<2.5){status='Povišan pretok';col='#ea580c';icon='⚠️';}
    else{status='Visok pretok!';col='var(--red)';icon='🚨';}

    const sparkMax=Math.max(...discharge)||1;
    const days=['Ned','Pon','Tor','Sre','Čet','Pet','Sob'];
    const startDay=new Date().getDay();
    const spark=discharge.map((v,i)=>{
      const hPct=Math.max(8,v/sparkMax*100);
      const dn=days[(startDay+i)%7];
      const bcol=i===0?col:'var(--blue)';
      return `<div class="flood-spark-bar" style="height:${hPct}%;background:${bcol};opacity:${i===0?1:.5}" title="${dn}: ${v.toFixed(1)} m³/s"></div>`;
    }).join('');

    el.innerHTML=`
      <div class="flood-status">
        <span class="flood-icon">${icon}</span>
        <div style="flex:1">
          <div style="font-family:'JetBrains Mono',monospace;font-size:1.3rem;color:var(--text)">${today.toFixed(1)} <span style="font-size:.7rem;color:var(--muted)">m³/s</span></div>
          <div style="font-size:.74rem;color:${col};font-weight:500">${status}</div>
        </div>
      </div>
      <div style="font-size:.7rem;color:var(--muted);margin-top:.3rem">Tipično ${mean.toFixed(1)} m³/s · ${Math.round(ratio*100)}% normale</div>
      <div class="flood-spark">${spark}</div>
      <div style="font-size:.66rem;color:var(--muted);margin-top:.4rem">7-dnevna napoved pretoka · GloFAS model</div>
      ${ratio>=2.5?'<div style="font-size:.7rem;color:var(--red);margin-top:.5rem;padding:.5rem;background:rgba(248,113,113,.1);border-radius:8px">⚠️ Spomni se avgusta 2023 — spremljaj uradna ARSO opozorila.</div>':''}
    `;
  }catch(e){
    el.innerHTML='<div style="color:var(--muted);font-size:.78rem">Pretok ni dosegljiv.</div>';
    console.warn('Flood:',e);
  }
}


let _installPrompt=null;
// iOS Safari ne podpira beforeinstallprompt – namestitev poteka ročno prek Deli → »Na začetni zaslon«
const _isIOS=/iphone|ipad|ipod/i.test(navigator.userAgent)||(navigator.platform==='MacIntel'&&navigator.maxTouchPoints>1);
const _isStandalone=window.matchMedia('(display-mode: standalone)').matches||navigator.standalone===true;
function _showInstallBtn(){const b=document.getElementById('install-btn');if(b)b.classList.add('show');}
function _hideInstallBtn(){const b=document.getElementById('install-btn');if(b)b.classList.remove('show');}
window.addEventListener('beforeinstallprompt',e=>{
  e.preventDefault();_installPrompt=e;
  _showInstallBtn();
});
window.addEventListener('appinstalled',()=>{_installPrompt=null;_hideInstallBtn();});
function installApp(){
  if(_installPrompt){
    _installPrompt.prompt();
    _installPrompt.userChoice.then(()=>{_installPrompt=null;_hideInstallBtn();});
    return;
  }
  if(_isIOS){
    // iOS: programska namestitev ni mogoča – pokaži navodila
    showToast('Za namestitev tapni ⬆️ (Deli) in izberi »Na začetni zaslon«',6000);
    return;
  }
  showToast('Namestitev v tem brskalniku ni na voljo');
}
// Na iOS-u beforeinstallprompt ne obstaja, zato gumb prikažemo ročno (če app še ni nameščen)
if(_isIOS&&!_isStandalone)_showInstallBtn();
if('serviceWorker' in navigator){
  window.addEventListener('load', async () => {
    const reg = await navigator.serviceWorker.register('./sw.js').catch(()=>null);
    if (!reg) return;

    document.addEventListener('visibilitychange', () => {
      if (!document.hidden && navigator.serviceWorker.controller) {
        navigator.serviceWorker.controller.postMessage({ type: 'REFRESH_CACHE' });
      }
    });

    if ('periodicSync' in reg) {
      const status = await navigator.permissions.query({ name: 'periodic-background-sync' }).catch(()=>({state:'denied'}));
      if (status.state === 'granted') {
        reg.periodicSync.register('weather-refresh', { minInterval: 30 * 60 * 1000 }).catch(()=>{});
      }
    }
  });
}

// Pause/resume all canvas animations when the tab is hidden (reduces battery/heat on mobile)
document.addEventListener('visibilitychange',()=>{
  _animPaused=document.hidden;
  if(!document.hidden){
    if(_meshCanvas&&!_meshAnimId)_meshDraw();
    if(_heroCanvas&&!_heroAnimId)animateHero();
    if(_sfActive&&!_sfAnim){_sfPrev=0;_sfAnim=requestAnimationFrame(_sfFrame);}
  }
});

// Tab nav scroll-fade indicator + bounce arrow
(function(){
  const nav=document.querySelector('.tab-nav');
  const wrap=document.querySelector('.tab-nav-wrap');
  const arrow=document.getElementById('tab-nav-arrow');
  if(!nav||!wrap)return;
  function _updateFade(){
    const atEnd=nav.scrollLeft+nav.clientWidth>=nav.scrollWidth-4;
    wrap.classList.toggle('at-end',atEnd);
    wrap.classList.toggle('scrolled',nav.scrollLeft>4);
  }
  nav.addEventListener('scroll',_updateFade,{passive:true});
  window.addEventListener('resize',_updateFade,{passive:true});
  window.addEventListener('resize',_syncAlertBarHeight,{passive:true});
  if(arrow){
    arrow.addEventListener('click',()=>nav.scrollBy({left:140,behavior:'smooth'}));
    // Hide arrow permanently after user scrolls manually (they know about it)
    nav.addEventListener('scroll',()=>arrow.classList.add('hidden'),{once:true,passive:true});
  }
  _updateFade();
})();



