// FOTO KONFIGURACIJA — dodaj svoje fotografije tukaj
// Pot: './photos/ime.jpg'  ali GitHub Pages URL
// Vsak vnos je niz URL ali objekt {url, caption}
// ══════════════════════════════════════════════════════════════
const PHOTOS = {

  // 🌧 Vremenska ozadja (najvišja prioriteta)
  rain:  [
    // {url:'./photos/rain-drops.jpg', caption:'Kapljice dežja · Filip Eremita'}
  ],
  snow:  [],
  fog:   [
    // {url:'./photos/morning-fog-valley.jpg', caption:'Jutranja megla v dolini'}
  ],
  storm: [],
  night: [
    // {url:'./photos/milky-way.jpg', caption:'Mlečna cesta nad Rečico'}
  ],

  // 🌱 FENOLOŠKE FAZE — tvoje makro fotografije po GDD
  // Aktivirajo se glede na nakopičene growing degree days od 1.1.
  gdd: {
    0:   [
      // {url:'./photos/frost-crystals.jpg', caption:'Ledeni kristali · makro'}
    ],
    50:  [
      // {url:'./photos/hazel-catkins.jpg', caption:'Leska — prvi cvetovi pomladi'}
      // {url:'./photos/snowdrop.jpg',       caption:'Zvonček · makro'}
    ],
    120: [
      // {url:'./photos/cherry-blossom.jpg', caption:'Češnjevi cvetovi · makro'}
      // {url:'./photos/plum-blossom-bee.jpg',caption:'Čebela na slivi · makro'}
    ],
    200: [
      // {url:'./photos/wild-violet.jpg',   caption:'Vijolica · makro'}
      // {url:'./photos/dandelion-macro.jpg',caption:'Regrat · makro'}
    ],
    300: [
      // {url:'./photos/butterfly-macro.jpg',caption:'Metulj na cvetlici · makro'}
      // {url:'./photos/ladybug.jpg',        caption:'Pikapolonica · makro'}
    ],
    400: [
      // {url:'./photos/elderflower.jpg',    caption:'Bezeg v cvetu'}
      // {url:'./photos/beetle-macro.jpg',   caption:'Hrošč · makro'}
    ],
    500: [
      // {url:'./photos/dragonfly.jpg',      caption:'Kačji pastir · makro'}
      // {url:'./photos/grasshopper.jpg',    caption:'Kobilica · makro'}
    ],
    700: [
      // {url:'./photos/spider-dew.jpg',     caption:'Pajčevina z roso · makro'}
      // {url:'./photos/wasp-macro.jpg',     caption:'Osa · makro'}
    ],
    900: [
      // {url:'./photos/autumn-leaves.jpg',  caption:'Jesenski listi · makro'}
      // {url:'./photos/mushroom-macro.jpg', caption:'Goba · makro'}
    ],
  },

  // 📅 Sezonska rezervna ozadja
  seasons: {
    winter: [],  // december · januar · februar
    spring: [],  // marec · april · maj
    summer: [],  // junij · julij · avgust
    autumn: [],  // september · oktober · november
  },

  // 🌤 Privzeto (ko ni drugega)
  default: [],
};
// ══════════════════════════════════════════════════════════════

// ── Photo background engine ───────────────────────────────────
const _photo={layerA:null,layerB:null,activeLayer:'a',url:null};
function _initPhotoLayers(){
  _photo.layerA=document.getElementById('pba');
  _photo.layerB=document.getElementById('pbb');
}
function _randomFrom(arr){
  if(!arr||!arr.length)return null;
  const item=arr[Math.floor(Math.random()*arr.length)];
  return typeof item==='string'?{url:item,caption:''}:item;
}
function _flatPhotos(arr){
  if(!arr||!arr.length)return[];
  return arr.map(x=>typeof x==='string'?{url:x,caption:''}:x);
}
function _selectPhoto(obs){
  const temp=obs?.metric?.temp??15;
  const rain=obs?.metric?.precipRate??0;
  const gddEl=document.getElementById('pheno-gdd-total');
  const gdd=gddEl?parseFloat(gddEl.textContent)||0:0;
  const h=new Date().getHours();
  const mo=new Date().getMonth(); // 0-11

  // 1. Vremenske prednosti
  let pool=[];
  if(temp<-1&&rain>0)    pool=_flatPhotos(PHOTOS.snow);
  else if(rain>1.5)      pool=_flatPhotos(PHOTOS.rain);
  else if(h<5||h>22)     pool=_flatPhotos(PHOTOS.night);
  if(pool.length)return _randomFrom(pool);

  // 2. GDD fenološka faza
  const gddKeys=[900,700,500,400,300,200,120,50,0];
  for(const k of gddKeys){
    if(gdd>=k&&PHOTOS.gdd[k]?.length){return _randomFrom(_flatPhotos(PHOTOS.gdd[k]));}
  }

  // 3. Sezonska rezerva
  const season=mo<=1||mo===11?'winter':mo<=4?'spring':mo<=7?'summer':'autumn';
  pool=_flatPhotos(PHOTOS.seasons[season]);
  if(pool.length)return _randomFrom(pool);

  // 4. Privzeto
  pool=_flatPhotos(PHOTOS.default);
  return pool.length?_randomFrom(pool):null;
}
function _applyPhoto(item){
  if(!item?.url)return;
  if(item.url===_photo.url)return; // same photo
  _photo.url=item.url;
  if(!_photo.layerA){_initPhotoLayers();}
  const bg=document.getElementById('bg');
  const incoming=_photo.activeLayer==='a'?_photo.layerB:_photo.layerA;
  const outgoing =_photo.activeLayer==='a'?_photo.layerA:_photo.layerB;
  // Preload then crossfade
  const img=new Image();
  img.onload=()=>{
    incoming.style.backgroundImage='url('+item.url+')';
    incoming.style.opacity='1';
    incoming.classList.add('active');
    outgoing.style.opacity='0';
    outgoing.classList.remove('active');
    _photo.activeLayer=_photo.activeLayer==='a'?'b':'a';
    bg?.classList.replace('no-photo','has-photo');
    const cr=document.getElementById('photo-credit');
    if(cr)cr.textContent=item.caption||'';
  };
  img.onerror=()=>{_photo.url=null;}; // reset on error so it retries next time
  img.src=item.url;
}
function updatePhotoBackground(obs){
  const item=_selectPhoto(obs);
  if(item)_applyPhoto(item);
  else{
    // No photo — show blobs
    document.getElementById('bg')?.classList.replace('has-photo','no-photo');
  }
}
// ── Moon phase ─────────────────────────────────────────────
function calcMoon(date=new Date()){
  const KNOWN=new Date(Date.UTC(2000,0,6,18,14));
  const SYN=29.53058867;
  const age=((( date-KNOWN)/(864e5)%SYN)+SYN)%SYN;
  const illum=Math.round(50*(1-Math.cos(2*Math.PI*age/SYN)));
  const phases=[
    [1.85,'🌑','Mlaj'],[7.38,'🌒','Rastoči srpec'],[9.22,'🌓','Prva četrtina'],
    [14.77,'🌔','Rastoča luna'],[16.61,'🌕','Polna luna'],[22.15,'🌖','Pojemajoča luna'],
    [23.99,'🌗','Zadnja četrtina'],[29.53,'🌘','Padajoči srpec']
  ];
  let emoji='🌑',phase='Mlaj';
  for(const[limit,em,ph] of phases){if(age<limit){emoji=em;phase=ph;break;}}
  // Next full moon
  const toFull=((14.77-age)+SYN)%SYN;
  const toNew=((0-age)+SYN)%SYN;
  return{age:age.toFixed(1),illum,emoji,phase,toFull:toFull.toFixed(0),toNew:toNew.toFixed(0)};
}
function applyMoon(){
  const m=calcMoon();
  set('moon-emoji',m.emoji);set('moon-phase',m.phase);set('moon-illum',m.illum);set('moon-age',m.age);
  const nx=document.getElementById('moon-next');
  if(nx)nx.innerHTML='Polna čez <b>'+m.toFull+'</b> dni · Mlaj čez <b>'+m.toNew+'</b> dni';
}

// ── Weather Score + Activities ────────────────────────────
function calcScore(obs){
  if(!obs)return{score:50,label:'—',color:'#64748b'};
  const m=obs.metric,temp=m.temp??15,rain=m.precipRate??0,wind=m.windSpeed??0,uv=obs.uv??0,hum=obs.humidity??60;
  let sc=100;
  if(temp<-10)sc-=55;else if(temp<0)sc-=38;else if(temp<5)sc-=22;else if(temp<10)sc-=10;
  if(temp>35)sc-=45;else if(temp>30)sc-=22;
  if(temp>=17&&temp<=24)sc+=5;
  sc-=Math.min(40,rain*8);
  if(wind>60)sc-=32;else if(wind>40)sc-=18;else if(wind>25)sc-=8;
  if(uv>=11)sc-=22;else if(uv>=8)sc-=10;
  if(hum>90)sc-=10;else if(hum>80)sc-=5;
  sc=Math.max(0,Math.min(100,Math.round(sc)));
  const [label,color]=sc>=90?['Odlično 🌟','#22c55e']:sc>=75?['Lepo ☀️','#84cc16']:sc>=60?['Prijetno 🌤','#eab308']:sc>=45?['Zmerno ⛅','#f97316']:sc>=30?['Slabo 🌦','#ef4444']:['Neurje ⛈','#9333ea'];
  return{score:sc,label,color};
}
function getActivities(obs){
  if(!obs)return[];
  const m=obs.metric,temp=m.temp??15,rain=m.precipRate??0,wind=m.windSpeed??0,uv=obs.uv??0;
  const sc=calcScore(obs).score;
  const acts=[];
  if(sc>=82&&temp>=14&&rain<0.1){if(temp>=17)acts.push('🚴 Kolesarjenje');acts.push('🏔 Planinarjenje');}
  if(sc>=75&&temp>=22&&rain<0.1)acts.push('🔥 Žar & piknik');
  if(sc>=70&&rain<0.1)acts.push('🌱 Vrtnarjenje');
  if(sc>=85&&temp>=24&&rain<0.1)acts.push('🏊 Kopanje');
  if(rain>0&&wind<15)acts.push('🍄 Gobarjenje');
  if(rain>5||sc<35)acts.push('📚 Doma je lepo');
  if(wind>=25&&wind<50&&rain<0.1)acts.push('🪁 Kite/jadralec');
  if(acts.length===0)acts.push('🚶 Sprehod');
  return acts.slice(0,3);
}
function applyScore(obs){
  const{score,label,color}=calcScore(obs);
  const ring=document.getElementById('score-ring');
  if(ring){ring.style.boxShadow='0 0 0 3px '+color+',0 0 24px '+color+'55';}
  set('score-num',score);set('score-lbl',label.split(' ')[0]);
  const desc=document.getElementById('score-desc');
  if(desc)desc.textContent=score>=75?'Dobro vreme za aktivnosti zunaj':score>=50?'Zmerno vreme':'Slabe razmere';
  const actEl=document.getElementById('activities');
  if(actEl){actEl.innerHTML='';getActivities(obs).forEach(a=>{const d=document.createElement('div');d.className='act';d.textContent=a;actEl.appendChild(d);});}
}

// ── Air Quality ───────────────────────────────────────────
async function fetchAirQuality(){
  try{
    const url='https://air-quality-api.open-meteo.com/v1/air-quality?latitude='+LAT+'&longitude='+LON+'&hourly=pm10,pm2_5,european_aqi,ozone,nitrogen_dioxide&timezone=Europe%2FLjubljana&forecast_days=1';
    const res=await fetch(url);const data=await res.json();
    const h=new Date().getHours();
    const aqi=data.hourly?.european_aqi?.[h]??0;
    const pm25=data.hourly?.pm2_5?.[h]??0;
    const pm10=data.hourly?.pm10?.[h]??0;
    const no2=data.hourly?.nitrogen_dioxide?.[h]??0;
    const ozone=data.hourly?.ozone?.[h]??0;
    const[label,col]=aqi<=20?['Zelo dobro','#22c55e']:aqi<=40?['Dobro','#84cc16']:aqi<=60?['Zmerno','#eab308']:aqi<=80?['Slabo','#f97316']:aqi<=100?['Zelo slabo','#ef4444']:['Nevarno','#9333ea'];
    const el=document.getElementById('aqi-val');if(el){el.style.color=col;el.childNodes[0].textContent=aqi;}
    set('aqi-lbl',' · '+label);
    const dot=document.getElementById('aqi-dot');if(dot)dot.style.left=Math.min(95,aqi/120*100)+'%';
    set('aqi-pm25',pm25.toFixed(1));set('aqi-pm10',pm10.toFixed(1));
    set('aqi-no2',no2.toFixed(1));set('aqi-ozone',ozone.toFixed(0));
  }catch(e){console.warn('AQI:',e);}
}

// ── Agrometeo ─────────────────────────────────────────────
async function fetchAgrometeo(){
  try{
    const url='https://api.open-meteo.com/v1/forecast?latitude='+LAT+'&longitude='+LON+'&daily=et0_fao_evapotranspiration,sunshine_duration,temperature_2m_max,temperature_2m_min,precipitation_sum&timezone=Europe%2FLjubljana&forecast_days=1';
    const res=await fetch(url);const data=await res.json();
    const d=data.daily;
    const et0=(d?.et0_fao_evapotranspiration?.[0]??0).toFixed(1);
    const sun=((d?.sunshine_duration?.[0]??0)/3600).toFixed(1);
    const tmax=d?.temperature_2m_max?.[0]??0,tmin=d?.temperature_2m_min?.[0]??0;
    const gdd=Math.max(0,(tmax+tmin)/2-10).toFixed(1);
    set('agro-et0',et0);set('agro-sun',sun);set('agro-gdd',gdd);
    const rain=d?.precipitation_sum?.[0]??0;
    const note=parseFloat(et0)>parseFloat(rain)?'💧 Zalijevanje priporočeno (ET₀ > padavine)':'🌱 Padavine zadoščajo';
    set('agro-note',note);
    set('agro-date',new Date().toLocaleDateString('sl',{weekday:'long',day:'numeric',month:'long'}));
  }catch(e){console.warn('Agro:',e);}
}

// ── Agrometeo Tab ─────────────────────────────────────────
// Fenološki pragovi hmelja so vezani na GDD₁₀ (baza 10 °C — agronomski standard za
// hmelj), umerjeni na večletno akumulacijo postaje IREICA1 (glej tools/generate_agrometeo_page.py).
const HOP_STAGES=[
  {min:0,   max:60,   label:'Mirovanje',                    emoji:'💤',col:'#6b7280'},
  {min:60,  max:150,  label:'Odganjanje poganjkov',         emoji:'🌱',col:'#4ade80'},
  {min:150, max:400,  label:'Vzdolžna rast trt',            emoji:'🌿',col:'#22c55e'},
  {min:400, max:600,  label:'Stransko razvejanje',          emoji:'🌾',col:'#86efac'},
  {min:600, max:950,  label:'Cvetenje in razvoj storžkov',  emoji:'🌸',col:'#f59e0b'},
  {min:950, max:1250, label:'Oblikovanje storžkov',         emoji:'🍺',col:'#f97316'},
  {min:1250,max:9999, label:'Tehnološka zrelost / obiranje',emoji:'🎉',col:'#ef4444'},
];
const CROP_GDD=[
  {name:'Hmelj',     emoji:'🌿',base:10,milestones:[{v:150,l:'odganjanje'},{v:400,l:'razvejanje'},{v:600,l:'cvetenje'},{v:950,l:'storžki'},{v:1250,l:'obiranje'}],        col:'#22c55e'},
  {name:'Koruza',    emoji:'🌽',base:10,milestones:[{v:100,l:'kalitev'},{v:600,l:'svilanje'},{v:1300,l:'metličenje'},{v:2400,l:'spravilo'}],                         col:'#f59e0b'},
  {name:'Krompir',   emoji:'🥔',base:7, milestones:[{v:200,l:'vznik'},{v:500,l:'nastavljanje gomoljev'},{v:1000,l:'debelitev gomoljev'},{v:1500,l:'spravilo'}],      col:'#a78bfa'},
  {name:'Pšenica',   emoji:'🌾',base:5, milestones:[{v:200,l:'vznik'},{v:600,l:'kolenčenje'},{v:1200,l:'klasenje'},{v:2000,l:'žetev'}],                             col:'#fbbf24'},
  {name:'Trava',     emoji:'🌱',base:5, milestones:[{v:100,l:'1. porast'},{v:400,l:'1. košnja'},{v:800,l:'2. košnja'},{v:1200,l:'3. košnja'}],col:'#34d399'},
];

let _agroFcCache=null,_agroFcTime=0;

async function initAgro(){
  const [gdd5,gdd10,rain30]=_calcAgroAccum();
  _buildAgroKPIs(gdd5,gdd10,rain30);
  _buildAgroHop(gdd10);
  _buildAgroGDD(gdd5,gdd10);
  _buildAgroFrost();
  await _fetchAgroFc(gdd5);
}

function _calcAgroAccum(){
  const store=_insStore();
  const yr=new Date().getFullYear();
  const today=_localDateStr(new Date());
  const d30=_localDateStr(new Date(Date.now()-30*864e5));
  let gdd5=0,gdd10=0,rain30=0;
  for(const[k,v] of Object.entries(store)){
    const avg=(v.tempHigh!=null&&v.tempLow!=null)?(v.tempHigh+v.tempLow)/2:(v.tempAvg??null);
    if(k>=yr+'-01-01'&&k<=today&&avg!=null){
      gdd5+=Math.max(0,avg-5);
      gdd10+=Math.max(0,avg-10);
    }
    if(k>=d30&&k<=today) rain30+=(v.precipTotal||0);
  }
  return[Math.round(gdd5),Math.round(gdd10),Math.round(rain30)];
}

function _buildAgroKPIs(gdd5,gdd10,rain30){
  set('ak-gdd5',gdd5);
  set('ak-gdd10',gdd10);
  set('ak-rain30',rain30);
  // ET₀, sun, wbal come from the hourly fetch — show loading for now
  const et0El=document.getElementById('ak-et0');
  const sunEl=document.getElementById('ak-sun');
  const wbalEl=document.getElementById('ak-wbal');
  if(et0El&&et0El.textContent==='—'){et0El.textContent='…';}
  if(sunEl&&sunEl.textContent==='—'){sunEl.textContent='…';}
  if(wbalEl&&wbalEl.textContent==='—'){wbalEl.textContent='…';}
}

function _buildAgroHop(gdd10){
  const body=document.getElementById('agro-hop-body');
  if(!body)return;
  const stage=HOP_STAGES.find(s=>gdd10>=s.min&&gdd10<s.max)||HOP_STAGES[HOP_STAGES.length-1];
  const nextStage=HOP_STAGES.find(s=>s.min>gdd10);
  const pct=Math.min(100,Math.round((gdd10-stage.min)/(stage.max-stage.min)*100));
  const toNext=nextStage?nextStage.min-gdd10:0;
  body.innerHTML=
    '<div style="display:flex;align-items:center;gap:.8rem;margin-bottom:.7rem">'
    +'<div style="font-size:2rem">'+stage.emoji+'</div>'
    +'<div><div style="font-size:.95rem;font-weight:600;color:var(--text)">'+stage.label+'</div>'
    +'<div style="font-size:.72rem;color:var(--muted)">GDD₁₀: '+gdd10+(nextStage?' · do naslednje faze: '+toNext+' GDD₁₀ ('+nextStage.label+')':'')+'</div></div>'
    +'</div>'
    +'<div class="hop-phase-bar"><div class="hop-phase-fill" style="width:'+pct+'%;background:'+stage.col+'"></div></div>'
    +'<div style="display:flex;justify-content:space-between;font-size:.62rem;color:var(--muted);margin-bottom:.85rem">'
    +'<span>'+stage.min+' GDD₁₀</span><span>'+pct+'%</span>'+(stage.max<9999?'<span>'+stage.max+' GDD₁₀</span>':'')+'</div>'
    +'<div class="agro-risk-grid" id="agro-disease-grid">'
    +'<div style="color:var(--muted);font-size:.75rem">Tveganje za bolezni – nalaganje podatkov …</div>'
    +'</div>';
}

function _buildAgroHopDisease(rh,temp){
  const grid=document.getElementById('agro-disease-grid');
  if(!grid)return;
  const dm=Math.max(0,Math.min(100,((rh-60)/30*60+(temp>10&&temp<25?30:0))));
  const pm=Math.max(0,Math.min(100,((temp>15&&temp<28?40:0)+(rh>45&&rh<80?40:0)+(temp>18&&temp<26?20:0))));
  const bot=Math.max(0,Math.min(100,((rh>80?50:0)+(temp>15&&temp<22?30:0)+(rh>90?20:0))));
  const diseases=[
    {name:'Hmeljeva peronospora',risk:dm,note:'T > 10 °C + visoka vlaga'},
    {name:'Hmeljeva pepelovka',  risk:pm,note:'T 15–27 °C + zmerna vlaga'},
    {name:'Siva plesen (Botrytis)',risk:bot,note:'T 15–22 °C + vlaga > 80 %'},
  ];
  grid.innerHTML=diseases.map(d=>{
    const col=d.risk<30?'var(--green)':d.risk<60?'var(--amber)':'var(--red)';
    const lbl=d.risk<30?'Nizko':d.risk<60?'Zmerno':'Visoko';
    return '<div class="agro-risk-card">'
      +'<div style="font-size:.75rem;font-weight:600;color:var(--text)">'+d.name+'</div>'
      +'<div class="agro-risk-bar"><div class="agro-risk-fill" style="width:'+Math.round(d.risk)+'%;background:'+col+'"></div></div>'
      +'<div style="display:flex;justify-content:space-between;font-size:.66rem">'
      +'<span style="color:'+col+'">'+lbl+' ('+Math.round(d.risk)+'%)</span>'
      +'<span style="color:var(--muted)">'+d.note+'</span></div>'
      +'</div>';
  }).join('');
}

function _buildAgroGDD(gdd5,gdd10){
  const body=document.getElementById('agro-gdd-body');
  if(!body)return;
  body.innerHTML='<div>'+CROP_GDD.map(c=>{
    const gdd=c.base===5?gdd5:c.base===7?Math.round(gdd5*0.72):c.base===10?gdd10:gdd5;
    const maxMil=c.milestones[c.milestones.length-1].v;
    const pct=Math.min(100,Math.round(gdd/maxMil*100));
    const curMil=c.milestones.slice().reverse().find(m=>gdd>=m.v);
    const nextMil=c.milestones.find(m=>m.v>gdd);
    const stageLabel=curMil?curMil.l:'pred vznikom';
    const nextLabel=nextMil?nextMil.l+' čez '+(nextMil.v-gdd)+' GDD':'zaključeno';
    return '<div class="gdd-crop-row">'
      +'<div class="gdd-crop-lbl">'+c.emoji+' '+c.name+'</div>'
      +'<div class="gdd-crop-bar"><div class="gdd-crop-fill" style="width:'+pct+'%;background:'+c.col+'"></div></div>'
      +'<div class="gdd-crop-val" style="color:'+c.col+'">'+gdd+'</div>'
      +'<div class="gdd-crop-stage">'+stageLabel+' · '+nextLabel+'</div>'
      +'</div>';
  }).join('')+'</div>';
}

function _buildAgroFrost(){
  const body=document.getElementById('agro-frost-body');
  if(!body)return;
  const fc=_fcDailyData;
  if(!fc||!fc.time?.length){body.innerHTML='<div style="color:var(--muted);font-size:.8rem">Temperaturna napoved ni na voljo.</div>';return;}
  const days=Math.min(7,fc.time.length);
  let html='<div class="frost-row">';
  for(let i=0;i<days;i++){
    const tmin=fc.temperature_2m_min?.[i]??null;
    const tmax=fc.temperature_2m_max?.[i]??null;
    const dateObj=new Date(fc.time[i]+'T12:00:00');
    const dayName=dateObj.toLocaleDateString('sl',{weekday:'short'});
    let bClass='frost-ok',bLabel='V redu';
    if(tmin!=null){
      if(tmin<=-3){bClass='frost-danger';bLabel='Pozeba!';}
      else if(tmin<0){bClass='frost-frost';bLabel='Zmrzal';}
      else if(tmin<3){bClass='frost-warn';bLabel='Pozor';}
      else{bClass='frost-safe';bLabel='Varno';}
    }
    html+='<div class="frost-day">'
      +'<div class="frost-day-name">'+dayName+'</div>'
      +'<div class="frost-day-temp">'+(tmax!=null?Math.round(tmax)+'°':'—')+'</div>'
      +'<div class="frost-day-temp" style="font-size:.73rem;color:var(--muted)">'+(tmin!=null?Math.round(tmin)+'°':'—')+'</div>'
      +'<div class="frost-day-badge '+bClass+'">'+bLabel+'</div>'
      +'</div>';
  }
  html+='</div>';
  const frostDays=[];
  for(let i=0;i<days;i++){
    const tmin=fc.temperature_2m_min?.[i]??null;
    if(tmin!=null&&tmin<0){
      const dateObj=new Date(fc.time[i]+'T12:00:00');
      frostDays.push(dateObj.toLocaleDateString('sl',{weekday:'long',day:'numeric',month:'short'})+' ('+Math.round(tmin)+' °C)');
    }
  }
  if(frostDays.length){
    html+='<div style="margin-top:.5rem;padding:.5rem .7rem;background:rgba(248,113,113,.08);border-radius:8px;font-size:.74rem;color:var(--red)">⚠️ Predvidena je pozeba/zmrzal: '+frostDays.join(', ')+'</div>';
  }else{
    html+='<div style="margin-top:.5rem;font-size:.74rem;color:var(--green)">✅ V prihodnjih 7 dneh ni predvidene pozebe.</div>';
  }
  body.innerHTML=html;
}

async function _fetchAgroFc(gdd5){
  try{
    if(!_agroFcCache||Date.now()-_agroFcTime>3600000){
      const url='https://api.open-meteo.com/v1/forecast?latitude='+LAT+'&longitude='+LON
        +'&hourly=temperature_2m,relative_humidity_2m,wind_speed_10m,precipitation,is_day'
        +'&daily=et0_fao_evapotranspiration,precipitation_sum,sunshine_duration,temperature_2m_max,temperature_2m_min'
        +'&timezone=Europe%2FLjubljana&forecast_days=7';
      const r=await fetch(url);
      _agroFcCache=await r.json();
      _agroFcTime=Date.now();
    }
    const d=_agroFcCache;
    // Update KPIs with fresh ET₀/sun
    if(d.daily?.et0_fao_evapotranspiration?.[0]!=null){
      const et0=d.daily.et0_fao_evapotranspiration[0].toFixed(1);
      const sun=((d.daily.sunshine_duration?.[0]??0)/3600).toFixed(1);
      const [,, rain30]=_calcAgroAccum();
      const todayRain=(d.daily.precipitation_sum?.[0]??0);
      const wbal=(todayRain-parseFloat(et0)).toFixed(1);
      set('ak-et0',et0);
      set('ak-sun',sun);
      set('ak-wbal',(parseFloat(wbal)>=0?'+':'')+wbal);
    }
    // Disease risk from current humidity (use hour 12 of today if available)
    const h=d.hourly;
    if(h?.relative_humidity_2m?.length){
      const nowHour=new Date().getHours();
      const rh=h.relative_humidity_2m[nowHour]??h.relative_humidity_2m[0]??70;
      const temp=h.temperature_2m[nowHour]??h.temperature_2m[0]??15;
      _buildAgroHopDisease(rh,temp);
    }
    _buildAgroSpray(d);
    _buildAgroHay(d);
    _buildAgroWaterBalance(d);
  }catch(e){
    console.warn('Agro fc:',e);
    ['agro-spray-body','agro-hay-body','agro-wbal-body'].forEach(id=>{
      const el=document.getElementById(id);
      if(el&&el.textContent.includes('Nalaganje'))el.innerHTML='<div style="color:var(--muted);font-size:.8rem">Napaka pri nalaganju podatkov.</div>';
    });
  }
}

function _buildAgroSpray(d){
  const body=document.getElementById('agro-spray-body');
  if(!body)return;
  const h=d.hourly;
  if(!h?.time?.length){body.innerHTML='<div style="color:var(--muted);font-size:.8rem">Urni podatki niso na voljo.</div>';return;}
  // Group by day, show 7 days × 24h grid (day hours 6-19 only shown)
  const days=[];
  const now=new Date();
  const todayStr=_localDateStr(now);
  for(let i=0;i<7;i++){
    const d2=new Date(now);d2.setDate(d2.getDate()+i);
    days.push(_localDateStr(d2));
  }
  let html='';
  for(const day of days){
    const indices=h.time.map((t,i)=>t.startsWith(day)?i:-1).filter(i=>i>=0);
    if(!indices.length)continue;
    const dateObj=new Date(day+'T12:00:00');
    const dayLbl=dateObj.toLocaleDateString('sl',{weekday:'short',day:'numeric',month:'numeric'});
    // Daytime slots 6-19
    const daySlots=indices.filter(i=>{
      const hr=parseInt(h.time[i].slice(11,13));
      return hr>=6&&hr<20;
    });
    if(!daySlots.length)continue;
    const slots=daySlots.map(i=>{
      const wind=h.wind_speed_10m[i]??99;
      const precip=h.precipitation[i]??0;
      const temp=h.temperature_2m[i]??0;
      const hr=parseInt(h.time[i].slice(11,13));
      const ok=wind<=4&&precip<0.1&&temp>=5;
      return{ok,hr,wind,precip,temp};
    });
    const okCount=slots.filter(s=>s.ok).length;
    html+='<div style="margin-bottom:.6rem">'
      +'<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:.2rem">'
      +'<span style="font-size:.73rem;color:var(--text);font-weight:600">'+dayLbl+'</span>'
      +'<span style="font-size:.67rem;color:'+(okCount>=4?'var(--green)':okCount>=2?'var(--amber)':'var(--red)')+'">'+okCount+' primernih ur</span>'
      +'</div>'
      +'<div class="spray-lbl-row">'+slots.map(s=>'<div class="spray-lbl">'+s.hr+'</div>').join('')+'</div>'
      +'<div class="spray-timeline">'+slots.map(s=>
        '<div class="spray-slot '+(s.ok?'spray-ok':'spray-no')+'" title="'+s.hr+':00 · veter '+s.wind.toFixed(1)+'m/s · padavine '+s.precip.toFixed(1)+'mm · '+s.temp.toFixed(0)+' °C"></div>'
      ).join('')+'</div>'
      +'</div>';
  }
  body.innerHTML=html
    +'<div style="font-size:.67rem;color:var(--muted);margin-top:.25rem">🟢 Primerno (veter ≤ 4 m/s, brez dežja, T ≥ 5 °C) &nbsp;⬜ Neprimerno</div>';
}

function _buildAgroHay(d){
  const body=document.getElementById('agro-hay-body');
  if(!body)return;
  const h=d.hourly;
  if(!h?.time?.length){body.innerHTML='<div style="color:var(--muted);font-size:.8rem">Urni podatki niso na voljo.</div>';return;}
  // Find windows of ≥6 consecutive daylight hours with: no rain, RH<65%, isDay
  const now=new Date();
  const windows=[];
  let currentWin=null;
  for(let i=0;i<Math.min(h.time.length,5*24);i++){
    const isDay=h.is_day?.[i]??0;
    const precip=h.precipitation?.[i]??0;
    const rh=h.relative_humidity_2m?.[i]??100;
    const temp=h.temperature_2m?.[i]??0;
    const wind=h.wind_speed_10m?.[i]??0;
    const goodDrying=isDay&&precip<0.1&&rh<65&&temp>=12;
    if(goodDrying){
      if(!currentWin)currentWin={start:h.time[i],end:h.time[i],hours:1,minRh:rh,maxTemp:temp,avgWind:wind};
      else{currentWin.end=h.time[i];currentWin.hours++;currentWin.minRh=Math.min(currentWin.minRh,rh);currentWin.maxTemp=Math.max(currentWin.maxTemp,temp);currentWin.avgWind=(currentWin.avgWind*(currentWin.hours-1)+wind)/currentWin.hours;}
    }else{
      if(currentWin&&currentWin.hours>=4)windows.push(currentWin);
      currentWin=null;
    }
  }
  if(currentWin&&currentWin.hours>=4)windows.push(currentWin);
  if(!windows.length){
    body.innerHTML='<div style="padding:.6rem;background:rgba(248,113,113,.07);border-radius:8px;font-size:.8rem;color:var(--muted)">⛅ V prihodnjih 5 dneh ni ugodnih oken za sušenje sena (vlaga, dež ali mraz).</div>';
    return;
  }
  body.innerHTML=windows.slice(0,4).map(w=>{
    const s=new Date(w.start),e=new Date(w.end);
    const sdl=s.toLocaleDateString('sl',{weekday:'short',day:'numeric',month:'short'});
    const stl=s.toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'});
    const etl=e.toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'});
    const quality=w.hours>=8&&w.minRh<55?'odlično':w.hours>=6&&w.minRh<60?'dobro':'zadostno';
    const qualityCol=quality==='odlično'?'var(--green)':quality==='dobro'?'var(--amber)':'var(--muted)';
    return '<div class="hay-window">'
      +'<div style="font-size:1.5rem">🌾</div>'
      +'<div class="hay-window-info">'
      +'<div class="hay-window-dates">'+sdl+' '+stl+'–'+etl+'</div>'
      +'<div class="hay-window-details">'+w.hours+'h sušenja · min. vlaga '+Math.round(w.minRh)+' % · maks. T '+Math.round(w.maxTemp)+' °C · veter ~'+w.avgWind.toFixed(1)+' m/s</div>'
      +'</div>'
      +'<div class="hay-window-badge" style="color:'+qualityCol+';border-color:'+qualityCol+'">'+quality+'</div>'
      +'</div>';
  }).join('');
}

function _buildAgroWaterBalance(d){
  const body=document.getElementById('agro-wbal-body');
  if(!body)return;
  const store=_insStore();
  const now=new Date();
  const rows=[];
  // Last 14 days from localStorage
  for(let i=13;i>=0;i--){
    const dt=new Date(now);dt.setDate(dt.getDate()-i);
    const k=_localDateStr(dt);
    const v=store[k];
    rows.push({date:k,rain:v?.precipTotal??null,et0:null,isHist:true});
  }
  // Next 7 days from forecast daily
  const fd=d.daily;
  if(fd?.time){
    for(let i=1;i<Math.min(fd.time.length,8);i++){
      const k=fd.time[i];
      if(rows.some(r=>r.date===k))continue;
      rows.push({date:k,rain:fd.precipitation_sum?.[i]??null,et0:fd.et0_fao_evapotranspiration?.[i]??null,isHist:false});
    }
  }
  const maxRain=Math.max(1,...rows.map(r=>r.rain??0));
  const maxET=Math.max(1,...rows.map(r=>r.et0??0));
  const maxBar=Math.max(maxRain,maxET);
  let html='<div style="display:flex;align-items:flex-end;gap:2px;height:65px;margin-bottom:.25rem">';
  for(const r of rows){
    const rainH=r.rain!=null?Math.round((r.rain/maxBar)*60):0;
    const et0H=r.et0!=null?Math.round((r.et0/maxBar)*60):0;
    const bal=(r.rain??0)-(r.et0??0);
    const col=r.rain==null?'var(--border)':bal>=0?'rgba(56,189,248,.6)':'rgba(248,113,113,.5)';
    html+='<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:0">';
    if(r.et0!=null)html+='<div style="width:100%;height:'+et0H+'px;background:rgba(251,191,36,.35);border-radius:2px 2px 0 0" title="ET₀ '+r.et0?.toFixed(1)+' mm"></div>';
    html+='<div style="width:100%;height:'+rainH+'px;background:'+col+';border-radius:'+(r.et0!=null?'0':'2px 2px')+'2px 2px" title="padavine '+(r.rain?.toFixed(1)??'—')+' mm"></div>';
    html+='</div>';
  }
  html+='</div>';
  // date labels (every ~4)
  html+='<div style="display:flex;gap:2px;margin-bottom:.35rem">';
  for(let i=0;i<rows.length;i++){
    const lbl=i%4===0?new Date(rows[i].date+'T12:00:00').toLocaleDateString('sl',{day:'numeric',month:'numeric'}):'';
    html+='<div style="flex:1;font-size:.52rem;color:var(--muted);text-align:center;white-space:nowrap;overflow:hidden">'+lbl+'</div>';
  }
  html+='</div>';
  // Cumulative balance
  const histRows=rows.filter(r=>r.isHist&&r.rain!=null);
  const totalRain=histRows.reduce((s,r)=>s+(r.rain||0),0);
  const histEt0rows=rows.filter(r=>!r.isHist&&r.et0!=null);
  html+='<div style="font-size:.72rem;color:var(--muted);margin-top:.15rem">'
    +'<span style="color:rgba(56,189,248,.9)">■</span> Padavine'
    +'&nbsp;&nbsp;<span style="background:rgba(251,191,36,.35);padding:0 3px">■</span> ET₀ (napoved)'
    +'&nbsp;&nbsp;Skupaj v 14 dneh: <strong style="color:var(--text)">'+Math.round(totalRain)+' mm</strong>'
    +'</div>';
  body.innerHTML=html;
}

// ── Climate comparison ────────────────────────────────────
async function fetchClimateComparison(){
  try{
    const now=new Date(),y=now.getFullYear(),m=now.getMonth()+1;
    const pad=n=>String(n).padStart(2,'0');
    const daysInMonth=new Date(y,m,0).getDate();
    const endDay=Math.min(now.getDate(),daysInMonth);

    const years=[1,2,3,4,5].map(n=>y-n).reverse(); // oldest first
    const results=await Promise.all(years.map(async yr=>{
      const sd=yr+'-'+pad(m)+'-01',ed=yr+'-'+pad(m)+'-'+pad(daysInMonth);
      try{
        const url='https://archive-api.open-meteo.com/v1/archive?latitude='+LAT+'&longitude='+LON
          +'&start_date='+sd+'&end_date='+ed
          +'&daily=temperature_2m_max,temperature_2m_min,precipitation_sum'
          +'&timezone=Europe%2FLjubljana';
        const res=await fetch(url);const data=await res.json();
        const maxT=data.daily?.temperature_2m_max??[];
        const minT=data.daily?.temperature_2m_min??[];
        const means=maxT.map((mx,i)=>mx!=null&&minT[i]!=null?(mx+minT[i])/2:null).filter(x=>x!=null);
        const rains=(data.daily?.precipitation_sum??[]).filter(x=>x!=null);
        // Only count up to endDay to compare fairly with current (partial) month
        const meansPartial=means.slice(0,endDay);
        const rainsPartial=rains.slice(0,endDay);
        const avgT=meansPartial.length?meansPartial.reduce((a,b)=>a+b,0)/meansPartial.length:null;
        const totR=rainsPartial.reduce((a,b)=>a+b,0);
        return{yr,avgT,totR,ok:true};
      }catch(e){return{yr,avgT:null,totR:0,ok:false};}
    }));

    // Current month from localStorage (partial)
    const pfx=y+'-'+pad(m);
    const stored=JSON.parse(localStorage.getItem('wx-history-v1')||'{}');
    const curEntries=Object.entries(stored).filter(([k])=>k.startsWith(pfx));
    const curTemps=curEntries.map(([,v])=>v.tempAvg).filter(x=>x!=null);
    const curAvgT=curTemps.length?curTemps.reduce((a,b)=>a+b,0)/curTemps.length:null;
    const curR=curEntries.reduce((s,[,v])=>s+(v.precipTotal||0),0);
    const allResults=[...results,{yr:y,avgT:curAvgT,totR:curR,isCurrent:true}];
    // Refresh ARSO normals anomaly with current month data
    try{buildArsoNormals(curAvgT,curR);}catch(_){}

    const histOk=results.filter(r=>r.avgT!=null);
    const histAvgT=histOk.length?histOk.reduce((s,r)=>s+r.avgT,0)/histOk.length:null;
    const histAvgR=results.reduce((s,r)=>s+r.totR,0)/results.length;

    const monthName=now.toLocaleDateString('sl',{month:'long',year:'numeric'});
    set('clim-month-lbl',monthName);
    set('clim-range','vs. povprečje '+(histOk.length)+' let (1.–'+endDay+'. '+now.toLocaleDateString('sl',{month:'short'})+')');

    const cont=document.getElementById('clim-content');if(!cont)return;

    // Stats row
    let statsHtml='<div style="display:flex;gap:2rem;flex-wrap:wrap;margin-bottom:1rem">';
    if(curAvgT!=null&&histAvgT!=null){
      const dT=(curAvgT-histAvgT),sT=dT>=0?'+':'';
      const col=Math.abs(dT)<1?'var(--muted)':dT>0?'var(--red)':'var(--blue)';
      statsHtml+='<div><div class="chart-range">Povp. temp. (1.–'+endDay+'.)</div>'
        +'<div style="font-size:1.1rem;font-family:JetBrains Mono,monospace;color:var(--text)">'+curAvgT.toFixed(1)+'°C'
        +' <span style="font-size:.78rem;color:'+col+'">'+sT+dT.toFixed(1)+'° vs. povp.</span></div></div>';
    }
    if(histAvgR>0){
      const dR=((curR-histAvgR)/histAvgR*100),sR=dR>=0?'+':'';
      const colR=Math.abs(dR)<10?'var(--muted)':dR>0?'var(--blue)':'var(--amber)';
      statsHtml+='<div><div class="chart-range">Padavine</div>'
        +'<div style="font-size:1.1rem;font-family:JetBrains Mono,monospace;color:var(--text)">'+curR.toFixed(1)+' mm'
        +' <span style="font-size:.78rem;color:'+colR+'">'+sR+dR.toFixed(0)+'% vs. povp.</span></div></div>';
    }
    statsHtml+='</div>';

    // Bars — scaled relative to max value among all years
    const allT=allResults.map(r=>r.avgT).filter(x=>x!=null);
    const allR=allResults.map(r=>r.totR);
    const maxT=allT.length?Math.max(...allT):20;
    const maxR=Math.max(...allR,1);

    const barsHtml='<div style="display:flex;gap:.5rem;margin-bottom:1.5rem">'
      +allResults.map(r=>{
        const hT=r.avgT!=null?Math.max(5,(r.avgT/maxT*100)).toFixed(0):5;
        const hR=Math.max(5,(r.totR/maxR*100)).toFixed(0);
        const isCur=r.isCurrent;
        const tCol=isCur?'var(--red)':'rgba(248,113,113,.45)';
        const rCol=isCur?'var(--blue)':'rgba(96,165,250,.45)';
        return '<div style="flex:1;display:flex;flex-direction:column;gap:3px;align-items:center">'
          +'<div style="width:100%;height:60px;display:flex;align-items:flex-end;gap:2px">'
          +'<div style="flex:1;height:'+hT+'%;background:'+tCol+';border-radius:3px 3px 0 0;min-height:3px;transition:height .8s"></div>'
          +'<div style="flex:1;height:'+hR+'%;background:'+rCol+';border-radius:3px 3px 0 0;min-height:3px;transition:height .8s"></div>'
          +'</div>'
          +'<div style="font-size:.72rem;color:'+(isCur?'var(--blue)':'var(--muted)')+';font-family:JetBrains Mono,monospace;font-weight:'+(isCur?'600':'400')+'">'+r.yr+'</div>'
          +(r.avgT!=null?'<div style="font-size:.7rem;color:var(--muted)">'+r.avgT.toFixed(1)+'°</div>':'')
          +'</div>';
      }).join('')
      +'</div>'
      +'<div style="display:flex;gap:1rem;font-size:.74rem;color:var(--muted)">'
      +'<span><span style="display:inline-block;width:8px;height:8px;border-radius:1px;background:var(--red);margin-right:3px;vertical-align:middle"></span>Temperatura</span>'
      +'<span><span style="display:inline-block;width:8px;height:8px;border-radius:1px;background:var(--blue);margin-right:3px;vertical-align:middle"></span>Padavine</span>'
      +'</div>';

    cont.innerHTML=statsHtml+barsHtml;
  }catch(e){console.warn('Klima:',e);const c=document.getElementById('clim-content');if(c)c.innerHTML='<span style="color:var(--muted);font-size:.8rem">Napaka pri nalaganju klimatskih podatkov</span>';}
}

// ── Blog: nov/posodobljen prispevek kot poudarjena postavka v tickerju ──
let _latestBlogPost=null;
function loadBlogTicker(){
  fetch('/blog.json').then(r=>r.json()).then(posts=>{
    if(!Array.isArray(posts)||!posts.length)return;
    const esc=s=>String(s).replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]));
    const top=[...posts].sort((a,b)=>(b.updated||b.date).localeCompare(a.updated||a.date))[0];
    const eff=top.updated||top.date;
    const freshDays=(Date.now()-new Date(eff+'T12:00:00').getTime())/86400000;
    if(freshDays>3)return; // ni več "svež" — v tickerju se ne prikaže
    const isUpdated=!!top.updated&&top.updated!==top.date;
    _latestBlogPost={
      icon: isUpdated?'☁️':'✨',
      label: isUpdated?'Posodobljen prispevek':'Nov prispevek na blogu',
      title: esc(top.title),
      url: esc(top.url)
    };
    buildTicker();
  }).catch(()=>{});
}

// ── Monthly summary ───────────────────────────────────────
function applyMonthlySummary(){
  const now=new Date(),y=now.getFullYear(),m=now.getMonth()+1;
  const pad=n=>String(n).padStart(2,'0');
  const pfx=y+'-'+pad(m);
  try{
    const stored=JSON.parse(localStorage.getItem('wx-history-v1')||'{}');
    const entries=Object.entries(stored).filter(([k])=>k.startsWith(pfx));
    if(entries.length<3){set('month-txt','Zbiranje podatkov za '+now.toLocaleDateString('sl',{month:'long',year:'numeric'})+'…');return;}
    const temps=entries.map(([,v])=>v.tempAvg).filter(x=>x!=null);
    const highs=entries.map(([,v])=>v.tempHigh).filter(x=>x!=null);
    const lows=entries.map(([,v])=>v.tempLow).filter(x=>x!=null);
    const rains=entries.map(([,v])=>v.precipTotal||0);
    const avgT=(temps.reduce((a,b)=>a+b,0)/temps.length).toFixed(1);
    const totR=rains.reduce((a,b)=>a+b,0).toFixed(1);
    const rainyDays=rains.filter(r=>r>1).length;
    const frostDays=lows.filter(t=>t<0).length;
    const maxT=Math.max(...highs).toFixed(1);
    const minT=Math.min(...lows).toFixed(1);
    const maxE=entries.find(([,v])=>v.tempHigh===parseFloat(maxT));
    const minE=entries.find(([,v])=>v.tempLow===parseFloat(minT));
    const fmtD=k=>new Date(k+'T12:00:00').toLocaleDateString('sl',{day:'numeric',month:'short'});
    const mn=now.toLocaleDateString('sl',{month:'long',year:'numeric'});
    set('month-title',mn);
    set('month-txt',mn+' — '+entries.length+' dni podatkov. Povprečna temperatura: <b>'+avgT+'°C</b>. Skupne padavine: <b>'+totR+' mm</b> v <b>'+rainyDays+' deževnih dnevih</b>.'+(frostDays>0?' Zmrzujočih dni: <b>'+frostDays+'</b>.':'')+' Najtoplejše: <b>'+maxT+'°C</b>'+(maxE?' ('+fmtD(maxE[0])+')':"")+'.'+ ' Najhladnejše: <b>'+minT+'°C</b>'+(minE?' ('+fmtD(minE[0])+')':"")+'.');
    document.getElementById('month-txt').innerHTML=document.getElementById('month-txt').textContent;
    // Rebuild with innerHTML
    const el=document.getElementById('month-txt');
    if(el)el.innerHTML=mn+' — '+entries.length+' dni podatkov. Povprečna temperatura: <b>'+avgT+'°C</b>. Skupne padavine: <b>'+totR+' mm</b> v <b>'+rainyDays+' deževnih dnevih</b>.'+(frostDays>0?' Zmrzujočih dni: <b>'+frostDays+'</b>.':'')+' Najtoplejše: <b>'+maxT+'°C</b>'+(maxE?' ('+fmtD(maxE[0])+')':"")+'.'+ ' Najhladnejše: <b>'+minT+'°C</b>'+(minE?' ('+fmtD(minE[0])+')':"")+'.'
  }catch(e){set('month-txt','Napaka: '+e.message);}
}

// ── Year records ──────────────────────────────────────────
function applyYearRecords(){
  const y=new Date().getFullYear();
  set('rec-year-lbl',y);
  try{
    const stored=JSON.parse(localStorage.getItem('wx-history-v1')||'{}');
    const entries=Object.entries(stored).filter(([k])=>k.startsWith(y+'-'));
    if(entries.length<3){const g=document.getElementById('yr-grid');if(g)g.innerHTML='<div style="color:var(--muted);font-size:.75rem">Zbiranje podatkov za '+y+'…</div>';return;}
    const fmtD=k=>new Date(k+'T12:00:00').toLocaleDateString('sl',{day:'numeric',month:'short'});
    const recs=[
      {icon:'🌡',lbl:'Najhoglejša temp.',val:()=>{const e=entries.filter(([,v])=>v.tempHigh!=null).reduce((m,c)=>parseFloat(c[1].tempHigh)>parseFloat(m[1].tempHigh)?c:m);return{v:parseFloat(e[1].tempHigh).toFixed(1)+'°C',d:fmtD(e[0])};},col:'var(--red)'},
      {icon:'❄️',lbl:'Najnižja temp.',val:()=>{const e=entries.filter(([,v])=>v.tempLow!=null).reduce((m,c)=>parseFloat(c[1].tempLow)<parseFloat(m[1].tempLow)?c:m);return{v:parseFloat(e[1].tempLow).toFixed(1)+'°C',d:fmtD(e[0])};},col:'var(--blue)'},
      {icon:'🌧',lbl:'Največ padavin',val:()=>{const e=entries.filter(([,v])=>(v.precipTotal||0)>0).sort((a,b)=>b[1].precipTotal-a[1].precipTotal)[0];return e?{v:parseFloat(e[1].precipTotal).toFixed(1)+' mm',d:fmtD(e[0])}:{v:'0 mm',d:'—'};},col:'var(--rain-col)'},
      {icon:'💨',lbl:'Najmočnejši sunek',val:()=>{const e=entries.filter(([,v])=>v.windspeedHigh!=null).reduce((m,c)=>parseFloat(c[1].windspeedHigh)>parseFloat(m[1].windspeedHigh)?c:m);return{v:parseFloat(e[1].windspeedHigh).toFixed(1)+' km/h',d:fmtD(e[0])};},col:'var(--purple)'},
    ];
    const g=document.getElementById('yr-grid');if(!g)return;g.innerHTML='';
    recs.forEach(r=>{
      try{const{v,d}=r.val();const item=document.createElement('div');item.className='yr-item';item.innerHTML='<div style="font-size:.74rem;color:var(--muted);text-transform:uppercase;letter-spacing:.1em;margin-bottom:.3rem">'+r.icon+' '+r.lbl+'</div><div class="yr-val" style="color:'+r.col+'">'+v+'</div><div class="yr-dt">'+d+'</div>';g.appendChild(item);}catch(_){}
    });
  }catch(e){const g=document.getElementById('yr-grid');if(g)g.innerHTML='<div style="color:var(--muted);font-size:.75rem">Ni dovolj podatkov</div>';}
}

// ── Heatmap calendar ──────────────────────────────────────
let _hmMode='rain';
function setHeatmapMode(mode){
  _hmMode=mode;
  document.getElementById('hm-btn-t')?.classList.toggle('active',mode==='temp');
  document.getElementById('hm-btn-r')?.classList.toggle('active',mode==='rain');
  drawHeatmap();
}
function drawHeatmap(){
  const svg=document.getElementById('heatmap-svg');if(!svg)return;
  const y=new Date().getFullYear();
  set('hm-year-lbl',y);
  try{
    const stored=JSON.parse(localStorage.getItem('wx-history-v1')||'{}');
    const SZ=11,GAP=2,STEP=SZ+GAP,TOP=20,LEFT=24;
    const weeks=54,W=LEFT+weeks*STEP+20,H=TOP+7*STEP+30;
    svg.setAttribute('viewBox','0 0 '+W+' '+H);svg.setAttribute('width',W);svg.setAttribute('height',H);
    svg.innerHTML='';
    const mkS=(parent,tag,attrs,txt)=>{const e=document.createElementNS('http://www.w3.org/2000/svg',tag);Object.entries(attrs).forEach(([k,v])=>e.setAttribute(k,v));if(txt)e.textContent=txt;parent.appendChild(e);return e;};
    // Temp colors: cold=blue, mild=green, hot=red
    const tempColor=t=>{if(t==null)return isDark()?'rgba(255,255,255,.05)':'rgba(0,0,0,.06)';if(t<0)return'#93c5fd';if(t<8)return'#6ee7b7';if(t<16)return'#86efac';if(t<22)return'#fcd34d';if(t<27)return'#fb923c';return'#f87171';};
    // Rain colors: white=dry, blue=wet
    const rainColor=r=>{if(r==null||r===0)return isDark()?'rgba(255,255,255,.05)':'rgba(0,0,0,.06)';if(r<1)return'#bfdbfe';if(r<5)return'#60a5fa';if(r<15)return'#3b82f6';if(r<30)return'#2563eb';return'#1e3a8a';};
    const jan1=new Date(y,0,1);
    const startWd=(jan1.getDay()+6)%7; // Mon=0
    const today=new Date();
    const months=['Jan','Feb','Mar','Apr','Maj','Jun','Jul','Avg','Sep','Okt','Nov','Dec'];
    let prevMonth=-1;
    for(let d=0;d<365;d++){
      const date=new Date(y,0,d+1);if(date>today)continue;
      const key=date.getFullYear()+'-'+String(date.getMonth()+1).padStart(2,'0')+'-'+String(date.getDate()).padStart(2,'0');
      const val=stored[key]??null;
      const col=_hmMode==='temp'?tempColor(val?.tempAvg??null):rainColor(val?.precipTotal??null);
      const col1=d+startWd,week=Math.floor(col1/7),dow=col1%7;
      const x=LEFT+week*STEP,y2=TOP+dow*STEP;
      const r=mkS(svg,'rect',{x,y:y2,width:SZ,height:SZ,rx:'2',fill:col});
      // Month labels
      if(date.getDate()===1&&prevMonth!==date.getMonth()){
        mkS(svg,'text',{x:x+2,y:TOP-5,'font-size':'7',fill:'var(--svg-lbl-d)','font-family':'JetBrains Mono,monospace'},months[date.getMonth()]);
        prevMonth=date.getMonth();
      }
    }
    // Day labels Mon/Wed/Fri
    ['P','T','S','Č','P','S','N'].forEach((d,i)=>{if(i%2===0)mkS(svg,'text',{x:2,y:TOP+i*STEP+SZ-2,'font-size':'7',fill:'var(--svg-lbl-d)','font-family':'JetBrains Mono,monospace'},d);});
    // Legend swatches
    const sw=document.getElementById('hm-swatches');
    if(sw){sw.innerHTML='';(_hmMode==='temp'?['#93c5fd','#86efac','#fcd34d','#fb923c','#f87171']:['rgba(0,0,0,.06)','#bfdbfe','#60a5fa','#3b82f6','#1e3a8a']).forEach(c=>{const d=document.createElement('div');d.className='hm-sw';d.style.background=c;d.style.border='1px solid var(--border)';sw.appendChild(d);});}
  }catch(e){console.warn('Heatmap:',e);}
}

// ── Lightning (Blitzortung) ───────────────────────────────
let _ltgStrikes=[],_ltgWs=null,_ltgEcowitt=null;
function haversine(lat1,lon1,lat2,lon2){
  const R=6371,dLat=(lat2-lat1)*Math.PI/180,dLon=(lon2-lon1)*Math.PI/180;
  const a=Math.sin(dLat/2)**2+Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dLon/2)**2;
  return R*2*Math.atan2(Math.sqrt(a),Math.sqrt(1-a));
}
// Blitzortung streams LZW-compressed strings, not plain JSON — must decode() first.
// See https://www.blitzortung.org/en/JS/lbr.js (encode/decode pair).
function _ltgDecode(b){
  var a,e={},d=b.split(""),c=d[0],f=c,g=[c],h=256,o=h;
  for(let i=1;i<d.length;i++){
    a=d[i].charCodeAt(0);
    a=h>a?d[i]:(e[a]?e[a]:f+c);
    g.push(a);c=a.charAt(0);e[o]=f+c;o++;f=a;
  }
  return g.join("");
}
function connectLightning(){
  if(_ltgWs&&_ltgWs.readyState<2)return;
  try{
    // live.blitzortung.org / ws.blitzortung.org have an expired TLS cert — use the
    // actual load-balanced pool the official live map connects to instead.
    const wsHosts=['ws1.blitzortung.org','ws2.blitzortung.org','ws7.blitzortung.org','ws8.blitzortung.org'];
    const wsHost=wsHosts[(_ltgRetry||0)%wsHosts.length];
    _ltgRetry=(_ltgRetry||0)+1;
    _ltgWs=new WebSocket('wss://'+wsHost);
    _ltgWs.onopen=()=>{_ltgWs.send('{"a":111}');applyLightning();};
    _ltgWs.onmessage=e=>{
      try{
        const d=JSON.parse(_ltgDecode(e.data));
        if(!('lat' in d)||!('lon' in d))return;
        let lat=Number(d.lat),lon=Number(d.lon);
        if(d.latc!=null)lat+=Number(d.latc);
        if(d.lonc!=null)lon+=Number(d.lonc);
        if(!Number.isFinite(lat)||!Number.isFinite(lon))return;
        const dist=haversine(LAT,LON,lat,lon);
        if(dist>200)return;
        const ts=Date.now();
        const t=new Date(ts);
        _ltgStrikes.unshift({dist:dist.toFixed(0),ts,time:t.toLocaleTimeString([],{hour:'2-digit',minute:'2-digit',second:'2-digit'}),source:'Blitzortung'});
        _ltgStrikes=_ltgStrikes.filter(s=>s.ts>Date.now()-3600000).slice(0,80);
        applyLightning();
      }catch(_){}
    };
    _ltgWs.onerror=_ltgWs.onclose=()=>{setTimeout(connectLightning,10000);};
  }catch(e){}
}
function updateLightningFromEcowitt(count,dist){
  if(count==null&&dist==null)return;
  _ltgEcowitt={
    count:Number(count)||0,
    dist:dist!=null&&Number.isFinite(Number(dist))?Number(dist):null,
    ts:Date.now()
  };
  updateStormMode({lightningCount:_ltgEcowitt.count,lightningDist:_ltgEcowitt.dist});
  applyLightning();
  renderStormAutopsy();
}
function applyLightning(){
  const hourAgo=Date.now()-3600000;
  _ltgStrikes=_ltgStrikes.filter(s=>(s.ts||0)>hourAgo);
  if(_ltgEcowitt&&Date.now()-_ltgEcowitt.ts>15*60*1000)_ltgEcowitt=null;
  const c=document.getElementById('ltg-count');
  const primaryCount=_ltgEcowitt?Math.round(_ltgEcowitt.count):_ltgStrikes.length;
  if(c)c.textContent=primaryCount;
  const win=document.getElementById('ltg-window');
  if(win)win.textContent=_ltgEcowitt?'udarov danes (Ecowitt)':'strel v zadnji uri';
  const nearest=_ltgStrikes.length?_ltgStrikes.reduce((m,s)=>parseFloat(s.dist)<parseFloat(m.dist)?s:m):null;
  const nearestDist=_ltgEcowitt?.dist??(nearest?parseFloat(nearest.dist):null);
  const nEl=document.getElementById('ltg-nearest');
  if(nEl)nEl.textContent=nearestDist!=null?'Najbližja: '+nearestDist.toFixed(0)+' km':'—';
  const list=document.getElementById('ltg-list');
  if(!list)return;list.innerHTML='';
  if(_ltgEcowitt){
    const row=document.createElement('div');
    row.className='ltg-row '+(_ltgEcowitt.dist!=null&&_ltgEcowitt.dist<30?'ltg-close':'ltg-far');
    row.textContent='Ecowitt · '+Math.round(_ltgEcowitt.count)+' danes'+(_ltgEcowitt.dist!=null?' · najbližja '+_ltgEcowitt.dist.toFixed(0)+' km':'');
    list.appendChild(row);
  }
  if(!_ltgStrikes.length&&!_ltgEcowitt){list.innerHTML='<div style="color:var(--muted)">Ni strel v zadnji uri · WebSocket: '+((_ltgWs&&_ltgWs.readyState===1)?'🟢 aktiven':'🔴 ni povezave')+'</div>';return;}
  _ltgStrikes.slice(0,15).forEach(s=>{const d=document.createElement('div');d.className='ltg-row '+(s.dist<30?'ltg-close':'ltg-far');d.textContent=s.time+' · '+s.dist+' km';list.appendChild(d);});
}

// ── Push notifications ────────────────────────────────────
// VAPID javni ključ (par zasebnega je skrivnost na Cloudflare Workerju)
const VAPID_PUBLIC="BCKBiX8AvTSRv98CufvMl51rpizfpg_LHm9K0rSCQYNJzfxV88tP60_n8mJ7bUEQo02zS02_l-FvTCtkSvfx3iY";
function _urlB64ToU8(b64){
  const pad='='.repeat((4-b64.length%4)%4);
  const base=(b64+pad).replace(/-/g,'+').replace(/_/g,'/');
  const raw=atob(base),out=new Uint8Array(raw.length);
  for(let i=0;i<raw.length;i++)out[i]=raw.charCodeAt(i);
  return out;
}
function _withTimeout(promise,ms){
  return Promise.race([promise,new Promise((_,rej)=>setTimeout(()=>rej(new Error('timeout')),ms))]);
}
async function toggleNotifications(){
  dismissNotifHint();
  const btn=document.getElementById('notif-btn');
  if(!('serviceWorker' in navigator)||!('PushManager' in window)){
    alert('Tvoj brskalnik ne podpira potisnih obvestil. Na iPhonu/iPadu najprej namesti aplikacijo (Deli → Na začetni zaslon), nato poskusi znova.');return;
  }
  // Že prej blokirano v brskalniku — requestPermission spodaj ne bo niti vprašal
  if(Notification.permission==='denied'){
    alert('Obvestila so blokirana v nastavitvah brskalnika za to stran. Odblokiraj jih v nastavitvah spletnega mesta (ikona ključavnice/i poleg naslova) in poskusi znova.');
    return;
  }
  let reg;
  try{reg=await _withTimeout(navigator.serviceWorker.ready,8000);}
  catch(_){alert('Obvestil ni bilo mogoče vklopiti — stran se še ni v celoti pripravila. Osveži stran in poskusi znova.');return;}
  let existing;
  try{existing=await reg.pushManager.getSubscription();}
  catch(e){alert('Obvestil ni bilo mogoče vklopiti. Poskusi znova.');return;}

  // Izklop: če je naročnina aktivna → odjava
  if(existing&&localStorage.getItem('wx-notif')==='on'){
    try{await fetch(PROXY+'/push/unsubscribe',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({endpoint:existing.endpoint})});}catch(_){}
    try{await existing.unsubscribe();}catch(_){}
    localStorage.setItem('wx-notif','off');
    btn?.classList.remove('on');
    return;
  }

  // Vklop
  let perm;
  try{perm=await Notification.requestPermission();}catch(_){perm='denied';}
  if(perm!=='granted'){
    alert('Obvestila niso bila vklopljena — dovoljenje ni bilo odobreno.');
    return;
  }
  let sub;
  try{
    sub=existing||await reg.pushManager.subscribe({userVisibleOnly:true,applicationServerKey:_urlB64ToU8(VAPID_PUBLIC)});
  }catch(e){
    console.error('pushManager.subscribe:',e);
    localStorage.setItem('wx-notif','off');
    btn?.classList.remove('on');
    alert('Obvestil ni bilo mogoče vklopiti — brskalnik ni uspel ustvariti naročnine ('+(e?.name||e?.message||'neznana napaka')+'). Poskusi v drugem brskalniku ali brez VPN/blokatorja oglasov.');
    return;
  }
  try{
    const r=await fetch(PROXY+'/push/subscribe',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({subscription:sub.toJSON()})});
    if(!r.ok)throw new Error('subscribe failed: HTTP '+r.status);
    localStorage.setItem('wx-notif','on');
    btn?.classList.add('on');
    reg.showNotification('Meteorec — obvestila vklopljena',{body:'Obvestili te bomo ob izrazitih dogodkih (močni sunki, nalivi, zmrzal) in vnaprej, ko se dež ali nevihta pričakuje v naslednjih ~45 minutah.',icon:'/icons/logo-192.png',badge:'/icons/badge-96.png'});
  }catch(e){
    console.error('push/subscribe:',e);
    localStorage.setItem('wx-notif','off');
    btn?.classList.remove('on');
    alert('Obvestil ni bilo mogoče vklopiti — strežnika ni bilo mogoče doseči ('+(e?.message||'neznana napaka')+'). Poskusi znova čez nekaj trenutkov.');
  }
}
function initNotifBtn(){
  const btn=document.getElementById('notif-btn');
  if(btn&&Notification.permission==='granted'&&localStorage.getItem('wx-notif')==='on')btn.classList.add('on');
  if(!('Notification' in window)&&btn)btn.style.display='none';
}
// ── Prvi obisk: opozori na gumbe za obvestila, da jih uporabnik takoj opazi ──
const NOTIF_HINT_KEY='wx-notif-hint-seen';
function dismissNotifHint(){
  const hint=document.getElementById('notif-hint');
  if(hint)hint.classList.remove('show');
  try{localStorage.setItem(NOTIF_HINT_KEY,'1');}catch(_){}
}
function initNotifHint(){
  if(!('Notification' in window))return;
  let seen=false; try{seen=!!localStorage.getItem(NOTIF_HINT_KEY);}catch(_){}
  // Ne kaži več, če je uporabnik obvestila že vklopil/izklopil ali jih brskalnik blokira
  if(seen||Notification.permission!=='default')return;
  setTimeout(()=>{
    const hint=document.getElementById('notif-hint');
    if(hint)hint.classList.add('show');
    setTimeout(dismissNotifHint,9000);
  },1800);
}
function maybePushAlert(title,body){
  if(Notification.permission==='granted'&&localStorage.getItem('wx-notif')==='on'){
    new Notification(title,{body,icon:'data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100"><text y="80" font-size="80">⚠️</text></svg>'});
  }
}


// ── Besedilna napoved — kompaktne kartice ────────────────
const _WMO_SL={0:'Jasno',1:'Pretežno jasno',2:'Delno oblačno',3:'Oblačno',45:'Megla',48:'Ivjna megla',51:'Rahlo rosenje',53:'Rosenje',55:'Močno rosenje',61:'Lahek dež',63:'Zmeren dež',65:'Močan dež',66:'Zmrzujoč dež',71:'Lahek sneg',73:'Zmeren sneg',75:'Močan sneg',77:'Sneg',80:'Plohe',81:'Plohe',82:'Močne plohe',85:'Snežne plohe',86:'Snežne plohe',95:'Nevihta',96:'Nevihta + toča',99:'Nevihta + toča'};
const _WMO_EMOJI={0:'☀️',1:'🌤',2:'⛅',3:'☁️',45:'🌫',48:'🌫',51:'🌦',53:'🌦',55:'🌧',61:'🌦',63:'🌧',65:'🌧',66:'🌨',71:'🌨',73:'❄️',75:'❄️',77:'❄️',80:'🌦',81:'🌧',82:'🌧',85:'🌨',86:'🌨',95:'⛈',96:'⛈',99:'⛈'};
const _WMO_EMOJI_NIGHT={0:'🌙',1:'🌙',2:'☁️',3:'☁️'};
const _WIND_DIR_SL=['S','SV','V','JV','J','JZ','Z','SZ'];
// ── Meteocons static SVG icon mapping ─────────────────────
const _WMO_ICON_DAY={0:'clear-day',1:'partly-cloudy-day',2:'partly-cloudy-day',3:'overcast',45:'fog-day',48:'fog-day',51:'drizzle',53:'drizzle',55:'overcast-drizzle',56:'sleet',57:'sleet',61:'rain',63:'overcast-rain',65:'overcast-rain',66:'sleet',67:'sleet',71:'overcast-day-snow',73:'overcast-snow',75:'overcast-snow',77:'snow',80:'partly-cloudy-day-rain',81:'partly-cloudy-day-rain',82:'overcast-rain',85:'partly-cloudy-day-snow',86:'overcast-snow',95:'thunderstorms-day-rain',96:'thunderstorms-day-hail',99:'thunderstorms-day-hail'};
const _WMO_ICON_NIGHT={0:'clear-night',1:'partly-cloudy-night',2:'partly-cloudy-night',3:'overcast',45:'fog-night',48:'fog-night',71:'overcast-night-snow',80:'partly-cloudy-night-rain',81:'partly-cloudy-night-rain',85:'partly-cloudy-night-snow',95:'thunderstorms-night-rain',96:'thunderstorms-night-hail',99:'thunderstorms-night-hail'};
const _COND_ICON={'Jasno sončno':'clear-day','Pretežno sončno':'partly-cloudy-day','Delno oblačno':'partly-cloudy-day','Pretežno oblačno':'overcast-day','Oblačno':'overcast','Jasna noč':'clear-night','Oblačna noč':'overcast-night','Rahel dež':'drizzle','Dež':'rain','Močan dež':'overcast-rain'};
const _WXCOND_ICON={snow:'snow',fog:'fog-day','fog-night':'fog-night',hot:'clear-day',storm:'thunderstorms-day-rain',rain:'overcast-rain',night:'clear-night'};
const _YR_ICON={clearsky:'clear-day',clearsky_night:'clear-night',fair:'partly-cloudy-day',fair_night:'partly-cloudy-night',partlycloudy:'partly-cloudy-day',partlycloudy_night:'partly-cloudy-night',cloudy:'overcast',fog:'fog-day',lightrain:'drizzle',rain:'rain',heavyrain:'overcast-rain',lightrainshowers:'partly-cloudy-day-rain',rainshowers:'partly-cloudy-day-rain',heavyrainshowers:'overcast-rain',lightsnow:'snow',snow:'snow',heavysnow:'overcast-snow',lightsnowshowers:'partly-cloudy-day-snow',snowshowers:'partly-cloudy-day-snow',sleet:'sleet',lightsleet:'sleet',lightsleetshowers:'sleet',sleetshowers:'sleet',thunderstorm:'thunderstorms-day-rain',thunderstormlightrain:'thunderstorms-day-rain',lightrainandthunder:'thunderstorms-day-rain',rainandthunder:'thunderstorms-day-rain',snowandthunder:'thunderstorms-day-rain',thunder:'thunderstorms-day-rain'};
function _wmoIconName(c,isDay=true){const map=isDay?_WMO_ICON_DAY:_WMO_ICON_NIGHT;return map[c]||_WMO_ICON_DAY[c]||_WMO_ICON_DAY[Math.floor((c||0)/10)*10]||'partly-cloudy-day';}
function _wmoImg(c,isDay=true,size=36){const n=_wmoIconName(c,isDay);return`<img src="icons/weather/${n}.svg" width="${size}" height="${size}" class="wx-icon" alt="${_wmoTxt(c)}">`;}
function _yrImg(sym,size=32){const base=(sym||'').replace(/_polartwilight/g,'');const n=_YR_ICON[base]||_YR_ICON[base.replace('_night','')]||(/_night/.test(base)?'partly-cloudy-night':'partly-cloudy-day');return`<img src="icons/weather/${n}.svg" width="${size}" height="${size}" class="wx-icon" alt="${sym}">`;}
function _condImg(label,size=100){const wc=typeof _wxCond==='string'?_wxCond:'';const n=_WXCOND_ICON[wc]||_COND_ICON[label]||'partly-cloudy-day';return`<img src="icons/weather/${n}.svg" width="${size}" height="${size}" class="wx-icon" alt="${label}">`;}
function _wmoTxt(c){return _WMO_SL[c]||_WMO_SL[Math.floor((c||0)/10)*10]||'Spremenljivo';}
function _wmoEmoji(c){return _WMO_EMOJI[c]||_WMO_EMOJI[Math.floor((c||0)/10)*10]||'🌤';}
function _wmoEmojiDN(c,isDay){if(!isDay&&c in _WMO_EMOJI_NIGHT)return _WMO_EMOJI_NIGHT[c];return _wmoEmoji(c);}

let _fcDailyData=null; // cached Open-Meteo daily data for all 4 forecast days
const _SL_DAYS_LOC=['nedeljo','ponedeljek','torek','sredo','četrtek','petek','soboto'];

function buildDailyForecastText({wmo,tmax,tmin,rain,prob,wind,uv,dayIdx=0}){
  const parts=[];
  const desc=_wmoTxt(wmo).toLowerCase();
  let dayWord='Danes';
  if(dayIdx===1)dayWord='Jutri';
  else if(dayIdx>1&&_fcDailyData){
    const dateObj=new Date(_fcDailyData.time[dayIdx]+'T12:00:00');
    dayWord='V '+_SL_DAYS_LOC[dateObj.getDay()];
  }
  parts.push(dayWord+' bo na Rečici ob Savinji predvidoma '+desc+', s temperaturo med '+Math.round(tmin)+'°C in '+Math.round(tmax)+'°C.');
  if(rain>=8)parts.push('Pričakovane so izrazitejše padavine, skupaj približno '+rain.toFixed(1)+' mm.');
  else if(rain>=0.5)parts.push('Možne so padavine, skupaj okoli '+rain.toFixed(1)+' mm.');
  else parts.push('Večjih padavin model ne nakazuje.');
  if(prob>=60)parts.push('Verjetnost padavin je povišana ('+Math.round(prob)+'%).');
  if(wind>=45)parts.push('Veter bo lahko moteč, z najmočnejšimi sunki okoli '+Math.round(wind)+' km/h.');
  else if(wind>=25)parts.push('Občasno bo pihal zmeren veter do približno '+Math.round(wind)+' km/h.');
  if(uv>=8)parts.push('UV indeks bo visok, zato je priporočljiva zaščita pred soncem.');
  return parts.join(' ');
}

function selectFcDay(el,i){
  document.querySelectorAll('#daily-fc-content .fc3-card').forEach(c=>c.classList.remove('fc3-active'));
  el.classList.add('fc3-active');
  if(!_fcDailyData)return;
  const d=_fcDailyData;
  const wmo=d.weather_code[i]||0;
  const tmax=d.temperature_2m_max[i]??0;
  const tmin=d.temperature_2m_min[i]??0;
  const rain=d.precipitation_sum[i]??0;
  const prob=d.precipitation_probability_max[i]??0;
  const wind=d.wind_speed_10m_max[i]??0;
  const uv=d.uv_index_max[i]??0;
  const dateObj=new Date(d.time[i]+'T12:00:00');
  const dateLbl=dateObj.toLocaleDateString('sl',{weekday:'long',day:'numeric',month:'long'});
  const text=buildDailyForecastText({wmo,tmax,tmin,rain,prob,wind,uv,dayIdx:i});
  const box=document.getElementById('daily-fc-content');
  const icon=box?.querySelector('.daily-fc-icon');
  const title=box?.querySelector('.daily-fc-title');
  const txt=box?.querySelector('.daily-fc-text');
  const kpis=box?.querySelectorAll('.daily-fc-kpi strong');
  if(icon)icon.innerHTML=_wmoImg(wmo,true,56);
  if(title)title.textContent=dateLbl+' · '+_wmoTxt(wmo);
  if(txt)txt.textContent=text;
  if(kpis?.[0])kpis[0].textContent=Math.round(tmax)+'° / '+Math.round(tmin)+'°';
  if(kpis?.[1])kpis[1].textContent=rain.toFixed(1)+' mm';
  if(kpis?.[2])kpis[2].textContent=Math.round(prob)+'%';
  if(kpis?.[3])kpis[3].textContent=Math.round(wind)+' km/h';
  if(kpis?.[4])kpis[4].textContent=Math.round(uv);
}

async function fetchLocalDailyForecast(){
  const box=document.getElementById('daily-fc-content');
  const upd=document.getElementById('daily-fc-updated');
  if(!box)return;
  try{
    // ── Open-Meteo: today for narrative text + KPIs, 4 days for cards ─
    const omUrl='https://api.open-meteo.com/v1/forecast'
      +'?latitude='+LAT+'&longitude='+LON
      +'&daily=weather_code,temperature_2m_max,temperature_2m_min,precipitation_sum,precipitation_probability_max,wind_speed_10m_max,uv_index_max'
      +'&timezone=Europe%2FLjubljana&forecast_days=4';
    const omData=await _archFetch(omUrl);
    const d=omData.daily;
    if(!d?.time?.length)throw new Error('No Open-Meteo data');
    _fcDailyData=d;
    buildTicker();
    const wmo=d.weather_code[0]||0;
    const tmax=d.temperature_2m_max[0]??0;
    const tmin=d.temperature_2m_min[0]??0;
    const rain=d.precipitation_sum[0]??0;
    const prob=d.precipitation_probability_max[0]??0;
    const wind=d.wind_speed_10m_max[0]??0;
    const uv=d.uv_index_max[0]??0;
    const text=buildDailyForecastText({wmo,tmax,tmin,rain,prob,wind,uv,dayIdx:0});
    const today=new Date(d.time[0]+'T12:00:00');
    const dateLbl=today.toLocaleDateString('sl',{weekday:'long',day:'numeric',month:'long'});
    // ── Try ARSO for 4-day cards ───────────────────────────────
    let cards4='',cardsSrc='Open-Meteo (rezervni vir)';
    try{
      const arso=await fetch(PROXY+'/arso-forecast').then(r=>r.json());
      if(arso?.days?.length){
        cards4=_buildArsoDailyCards(arso);
        if(cards4)cardsSrc='ARSO · '+(arso.location?.title||arso.location?.name||'Rečica ob Savinji');
      }
    }catch(_){}
    // ── Fallback: Open-Meteo 4-day cards ──────────────────────
    if(!cards4){
      const SL_DAYS=['nedelja','ponedeljek','torek','sreda','četrtek','petek','sobota'];
      cards4=d.time.slice(0,4).map((t,i)=>{
        const wcode=d.weather_code[i]||0;
        const tx=d.temperature_2m_max[i]??null;
        const tn=d.temperature_2m_min[i]??null;
        const dateObj=new Date(t+'T12:00:00');
        const isToday=i===0,isTomorrow=i===1;
        const dayLbl=isToday?'Danes':isTomorrow?'Jutri':SL_DAYS[dateObj.getDay()];
        const dl=dateObj.toLocaleDateString('sl',{day:'numeric',month:'long'});
        return`<div class="fc3-card${isToday?' fc3-today fc3-active':''}" onclick="selectFcDay(this,${i})">
  <div class="fc3-day">${dayLbl} <span style="font-weight:400;text-transform:none">${dl}</span></div>
  <div class="fc3-icon">${_wmoImg(wcode,true,44)}</div>
  ${tx!=null&&tn!=null?`<div class="fc3-temps">${Math.round(tx)}° <span class="fc3-tmin">/ ${Math.round(tn)}°</span></div>`:''}
  <div class="fc3-text" style="-webkit-line-clamp:unset">${_wmoTxt(wcode)}</div>
</div>`;
      }).join('');
    }
    box.innerHTML=
      '<div class="daily-fc-hero">'+
        '<div>'+
          '<div class="daily-fc-main">'+
            '<div class="daily-fc-icon">'+_wmoImg(wmo,true,64)+'</div>'+
            '<div>'+
              '<div class="daily-fc-title">'+dateLbl+' · '+_wmoTxt(wmo)+'</div>'+
              '<div class="daily-fc-text">'+text+'</div>'+
            '</div>'+
          '</div>'+
          '<div class="daily-fc-note">Napoved je modelna ocena za koordinate postaje IREICA1 pri Rečici ob Savinji in se samodejno osvežuje.</div>'+
        '</div>'+
        '<div class="daily-fc-kpis">'+
          '<div class="daily-fc-kpi"><strong>'+Math.round(tmax)+'° / '+Math.round(tmin)+'°</strong><span>temperatura</span></div>'+
          '<div class="daily-fc-kpi"><strong>'+rain.toFixed(1)+' mm</strong><span>padavine</span></div>'+
          '<div class="daily-fc-kpi"><strong>'+Math.round(prob)+'%</strong><span>verj. padavin</span></div>'+
          '<div class="daily-fc-kpi"><strong>'+Math.round(wind)+' km/h</strong><span>veter max</span></div>'+
          '<div class="daily-fc-kpi"><strong>'+Math.round(uv)+'</strong><span>UV max</span></div>'+
          '<div class="daily-fc-kpi"><strong>Rečica</strong><span>lokacija</span></div>'+
        '</div>'+
      '</div>'+
      '<div class="fc3-grid" style="margin-top:1rem">'+cards4+'</div>'+
      '<div class="fc3-src">'+cardsSrc+'</div>';
    if(upd)upd.textContent=(cardsSrc.startsWith('ARSO')?'ARSO':'Open-Meteo')+' · '+new Date().toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'});
  }catch(e){
    box.innerHTML='<div style="color:var(--muted);font-size:.8rem">Dnevna napoved trenutno ni na voljo.</div>';
    if(upd)upd.textContent='ni na voljo';
    console.warn('LocalDailyForecast:',e);
  }
}

function _buildArsoDailyCards(arso){
  const todayStr=_localDateStr(new Date());
  const targets=[0,1,2,3].map(i=>_localDateStr(new Date(Date.now()+i*864e5)));
  const SL_DAYS=['nedelja','ponedeljek','torek','sreda','četrtek','petek','sobota'];
  const days4=[];
  for(const t of targets){
    const found=arso.days.find(x=>(x.valid_date||x.date||'').startsWith(t));
    if(found)days4.push({d:found,key:t});
  }
  if(!days4.length)arso.days.slice(0,4).forEach((d,i)=>days4.push({d,key:targets[i]||''}));
  if(!days4.length)return'';
  return days4.map(({d,key},i)=>{
    const tmax=d.tmax_24h??d.tmax??d.tx??d.temperature_max??null;
    const tmin=d.tmin_24h??d.tmin??d.tn??d.temperature_min??null;
    const desc=d.nn24||d.nn||d.weather||d.shortFcst_sl||d.shortFcst||'';
    const fcText=d.longFcst_sl||d.longFcst||d.shortFcst_sl||d.shortFcst||d.fcst||d.napoved||'';
    const icon=_arsoIcon(desc||fcText);
    const isToday=i===0,isTomorrow=i===1;
    const dateObj=new Date((key||todayStr)+'T12:00:00');
    const dayLbl=isToday?'Danes':isTomorrow?'Jutri':SL_DAYS[dateObj.getDay()];
    const dateLbl=dateObj.toLocaleDateString('sl',{day:'numeric',month:'long'});
    return`<div class="fc3-card${isToday?' fc3-today fc3-active':''}" onclick="selectFcDay(this,${i})">
  <div class="fc3-day">${dayLbl} <span style="font-weight:400;text-transform:none">${dateLbl}</span></div>
  <div class="fc3-icon">${icon}</div>
  ${tmax!=null&&tmin!=null?`<div class="fc3-temps">${Math.round(tmax)}° <span class="fc3-tmin">/ ${Math.round(tmin)}°</span></div>`:''}
  ${fcText||desc?`<div class="fc3-text" style="-webkit-line-clamp:unset">${fcText||desc}</div>`:''}
</div>`;
  }).join('');
}

function _arsoIcon(txt){
  if(!txt)return'🌤';
  if(txt.match(/ploha|nevihta|thunderstorm/i))return'⛈';
  if(txt.match(/dež|padavin|deževn/i))return'🌧';
  if(txt.match(/sneg|snežen/i))return'❄️';
  if(txt.match(/burja|veter|vetrovno/i))return'💨';
  if(txt.match(/megla|megleno/i))return'🌫';
  if(txt.match(/spremenljivo|delno oblačno/i))return'⛅';
  if(txt.match(/oblačno|oblak/i))return'☁️';
  if(txt.match(/jasno|sončno|jasn/i))return'☀️';
  return'🌤';
}
function _renderArsoDailyForecast(arso,box,upd){
  const loc=arso.location||{};
  const locTitle=loc.title||loc.name||'Rečica ob Savinji';
  const todayStr=_localDateStr(new Date());
  const targets=[0,1,2,3].map(i=>_localDateStr(new Date(Date.now()+i*864e5)));

  const days4=[];
  for(const t of targets){
    const found=arso.days.find(x=>(x.valid_date||x.date||'').startsWith(t));
    if(found)days4.push({d:found,key:t});
  }
  if(!days4.length){
    arso.days.slice(0,4).forEach((d,i)=>days4.push({d,key:targets[i]||''}));
  }
  if(!days4.length){if(box)box.innerHTML='<div style="color:var(--muted);font-size:.8rem">ARSO: ni podatkov.</div>';return;}

  const SL_DAYS=['nedelja','ponedeljek','torek','sreda','četrtek','petek','sobota'];
  const cards=days4.map(({d,key},i)=>{
    const tmax=d.tmax_24h??d.tmax??d.tx??d.temperature_max??null;
    const tmin=d.tmin_24h??d.tmin??d.tn??d.temperature_min??null;
    const desc=d.nn24||d.nn||d.weather||d.shortFcst_sl||d.shortFcst||'';
    const fcText=d.longFcst_sl||d.longFcst||d.shortFcst_sl||d.shortFcst||d.fcst||d.napoved||'';
    const icon=_arsoIcon(desc||fcText);
    const isToday=i===0,isTomorrow=i===1;
    const dateObj=new Date((key||todayStr)+'T12:00:00');
    const dayLbl=isToday?'Danes':isTomorrow?'Jutri':SL_DAYS[dateObj.getDay()];
    const dateLbl=dateObj.toLocaleDateString('sl',{day:'numeric',month:'long'});
    return`<div class="fc3-card${isToday?' fc3-today':''}">
  <div class="fc3-day">${dayLbl} <span style="font-weight:400;text-transform:none">${dateLbl}</span></div>
  <div class="fc3-icon">${icon}</div>
  ${tmax!=null&&tmin!=null?`<div class="fc3-temps">${Math.round(tmax)}° <span class="fc3-tmin">/ ${Math.round(tmin)}°</span></div>`:''}
  ${fcText||desc?`<div class="fc3-text" style="-webkit-line-clamp:unset">${fcText||desc}</div>`:''}
</div>`;
  }).join('');

  box.innerHTML=`<div class="fc3-grid">${cards}</div><div class="fc3-src">ARSO · ${locTitle}</div>`;
  if(upd)upd.textContent='ARSO · '+new Date().toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'});
}

// ── AI Forecast (yr.no + Gemini) ──────────────────────────
const _YR_ICONS={
  clearsky:'☀️',fair:'🌤',partlycloudy:'⛅',cloudy:'☁️',fog:'🌫️',
  lightrain:'🌦',rain:'🌧',heavyrain:'🌧',lightrainshowers:'🌦',rainshowers:'🌧',heavyrainshowers:'🌧',
  lightsnow:'🌨',snow:'❄️',heavysnow:'❄️',lightsnowshowers:'🌨',snowshowers:'🌨',
  sleet:'🌧',lightsleet:'🌧',lightsleetshowers:'🌧',sleetshowers:'🌧',
  thunderstorm:'⛈',thunderstormlightrain:'⛈',lightrainandthunder:'⛈',rainandthunder:'⛈',
  snowandthunder:'⛈',thunder:'⛈',
};
function _yrIcon(sym){
  const base=(sym||'').replace(/_day|_night|_polartwilight/g,'');
  return _YR_ICONS[base]||'🌤';
}

async function fetchAIForecast(force=false){
  const CACHE_KEY='aifc-v8',CACHE_TTL=30*60*1000;
  const textEl=document.getElementById('aifc-text');
  const daysEl=document.getElementById('aifc-days');
  const metaEl=document.getElementById('aifc-meta');
  if(!textEl)return;
  if(!force){
    try{
      const c=JSON.parse(localStorage.getItem(CACHE_KEY)||'null');
      if(c&&Date.now()-c.ts<CACHE_TTL){_renderAIFC(c);return;}
    }catch(_){}
  }
  textEl.className='aifc-text loading';textEl.textContent='Generiram napoved…';
  if(daysEl)daysEl.innerHTML='';if(metaEl)metaEl.textContent='';
  try{
    const res=await fetch(PROXY+'/ai-forecast?_='+Date.now(),{cache:'no-store'});
    if(!res.ok)throw new Error('HTTP '+res.status);
    const data=await res.json();
    const payload={...data,ts:Date.now()};
    try{localStorage.setItem(CACHE_KEY,JSON.stringify(payload));}catch(_){}
    _renderAIFC(payload);
  }catch(e){
    if(textEl){textEl.className='aifc-text';textEl.textContent='Napoved trenutno ni na voljo.';}
    console.warn('fetchAIForecast',e);
  }
}

function _renderAIFC(data){
  const textEl=document.getElementById('aifc-text');
  const daysEl=document.getElementById('aifc-days');
  const metaEl=document.getElementById('aifc-meta');
  const srcBadge=document.getElementById('aifc-src-badge');
  const SL_DS=['ned','pon','tor','sre','čet','pet','sob'];
  if(srcBadge&&data.source){srcBadge.textContent=data.source;}
  if(textEl){
    if(data.text){
      textEl.className='aifc-text';
      textEl.textContent=data.text;
    }else if(data.summaries?.length){
      const s=data.summaries;
      const lines=[];
      if(s[0])lines.push(`Danes bo na Rečici ob Savinji temperatura med ${s[0].tmin}°C in ${s[0].tmax}°C${s[0].rain>0.5?`, pričakuje se ${s[0].rain} mm padavin`:''}.`);
      if(s[1])lines.push(`Jutri ${s[1].tmax!=null?s[1].tmin+'–'+s[1].tmax+'°C':''}.`);
      textEl.className='aifc-text';
      textEl.textContent=lines.join(' ');
    }
  }
  if(daysEl&&data.summaries?.length){
    const today=_localDateStr(new Date());
    daysEl.innerHTML=data.summaries.slice(0,7).map((s,i)=>{
      const dt=new Date(s.date+'T12:00:00');
      const lbl=i===0?'Danes':i===1?'Jutri':SL_DS[dt.getDay()];
      return`<div class="aifc-day${s.date===today?' today':''}">
<div class="aifc-day-name">${lbl}</div>
<div class="aifc-day-icon">${_yrImg(s.symbol,28)}</div>
<div class="aifc-day-t">${s.tmax!=null?Math.round(s.tmax)+'°':''}<span class="aifc-day-tlo">${s.tmin!=null?' /'+Math.round(s.tmin)+'°':''}</span></div>
${s.rain>0.3?`<div class="aifc-day-rain">💧${s.rain}</div>`:''}
</div>`;
    }).join('');
  }
  if(metaEl){
    const t=data.ts?new Date(data.ts).toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'}):'';
    metaEl.textContent=(data.source||'yr.no')+(t?' · '+t:'');
  }
}

async function fetchTextForecast(){
  try{
    const url='https://api.open-meteo.com/v1/forecast'
      +'?latitude='+LAT+'&longitude='+LON
      +'&daily=weather_code,temperature_2m_max,temperature_2m_min,precipitation_sum,'
      +'wind_speed_10m_max,wind_direction_10m_dominant,precipitation_probability_max'
      +'&timezone=Europe%2FLjubljana&forecast_days=7';
    const res=await fetch(url);const data=await res.json();
    const d=data.daily;if(!d?.time?.length)return;

    const SL_DAYS_SHORT=['ned','pon','tor','sre','čet','pet','sob'];
    const SL_DAYS_FULL=['Nedelja','Ponedeljek','Torek','Sreda','Četrtek','Petek','Sobota'];
    const SL_MON=['jan','feb','mar','apr','maj','jun','jul','avg','sep','okt','nov','dec'];

    const grid=document.getElementById('txfc-grid');if(!grid)return;
    grid.innerHTML='';

    d.time.forEach((t,i)=>{
      const date=new Date(t+'T12:00:00');
      const isToday=i===0, isTomorrow=i===1;
      const lbl=isToday?'Danes':isTomorrow?'Jutri':SL_DAYS_SHORT[date.getDay()]+' '+date.getDate()+'.';
      const wmo=d.weather_code[i];
      const tmax=d.temperature_2m_max[i],tmin=d.temperature_2m_min[i];
      const rain=d.precipitation_sum[i]||0;
      const wind=d.wind_speed_10m_max[i];
      const prob=d.precipitation_probability_max[i];

      const desc=_wmoTxt(wmo)+(wind>=30?' · '+Math.round(wind)+' km/h':'');

      const card=document.createElement('div');
      card.className='txfc-card'+(isToday?' today':'');
      card.title=(isToday?SL_DAYS_FULL[date.getDay()]+', ':'')+date.getDate()+'. '+SL_MON[date.getMonth()]
        +(rain>0?' · '+rain.toFixed(1)+' mm':'')
        +(prob?(' · '+prob+'% verj. dežja'):'')
        +(wind?' · veter '+Math.round(wind)+' km/h':'');
      card.innerHTML=
        '<div class="txfc-lbl">'+lbl+'</div>'+
        '<div class="txfc-emoji">'+_wmoImg(wmo,true,40)+'</div>'+
        '<div class="txfc-desc">'+desc+'</div>'+
        '<div class="txfc-temp"><span class="txfc-th">'+Math.round(tmax)+'°</span><span style="color:var(--muted);font-size:.74rem">/</span><span class="txfc-tl">'+Math.round(tmin)+'°</span></div>'+
        (rain>0.3?'<div class="txfc-rain">🌧 '+rain.toFixed(1)+' mm</div>':'');
      grid.appendChild(card);
    });

    const upd=document.getElementById('txfc-updated');
    if(upd)upd.textContent='posod. '+new Date().toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'});
  }catch(e){
    const g=document.getElementById('txfc-grid');
    if(g)g.innerHTML='<div style="color:var(--muted);font-size:.8rem;padding:.5rem 0">Napoved trenutno ni na voljo.</div>';
    console.warn('TextForecast:',e);
  }
}

function _omxNums(arr){return (arr||[]).filter(v=>Number.isFinite(v));}
function _omxPct(arr,p){
  const a=_omxNums(arr).sort((x,y)=>x-y);if(!a.length)return null;
  const i=(a.length-1)*p,lo=Math.floor(i),hi=Math.ceil(i);
  return lo===hi?a[lo]:a[lo]+(a[hi]-a[lo])*(i-lo);
}
function _omxMemberKeys(hourly,base){return Object.keys(hourly||{}).filter(k=>k.startsWith(base+'_member')).sort();}
function _omxSet(id,html){const el=document.getElementById(id);if(el)el.innerHTML=html;}
function _omxLoadingError(id,title){_omxSet(id,'<div class="omx-head"><div class="omx-title">'+title+'</div><span class="omx-badge">Open-Meteo</span></div><div class="omx-sub">Podatek trenutno ni na voljo.</div>');}

async function fetchForecastExtras(){
  if(!document.getElementById('omx-grid'))return;
  await Promise.allSettled([fetchForecastTrust(),fetchEnsembleConfidence(),fetchMinuteNowcast(),fetchSoilForecast()]);
}

function _trustYesterdayKey(){
  const d=new Date();d.setDate(d.getDate()-1);
  return _localDateStr(d);
}
function _trustActualFor(dateKey){
  const fromCache=(_histCache['7']||[]).find(d=>d.obsTimeLocal===dateKey);
  if(fromCache?.metric)return fromCache.metric;
  const fromLS=getLocalHistory('all').find(d=>d.obsTimeLocal===dateKey);
  return fromLS?.metric||null;
}
function _trustGrade(score){
  return score>=85?['Odlično','var(--green)']:score>=70?['Dobro','var(--blue)']:score>=55?['Mešano','var(--amber)']:['Slabo','var(--red)'];
}
async function fetchForecastTrust(){
  const el=document.getElementById('omx-trust');if(!el)return;
  const dateKey=_trustYesterdayKey();
  const actual=_trustActualFor(dateKey);
  if(!actual||actual.tempHigh==null||actual.tempLow==null){
    _omxSet('omx-trust','<div class="omx-head"><div class="omx-title">✅ Zaupanje napovedi</div><span class="omx-badge">IREICA1</span></div><div class="omx-sub">Za oceno potrebujem zaključen včerajšnji dan iz postaje. Podatek se prikaže, ko se naloži zgodovina.</div>');
    return;
  }
  try{
    const url='https://historical-forecast-api.open-meteo.com/v1/forecast?latitude='+LAT+'&longitude='+LON
      +'&start_date='+dateKey+'&end_date='+dateKey
      +'&daily=temperature_2m_max,temperature_2m_min,precipitation_sum,wind_gusts_10m_max'
      +'&timezone=Europe%2FLjubljana';
    const res=await fetch(url);if(!res.ok)throw new Error('HTTP '+res.status);
    const d=(await res.json()).daily;if(!d?.time?.length)throw new Error('No forecast verification data');
    const f={
      tempHigh:d.temperature_2m_max?.[0],
      tempLow:d.temperature_2m_min?.[0],
      precipTotal:d.precipitation_sum?.[0]??0,
      windspeedHigh:d.wind_gusts_10m_max?.[0],
    };
    const tempErr=((Math.abs((f.tempHigh??actual.tempHigh)-actual.tempHigh)+Math.abs((f.tempLow??actual.tempLow)-actual.tempLow))/2);
    const rainErr=Math.abs((f.precipTotal??0)-(actual.precipTotal??0));
    const windErr=actual.windspeedHigh!=null&&f.windspeedHigh!=null?Math.abs(f.windspeedHigh-actual.windspeedHigh):0;
    const rainMiss=((actual.precipTotal??0)>=1&&(f.precipTotal??0)<0.5)||((actual.precipTotal??0)<0.5&&(f.precipTotal??0)>=1);
    let score=100;
    score-=Math.min(35,tempErr*8);
    score-=Math.min(25,rainErr*4);
    score-=Math.min(22,windErr*1.2);
    if(rainMiss)score-=12;
    score=Math.max(0,Math.round(score));
    const [grade,col]=_trustGrade(score);
    _omxSet('omx-trust',
      '<div class="omx-head"><div class="omx-title">✅ Zaupanje napovedi</div><span class="omx-badge">včeraj</span></div>'+
      '<div class="omx-main" style="color:'+col+'">'+score+'/100</div>'+
      '<div class="omx-sub">'+grade+' ujemanje modela z meritvami IREICA1 za '+new Date(dateKey+'T12:00:00').toLocaleDateString('sl',{day:'numeric',month:'short'})+'.</div>'+
      '<div class="omx-kpis">'+
        '<div class="omx-kpi"><b>'+tempErr.toFixed(1)+'°C</b>napaka temp.</div>'+
        '<div class="omx-kpi"><b>'+rainErr.toFixed(1)+' mm</b>napaka dežja</div>'+
        '<div class="omx-kpi"><b>'+windErr.toFixed(0)+' km/h</b>napaka sunkov</div>'+
        '<div class="omx-kpi"><b>'+Math.round(f.tempHigh)+'/'+Math.round(actual.tempHigh)+'°</b>max model/postaja</div>'+
      '</div>');
  }catch(e){console.warn('ForecastTrust:',e);_omxLoadingError('omx-trust','✅ Zaupanje napovedi');}
}

async function fetchEnsembleConfidence(){
  try{
    const url='https://ensemble-api.open-meteo.com/v1/ensemble?latitude='+LAT+'&longitude='+LON
      +'&hourly=temperature_2m,precipitation,wind_gusts_10m&models=icon_eu'
      +'&forecast_hours=24&timezone=Europe%2FLjubljana';
    const res=await fetch(url);if(!res.ok)throw new Error('HTTP '+res.status);
    const h=(await res.json()).hourly;if(!h?.time?.length)throw new Error('No ensemble data');
    const tempKeys=_omxMemberKeys(h,'temperature_2m');
    const rainKeys=_omxMemberKeys(h,'precipitation');
    const gustKeys=_omxMemberKeys(h,'wind_gusts_10m');
    const tempMax=tempKeys.map(k=>Math.max(..._omxNums(h[k])));
    const rainTotals=rainKeys.map(k=>_omxNums(h[k]).reduce((a,b)=>a+b,0));
    const gustMax=gustKeys.map(k=>Math.max(..._omxNums(h[k])));
    const tempSpread=(_omxPct(tempMax,.9)??0)-(_omxPct(tempMax,.1)??0);
    const rainProb=rainTotals.length?rainTotals.filter(v=>v>=0.5).length/rainTotals.length*100:0;
    const heavyProb=rainTotals.length?rainTotals.filter(v=>v>=8).length/rainTotals.length*100:0;
    const gustP90=_omxPct(gustMax,.9)??0;
    const disagreement=Math.min(rainProb,100-rainProb);
    const confidence=tempSpread<=2.2&&disagreement<=20?'Visoka':tempSpread<=4&&disagreement<=35?'Srednja':'Nizka';
    const ccol=confidence==='Visoka'?'var(--green)':confidence==='Srednja'?'var(--amber)':'var(--red)';
    _omxSet('omx-ensemble','<div class="omx-head"><div class="omx-title">🎲 Zanesljivost napovedi</div><span class="omx-badge">ICON-EU EPS</span></div><div class="omx-main" style="color:'+ccol+'">'+confidence+'</div><div class="omx-sub">Razpon med člani ansambla za naslednjih 24 ur. Nižja zanesljivost pomeni, da so možni hitri lokalni obrati.</div><div class="omx-kpis"><div class="omx-kpi"><b>'+tempSpread.toFixed(1)+'°C</b>razpon Tmax</div><div class="omx-kpi"><b>'+Math.round(rainProb)+'%</b>člani z dežjem</div><div class="omx-kpi"><b>'+Math.round(heavyProb)+'%</b>močnejši dež</div><div class="omx-kpi"><b>'+Math.round(gustP90)+' km/h</b>p90 sunki</div></div>');
  }catch(e){console.warn('Ensemble:',e);_omxLoadingError('omx-ensemble','🎲 Zanesljivost napovedi');}
}

async function fetchMinuteNowcast(){
  try{
    const url='https://api.open-meteo.com/v1/forecast?latitude='+LAT+'&longitude='+LON
      +'&minutely_15=precipitation,weather_code,wind_gusts_10m,cape'
      +'&forecast_minutely_15=16&timezone=Europe%2FLjubljana';
    const res=await fetch(url);if(!res.ok)throw new Error('HTTP '+res.status);
    const m=(await res.json()).minutely_15;if(!m?.time?.length)throw new Error('No minutely data');
    const rain=m.precipitation||[],wmo=m.weather_code||[],gust=m.wind_gusts_10m||[],cape=m.cape||[];
    const firstWet=rain.findIndex((v,i)=>v>0.1||[80,81,82,95,96,99].includes(wmo[i]));
    const stormIdx=wmo.findIndex(v=>[95,96,99].includes(v));
    const total=rain.reduce((a,b)=>a+(b||0),0);
    const maxGust=Math.max(0,..._omxNums(gust));
    const maxCape=Math.max(0,..._omxNums(cape));
    const msg=firstWet<0?'Naslednje 4 ure večinoma suho':(firstWet===0?'Padavine zdaj':('Prve padavine okoli '+new Date(m.time[firstWet]).toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'})));
    const bars=rain.map((v,i)=>{const h=Math.max(6,Math.min(100,(v||0)/Math.max(1,total,2)*100));const cls=[95,96,99].includes(wmo[i])?' storm':(v>0.1?' hit':'');return '<div class="omx-bar'+cls+'" title="'+new Date(m.time[i]).toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'})+' · '+(v||0).toFixed(1)+' mm" style="height:'+h+'%"></div>';}).join('');
    _omxSet('omx-nowcast','<div class="omx-head"><div class="omx-title">⏱ 15-minutni potek</div><span class="omx-badge">4 ure</span></div><div class="omx-main">'+msg+'</div><div class="omx-bars">'+bars+'</div><div class="omx-kpis"><div class="omx-kpi"><b>'+total.toFixed(1)+' mm</b>skupaj</div><div class="omx-kpi"><b>'+Math.round(maxGust)+' km/h</b>najvišji sunek</div><div class="omx-kpi"><b>'+Math.round(maxCape)+'</b>CAPE</div><div class="omx-kpi"><b>'+(stormIdx>=0?'možna':'ne')+'</b>nevihta</div></div>');
    updateStormMode({nowcast:{message:msg,rain:total,gust:maxGust,cape:maxCape,storm:stormIdx>=0},active:_stormMode.active||stormIdx>=0||maxGust>=60||maxCape>=1000,level:_stormMode.level||((stormIdx>=0||maxGust>=70||maxCape>=1500)?'orange':'yellow')});
  }catch(e){console.warn('15-min forecast:',e);_omxLoadingError('omx-nowcast','⏱ 15-minutni potek');}
}

async function fetchSoilForecast(){
  try{
    const url='https://api.open-meteo.com/v1/forecast?latitude='+LAT+'&longitude='+LON
      +'&hourly=soil_temperature_0cm,soil_temperature_6cm,soil_moisture_0_to_1cm,soil_moisture_1_to_3cm,soil_moisture_3_to_9cm'
      +'&forecast_hours=6&timezone=Europe%2FLjubljana';
    const res=await fetch(url);if(!res.ok)throw new Error('HTTP '+res.status);
    const h=(await res.json()).hourly;if(!h?.time?.length)throw new Error('No soil data');
    const t0=h.soil_temperature_0cm?.[0],t6=h.soil_temperature_6cm?.[0];
    const m1=h.soil_moisture_0_to_1cm?.[0],m3=h.soil_moisture_1_to_3cm?.[0],m9=h.soil_moisture_3_to_9cm?.[0];
    const root=(m3+m9)/2;
    const status=root<0.09?'Zelo suho':root<0.16?'Suho':root<0.28?'V redu':'Mokro';
    const scol=status==='V redu'?'var(--green)':status==='Mokro'?'var(--blue)':status==='Suho'?'var(--amber)':'var(--red)';
    const note=status==='Zelo suho'||status==='Suho'?'Tla imajo malo vode v zgornji plasti; za vrt je smiselno spremljati padavine.':status==='Mokro'?'Zgornje plasti so dobro namočene; po nalivih pričakuj počasnejše sušenje.':'Vlaga v zgornjih plasteh je trenutno ugodna.';
    _omxSet('omx-soil','<div class="omx-head"><div class="omx-title">🌱 Tla in vlaga</div><span class="omx-badge">0–9 cm</span></div><div class="omx-main" style="color:'+scol+'">'+status+'</div><div class="omx-sub">'+note+'</div><div class="omx-kpis"><div class="omx-kpi"><b>'+Number(t0).toFixed(1)+'°C</b>površina</div><div class="omx-kpi"><b>'+Number(t6).toFixed(1)+'°C</b>6 cm</div><div class="omx-kpi"><b>'+Number(m1).toFixed(3)+'</b>0–1 cm</div><div class="omx-kpi"><b>'+root.toFixed(3)+'</b>1–9 cm</div></div>');
  }catch(e){console.warn('Soil forecast:',e);_omxLoadingError('omx-soil','🌱 Tla in vlaga');}
}




// ── Photo times (astronomical) ────────────────────────────
function calcPhotoTimes(){
  const now=new Date();
  const jd=now.getTime()/86400000+2440587.5;
  const n=jd-2451545;
  const L=(280.46+0.9856474*n)%360;
  const g=((357.528+0.9856003*n)%360)*Math.PI/180;
  const lam=(L+1.915*Math.sin(g)+0.02*Math.sin(2*g))*Math.PI/180;
  const eps=23.439*Math.PI/180;
  const dec=Math.asin(Math.sin(eps)*Math.sin(lam));
  const latR=LAT*Math.PI/180;
  const eot=-7.655*Math.sin(g)+9.873*Math.sin(2*lam+3.588)+0.439*Math.sin(4*lam-6.714);
  const snUtc=12-LON/15-eot/60;
  const tz=-now.getTimezoneOffset()/60;

  // Hour angle for given solar elevation (null if no crossing)
  const ha=elev=>{
    const c=(Math.sin(elev*Math.PI/180)-Math.sin(latR)*Math.sin(dec))/(Math.cos(latR)*Math.cos(dec));
    return Math.abs(c)<=1?Math.acos(c)*180/Math.PI/15:null;
  };
  const toLocal=h=>((h+tz)%24+24)%24;
  const fmt=h=>{if(h==null)return'—';const l=toLocal(h);return String(Math.floor(l)).padStart(2,'0')+':'+String(Math.round((l%1)*60)).padStart(2,'0');};
  const toH=h=>h==null?null:toLocal(h);

  const hh=ha(0);   if(hh==null)return null;  // no sunrise — polar day/night
  const hg=ha(10);  // golden hour: sun 0°→10° (after sunrise / before sunset)
  const hb=ha(-6);  // blue hour: sun 0°→-6° (civil twilight)
  const hn=ha(-12); // nautical twilight end

  return{
    // Morning (dark → bright)
    nautAMh: toH(snUtc-(hn||hb||hh)),  nautAM:  fmt(snUtc-(hn||hb||hh)),
    blueAMh: toH(snUtc-(hb||hh)),      blueAM:  fmt(snUtc-(hb||hh)),
    sunriseH:toH(snUtc-hh),             sunrise: fmt(snUtc-hh),
    goldAMh: toH(snUtc-(hg||hh)+(hg?0:1)), goldAM:fmt(snUtc-(hg||hh)),  // end of golden AM
    // Midday
    noonH:   toH(snUtc),                noon:    fmt(snUtc),
    // Evening (bright → dark)
    goldPMh: toH(snUtc+(hg||hh)),       goldPM:  fmt(snUtc+(hg||hh)),  // start of golden PM
    sunsetH: toH(snUtc+hh),             sunset:  fmt(snUtc+hh),
    bluePMh: toH(snUtc+(hb||hh)),       bluePM:  fmt(snUtc+(hb||hh)),
    nautPMh: toH(snUtc+(hn||hb||hh)),   nautPM:  fmt(snUtc+(hn||hb||hh)),
  };
}

function calcMacroScore(temp,wind,humidity,rain){
  let s=100;
  if(temp<10)s-=50;else if(temp<16)s-=20;else if(temp>30)s-=30;else if(temp>26)s-=10;
  if(wind>20)s-=40;else if(wind>12)s-=20;else if(wind>6)s-=8;
  if(humidity<40)s-=20;else if(humidity>95)s-=10;
  if(rain>0)s-=30;
  return Math.max(0,Math.min(100,Math.round(s)));
}

function applyPhotographyWidget(obs){
  try{
    const pt=calcPhotoTimes();if(!pt)return;
    const now=new Date(),nowH=now.getHours()+now.getMinutes()/60;

    // ── Light timeline (correct order: night→blue→sunrise→gold→day→gold→sunset→blue→night)
    const segs=[
      {from:0,           to:pt.nautAMh,  c:'#020617'},
      {from:pt.nautAMh,  to:pt.blueAMh,  c:'#1e3a5f'},
      {from:pt.blueAMh,  to:pt.sunriseH, c:'#1d4ed8'},
      {from:pt.sunriseH, to:pt.goldAMh,  c:'#b45309'},
      {from:pt.goldAMh,  to:pt.goldPMh,  c:'#38bdf8'},
      {from:pt.goldPMh,  to:pt.sunsetH,  c:'#b45309'},
      {from:pt.sunsetH,  to:pt.bluePMh,  c:'#1d4ed8'},
      {from:pt.bluePMh,  to:pt.nautPMh,  c:'#1e3a5f'},
      {from:pt.nautPMh,  to:24,          c:'#020617'},
    ].filter(sg=>sg.from!=null&&sg.to!=null&&sg.to>sg.from);

    const tl=document.getElementById('photo-timeline');
    if(tl){
      tl.innerHTML='';
      segs.forEach(sg=>{
        const d=document.createElement('div');d.className='photo-tl-seg';
        d.style.cssText='flex:'+(sg.to-sg.from)+';background:'+sg.c;
        tl.appendChild(d);
      });
      const ind=document.createElement('div');ind.className='photo-tl-now';
      ind.style.left=(nowH/24*100)+'%';tl.appendChild(ind);
    }

    // ── Current phase
    let phase='☀️ Dan',phaseColor='var(--blue)';
    if(nowH<pt.nautAMh||nowH>pt.nautPMh)          {phase='🌙 Noč';         phaseColor='var(--muted)';}
    else if(nowH<pt.blueAMh)                       {phase='🌌 Somrak';      phaseColor='#475569';}
    else if(nowH<pt.sunriseH)                      {phase='💙 Modra ura ↑'; phaseColor='#3b82f6';}
    else if(nowH<pt.goldAMh)                       {phase='🌅 Zlata ura ↑'; phaseColor='#f97316';}
    else if(nowH>pt.goldPMh&&nowH<pt.sunsetH)      {phase='🌇 Zlata ura ↓'; phaseColor='#f97316';}
    else if(nowH>pt.sunsetH&&nowH<pt.bluePMh)      {phase='💙 Modra ura ↓'; phaseColor='#3b82f6';}
    else if(nowH>pt.bluePMh&&nowH<pt.nautPMh)      {phase='🌌 Somrak';      phaseColor='#475569';}
    const phEl=document.getElementById('photo-phase-lbl');
    if(phEl){phEl.textContent=phase;phEl.style.color=phaseColor;}

    // ── Event labels
    const ev=document.getElementById('photo-events');
    if(ev)ev.innerHTML=[
      {h:pt.blueAMh,  l:'💙 '+pt.blueAM},
      {h:pt.sunriseH, l:'☀️ '+pt.sunrise},
      {h:pt.goldAMh,  l:'🌅 '+pt.goldAM},
      {h:pt.noonH,    l:'🌞 '+pt.noon},
      {h:pt.goldPMh,  l:'🌇 '+pt.goldPM},
      {h:pt.sunsetH,  l:'🌆 '+pt.sunset},
      {h:pt.bluePMh,  l:'💙 '+pt.bluePM},
    ].filter(p=>p.h!=null).map(p=>`<span style="color:${Math.abs(p.h-nowH)<0.5?'var(--amber)':'var(--muted)'}">${p.l}</span>`).join('');

    // ── Macro scores
    const m=obs?.metric||{};
    const T=m.temp??15,W=m.windSpeed??0,H=obs?.humidity??70,R=m.precipRate??0;
    const ms=calcMacroScore(T,W,H,R);
    const ls=phase.includes('Zlata')?95:phase.includes('Modra')?85:phase.includes('Noč')||phase.includes('Somrak')?10:65;
    const ws=Math.max(0,Math.round(100-W*3.5));
    const mg=document.getElementById('photo-macro-grid');
    if(mg)mg.innerHTML=[
      {n:ms,          l:'Makro pogoji', c:ms>=70?'var(--green)':ms>=45?'var(--amber)':'var(--red)',    s:'%'},
      {n:ls,          l:'Svetloba',     c:ls>=80?'var(--amber)':ls>=50?'var(--blue)':'var(--muted)',   s:'%'},
      {n:ws,          l:'Mirnost vetra',c:ws>=80?'var(--green)':ws>=50?'var(--amber)':'var(--red)',    s:'%'},
      {n:T.toFixed(1),l:'Temperatura',  c:T>=16&&T<=26?'var(--green)':T>=10?'var(--amber)':'var(--blue)',s:'°C'},
    ].map(it=>`<div class="photo-macro-item"><div class="photo-macro-score" style="color:${it.c}">${it.n}${it.s}</div><div class="photo-macro-lbl">${it.l}</div></div>`).join('');

    // ── Subjects
    const subjects=[
      {e:'🦋',n:'Metulji',      a:T>=18&&T<=30&&W<15&&R<0.1},
      {e:'🐝',n:'Čebele',       a:T>=15&&W<20&&R<0.1},
      {e:'🦗',n:'Kobilice',     a:T>=22&&W<20&&R<0.1},
      {e:'🐛',n:'Hrošči',       a:T>=14&&T<=28},
      {e:'🕷',n:'Pajki',        a:T>=10&&T<=24},
      {e:'🐉',n:'Kačji pastirji',a:T>=20&&W<20&&R<0.1},
      {e:'🌸',n:'Cvetlice',     a:true},
      {e:'🍄',n:'Gobe',         a:R>0||H>=85},
    ];
    const sEl=document.getElementById('photo-subjects');
    if(sEl)sEl.innerHTML=subjects.map(s=>`<div class="photo-subject ${s.a?'active':'low'}">${s.e} ${s.n}</div>`).join('');

    // ── Tip
    const tips=[];
    if(phase.includes('Zlata'))     tips.push('Idealen čas — zlata svetloba, dolge sence.');
    if(phase.includes('Modra'))     tips.push('Modra ura: mehka difuzna svetloba brez senc.');
    if(H>=80&&T>=10&&T<=20)         tips.push('Visoka vlaga — pričakuj roso in kapljice.');
    if(R<0.1&&T>=18&&W<10)          tips.push('Idealni pogoji za žuželke — mirno in toplo.');
    if(W>20)                        tips.push('Preveč vetra za makro. Poiščite zavetje.');
    const tipEl=document.getElementById('photo-tip');
    if(tipEl)tipEl.textContent=tips[0]||'';
  }catch(e){console.warn('PhotoWidget:',e);}
}


async function checkSmartNotifications(){
  if(!('Notification'in window)||Notification.permission!=='granted'||localStorage.getItem('wx-notif')!=='on')return;
  const today=new Date().toDateString();
  if(localStorage.getItem('wx-notif-day')===today)return;
  localStorage.setItem('wx-notif-day',today);
  try{
    const url='https://api.open-meteo.com/v1/forecast?latitude='+LAT+'&longitude='+LON+'&daily=temperature_2m_max,temperature_2m_min,precipitation_sum,wind_gusts_10m_max,weather_code&hourly=dew_point_2m,temperature_2m,wind_speed_10m&timezone=Europe%2FLjubljana&forecast_days=3';
    const res=await fetch(url);const data=await res.json();
    const d=data.daily,h=data.hourly;
    const notify=(t,b,i)=>{try{new Notification(t,{body:b});}catch(_){}};
    if((d.temperature_2m_max?.[1]||0)>=28)notify('🌡 Jutri bo vroče!','Temperatura do '+d.temperature_2m_max[1].toFixed(0)+'°C.');
    if((d.temperature_2m_min?.[1]||99)<=0)notify('❄️ Jutri možna zmrzal','Min: '+d.temperature_2m_min[1].toFixed(1)+'°C');
    const fogH=(h?.time||[]).slice(0,48).filter((_,i)=>{const hr=new Date(h.time[i]).getHours();return hr>=4&&hr<=8&&(h.temperature_2m[i]-h.dew_point_2m[i])<1.5&&(h.wind_speed_10m[i]||10)<5;});
    if(fogH.length>=2)notify('🌫 Jutri zjutraj megla','Pričakujemo meglo med 4:00 in 8:00.');
    const tmx=d.temperature_2m_max?.[1]||0,tgust=d.wind_gusts_10m_max?.[1]||99,tc=d.weather_code?.[1]||0;
    if(tmx>=18&&tmx<=27&&tgust<20&&![61,63,65,80,95].includes(tc))notify('📷 Jutri idealno za fotografiranje!','Temp '+tmx.toFixed(0)+'°C, brez dežja, miren veter. Odlično za makro!');
    if((d.precipitation_sum?.[1]||0)>=20)notify('🌧 Jutri obilne padavine',d.precipitation_sum[1].toFixed(0)+' mm. Možne poplave!');
    if([95,96,99].includes(tc))notify('⛈ Jutri nevihta!','Pričakovana nevihta. Ostani na varnem.');
  }catch(e){console.warn('SmartNotif:',e);}
}

// ── Elevation profile ─────────────────────────────────────
function drawElevationProfile(stations){
  const svg=document.getElementById('elev-svg');if(!svg)return;
  const valid=stations.filter(s=>s.cur?.temperature_2m!=null);
  if(valid.length<2)return;
  const VW=700,VH=260,pad={t:20,r:90,b:45,l:55};
  const cw=VW-pad.l-pad.r,ch=VH-pad.t-pad.b;
  const temps=valid.map(s=>s.cur.temperature_2m),alts=valid.map(s=>s.alt);
  const tmin=Math.min(...temps)-1.5,tmax=Math.max(...temps)+1.5,amax=Math.max(...alts)+150;
  const xS=t=>pad.l+(t-tmin)/(tmax-tmin)*cw;
  const yS=a=>pad.t+(1-a/amax)*ch;
  const mk=(tag,attrs,txt)=>{const e=document.createElementNS('http://www.w3.org/2000/svg',tag);Object.entries(attrs).forEach(([k,v])=>e.setAttribute(k,v));if(txt)e.textContent=txt;svg.appendChild(e);return e;};
  svg.innerHTML='';
  for(let i=0;i<=4;i++){const x=pad.l+i/4*cw;mk('line',{x1:x,x2:x,y1:pad.t,y2:VH-pad.b,stroke:CC.grid,'stroke-width':'1'});mk('text',{x:x,y:VH-pad.b+14,'text-anchor':'middle','font-size':'10',fill:CC.label,'font-family':'JetBrains Mono,monospace'},(tmin+i/4*(tmax-tmin)).toFixed(1)+'°');}
  [0,300,600,900,1200,1500].filter(a=>a<=amax).forEach(a=>{const y=yS(a);mk('line',{x1:pad.l,x2:VW-pad.r,y1:y,y2:y,stroke:CC.grid,'stroke-width':'1'});mk('text',{x:pad.l-6,y:y+4,'text-anchor':'end','font-size':'10',fill:CC.label,'font-family':'JetBrains Mono,monospace'},a);});
  // Lapse line
  const ref=valid.find(s=>s.mine)||valid[0];
  const lt1=ref.cur.temperature_2m+6.5*(ref.alt/1000),lt2=ref.cur.temperature_2m-6.5*((amax-ref.alt)/1000);
  mk('line',{x1:xS(lt1),y1:yS(0),x2:xS(lt2),y2:yS(amax),stroke:'rgba(255,255,255,.12)','stroke-width':'2','stroke-dasharray':'6,4'});
  mk('text',{x:VW-pad.r+6,y:yS(amax/2),'font-size':'9',fill:'rgba(255,255,255,.3)','font-family':'JetBrains Mono,monospace'},'-6.5°/km');
  const colors=['#38bdf8','#4ade80','#fbbf24','#f87171','#a78bfa','#67e8f9'];
  valid.forEach((s,i)=>{
    const x=xS(s.cur.temperature_2m),y=yS(s.alt),col=s.mine?'#38bdf8':colors[(i+1)%colors.length];
    mk('circle',{cx:x,cy:y,r:s.mine?9:6,fill:col,stroke:'white','stroke-width':s.mine?'2':'1.5'});
    const anchor=s.cur.temperature_2m<(tmin+tmax)/2?'start':'end';
    mk('text',{x:x+(anchor==='start'?12:-12),y:y+4,'text-anchor':anchor,'font-size':'10',fill:CC.label,'font-family':'JetBrains Mono,monospace'},s.name.split(' ')[0]+' '+s.cur.temperature_2m.toFixed(1)+'°');
  });
  mk('text',{x:pad.l+cw/2,y:VH-5,'text-anchor':'middle','font-size':'10',fill:CC.label,'font-family':'JetBrains Mono,monospace'},'Temperatura (°C)');
  const sorted=valid.slice().sort((a,b)=>a.alt-b.alt);
  if(sorted.length>=2){
    const lr=(sorted[0].cur.temperature_2m-sorted[sorted.length-1].cur.temperature_2m)/(sorted[sorted.length-1].alt-sorted[0].alt)*1000;
    const lapseEl=document.getElementById('elev-lapse');
    if(lapseEl)lapseEl.textContent='Izmerjen gradient: −'+Math.abs(lr).toFixed(1)+'°C/1000 m (std. −6.5°C/1000 m)'+(Math.abs(lr)<2?' · ⚠️ Toplotna inverzija!':'');
  }
  const leg=document.getElementById('elev-legend');
  if(leg)leg.innerHTML=valid.map((s,i)=>`<span style="display:inline-flex;align-items:center;gap:.3rem"><span style="width:10px;height:10px;border-radius:50%;background:${s.mine?'#38bdf8':colors[(i+1)%colors.length]};display:inline-block"></span>${s.name} (${s.alt} m)</span>`).join('');
}

function calcHumidex(T,Td){
  const e=6.112*Math.exp(17.67*Td/(Td+243.5));
  return+(T+0.5555*(e-10)).toFixed(1);
}
function calcWindChill(T,V){
  if(T>10||V<=5)return null;
  return+(13.12+0.6215*T-11.37*Math.pow(V,0.16)+0.3965*T*Math.pow(V,0.16)).toFixed(1);
}
function applyBiometeo(obs){
  const m=obs.metric,T=m.temp??15,Td=m.dewpt??T-5,V=m.windSpeed??0;
  // Humidex
  const hx=calcHumidex(T,Td);
  const[hCat,hCol,hTip]=hx<27?['Prijetno','var(--green)','Normalne razmere']:
    hx<32?['Opazno neudobje','var(--amber)','Nekoliko neugodno']:
    hx<40?['Precejšnje neudobje','#f97316','Izogibaj se fizičnemu naporu']:
    hx<46?['Vroče — nevarnost','var(--red)','Možna toplotna izčrpanost']:
    ['NEVARNO','#9333ea','Toplotni udar — ostani v senci!'];
  set('bio-humidex',hx+'°');set('bio-humidex-cat',hCat);set('bio-humidex-tip',hTip);
  const hBox=document.getElementById('bio-humidex-box');
  if(hBox)hBox.style.borderColor=hCol+'55';
  document.getElementById('bio-humidex')?.style&&(document.getElementById('bio-humidex').style.color=hCol);
  document.getElementById('bio-humidex-cat')&&(document.getElementById('bio-humidex-cat').style.color=hCol);
  // Wind Chill
  const wc=calcWindChill(T,V);
  const wcEl=document.getElementById('bio-chill');
  if(wc===null){
    set('bio-chill','—');set('bio-chill-cat',T>10?'Ni hladno':'Premalo vetra');set('bio-chill-tip','');
  }else{
    const[wcCat,wcCol,wcTip]=wc>0?['Sveže','var(--cyan)','']:
      wc>-10?['Hladno','#60a5fa','']:
      wc>-28?['Zelo hladno','#3b82f6','Možnost ozeblin po 30+ min']:
      wc>-40?['Nevarno hladno','var(--purple)','Ozebline v 10–30 min']:
      ['EKSTREMNO','#9333ea','Ozebline v manj kot 5 min!'];
    set('bio-chill',wc+'°');set('bio-chill-cat',wcCat);set('bio-chill-tip',wcTip);
    if(wcEl)wcEl.style.color=wcCol;
    const cBox=document.getElementById('bio-chill-box');if(cBox)cBox.style.borderColor=wcCol+'55';
    document.getElementById('bio-chill-cat')&&(document.getElementById('bio-chill-cat').style.color=wcCol);
  }
  // Overall
  const ov=document.getElementById('bio-overall');
  if(ov){
    if(hx>=40)ov.innerHTML='⚠️ <strong>Visok toplotni stres</strong> — omejite gibanje na prostem';
    else if(wc!==null&&wc<-20)ov.innerHTML='⚠️ <strong>Hladni stres</strong> — pokrijte izpostavljeno kožo';
    else ov.innerHTML='✓ Biometeorološke razmere so ugodne';
  }
}

// ── Fog forecast ──────────────────────────────────────────
function fogProb(T,Td,wind,hour){
  const dep=T-Td;
  let p=0;
  if(dep<1)p=85;else if(dep<2)p=65;else if(dep<3)p=40;else if(dep<5)p=15;
  if(wind>15)p-=30;else if(wind>8)p-=15;else if(wind<3)p+=12;
  if(hour>=20||hour<7)p+=15; // night/dawn bonus for valley fog
  return Math.max(0,Math.min(100,Math.round(p)));
}
async function fetchFogForecast(){
  try{
    const url='https://api.open-meteo.com/v1/forecast?latitude='+LAT+'&longitude='+LON
      +'&hourly=temperature_2m,dew_point_2m,wind_speed_10m,visibility&timezone=Europe%2FLjubljana&forecast_days=2';
    const res=await fetch(url);const data=await res.json();
    const times=data.hourly?.time??[];
    const temps=data.hourly?.temperature_2m??[];
    const dews=data.hourly?.dew_point_2m??[];
    const winds=data.hourly?.wind_speed_10m??[];
    const vis=data.hourly?.visibility??[];
    const now=new Date(),nowH=now.getHours();
    // Find current and next 24h
    const startIdx=times.findIndex(t=>new Date(t)>=now)||(0);
    const slice=times.slice(startIdx,startIdx+24);
    const fogData=slice.map((_,i)=>{
      const idx=startIdx+i;
      const T=temps[idx]??15,Td=dews[idx]??T-5,V=winds[idx]??0;
      const h=new Date(times[idx]).getHours();
      const vis_m=vis[idx]??10000;
      // Use actual visibility if available, else calculate
      const prob=vis_m<1000?90:vis_m<5000?Math.max(fogProb(T,Td,V,h),50):fogProb(T,Td,V,h);
      return{time:times[idx],prob,h};
    });
    // Current fog
    const curProb=fogData[0]?.prob??0;
    const curEl=document.getElementById('fog-now-val');
    if(curEl){curEl.childNodes[0].textContent=curProb;curEl.style.color=curProb>=70?'var(--amber)':curProb>=40?'var(--blue)':'var(--green)';}
    const lbl=curProb>=70?'⚠️ Velika verjetnost megle':curProb>=40?'Zmerna verjetnost megle':curProb>=20?'Majhna verjetnost megle':'Megla malo verjetna';
    set('fog-now-lbl',lbl);
    // Timeline (every 3h for 24h = 8 bars)
    const step3=fogData.filter((_,i)=>i%3===0);
    const tl=document.getElementById('fog-timeline'),ll=document.getElementById('fog-labels');
    if(tl){tl.innerHTML='';step3.forEach(d=>{const bar=document.createElement('div');bar.className='fog-bar';const h=Math.max(4,d.prob)+'%';bar.style.cssText='flex:1;border-radius:3px;height:'+h+';align-self:flex-end;background:'+(d.prob>=70?'rgba(217,119,6,.7)':d.prob>=40?'rgba(77,159,248,.6)':'rgba(100,160,100,.4)');tl.appendChild(bar);});}
    if(ll){ll.innerHTML='';step3.forEach(d=>{const s=document.createElement('span');s.textContent=String(new Date(d.time).getHours()).padStart(2,'0')+':00';ll.appendChild(s);});}
    // Peak fog note
    const maxFog=Math.max(...fogData.map(d=>d.prob));
    const maxFogEntry=fogData.find(d=>d.prob===maxFog);
    const note=document.getElementById('fog-note');
    if(note&&maxFog>=40){const t=new Date(maxFogEntry.time);note.textContent='Največja verjetnost: '+maxFog+'% ob '+t.getHours()+':00';}
    else if(note){note.textContent='Megla v naslednjih 24 urah malo verjetna';}
  }catch(e){console.warn('Fog:',e);}
}

// ── Hourly temperature profile ────────────────────────────
function drawHourlyProfile(observations){
  const svg=document.getElementById('hourly-svg');if(!svg||!observations.length)return;
  const byHour=Array.from({length:24},()=>[]);
  observations.forEach(o=>{
    const h=new Date(o.obsTimeLocal.replace(' ','T')).getHours();
    const t=o.metric?.tempAvg??o.metric?.temp;
    if(t!=null)byHour[h].push(t);
  });
  const avgs=byHour.map((ts,h)=>({h,avg:ts.length?ts.reduce((a,b)=>a+b,0)/ts.length:null}));
  const validAvgs=avgs.filter(a=>a.avg!=null);if(validAvgs.length<6){return;}
  // Interpolate missing hours
  const filled=avgs.map((a,i)=>{
    if(a.avg!=null)return a;
    const prev=avgs.slice(0,i).reverse().find(x=>x.avg!=null);
    const next=avgs.slice(i+1).find(x=>x.avg!=null);
    if(prev&&next){const w=(i-prev.h)/(next.h-prev.h);return{h:i,avg:prev.avg*(1-w)+next.avg*w};}
    return{h:i,avg:prev?.avg??next?.avg??15};
  });
  svg.innerHTML='';
  const VW=880,VH=160,pad={t:20,r:20,b:30,l:40};
  const cw=VW-pad.l-pad.r,ch=VH-pad.t-pad.b;
  const temps=filled.map(a=>a.avg);
  const mn=Math.min(...temps)-1,mx=Math.max(...temps)+1;
  const xS=h=>pad.l+h/23*cw,yS=v=>pad.t+(1-(v-mn)/(mx-mn))*ch;
  const mk=(tag,attrs,txt)=>{const e=document.createElementNS('http://www.w3.org/2000/svg',tag);Object.entries(attrs).forEach(([k,v])=>e.setAttribute(k,v));if(txt)e.textContent=txt;svg.appendChild(e);return e;};
  // Grid
  for(let i=0;i<=4;i++){const y=pad.t+i/4*ch,v=mx-(i/4*(mx-mn));mk('line',{x1:pad.l,x2:VW-pad.r,y1:y,y2:y,stroke:CC.grid,'stroke-width':'1'});mk('text',{x:pad.l-5,y:y+4,'text-anchor':'end','font-size':'9',fill:CC.label,'font-family':'JetBrains Mono,monospace'},v.toFixed(0)+'°');}
  [0,3,6,9,12,15,18,21].forEach(h=>mk('text',{x:xS(h),y:VH-4,'text-anchor':'middle','font-size':'9',fill:CC.label,'font-family':'JetBrains Mono,monospace'},(h<10?'0':'')+h+':00'));
  const defs=mk('defs',{});
  defs.innerHTML='<linearGradient id="hpg" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="'+CC.tempLine+'" stop-opacity="0.2"/><stop offset="100%" stop-color="'+CC.tempLine+'" stop-opacity="0"/></linearGradient>';
  const pts=filled.map(a=>({x:xS(a.h),y:yS(a.avg)}));
  const lp=smoothPath(pts);
  mk('path',{d:lp+' L '+xS(23)+','+(VH-pad.b)+' L '+xS(0)+','+(VH-pad.b)+' Z',fill:'url(#hpg)'});
  mk('path',{d:lp,fill:'none',stroke:CC.tempLine,'stroke-width':'2.5','stroke-linecap':'round'});
  // Highlight max and min
  const maxA=filled.reduce((m,a)=>a.avg>m.avg?a:m);
  const minA=filled.reduce((m,a)=>a.avg<m.avg?a:m);
  mk('circle',{cx:xS(maxA.h),cy:yS(maxA.avg),r:'5',fill:'#f87171',stroke:'white','stroke-width':'2'});
  mk('circle',{cx:xS(minA.h),cy:yS(minA.avg),r:'5',fill:CC.tempLine,stroke:'white','stroke-width':'2'});
  mk('text',{x:xS(maxA.h),y:yS(maxA.avg)-9,'text-anchor':'middle','font-size':'8',fill:'#f87171','font-family':'JetBrains Mono,monospace'},maxA.avg.toFixed(1)+'°');
  mk('text',{x:xS(minA.h),y:yS(minA.avg)+16,'text-anchor':'middle','font-size':'8',fill:CC.tempLine,'font-family':'JetBrains Mono,monospace'},minA.avg.toFixed(1)+'°');
  // Interactive crosshair — scrub through hourly averages with mouse or finger
  const tipLine=mk('line',{x1:0,x2:0,y1:pad.t,y2:VH-pad.b,stroke:CC.now,'stroke-width':'1','stroke-dasharray':'3,2',opacity:'0',style:'pointer-events:none'});
  const tipDot=mk('circle',{cx:0,cy:0,r:'5',fill:CC.tempLine,stroke:'white','stroke-width':'2',opacity:'0',style:'pointer-events:none'});
  mk('rect',{x:pad.l,y:pad.t,width:cw,height:ch,fill:'transparent'});
  const htip=document.getElementById('chart-tip');
  attachScrub(svg,(sx,clientX,clientY)=>{if(!htip)return;const h=Math.max(0,Math.min(23,Math.round((sx-pad.l)/cw*23)));const a=filled[h];if(!a)return;const px=xS(a.h),py=yS(a.avg);tipLine.setAttribute('x1',px);tipLine.setAttribute('x2',px);tipLine.setAttribute('opacity','1');tipDot.setAttribute('cx',px);tipDot.setAttribute('cy',py);tipDot.setAttribute('opacity','1');htip.innerHTML='<span style="color:'+CC.tempLine+';font-weight:600">'+a.avg.toFixed(1)+'°C</span>&ensp;'+(a.h<10?'0':'')+a.h+':00';htip.style.opacity='1';htip.style.left=Math.min(clientX+14,window.innerWidth-120)+'px';htip.style.top=Math.max(8,clientY-28)+'px';},()=>{tipLine.setAttribute('opacity','0');tipDot.setAttribute('opacity','0');if(htip)htip.style.opacity='0';});
  const peaks=document.getElementById('hourly-peaks');
  if(peaks)peaks.innerHTML='<div class="hourly-peak-item">🔴 Najtopleje ob <b>'+(maxA.h<10?'0':'')+maxA.h+':00 ('+maxA.avg.toFixed(1)+'°C)</b></div><div class="hourly-peak-item">🔵 Najhladneje ob <b>'+(minA.h<10?'0':'')+minA.h+':00 ('+minA.avg.toFixed(1)+'°C)</b></div><div class="hourly-peak-item">Amplituda: <b>'+(maxA.avg-minA.avg).toFixed(1)+'°C</b></div>';
}

// ── Phenological calendar ─────────────────────────────────
const PHENO=[
  {gdd:[20,90],doy:[35,85],icon:'🌳',name:'Leska / dren cveti',note:'zgodnja pomlad, zelo odvisno od mikrolokacije'},
  {gdd:[80,170],doy:[65,105],icon:'🌼',name:'Regrat in prve travniške cvetlice',note:'prisojni travniki prej, dolina kasneje'},
  {gdd:[140,260],doy:[85,120],icon:'🌸',name:'Koščičasto sadje cveti',note:'sliva, češnja; pozeba je še pomembno tveganje'},
  {gdd:[220,380],doy:[105,140],icon:'🍎',name:'Jablane in hruške cvetijo',note:'sadovnjakarsko najobčutljivejše okno'},
  {gdd:[360,560],doy:[125,160],icon:'🌿',name:'Polno olistanje gozda',note:'bukev/hrast na pobočjih, dolina z zamikom'},
  {gdd:[520,760],doy:[145,175],icon:'🌺',name:'Bezeg in akacija',note:'močan lokalni signal pozne pomladi'},
  {gdd:[700,980],doy:[160,195],icon:'🌾',name:'Prva košnja / travni vrh',note:'odvisno od padavin in rasti trav'},
  {gdd:[950,1350],doy:[185,230],icon:'🦋',name:'Poletni insekti in suhi travniki',note:'metulji, kobilice, kačji pastirji'},
  {gdd:[1350,1850],doy:[225,275],icon:'🍄',name:'Pozno poletje: rosa, pajki, gobe po dežju',note:'vlaga in padavine sta pomembnejši od GDD'},
  {gdd:[0,9999],doy:[276,330],icon:'🍂',name:'Jesensko obarvanje in prva slana',note:'vodijo nočne temperature in dolinska inverzija'},
];
async function applyPheno(){
  const y=new Date().getFullYear();
  set('pheno-year',y);
  try{
    const stored=JSON.parse(localStorage.getItem('wx-history-v1')||'{}');
    // Get all entries for current year sorted by date
    let entries=Object.entries(stored)
      .filter(([k])=>k.startsWith(y+'-'))
      .sort(([a],[b])=>a.localeCompare(b));
    if(entries.length<5){
      const start=y+'-01-01';
      const end=_localDateStr(new Date());
      const url='https://archive-api.open-meteo.com/v1/archive?latitude='+LAT+'&longitude='+LON+'&start_date='+start+'&end_date='+end+'&daily=temperature_2m_max,temperature_2m_min&timezone=Europe%2FLjubljana';
      const data=await _archFetch(url);
      entries=(data.daily?.time||[]).map((d,i)=>[d,{tempHigh:data.daily.temperature_2m_max?.[i],tempLow:data.daily.temperature_2m_min?.[i]}]);
    }
    if(entries.length<5){const pl=document.getElementById('pheno-list-left');if(pl)pl.innerHTML='<div style="color:var(--muted);font-size:.75rem">Zbiranje podatkov za fenološki izračun…</div>';return;}
    // Accumulate phenological GDD base 5 from Jan 1
    let totalGdd=0;
    const gddByDate={};
    entries.forEach(([date,v])=>{
      const tmax=v.tempHigh??v.tempAvg??0,tmin=v.tempLow??v.tempAvg??0;
      const daily=Math.max(0,(tmax+tmin)/2-5);
      totalGdd+=daily;
      gddByDate[date]=totalGdd;
    });
    set('pheno-gdd-total',Math.round(totalGdd));
    const today=new Date();
    const doy=Math.floor((today-new Date(y,0,0))/864e5);
    const fmtD=d=>d.toLocaleDateString('sl',{day:'numeric',month:'short'});
    const fmtDoy=d=>fmtD(new Date(y,0,d));
    const statusFor=p=>{
      const inGdd=totalGdd>=p.gdd[0]&&totalGdd<=p.gdd[1];
      const inDate=doy>=p.doy[0]&&doy<=p.doy[1];
      if(inGdd&&inDate)return{cls:'active',txt:'aktivno',col:'var(--green)'};
      if(doy>p.doy[1]||totalGdd>p.gdd[1])return{cls:'pheno-done',txt:'mimo',col:'var(--muted)'};
      if(doy>=p.doy[0]-14||totalGdd>=p.gdd[0]-80)return{cls:'pheno-soon',txt:'kmalu',col:'var(--amber)'};
      return{cls:'pheno-future',txt:'kasneje',col:'var(--muted)'};
    };
    const half=Math.ceil(PHENO.length/2);
    const renderList=(items,elId)=>{
      const el=document.getElementById(elId);if(!el)return;el.innerHTML='';
      items.forEach(p=>{
        const st=statusFor(p);
        const reached=Object.entries(gddByDate).find(([,g])=>g>=p.gdd[0]);
        const dateStr=st.txt==='mimo'&&reached?fmtD(new Date(reached[0]+'T12:00:00')):fmtDoy(p.doy[0])+'–'+fmtDoy(p.doy[1]);
        const row=document.createElement('div');
        row.className='pheno-row '+st.cls;
        row.innerHTML=
          '<div class="pheno-icon">'+p.icon+'</div>'+
          '<div class="pheno-name"><span>'+p.name+'</span><div style="font-size:.67rem;color:var(--muted);line-height:1.35;margin-top:.1rem">'+p.note+'</div></div>'+
          '<div class="pheno-gdd">'+p.gdd[0]+'–'+p.gdd[1]+' GDD5</div>'+
          '<div class="pheno-date" style="color:'+st.col+'"><span>'+dateStr+'</span> <span class="pheno-status">'+st.txt+'</span></div>';
        el.appendChild(row);
      });
    };
    renderList(PHENO.slice(0,half),'pheno-list-left');
    renderList(PHENO.slice(half),'pheno-list-right');
    const next=PHENO.find(p=>statusFor(p).txt==='aktivno')||PHENO.find(p=>statusFor(p).txt==='kmalu');
    const note=document.getElementById('pheno-note');
    if(note&&next)note.textContent='Fenološki koledar je ocena za dolinsko lego Rečice: GDD5 + sezonsko okno. Trenutni signal: '+next.icon+' '+next.name+'. To ni točen datum cvetenja, ampak lokalno verjetnostno okno.';
  }catch(e){console.warn('Pheno:',e);}
}

// ── Water balance ─────────────────────────────────────────
async function fetchWaterBalance(){
  try{
    const now=new Date(),y=now.getFullYear(),m=now.getMonth()+1;
    const pad=n=>String(n).padStart(2,'0');
    const pfx=y+'-'+pad(m);
    const sd=y+'-'+pad(m)+'-01',ed=y+'-'+pad(m)+'-'+pad(now.getDate());
    // Fetch ET₀ from archive
    const url='https://archive-api.open-meteo.com/v1/archive?latitude='+LAT+'&longitude='+LON+'&start_date='+sd+'&end_date='+ed+'&daily=et0_fao_evapotranspiration,precipitation_sum&timezone=Europe%2FLjubljana';
    const data=await _archFetch(url);
    const et0List=data.daily?.et0_fao_evapotranspiration??[];
    const omRain=data.daily?.precipitation_sum??[];
    // Get local station rain from localStorage
    const stored=JSON.parse(localStorage.getItem('wx-history-v1')||'{}');
    const stationEntries=Object.entries(stored).filter(([k])=>k.startsWith(pfx));
    const dates=data.daily?.time??[];
    // Build daily balance
    const balDays=dates.map((date,i)=>{
      const stEntry=stationEntries.find(([k])=>k===date);
      const rain=stEntry?stEntry[1].precipTotal:omRain[i]??0;
      const et=et0List[i]??0;
      return{date,rain:rain??0,et0:et,bal:(rain??0)-et};
    }).filter(d=>d.date<=ed);
    const totRain=balDays.reduce((s,d)=>s+d.rain,0);
    const totEt=balDays.reduce((s,d)=>s+d.et0,0);
    const totBal=totRain-totEt;
    const monthName=now.toLocaleDateString('sl',{month:'long',year:'numeric'});
    set('wbal-month',monthName);
    set('wbal-rain',totRain.toFixed(1)+' mm');
    set('wbal-et0',totEt.toFixed(1)+' mm');
    const balEl=document.getElementById('wbal-bal');
    if(balEl){balEl.textContent=(totBal>=0?'+':'')+totBal.toFixed(1)+' mm';balEl.style.color=totBal>=0?'var(--blue)':'var(--amber)';}
    const statusEl=document.getElementById('wbal-status');
    if(statusEl){statusEl.textContent=totBal>20?'💧 Presežek — mokro':totBal>0?'🌱 Uravnoteženo':totBal>-20?'🌤 Rahel primanjkljaj':'☀️ Suho — priporočeno zalivanje';statusEl.style.color=totBal>0?'var(--blue)':'var(--amber)';}
    // Bar chart
    const maxAbs=Math.max(...balDays.map(d=>Math.abs(d.bal)),1);
    const barsEl=document.getElementById('wbal-bars');
    const labsEl=document.getElementById('wbal-labels');
    if(barsEl){
      barsEl.innerHTML='';
      balDays.forEach(d=>{
        const pct=Math.min(48,(Math.abs(d.bal)/maxAbs)*48);
        const pos=d.bal>=0;
        const wrap=document.createElement('div');
        wrap.style.cssText='flex:1;display:flex;flex-direction:column;align-items:center;justify-content:'+(pos?'flex-end':'flex-start')+';height:100%';
        const bar=document.createElement('div');
        bar.style.cssText='width:100%;height:'+pct+'px;background:'+(pos?'rgba(96,165,250,.7)':'rgba(251,191,36,.6)')+';border-radius:'+(pos?'3px 3px 0 0':'0 0 3px 3px')+';min-height:1px';
        wrap.appendChild(bar);barsEl.appendChild(wrap);
      });
    }
    if(labsEl){
      labsEl.innerHTML='';
      const step=Math.max(1,Math.floor(balDays.length/6));
      balDays.forEach((d,i)=>{const s=document.createElement('span');s.textContent=i%step===0?new Date(d.date+'T12:00:00').getDate()+'.':'';labsEl.appendChild(s);});
    }
  }catch(e){console.warn('WaterBalance:',e);}
}

// ── Analysis charts ───────────────────────────────────────
// ══════════════════════════════════════════════════════════
// ── 1. Climate Stripes (Ed Hawkins stil) ─────────────────
// ══════════════════════════════════════════════════════════
function buildClimateStripes(){
  const el=document.getElementById('climate-stripes-svg');if(!el)return;
  const data=XLSX_LETNO.filter(l=>l.y>=2020); // skip partial years
  if(!data.length)return;
  const W=Math.max(300,el.closest('.nt-card,.card')?.offsetWidth-40||600),H=120;
  el.setAttribute('viewBox',`0 0 ${W} ${H}`);

  const temps=data.map(l=>l.T);
  const tMin=Math.min(...temps),tMax=Math.max(...temps),tRange=tMax-tMin||1;
  const sw=W/data.length;

  // Ed Hawkins blue→red colour scale based on deviation from mean
  const mean=temps.reduce((a,b)=>a+b,0)/temps.length;
  const stripeColor=t=>{
    const dev=(t-mean)/(tRange/2); // -1..+1 roughly
    if(dev<0){ // cooler = blue
      const i=Math.min(1,Math.abs(dev));
      const r=Math.round(8+(180-8)*(1-i)),g=Math.round(48+(210-48)*(1-i)),b=Math.round(107+(230-107)*(1-i));
      return `rgb(${r},${g},${b})`;
    }else{ // warmer = red
      const i=Math.min(1,dev);
      const r=Math.round(255-(255-103)*(1-i)),g=Math.round(80+(180-80)*(1-i)),b=Math.round(60+(160-60)*(1-i));
      return `rgb(${Math.min(255,r)},${g},${b})`;
    }
  };

  let svg='';
  data.forEach((l,i)=>{
    svg+=`<rect x="${(i*sw).toFixed(1)}" y="0" width="${(sw+0.5).toFixed(1)}" height="${H-22}" fill="${stripeColor(l.T)}"/>`;
    svg+=`<text x="${(i*sw+sw/2).toFixed(1)}" y="${H-7}" text-anchor="middle" font-size="9.5" fill="var(--muted)" font-family="JetBrains Mono,monospace">${String(l.y).slice(2)}</text>`;
    svg+=`<text x="${(i*sw+sw/2).toFixed(1)}" y="${(H-30).toFixed(1)}" text-anchor="middle" font-size="8.5" fill="rgba(255,255,255,.85)" font-family="JetBrains Mono,monospace" style="paint-order:stroke;stroke:rgba(0,0,0,.3);stroke-width:2px">${l.T.toFixed(1)}°</text>`;
  });
  el.innerHTML=svg;
}

// ══════════════════════════════════════════════════════════
// ── 2. Vremenski dvojnik (najbolj podoben dan) ───────────
// ══════════════════════════════════════════════════════════
function findWeatherTwin(){
  const el=document.getElementById('twin-content');if(!el)return;
  const obs=_lastBriefObs;
  if(!obs?.metric){el.innerHTML='<div style="color:var(--muted);font-size:.78rem">Čakam na trenutne meritve …</div>';return;}

  const m=obs.metric;
  const today={T:m.temp,hum:obs.humidity,pres:m.pressure,wind:m.windSpeed};
  const stored=JSON.parse(localStorage.getItem(LS_KEY)||'{}');
  const todayStr=_localDateStr(new Date());

  let best=null,bestScore=Infinity;
  Object.entries(stored).forEach(([date,v])=>{
    if(date===todayStr)return;
    const t=v.tempAvg??v.tempHigh;if(t==null)return;
    // Weighted distance (T matters most, then humidity, pressure)
    const dT=Math.abs(t-today.T)*3;
    const dH=v.humidity!=null&&today.hum!=null?Math.abs(v.humidity-today.hum)*0.3:0;
    const dP=v.pressure!=null&&today.pres!=null?Math.abs(v.pressure-today.pres)*0.5:0;
    const score=dT+dH+dP;
    if(score<bestScore){bestScore=score;best={date,...v,score};}
  });

  if(!best){el.innerHTML='<div style="color:var(--muted);font-size:.78rem">Premalo podatkov.</div>';return;}

  const bd=new Date(best.date+'T12:00:00');
  const daysAgo=Math.round((Date.now()-bd)/864e5);
  const fmt=(v,u)=>v!=null?Math.round(v)+u:'—';
  const tempV=best.tempAvg??best.tempHigh;

  el.innerHTML=
    `<div style="display:flex;align-items:baseline;gap:.5rem;margin-bottom:.6rem">
      <span style="font-family:'JetBrains Mono',monospace;font-size:1.4rem;color:var(--text)">${bd.toLocaleDateString('sl',{day:'numeric',month:'long',year:'numeric'})}</span>
    </div>
    <div style="font-size:.74rem;color:var(--muted);margin-bottom:.7rem">pred ${daysAgo} dnevi · ujemanje ${Math.max(0,Math.round(100-best.score*2))}%</div>
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(85px,1fr));gap:.5rem">
      <div class="ecw-item"><div class="ecw-val">${fmt(tempV,'°C')}</div><div class="ecw-lbl">Temp (dvojnik)</div></div>
      <div class="ecw-item"><div class="ecw-val">${fmt(best.humidity,'%')}</div><div class="ecw-lbl">Vlaga</div></div>
      <div class="ecw-item"><div class="ecw-val">${fmt(best.pressure,'')}</div><div class="ecw-lbl">Tlak hPa</div></div>
      ${best.precipTotal?`<div class="ecw-item"><div class="ecw-val">${best.precipTotal.toFixed(1)}</div><div class="ecw-lbl">Dež mm</div></div>`:''}
    </div>
    <div style="font-size:.72rem;color:var(--muted);margin-top:.7rem;line-height:1.6">Danes: ${fmt(today.T,'°C')} · ${fmt(today.hum,'%')} vlaga · ${fmt(today.pres,'')} hPa. Najbolj podoben dan v arhivu postaje.</div>`;
}

// ══════════════════════════════════════════════════════════
// ── 3. Fenološki koledar ──────────────────────────────────
// ══════════════════════════════════════════════════════════
function buildPhenologyCalendar(){
  const el=document.getElementById('pheno-content');if(!el)return;
  const a=XLSX_PHENO.avg,r=XLSX_PHENO.ranges;
  const d2date=doy=>{const d=new Date(2025,0,1);d.setDate(doy);return d.toLocaleDateString('sl',{day:'numeric',month:'long'});};
  const d2short=doy=>{const d=new Date(2025,0,1);d.setDate(doy);return d.toLocaleDateString('sl',{day:'numeric',month:'short'});};
  const now=new Date();
  const todayDoy=Math.floor((now-new Date(now.getFullYear(),0,0))/864e5);

  const events=[
    {icon:'❄️',name:'Zadnja spomladanska zmrzal',doy:a.lastSpringFrost,range:r.lastSpringFrost,col:'#60a5fa',note:'Po tem datumu varno saditi občutljive rastline'},
    {icon:'🌱',name:'Prvi poletni dan (25°C)',doy:a.firstSummer,range:r.firstSummer,col:'#fbbf24',note:'Začetek aktivne sezone žuželk'},
    {icon:'🔥',name:'Prvi vroči dan (30°C)',doy:a.firstHot,range:r.firstHot,col:'#f87171',note:'Vrhunec poletne aktivnosti'},
    {icon:'🍂',name:'Prva jesenska zmrzal',doy:a.firstAutumnFrost,range:r.firstAutumnFrost,col:'#a78bfa',note:'Konec rastne sezone'},
  ].filter(e=>e.doy);

  const growSeason=a.firstAutumnFrost&&a.lastSpringFrost?a.firstAutumnFrost-a.lastSpringFrost:null;

  let html='<div style="position:relative;margin:.5rem 0 1rem">';
  // Year timeline bar
  html+='<div style="position:relative;height:8px;background:linear-gradient(to right,#60a5fa,#34d399,#fbbf24,#f87171,#fbbf24,#a78bfa,#60a5fa);border-radius:4px;margin-bottom:1.2rem">';
  // Today marker
  const todayPct=todayDoy/365*100;
  html+=`<div style="position:absolute;left:${todayPct}%;top:-4px;width:2px;height:16px;background:var(--text)"></div>`;
  html+=`<div style="position:absolute;left:${todayPct}%;top:-20px;transform:translateX(-50%);font-size:.62rem;color:var(--text);white-space:nowrap">danes</div>`;
  // Event markers
  events.forEach(e=>{
    const pct=e.doy/365*100;
    html+=`<div style="position:absolute;left:${pct}%;top:10px;transform:translateX(-50%);font-size:.85rem" title="${e.name}">${e.icon}</div>`;
  });
  html+='</div></div>';

  // Event list
  html+='<div style="display:flex;flex-direction:column;gap:.55rem">';
  events.forEach(e=>{
    const passed=todayDoy>e.doy;
    html+=`<div style="display:flex;align-items:flex-start;gap:.6rem;padding:.5rem 0;border-bottom:1px solid var(--border)">
      <span style="font-size:1.1rem;flex-shrink:0">${e.icon}</span>
      <div style="flex:1">
        <div style="font-size:.78rem;color:var(--text);font-weight:500">${e.name} ${passed?'<span style="color:var(--green);font-size:.66rem">✓ že mimo</span>':''}</div>
        <div style="font-family:'JetBrains Mono',monospace;font-size:.8rem;color:${e.col};margin:.15rem 0">povp. ${d2date(e.doy)}</div>
        <div style="font-size:.68rem;color:var(--muted)">razpon ${d2short(e.range[0])} – ${d2short(e.range[1])} · ${e.note}</div>
      </div>
    </div>`;
  });
  html+='</div>';

  if(growSeason){
    html+=`<div style="margin-top:.8rem;padding:.65rem .85rem;background:var(--fc-bg);border-radius:9px;font-size:.74rem;color:var(--muted);line-height:1.6">
      🌿 <strong style="color:var(--text)">Rastna sezona traja pribl. ${growSeason} dni</strong> (med zadnjo in prvo zmrzaljo). Tipično za dolinsko lego na 366 m z radiacijskim ohlajanjem.</div>`;
  }

  el.innerHTML=html;
}


function buildKlimatogram(){
  const el=document.getElementById('klima-svg');if(!el)return;
  const W=Math.max(300,el.closest('.nt-card,.chart-card,.card')?.offsetWidth-40||el.parentElement?.offsetWidth||600),H=220;
  el.setAttribute('viewBox',`0 0 ${W} ${H}`);
  const pad={l:44,r:16,t:18,b:28};
  const cw=(W-pad.l-pad.r)/12;
  const months=['J','F','M','A','M','J','J','A','S','O','N','D'];

  // Scales
  const Ts=XLSX_KLIMA.map(k=>k.T);
  const Rs=XLSX_KLIMA.map(k=>k.rain);
  const Tmin=Math.min(...Ts)-2,Tmax=Math.max(...Ts)+2;
  const Rmax=Math.max(...Rs)*1.2;
  const dark=isDark();
  const tc=dark?'rgba(255,255,255,.6)':'rgba(0,0,0,.55)';
  const yT=t=>pad.t+(1-(t-Tmin)/(Tmax-Tmin))*(H-pad.t-pad.b);
  const yR=r=>pad.t+(1-r/Rmax)*(H-pad.t-pad.b);

  let svg=`<defs><linearGradient id="kgrad" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="rgba(96,165,250,.5)"/><stop offset="100%" stop-color="rgba(96,165,250,.05)"/></linearGradient></defs>`;

  // Rain bars
  XLSX_KLIMA.forEach((k,i)=>{
    const x=pad.l+i*cw,bh=yR(0)-yR(k.rain),by=yR(k.rain);
    const col=k.rain>150?'rgba(37,99,235,.7)':k.rain>100?'rgba(59,130,246,.6)':'rgba(147,197,253,.6)';
    svg+=`<rect x="${(x+2).toFixed(1)}" y="${by.toFixed(1)}" width="${(cw-4).toFixed(1)}" height="${bh.toFixed(1)}" fill="${col}" rx="2"/>`;
  });

  // Temperature area + line
  const tPts=XLSX_KLIMA.map((k,i)=>({x:pad.l+i*cw+cw/2,y:yT(k.T)}));
  const d=tPts.map((p,i)=>i===0?`M${p.x.toFixed(1)},${p.y.toFixed(1)}`:`L${p.x.toFixed(1)},${p.y.toFixed(1)}`).join(' ');
  const lastP=tPts[tPts.length-1],firstP=tPts[0];
  svg+=`<path d="${d} L${lastP.x},${yT(0)} L${firstP.x},${yT(0)} Z" fill="url(#kgrad)" opacity=".6"/>`;
  svg+=`<path d="${d}" fill="none" stroke="#f87171" stroke-width="2.5" stroke-linejoin="round"/>`;

  // T dots + labels
  XLSX_KLIMA.forEach((k,i)=>{
    const x=pad.l+i*cw+cw/2,y=yT(k.T);
    svg+=`<circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="3" fill="#f87171" stroke="white" stroke-width="1"/>`;
    if(i===0||i===6||k.T===Math.max(...Ts)||k.T===Math.min(...Ts)){
      svg+=`<text x="${x.toFixed(1)}" y="${(y-6).toFixed(1)}" text-anchor="middle" font-size="7.5" fill="#f87171" font-family="JetBrains Mono,monospace">${k.T}°</text>`;
    }
  });

  // Rain labels on tallest bars
  XLSX_KLIMA.forEach((k,i)=>{
    if(k.rain>=130||i===0){
      const x=pad.l+i*cw+cw/2,y=yR(k.rain)-3;
      svg+=`<text x="${x.toFixed(1)}" y="${y.toFixed(1)}" text-anchor="middle" font-size="7" fill="${dark?'rgba(147,197,253,.9)':'rgba(37,99,235,.8)'}" font-family="JetBrains Mono,monospace">${k.rain}</text>`;
    }
  });

  // X axis labels
  months.forEach((m,i)=>{
    const x=pad.l+i*cw+cw/2;
    svg+=`<text x="${x.toFixed(1)}" y="${H-8}" text-anchor="middle" font-size="9" fill="${tc}" font-family="Inter,sans-serif">${m}</text>`;
  });

  // Y axis (T left, rain right)
  [Tmin,0,10,20,Tmax].forEach(t=>{
    if(t<Tmin-1||t>Tmax+1)return;
    const y=yT(t);
    svg+=`<line x1="${pad.l-4}" x2="${(W-pad.r).toFixed(1)}" y1="${y.toFixed(1)}" y2="${y.toFixed(1)}" stroke="${dark?'rgba(255,255,255,.07)':'rgba(0,0,0,.07)'}" stroke-width="1"/>`;
    svg+=`<text x="${(pad.l-6).toFixed(1)}" y="${(y+3).toFixed(1)}" text-anchor="end" font-size="8" fill="${tc}" font-family="JetBrains Mono,monospace">${t}°</text>`;
  });

  el.innerHTML=svg;
}

function buildXLSXCharts(){
  const dark=isDark();
  const tc=dark?'#94a3b8':'#64748b';
  const gridC=dark?'rgba(255,255,255,.07)':'rgba(0,0,0,.07)';
  const base={responsive:true,maintainAspectRatio:false,
    plugins:{legend:{labels:{color:tc,font:{size:10},boxWidth:10}}},
    scales:{x:{ticks:{color:tc,font:{size:10}},grid:{color:gridC}},
            y:{ticks:{color:tc,font:{size:10}},grid:{color:gridC}}}};
  const mk=(id,cfg)=>{const el=document.getElementById(id);if(!el)return;
    try{const existing=typeof Chart.getChart==='function'?Chart.getChart(el):null;if(existing)existing.destroy();}catch(_){}
    new Chart(el.getContext('2d'),cfg);};

  const yrs=XLSX_LETNO.map(l=>l.y);

  // Summer + Hot days per year
  mk('xlsx-summer-chart',{type:'bar',data:{labels:yrs.filter(y=>y<new Date().getFullYear()),datasets:[
    {label:'Poletni (≥25°C)',data:XLSX_LETNO.filter(l=>l.y<new Date().getFullYear()).map(l=>l.summer),backgroundColor:'rgba(251,191,36,.55)',borderColor:'#fbbf24',borderWidth:1},
    {label:'Vroči (≥30°C)',data:XLSX_LETNO.filter(l=>l.y<new Date().getFullYear()).map(l=>l.hot),backgroundColor:'rgba(248,113,113,.55)',borderColor:'#f87171',borderWidth:1},
    {label:'Zmrzalni (≤0°C)',data:XLSX_LETNO.filter(l=>l.y<new Date().getFullYear()).map(l=>l.frost),backgroundColor:'rgba(56,189,248,.45)',borderColor:'#60a5fa',borderWidth:1},
  ]},options:{...JSON.parse(JSON.stringify(base)),plugins:{...base.plugins,title:{display:false}}}});

  // HDD/CDD per year
  mk('xlsx-hdd-chart',{type:'bar',data:{labels:yrs,datasets:[
    {label:'HDD18 (ogrevalne enote)',data:XLSX_LETNO.map(l=>l.HDD),backgroundColor:'rgba(96,165,250,.5)',borderColor:'#60a5fa',borderWidth:1,yAxisID:'y'},
    {label:'CDD22 (hladilne enote)',data:XLSX_LETNO.map(l=>l.CDD),backgroundColor:'rgba(248,113,113,.5)',borderColor:'#f87171',borderWidth:1,yAxisID:'y1'},
  ]},options:{...JSON.parse(JSON.stringify(base)),scales:{x:{ticks:{color:tc},grid:{color:gridC}},y:{ticks:{color:tc},grid:{color:gridC},position:'left'},y1:{ticks:{color:tc},grid:{color:'transparent'},position:'right'}}}});

  // Wind rose (horizontal bar, sorted)
  const wSorted=[...XLSX_WIND].sort((a,b)=>b.pct-a.pct);
  mk('xlsx-wind-rose',{type:'bar',indexAxis:'y',data:{labels:wSorted.map(w=>w.dir),datasets:[
    {label:'% časa',data:wSorted.map(w=>w.pct),backgroundColor:wSorted.map(w=>w.pct>30?'rgba(248,113,113,.7)':w.pct>10?'rgba(251,191,36,.6)':'rgba(96,165,250,.5)'),borderWidth:0},
  ]},options:{...JSON.parse(JSON.stringify(base)),plugins:{legend:{display:false}},
    scales:{x:{ticks:{color:tc,callback:v=>v+'%'},grid:{color:gridC}},y:{ticks:{color:tc,font:{size:11,weight:'500'}},grid:{color:'transparent'}}}}});

  buildKlimatogram();
}


function computeAN(){
  const stored=JSON.parse(localStorage.getItem(LS_KEY)||'{}');
  const entries=Object.entries(stored)
    .filter(([,v])=>v.tempAvg!=null||v.precipTotal!=null)
    .map(([d,v])=>({d,year:+d.slice(0,4),month:+d.slice(5,7),v}));

  if(entries.length<30) return null; // not enough data

  const years=[...new Set(entries.map(e=>e.year))].filter(y=>y>=2019&&y<=new Date().getFullYear()).sort();
  const avg=arr=>arr.length?arr.reduce((a,b)=>a+b,0)/arr.length:null;

  const annualTemps=years.map(y=>{
    const t=entries.filter(e=>e.year===y&&e.v.tempAvg!=null).map(e=>e.v.tempAvg);
    return t.length?+avg(t).toFixed(2):null;
  });
  const validTemps=annualTemps.filter(x=>x!=null);
  const validYears=years.filter((_,i)=>annualTemps[i]!=null);

  // Linear trend
  let trendLine=annualTemps.map(()=>null);
  if(validTemps.length>=2){
    const x=validYears.map((_,i)=>i),y=validTemps;
    const n=x.length,sx=x.reduce((a,b)=>a+b,0),sy=y.reduce((a,b)=>a+b,0);
    const sxx=x.reduce((a,b)=>a+b*b,0),sxy=x.reduce((a,b,i)=>a+b*y[i],0);
    const slope=(n*sxy-sx*sy)/(n*sxx-sx*sx);
    const inter=(sy-slope*sx)/n;
    let vi=0;
    trendLine=years.map((_,i)=>annualTemps[i]!=null?+((inter+slope*vi++).toFixed(2)):null);
  }

  const annualRain=years.map(y=>Math.round(entries.filter(e=>e.year===y).reduce((s,e)=>s+(e.v.precipTotal||0),0)));
  const annualFrost=years.map(y=>entries.filter(e=>e.year===y&&(e.v.tempLow??e.v.tempAvg??1)<=0).length);
  const annualSummer=years.map(y=>entries.filter(e=>e.year===y&&(e.v.tempHigh??e.v.tempAvg??0)>=25).length);
  const annualHot30=years.map(y=>entries.filter(e=>e.year===y&&(e.v.tempHigh??e.v.tempAvg??0)>=30).length);

  const seasonMonths={Pomlad:[3,4,5],Poletje:[6,7,8],Jesen:[9,10,11],Zima:[12,1,2]};
  const seasonTemps={};
  Object.entries(seasonMonths).forEach(([s,months])=>{
    seasonTemps[s]=years.map(y=>{
      const t=entries.filter(e=>e.year===y&&months.includes(e.month)&&e.v.tempAvg!=null).map(e=>e.v.tempAvg);
      return t.length?+avg(t).toFixed(1):null;
    });
  });

  const monthlyTemp=Array.from({length:12},(_,mi)=>{
    const t=entries.filter(e=>e.month===mi+1&&e.v.tempAvg!=null).map(e=>e.v.tempAvg);
    return t.length?+avg(t).toFixed(1):0;
  });
  const monthlyRain=Array.from({length:12},(_,mi)=>{
    const r=entries.filter(e=>e.month===mi+1).reduce((s,e)=>s+(e.v.precipTotal||0),0);
    const cnt=years.length||1;
    return +(r/cnt).toFixed(1);
  });

  const sepRain=years.map(y=>Math.round(entries.filter(e=>e.year===y&&e.month===9).reduce((s,e)=>s+(e.v.precipTotal||0),0)));
  const octRain=years.map(y=>Math.round(entries.filter(e=>e.year===y&&e.month===10).reduce((s,e)=>s+(e.v.precipTotal||0),0)));

  const rainMatrix={};
  years.forEach(y=>{rainMatrix[y]=Array.from({length:12},(_,mi)=>Math.round(entries.filter(e=>e.year===y&&e.month===mi+1).reduce((s,e)=>s+(e.v.precipTotal||0),0)));});

  // Top gusts
  const topGusts=entries.filter(e=>e.v.windspeedHigh>0)
    .sort((a,b)=>b.v.windspeedHigh-a.v.windspeedHigh).slice(0,6)
    .map(e=>({d:new Date(e.d+'T12:00:00').toLocaleDateString('sl',{day:'numeric',month:'short',year:'numeric'}),v:e.v.windspeedHigh}));

  return{years,annualTemps,trendLine,annualRain,annualFrost,annualSummer,annualHot30,seasonTemps,monthlyTemp,monthlyRain,sepRain,octRain,rainMatrix,topGusts,months:['Jan','Feb','Mar','Apr','Maj','Jun','Jul','Avg','Sep','Okt','Nov','Dec']};
}

// Fallback hardcoded data from XLSX analysis (used if localStorage has <30 days)
const AN_FALLBACK={years:[2020,2021,2022,2023,2024,2025],annualTemps:[10.20,9.77,10.97,11.07,11.48,11.18],trendLine:[10.05,10.34,10.63,10.92,11.21,11.50],annualRain:[1353,1396,1069,1959,1449,1287],annualFrost:[0,70,108,106,90,93],annualSummer:[0,78,103,92,95,90],annualHot30:[0,29,36,26,46,29],seasonTemps:{Pomlad:[9.8,8.2,9.5,9.8,11.4,10.9],Poletje:[19.1,20.1,21.0,20.0,21.3,20.5],Jesen:[10.0,9.5,11.1,12.4,10.6,11.0],Zima:[2.4,1.1,2.1,2.2,2.5,2.1]},monthlyTemp:[1.0,3.8,6.2,9.8,13.9,20.0,20.8,20.3,15.8,11.4,5.3,1.6],monthlyRain:[93.8,72.6,91.3,86.8,181.3,110.2,176.4,97.8,167.7,144.1,131.7,124.5],sepRain:[145,67,293,48,247,206],octRain:[203,71,52,238,207,94],topGusts:[{d:'1. apr 2024',v:115.6},{d:'18. avg 2022',v:77.1},{d:'9. mar 2023',v:73.4},{d:'21. okt 2020',v:64.4}],rainMatrix:{2020:[24,36,100,22,110,180,171,137,145,203,56,164],2021:[112,97,34,78,263,45,179,149,67,71,185,84],2022:[17,30,33,94,124,122,86,41,293,52,77,140],2023:[160,25,78,90,171,161,291,96,48,238,183,170],2024:[95,90,121,118,183,124,148,89,247,207,53,30],2025:[91,60,162,85,114,30,183,75,206,94,88,36]},months:['Jan','Feb','Mar','Apr','Maj','Jun','Jul','Avg','Sep','Okt','Nov','Dec']};


// Update only KPI cards (no chart recreation)
function updateAnalysisKPIs(){
  const _an=computeAN();
  const AN=_an||AN_FALLBACK;
  const src=_an?'📡 Postaja IREICA1 (localStorage)':'🛰 Referenčni podatki XLSX';
  const srcEl=document.getElementById('an-data-source');
  if(srcEl)srcEl.textContent=src+' · '+AN.years[0]+'–'+AN.years[AN.years.length-1];
  const floodNote=document.getElementById('an-flood-note');
  if(floodNote)floodNote.style.display='block';
  const set=(id,v)=>{const e=document.getElementById(id);if(e)e.textContent=v;};
  const validT=AN.annualTemps.filter(x=>x!=null);
  const avgT=validT.length?validT.reduce((a,b)=>a+b,0)/validT.length:null;
  set('an-kpi-tavg', avgT!=null?avgT.toFixed(1)+'°C':'—');
  set('an-kpi-tmax', STATION_RECORDS.Tmax.val.toFixed(1)+'°C');
  set('an-kpi-tmin', STATION_RECORDS.Tmin.val.toFixed(1)+'°C');
  const validYrIdx=AN.years.reduce((acc,_,i)=>AN.annualTemps[i]!=null?[...acc,i]:acc,[]);
  if(validYrIdx.length>=2){
    const dy=AN.annualTemps[validYrIdx[validYrIdx.length-1]]-AN.annualTemps[validYrIdx[0]];
    const dx=AN.years[validYrIdx[validYrIdx.length-1]]-AN.years[validYrIdx[0]];
    const slope=dx>0?dy/dx:0;
    set('an-kpi-trend',(slope>=0?'+':'')+slope.toFixed(2)+'°');
  }
  const validR=AN.annualRain.filter(x=>x>0);
  set('an-kpi-rain', validR.length?Math.round(validR.reduce((a,b)=>a+b,0)/validR.length)+' mm':'—');
  set('an-kpi-gust', AN.topGusts?.length?AN.topGusts[0].v.toFixed(0):'—');
}

let _anChartsInit=false;
function initAnalysisCharts(){
  if(_anChartsInit)return; _anChartsInit=true;
  const _an=computeAN();
  const AN=_an||AN_FALLBACK;
  const src=_an?'📡 Postaja IREICA1 (localStorage)':'🛰 Referenčni podatki XLSX';
  // Show data source
  const srcEl=document.getElementById('an-data-source');
  if(srcEl)srcEl.textContent=src+' · '+AN.years[0]+'–'+AN.years[AN.years.length-1];

  // Flood / data gap warning for 2023
  const floodNote=document.getElementById('an-flood-note');
  if(floodNote)floodNote.style.display='block';

  updateAnalysisKPIs(); // KPI cards updated here

  const dark=isDark();
  const gridC=dark?'rgba(255,255,255,.07)':'rgba(0,0,0,.07)';
  const textC=dark?'#94a3b8':'#64748b';
  const base={responsive:true,maintainAspectRatio:false,plugins:{legend:{labels:{color:textC,font:{size:10},boxWidth:10}}},scales:{x:{ticks:{color:textC,font:{size:10}},grid:{color:gridC}},y:{ticks:{color:textC,font:{size:10}},grid:{color:gridC}}}};
  const mk=(id,cfg)=>{const el=document.getElementById(id);if(!el)return;new Chart(el.getContext('2d'),cfg);};
  const yr=AN.years;

  // Annual temp + trend
  mk('an-temp-annual',{type:'bar',data:{labels:yr,datasets:[
    {label:'Povp. temp °C',data:AN.annualTemps,backgroundColor:AN.annualTemps.map(t=>t>11?'rgba(248,113,113,.65)':'rgba(56,189,248,.6)'),borderRadius:6,order:2},
    {label:'Trend',data:AN.trendLine,type:'line',borderColor:'#fbbf24',borderWidth:2,pointRadius:0,tension:.3,order:1,borderDash:[5,3]}
  ]},options:{...base,scales:{...base.scales,y:{...base.scales.y,min:9,max:12,ticks:{...base.scales.y.ticks,callback:v=>v+'°'}}}}});

  // Seasonal trends
  const sColors={Pomlad:'#4ade80',Poletje:'#f87171',Jesen:'#fbbf24',Zima:'#38bdf8'};
  mk('an-seasons',{type:'line',data:{labels:yr,datasets:Object.entries(AN.seasonTemps).map(([k,v])=>({label:k,data:v,borderColor:sColors[k],backgroundColor:sColors[k]+'18',tension:.4,fill:false,pointRadius:3,pointHoverRadius:5}))},options:base});

  // Monthly temp
  mk('an-monthly-temp',{type:'bar',data:{labels:AN.months,datasets:[{label:'°C',data:AN.monthlyTemp,backgroundColor:AN.monthlyTemp.map(t=>t<2?'#38bdf8':t<10?'#67e8f9':t<18?'#4ade80':t<23?'#fbbf24':'#f87171'),borderRadius:4}]},options:{...base,plugins:{legend:{display:false}},scales:{...base.scales,y:{...base.scales.y,ticks:{...base.scales.y.ticks,callback:v=>v+'°'}}}}});

  // Frost + hot days
  mk('an-extremes',{type:'bar',data:{labels:yr,datasets:[
    {label:'Zmrzalni dnevi (Tmin≤0°C)',data:AN.annualFrost,backgroundColor:'rgba(56,189,248,.65)',borderRadius:4},
    {label:'Poletni dnevi (Tmax≥25°C)',data:AN.annualSummer,backgroundColor:'rgba(251,191,36,.6)',borderRadius:4},
    {label:'Vroči dnevi (Tmax≥30°C)',data:AN.annualHot30,backgroundColor:'rgba(248,113,113,.65)',borderRadius:4}
  ]},options:base});

  // Annual rain
  mk('an-rain-annual',{type:'bar',data:{labels:yr,datasets:[{label:'mm',data:AN.annualRain,backgroundColor:AN.annualRain.map(r=>r>1500?'rgba(56,189,248,.8)':r>1300?'rgba(96,165,250,.6)':'rgba(251,191,36,.6)'),borderRadius:6}]},options:{...base,plugins:{legend:{display:false}}}});

  // Sep + Oct
  mk('an-sepokt',{type:'bar',data:{labels:yr,datasets:[
    {label:'September',data:AN.sepRain,backgroundColor:'rgba(56,189,248,.7)',borderRadius:4},
    {label:'Oktober',data:AN.octRain,backgroundColor:'rgba(167,139,250,.7)',borderRadius:4}
  ]},options:base});

  // Monthly avg rain
  mk('an-monthly-rain',{type:'bar',data:{labels:AN.months,datasets:[{label:'mm (povp.)',data:AN.monthlyRain,backgroundColor:'rgba(96,165,250,.7)',borderRadius:4}]},options:{...base,plugins:{legend:{display:false}}}});

  // Top gusts
  mk('an-gusts',{type:'bar',data:{labels:AN.topGusts.map(g=>g.d),datasets:[{label:'km/h',data:AN.topGusts.map(g=>g.v),backgroundColor:AN.topGusts.map((_,i)=>i===0?'rgba(167,139,250,.85)':'rgba(167,139,250,.45)'),borderRadius:4}]},options:{...base,indexAxis:'y',plugins:{legend:{display:false}},scales:{x:{...base.scales.x,min:40},y:{...base.scales.y,ticks:{...base.scales.y.ticks,font:{size:9}}}}}});

  // Rain heatmap table
  const tbl=document.getElementById('an-rain-hm');
  if(tbl){
    const maxR=300;
    const rainBg=v=>{if(!v)return dark?'rgba(255,255,255,.04)':'rgba(0,0,0,.04)';const p=Math.min(v/maxR,1);return p<.1?'rgba(219,234,254,.3)':p<.25?'rgba(96,165,250,.45)':p<.45?'rgba(59,130,246,.6)':p<.65?'rgba(29,78,216,.75)':'rgba(17,24,107,.9)';};
    const rainTxt=v=>v>120?'#fff':'#94a3b8';
    let h='<tr><th></th>'+AN.months.map(m=>`<th>${m}</th>`).join('')+'</tr>';
    for(const y of AN.years){h+='<tr><td class="hm-yr-lbl">'+y+'</td>'+AN.rainMatrix[y].map((v,i)=>`<td style="background:${rainBg(v)};color:${rainTxt(v)};border-radius:3px" title="${AN.months[i]} ${y}: ${v} mm">${v||'0'}</td>`).join('')+'</tr>';}
    tbl.innerHTML=h;
  }
}


// ═══════════════════════════════════════════════════════
// ── Tab: Podrobna napoved 48h ──────────────────────────
// ═══════════════════════════════════════════════════════
let _fc2Init=false;
// ── Dnevni trak neba ──────────────────────────────────────
async function drawDailySkyStrip(){
  const svg=document.getElementById('sky-strip-fc');
  const info=document.getElementById('sky-strip-info');
  if(!svg)return;
  try{
    const url='https://api.open-meteo.com/v1/forecast?latitude='+LAT+'&longitude='+LON
      +'&hourly=temperature_2m,precipitation,wind_speed_10m,uv_index,weather_code,cloud_cover'
      +'&timezone=Europe%2FLjubljana&forecast_days=2';
    const res=await fetch(url);const data=await res.json();
    const h=data.hourly;if(!h?.time)return;
    const now=new Date();
    const hi=Math.max(0,h.time.findIndex(t=>new Date(t)>=now)||0);
    const N=24;
    const sl={
      times:h.time.slice(hi,hi+N),temp:h.temperature_2m.slice(hi,hi+N),
      rain:h.precipitation.slice(hi,hi+N),wind:h.wind_speed_10m.slice(hi,hi+N),
      uv:h.uv_index.slice(hi,hi+N),wmo:h.weather_code.slice(hi,hi+N),
      cloud:h.cloud_cover.slice(hi,hi+N),
    };
    if(sl.temp.length<6)return;
    const VW=1000,VH=170,pad={t:28,r:10,b:30,l:10};
    const CW=VW-pad.l-pad.r,CH=VH-pad.t-pad.b;
    const xS=i=>pad.l+i/(N-1)*CW;
    const pt=calcPhotoTimes()||{};
    const nowH=now.getHours()+now.getMinutes()/60;
    const bw=CW/N;

    // Sky color interpolation
    function skyAtHour(absH){
      const h24=((absH%24)+24)%24;
      const lerp=(a,b,t)=>Math.round(a+(b-a)*Math.max(0,Math.min(1,t)));
      const lerpRGB=(ca,cb,t)=>ca.map((v,i)=>lerp(v,cb[i],t));
      const NIGHT=[2,6,23],NAUT=[12,26,63],BLUE=[22,60,153],
            ORANGE=[146,64,9],GOLD=[174,80,9],SKY=[3,132,199];
      const na=pt.nautAMh??4,bl=pt.blueAMh??5,sr=pt.sunriseH??5.5,
            ga=pt.goldAMh??6.5,gp=pt.goldPMh??19.5,ss=pt.sunsetH??20.5,
            bp=pt.bluePMh??21.5,np=pt.nautPMh??22.5;
      if(h24<=na||h24>=np) return NIGHT;
      if(h24<=bl)  return lerpRGB(NIGHT,BLUE,(h24-na)/(bl-na));
      if(h24<=sr)  return lerpRGB(BLUE,ORANGE,(h24-bl)/(sr-bl));
      if(h24<=ga)  return lerpRGB(ORANGE,GOLD,(h24-sr)/(ga-sr));
      if(h24<=ga+1.5) return lerpRGB(GOLD,SKY,(h24-ga)/1.5);
      if(h24>=np-0.5) return lerpRGB(NAUT,NIGHT,(h24-(np-0.5))/0.5);
      if(h24>=bp)  return lerpRGB(BLUE,NAUT,(h24-bp)/(np-bp));
      if(h24>=ss)  return lerpRGB(ORANGE,BLUE,(h24-ss)/(bp-ss));
      if(h24>=gp)  return lerpRGB(GOLD,ORANGE,(h24-gp)/(ss-gp));
      if(h24>=gp-1.5) return lerpRGB(SKY,GOLD,(h24-(gp-1.5))/1.5);
      return SKY;
    }

    const mk=(tag,attrs,txt)=>{
      const e=document.createElementNS('http://www.w3.org/2000/svg',tag);
      Object.entries(attrs).forEach(([k,v])=>e.setAttribute(k,v));
      if(txt!=null)e.textContent=txt;svg.appendChild(e);return e;
    };
    svg.innerHTML='';

    // Layer 1: Sky gradient
    const defs=mk('defs',{});
    let gs='';
    for(let i=0;i<N;i++){const [r,g,b]=skyAtHour(nowH+i);gs+=`<stop offset="${(i/(N-1)*100).toFixed(1)}%" stop-color="rgb(${r},${g},${b})"/>`;}
    defs.innerHTML=`<linearGradient id="sg" x1="0" x2="1" y1="0" y2="0">${gs}</linearGradient><linearGradient id="tg" x1="0" x2="0" y1="0" y2="1"><stop offset="0%" stop-color="rgba(56,189,248,.28)"/><stop offset="100%" stop-color="rgba(56,189,248,0)"/></linearGradient>`;
    mk('rect',{x:0,y:0,width:VW,height:VH,fill:'url(#sg)'});

    // Layer 2: Cloud/fog overlays
    sl.cloud.forEach((cc,i)=>{
      if(!cc&&!(sl.wmo[i]>=45&&sl.wmo[i]<=48))return;
      const isFog=sl.wmo[i]>=45&&sl.wmo[i]<=48;
      const alpha=isFog?0.42:(cc/100)*0.32;
      mk('rect',{x:(xS(i)-bw/2).toFixed(1),y:pad.t,width:(bw+1).toFixed(1),height:CH,fill:isFog?`rgba(220,220,220,${alpha})`:`rgba(150,160,185,${alpha})`});
    });

    // Layer 3: UV band (top strip)
    const maxUV=Math.max(...sl.uv,1);
    sl.uv.forEach((uv,i)=>{
      if(!uv||uv<0.5)return;
      const bh=Math.min(11,(uv/Math.max(maxUV,8))*11);
      mk('rect',{x:(xS(i)-bw/2+1).toFixed(1),y:(pad.t-bh).toFixed(1),width:(bw-2).toFixed(1),height:bh.toFixed(1),fill:`rgba(251,191,36,${0.35+uv/12*0.5})`,rx:'2'});
    });

    // Layer 4: Rain bars (bottom)
    const maxRain=Math.max(...sl.rain,0.5);
    sl.rain.forEach((r,i)=>{
      if(r<0.1)return;
      const bh=Math.min(24,(r/maxRain)*24);
      mk('rect',{x:(xS(i)-bw/2+2).toFixed(1),y:(pad.t+CH-bh).toFixed(1),width:(bw-4).toFixed(1),height:bh.toFixed(1),fill:'rgba(96,165,250,0.75)',rx:'2'});
    });

    // Layer 5: Temperature area + line
    const temps=sl.temp.filter(t=>t!=null);
    const tmin=Math.min(...temps)-2,tmax=Math.max(...temps)+2;
    const yT=t=>pad.t+(1-(t-tmin)/(tmax-tmin))*CH;
    const pts=sl.temp.map((t,i)=>({x:xS(i),y:t!=null?yT(t):null})).filter(p=>p.y!=null);
    if(pts.length>1){
      const lp=smoothPath(pts);
      mk('path',{d:lp+' L '+xS(N-1)+','+(pad.t+CH)+' L '+xS(0)+','+(pad.t+CH)+' Z',fill:'url(#tg)'});
      mk('path',{d:lp,fill:'none',stroke:'#38bdf8','stroke-width':'2.5','stroke-linecap':'round'});
    }

    // Layer 6: Wind spikes
    sl.wind.forEach((w,i)=>{
      if(w<18)return;
      const intensity=Math.min(1,(w-18)/40);
      const x=xS(i),baseY=yT(sl.temp[i]??((tmin+tmax)/2))-3;
      const sh=4+intensity*12;
      mk('line',{x1:x,y1:baseY,x2:x,y2:baseY-sh,stroke:`rgba(167,139,250,${0.55+intensity*0.4})`,strokeWidth:'2','stroke-width':'2','stroke-linecap':'round'});
      mk('polygon',{points:`${x},${baseY-sh} ${x-3.5},${baseY-sh+6} ${x+3.5},${baseY-sh+6}`,fill:`rgba(167,139,250,${0.45+intensity*0.4})`});
    });

    // Layer 7: Weather emojis every 3h
    for(let i=0;i<N;i+=3){
      const e=mk('text',{x:xS(i).toFixed(1),y:(pad.t-8).toFixed(1),'text-anchor':'middle','font-size':'14'});
      e.textContent=_wmoEmoji(sl.wmo[i]||0);
    }

    // Layer 8: Temperature labels (max + min)
    const maxTi=sl.temp.indexOf(Math.max(...sl.temp));
    const minTi=sl.temp.indexOf(Math.min(...sl.temp));
    [[maxTi,'#f87171',true],[minTi,'#7dd3fc',false]].forEach(([i,col,above])=>{
      if(i<0)return;
      const y=yT(sl.temp[i]);
      mk('text',{x:xS(i).toFixed(1),y:(above?y-6:y+13).toFixed(1),'text-anchor':'middle','font-size':'9.5',fill:col,'font-family':'JetBrains Mono,monospace','font-weight':'600'},sl.temp[i].toFixed(1)+'°');
    });

    // Layer 9: Time labels every 3h
    for(let i=0;i<N;i+=3){
      const date=new Date(sl.times[i]);
      const hr=date.getHours();
      const lbl=i===0?'zdaj':(hr<10?'0':'')+hr+':00';
      const [r,g,b]=skyAtHour(nowH+i);
      const textCol=(r+g+b)/3<80?'rgba(255,255,255,.65)':'rgba(0,0,0,.5)';
      mk('text',{x:xS(i).toFixed(1),y:(VH-8).toFixed(1),'text-anchor':'middle','font-size':'8.5',fill:textCol,'font-family':'JetBrains Mono,monospace'},lbl);
    }

    // Layer 10: Now line
    mk('line',{x1:xS(0)+1,x2:xS(0)+1,y1:pad.t,y2:VH-pad.b,stroke:'rgba(255,200,0,.85)','stroke-width':'2','stroke-dasharray':'4,3'});

    // Layer 11: Sunrise/sunset markers
    [[pt.sunriseH,'☀️'],[pt.sunsetH,'🌇']].forEach(([h,lbl])=>{
      if(!h)return;
      const diffH=h-nowH;if(diffH<0.5||diffH>N-0.5)return;
      const x=xS(diffH/(N-1)*(N-1));
      mk('line',{x1:x.toFixed(1),x2:x.toFixed(1),y1:pad.t,y2:VH-pad.b,stroke:'rgba(251,191,36,.35)','stroke-width':'1','stroke-dasharray':'3,5'});
      mk('text',{x:x.toFixed(1),y:(pad.t-9).toFixed(1),'text-anchor':'middle','font-size':'11'},lbl);
    });

    // Hover tooltip
    const wrap=document.getElementById('sky-strip-wrap');
    const tip=document.getElementById('sky-tooltip');
    if(wrap&&tip){
      svg.onmousemove=e=>{
        const rect=svg.getBoundingClientRect();
        const idx=Math.round(((e.clientX-rect.left)/rect.width)*(N-1));
        if(idx<0||idx>=N)return;
        const dt=new Date(sl.times[idx]);
        const lbl=idx===0?'Zdaj':dt.toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'});
        tip.style.cssText=`display:block;opacity:1;left:${Math.min(e.clientX-rect.left+12,rect.width-160)}px;top:8px`;
        tip.innerHTML=`<b>${lbl}</b> ${_wmoImg(sl.wmo[idx]||0,true,16)}<br>🌡 ${sl.temp[idx]?.toFixed(1)??'—'}°C  💨 ${Math.round(sl.wind[idx]||0)} km/h<br>🌧 ${(sl.rain[idx]||0).toFixed(1)} mm  ☀️ UV ${(sl.uv[idx]||0).toFixed(1)}`;
      };
      svg.onmouseleave=()=>{tip.style.opacity='0';setTimeout(()=>{tip.style.display='none';},200);};
    }

    const tRange=`${Math.min(...temps).toFixed(1)}° – ${Math.max(...temps).toFixed(1)}°C`;
    const totalRain=sl.rain.reduce((a,b)=>a+b,0);
    if(info)info.textContent=tRange+(totalRain>0.1?'  ·  🌧 '+totalRain.toFixed(1)+' mm':'');
  }catch(e){console.warn('SkyStrip:',e);}
}

async function initForecast2(){
  if(_fc2Init)return;_fc2Init=true;
  drawDailySkyStrip(); // sky strip – neodvisno od 48h podatkov
  try{
    const url='https://api.open-meteo.com/v1/forecast?latitude='+LAT+'&longitude='+LON
      +'&hourly=temperature_2m,apparent_temperature,precipitation,wind_speed_10m,wind_direction_10m,uv_index,relative_humidity_2m,weather_code'
      +'&daily=weather_code,temperature_2m_max,temperature_2m_min,precipitation_sum,uv_index_max,wind_speed_10m_max'
      +'&timezone=Europe%2FLjubljana&forecast_days=4';
    const res=await fetch(url);const data=await res.json();
    const h=data.hourly,d=data.daily;
    const now=new Date();
    // Find current hour index
    const hi=h.time.findIndex(t=>new Date(t)>=now)||0;
    const slice48=h.time.slice(hi,hi+48);

    // ── SVG chart: temp line + precip bars ─────────────
    const svg=document.getElementById('fc2-svg');
    if(svg){
      const temps=h.temperature_2m.slice(hi,hi+48);
      const rains=h.precipitation.slice(hi,hi+48);
      const VW=900,VH=240,pad={t:20,r:20,b:38,l:36};
      const cw=VW-pad.l-pad.r,ch=VH-pad.t-pad.b;
      const tmin=Math.min(...temps)-1,tmax=Math.max(...temps)+1;
      const rmax=Math.max(...rains,0.5);
      const xS=i=>pad.l+i/(slice48.length-1)*cw;
      const yT=v=>pad.t+(1-(v-tmin)/(tmax-tmin))*ch;
      const mk=(tag,attrs,txt)=>{const e=document.createElementNS('http://www.w3.org/2000/svg',tag);Object.entries(attrs).forEach(([k,v])=>e.setAttribute(k,v));if(txt)e.textContent=txt;svg.appendChild(e);return e;};
      svg.innerHTML='';
      const defs=mk('defs',{});
      defs.innerHTML='<linearGradient id="fc2g" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="'+CC.tempLine+'" stop-opacity="0.18"/><stop offset="100%" stop-color="'+CC.tempLine+'" stop-opacity="0"/></linearGradient>';
      // Grid lines
      for(let i=0;i<=3;i++){const y=pad.t+i/3*ch;const v=(tmax-i/3*(tmax-tmin)).toFixed(0);mk('line',{x1:pad.l,x2:VW-pad.r,y1:y,y2:y,stroke:CC.grid,'stroke-width':'1'});mk('text',{x:pad.l-4,y:y+3,'text-anchor':'end','font-size':'8',fill:CC.label,'font-family':'JetBrains Mono,monospace'},v+'°');}
      // Hour labels every 6h
      slice48.forEach((t,i)=>{if(i%6===0){const h2=new Date(t).getHours();mk('text',{x:xS(i),y:VH-10,'text-anchor':'middle','font-size':'8',fill:CC.label,'font-family':'JetBrains Mono,monospace'},(h2<10?'0':'')+h2+':00');}});
      // Precip bars
      const bw=cw/slice48.length*0.7;
      rains.forEach((r,i)=>{if(r>0){const bh=Math.max(3,(r/rmax)*ch*0.4);mk('rect',{x:(xS(i)-bw/2).toFixed(1),y:(VH-pad.b-bh).toFixed(1),width:bw.toFixed(1),height:bh.toFixed(1),fill:CC.rainBar,rx:'1.5',opacity:'.7'});}});
      // Temp area + line
      const pts=temps.map((_,i)=>({x:xS(i),y:yT(temps[i])}));
      const lp=smoothPath(pts);
      mk('path',{d:lp+' L '+xS(temps.length-1)+','+(VH-pad.b)+' L '+xS(0)+','+(VH-pad.b)+' Z',fill:'url(#fc2g)'});
      mk('path',{d:lp,fill:'none',stroke:CC.tempLine,'stroke-width':'2.2','stroke-linecap':'round'});
      // Now line
      mk('line',{x1:xS(0)+1,x2:xS(0)+1,y1:pad.t,y2:VH-pad.b,stroke:'rgba(255,180,0,.6)','stroke-width':'1.5','stroke-dasharray':'4,3'});
    }
    // Update chart label
    set('fc2-chart-lbl','Temperatura in padavine — '+slice48.length+'h napoved');
    const totRain=h.precipitation.slice(hi,hi+48).reduce((a,b)=>a+b,0);
    set('fc2-chart-sub','Skupaj padavine: '+totRain.toFixed(1)+' mm');

    // ── Stats row ─────────────────────────────────────
    const statsEl=document.getElementById('fc2-stats');
    if(statsEl){
      const temps2=h.temperature_2m.slice(hi,hi+48);
      const uvs=h.uv_index.slice(hi,hi+48);
      const winds=h.wind_speed_10m.slice(hi,hi+48);
      statsEl.innerHTML=[
        {n:Math.max(...temps2).toFixed(1)+'°C',l:'Max temp',c:'var(--red)'},
        {n:Math.min(...temps2).toFixed(1)+'°C',l:'Min temp',c:'var(--blue)'},
        {n:totRain.toFixed(1)+' mm',l:'Padavine',c:'var(--rain-col)'},
        {n:Math.max(...uvs).toFixed(0),l:'Max UV',c:'var(--amber)'},
        {n:Math.max(...winds).toFixed(0)+' km/h',l:'Max veter',c:'var(--purple)'},
      ].map(s=>`<div class="fc2-stat"><div class="fc2-stat-n" style="color:${s.c}">${s.n}</div><div class="fc2-stat-l">${s.l}</div></div>`).join('');
    }

    // ── Hourly cards ──────────────────────────────────
    const hoursEl=document.getElementById('fc2-hours');
    if(hoursEl){
      hoursEl.innerHTML='';
      slice48.forEach((t,i)=>{
        const date=new Date(t);const isNow=i===0;
        const card=document.createElement('div');card.className='fc2-h'+(isNow?' now':'');
        const wcode=h.weather_code[hi+i]||0;
        card.innerHTML=
          '<div class="fc2-h-time">'+(isNow?'zdaj':String(date.getHours()).padStart(2,'0')+':00')+'</div>'+
          '<div class="fc2-h-emoji">'+_wmoImg(wcode,true,30)+'</div>'+
          '<div class="fc2-h-temp">'+(h.temperature_2m[hi+i]||0).toFixed(1)+'°</div>'+
          '<div class="fc2-h-rain">'+(h.precipitation[hi+i]>0.1?'🌧'+(h.precipitation[hi+i]).toFixed(1):'')+'</div>'+
          '<div class="fc2-h-wind">'+(h.wind_speed_10m[hi+i]>0?Math.round(h.wind_speed_10m[hi+i])+'km/h':'')+'</div>';
        hoursEl.appendChild(card);
      });
    }

    // ── Daily summary grid ─────────────────────────────
    const dailyEl=document.getElementById('fc2-daily-grid');
    if(dailyEl&&d?.time){
      dailyEl.innerHTML='';
      d.time.forEach((dt,i)=>{
        const date=new Date(dt+'T12:00:00');
        const isToday=i===0;
        const lbl=isToday?'Danes':date.toLocaleDateString('sl',{weekday:'short',day:'numeric',month:'short'});
        const card=document.createElement('div');card.className='nt-card';
        card.innerHTML=
          '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:.5rem">'+
            '<div style="font-size:.72rem;font-weight:600">'+(isToday?'<span style="color:var(--blue)">Danes</span>':lbl)+'</div>'+
            '<div>'+_wmoImg(d.weather_code[i],true,28)+'</div>'+
          '</div>'+
          '<div style="display:flex;gap:.75rem;font-family:\'JetBrains Mono\',monospace;font-size:.88rem">'+
            '<span style="color:var(--red)">↑ '+(d.temperature_2m_max[i]||0).toFixed(1)+'°</span>'+
            '<span style="color:var(--blue)">↓ '+(d.temperature_2m_min[i]||0).toFixed(1)+'°</span>'+
          '</div>'+
          '<div style="font-size:.76rem;color:var(--muted);margin-top:.3rem">'+
            (d.precipitation_sum[i]>0.1?'🌧 '+(d.precipitation_sum[i]).toFixed(1)+' mm  ':'')+
            'UV max: '+(d.uv_index_max[i]||0).toFixed(0)+'  '+
            '💨 '+(d.wind_speed_10m_max[i]||0).toFixed(0)+' km/h'+
          '</div>';
        dailyEl.appendChild(card);
      });
    }
  }catch(e){console.warn('Forecast2:',e);}
}

