const NEARBY=[
  {name:'Rečica ob Savinji',note:'Postaja IREICA1',lat:46.326,lon:14.921,alt:366,mine:true},
  {name:'Mozirje',note:'5 km, 340 m n. m.',lat:46.338,lon:14.976,alt:340},
  {name:'Šoštanj',note:'15 km, 400 m n. m.',lat:46.383,lon:15.050,alt:400},
  {name:'Celje',note:'35 km, 241 m n. m.',lat:46.233,lon:15.267,alt:241},
  {name:'Logarska dolina',note:'25 km, 838 m n. m.',lat:46.393,lon:14.630,alt:838},
  {name:'Rogla',note:'45 km, 1517 m n. m.',lat:46.450,lon:15.333,alt:1517},
];
let _surInit=false;

// Hardcoded nearby WU stations (bližnje postaje, ročno potrjene)
const WU_NEARBY_IDS=['IMOZIR4','IMARTN16','IBRASL105','IMOZIR5','INAZAR37','IGORNJ48','IGORNJ53','IKAMNI50'];
const WUH_PALETTE=['#38bdf8','#4ade80','#fbbf24','#f87171','#a78bfa','#67e8f9','#fb923c','#34d399','#e879f9'];

// ── Micro-climate map (Okolica): live temp deltas of nearby WU stations ──
let _microMap=null;
function _microMapColor(diff){
  if(diff==null)return isDark()?'#94a3b8':'#64748b';
  if(diff<=-2)return'#1d4ed8';
  if(diff<0)return'#60a5fa';
  if(diff===0)return'#e2e8f0';
  if(diff<2)return'#fca5a5';
  return'#dc2626';
}
async function renderMicroMap(myTemp,stations){
  const mapEl=document.getElementById('micro-map');
  if(!mapEl)return;
  if(typeof L==='undefined'){
    _loadCss('https://unpkg.com/leaflet@1.9.4/dist/leaflet.css');
    await _loadScript('https://unpkg.com/leaflet@1.9.4/dist/leaflet.js');
  }
  if(!_microMap){
    _microMap=L.map('micro-map',{zoomControl:true,attributionControl:false,minZoom:8,maxZoom:14}).setView([LAT,LON],11);
    const baseUrl=isDark()
      ? 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png'
      : 'https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png';
    L.tileLayer(baseUrl,{maxZoom:14,maxNativeZoom:19,subdomains:'abcd'}).addTo(_microMap);
  }
  L.circleMarker([LAT,LON],{radius:9,color:'#2563eb',fillColor:'#4d9ff8',fillOpacity:.95,weight:2}).addTo(_microMap)
    .bindPopup('<div class="micromap-pop"><b>📡 IREICA1 · Rečica ob Savinji'+(myTemp!=null?' ('+myTemp.toFixed(1).replace('.',',')+' °C)':'')+'</b></div>');
  stations.forEach(s=>{
    const o=s.obs||{};
    if(o.lat==null||o.lon==null)return;
    const T=o.metric?.temp??null;
    const diff=myTemp!=null&&T!=null?T-myTemp:null;
    L.circleMarker([o.lat,o.lon],{
      radius:7,weight:2,color:_microMapColor(diff),fillColor:_microMapColor(diff),fillOpacity:.85
    }).addTo(_microMap).bindPopup(
      '<div class="micromap-pop"><b>'+s.name+'</b>'+
      (T!=null?' · '+T.toFixed(1).replace('.',',')+' °C':'')+
      (diff!=null?' <span style="color:'+(diff>0?'#dc2626':'#1d4ed8')+'">('+(diff>0?'+':'')+diff.toFixed(1).replace('.',',')+' °C glede na IREICA1)</span>':'')+
      (s.distKm!=null?' · <span style="color:var(--muted)">'+(+s.distKm).toFixed(1).replace('.',',')+' km stran</span>':'')+
      '</div>'
    );
  });
}

async function fetchWUHistory(){
  const section=document.getElementById('wuh-section');
  const rankEl=document.getElementById('wuh-rank');
  if(!section)return;

  // IREICA1: use real WU 7-day daily history
  // Nearby stations: fetch current obs to get lat/lon, then Open-Meteo for history
  const results=await Promise.all(['IREICA1',...WU_NEARBY_IDS].map(async(id,idx)=>{
    try{
      if(id==='IREICA1'){
        let days=[];
        try{
          const d=await fetch(PROXY+'/wu-station-history?id=IREICA1').then(r=>r.json());
          const obs=d.observations||d.summaries||[];
          days=obs.map(o=>({
            date:(o.obsTimeLocal||o.obsTimeUtc||'').slice(0,10),
            tmax:o.metric?.tempHigh??null,
            tmin:o.metric?.tempLow??null,
            rain:o.metric?.precipTotal??null,
          })).filter(d=>d.date&&d.tmax!=null);
        }catch(_){}
        if(!days.length){
          // Fallback: Open-Meteo for IREICA1 coords
          const om=await fetch('https://api.open-meteo.com/v1/forecast?latitude='+LAT+'&longitude='+LON+'&daily=temperature_2m_max,temperature_2m_min,precipitation_sum&timezone=Europe%2FLjubljana&past_days=7&forecast_days=0').then(r=>r.json());
          const d2=om.daily;
          if(d2?.time?.length) days=d2.time.map((t,i)=>({date:t,tmax:d2.temperature_2m_max[i]??null,tmin:d2.temperature_2m_min[i]??null,rain:d2.precipitation_sum[i]??null})).filter(d=>d.tmax!=null);
        }
        if(!days.length)throw new Error('no data');
        return{id,name:'IREICA1 (Rečica)',color:WUH_PALETTE[0],mine:true,days};
      }
      // Nearby: get coords from current obs, then Open-Meteo history
      const cur=await fetch(PROXY+'/wu-station?id='+id).then(r=>r.json());
      const obs=cur.observations?.[0];
      if(!obs)return null;
      const lat=obs.lat,lon=obs.lon;
      const name=obs.neighborhood||id;
      const omUrl='https://api.open-meteo.com/v1/forecast?latitude='+lat+'&longitude='+lon
        +'&daily=temperature_2m_max,temperature_2m_min,precipitation_sum'
        +'&timezone=Europe%2FLjubljana&past_days=7&forecast_days=0';
      const om=await fetch(omUrl).then(r=>r.json());
      const d2=om.daily;
      if(!d2?.time?.length)return null;
      return{
        id,name,color:WUH_PALETTE[idx%WUH_PALETTE.length],mine:false,
        days:d2.time.map((t,i)=>({
          date:t,
          tmax:d2.temperature_2m_max[i]??null,
          tmin:d2.temperature_2m_min[i]??null,
          rain:d2.precipitation_sum[i]??null,
        })).filter(d=>d.tmax!=null)
      };
    }catch(_){return null;}
  }));

  const valid=results.filter(r=>r&&r.days.length);
  if(!valid.length){if(rankEl)rankEl.innerHTML='<div style="color:var(--muted);font-size:.8rem">Ni podatkov.</div>';return;}
  _renderWUHRanking(valid);
  _renderWUHChart(valid);
  _renderWUHTable(valid);
}

function _renderWUHRanking(stations){
  const el=document.getElementById('wuh-rank');
  if(!el)return;
  const todayStr=_localDateStr(new Date());
  const ranked=stations
    .map(s=>({...s,todayMax:s.days.find(d=>d.date===todayStr)?.tmax??null}))
    .filter(s=>s.todayMax!=null)
    .sort((a,b)=>b.todayMax-a.todayMax);
  if(!ranked.length){el.innerHTML='';return;}
  const medals=['🥇','🥈','🥉'];
  el.innerHTML=ranked.map((s,i)=>
    `<div style="background:var(--fc-bg);border:1px solid ${s.mine?'var(--blue)':'var(--fc-border)'};border-left:3px solid ${s.color};border-radius:12px;padding:.55rem .85rem;min-width:110px">`+
    `<div style="font-size:.67rem;color:var(--muted);margin-bottom:.1rem">${medals[i]||(i+1)+'.'} ${s.mine?'📡 ':''}${s.name}</div>`+
    `<div style="font-family:'JetBrains Mono',monospace;font-size:1.1rem;color:${s.color}">${s.todayMax.toFixed(1)}°C</div>`+
    `</div>`
  ).join('');
}

function _renderWUHChart(stations){
  const svg=document.getElementById('wuh-svg');
  const leg=document.getElementById('wuh-legend');
  const lbl=document.getElementById('wuh-chart-lbl');
  if(!svg)return;
  const allDates=[...new Set(stations.flatMap(s=>s.days.map(d=>d.date)))].sort();
  const allTemps=stations.flatMap(s=>s.days.map(d=>d.tmax)).filter(v=>v!=null);
  if(!allDates.length||!allTemps.length)return;
  const VW=900,VH=240,pad={t:20,r:20,b:38,l:40};
  const cw=VW-pad.l-pad.r,ch=VH-pad.t-pad.b;
  const tmin=Math.min(...allTemps)-1,tmax=Math.max(...allTemps)+1;
  const xS=i=>pad.l+i/Math.max(1,allDates.length-1)*cw;
  const yT=v=>pad.t+(1-(v-tmin)/(tmax-tmin))*ch;
  const ns='http://www.w3.org/2000/svg';
  const mk=(tag,attrs={},text='')=>{const el=document.createElementNS(ns,tag);Object.entries(attrs).forEach(([k,v])=>el.setAttribute(k,v));if(text)el.textContent=text;svg.appendChild(el);return el;};
  svg.innerHTML='';
  for(let i=0;i<=4;i++){const y=pad.t+i/4*ch;const v=(tmax-i/4*(tmax-tmin)).toFixed(0);mk('line',{x1:pad.l,x2:VW-pad.r,y1:y,y2:y,stroke:'rgba(128,128,128,.12)','stroke-width':'1'});mk('text',{x:pad.l-4,y:y+3,'text-anchor':'end','font-size':'8',fill:'rgba(180,180,180,.7)','font-family':'JetBrains Mono,monospace'},v+'°');}
  allDates.forEach((date,i)=>{
    const d=new Date(date+'T12:00:00');
    mk('text',{x:xS(i),y:VH-10,'text-anchor':'middle','font-size':'7.5',fill:'rgba(180,180,180,.7)','font-family':'JetBrains Mono,monospace'},d.getDate()+'.'+(d.getMonth()+1)+'.');
  });
  [...stations].sort((a,b)=>a.mine?1:-1).forEach(s=>{
    const ptArr=allDates.map((date,i)=>{const day=s.days.find(d=>d.date===date);return day?xS(i).toFixed(1)+','+yT(day.tmax).toFixed(1):null;});
    // Draw as segments to handle gaps
    let seg=[];
    ptArr.forEach((pt,i)=>{
      if(pt){seg.push(pt);}
      else if(seg.length){mk('polyline',{points:seg.join(' '),fill:'none',stroke:s.color,'stroke-width':s.mine?'2.5':'1.5','stroke-linecap':'round','stroke-linejoin':'round',opacity:s.mine?'1':'0.7'});seg=[];}
    });
    if(seg.length)mk('polyline',{points:seg.join(' '),fill:'none',stroke:s.color,'stroke-width':s.mine?'2.5':'1.5','stroke-linecap':'round','stroke-linejoin':'round',opacity:s.mine?'1':'0.7'});
  });
  if(leg)leg.innerHTML=stations.map(s=>`<span style="display:flex;align-items:center;gap:.3rem"><span style="width:16px;height:${s.mine?'3':'2'}px;background:${s.color};border-radius:2px;display:inline-block;flex-shrink:0"></span><span style="color:var(--muted)">${s.mine?'📡 ':''}${s.name}</span></span>`).join('');
  if(lbl)lbl.textContent=allDates[0]?.slice(5).replace('-','.')+'–'+allDates.at(-1)?.slice(5).replace('-','.');
}

function _renderWUHTable(stations){
  const el=document.getElementById('wuh-table');
  if(!el)return;
  const allDates=[...new Set(stations.flatMap(s=>s.days.map(d=>d.date)))].sort();
  const SL=['ned','pon','tor','sre','čet','pet','sob'];
  const todayStr=_localDateStr(new Date());
  let t='<table class="wuh-table"><tr><th class="wuh-label">Postaja</th>';
  allDates.forEach(date=>{
    const d=new Date(date+'T12:00:00');
    const today=date===todayStr;
    t+=`<th style="color:${today?'var(--blue)':'var(--muted)'};font-weight:${today?700:500}">${SL[d.getDay()]}<br><span style="font-size:.63rem">${d.getDate()}.${d.getMonth()+1}.</span></th>`;
  });
  t+='</tr>';
  stations.forEach(s=>{
    t+=`<tr><td class="wuh-label"><span style="width:8px;height:8px;border-radius:50%;background:${s.color};display:inline-block;margin-right:.3rem"></span>${s.mine?'📡 ':''}${s.name}</td>`;
    allDates.forEach(date=>{
      const day=s.days.find(d=>d.date===date);
      const today=date===todayStr;
      t+=`<td style="background:${today?'rgba(56,189,248,.04)':'transparent'}">`;
      if(day&&day.tmax!=null){
        t+=`<span style="font-family:'JetBrains Mono',monospace;color:var(--red)">${day.tmax.toFixed(0)}°</span>`;
        if(day.tmin!=null)t+=`<span style="font-size:.63rem;color:var(--muted)">/${day.tmin.toFixed(0)}°</span>`;
        if(day.rain)t+=`<br><span style="font-size:.63rem;color:var(--blue)">${(+day.rain).toFixed(1)}mm</span>`;
      }else t+='<span style="color:var(--border)">—</span>';
      t+='</td>';
    });
    t+='</tr>';
  });
  t+='</table>';
  el.innerHTML=t;
}

async function fetchWUNearby(){
  const grid=document.getElementById('wu-nearby-grid');
  if(!grid)return;
  try{
    const stations=WU_NEARBY_IDS.map(id=>({id,name:id,distKm:null}));

    // Fetch current obs in parallel
    const obs=await Promise.all(stations.map(async s=>{
      try{
        const d=await fetch(PROXY+'/wu-station?id='+s.id).then(r=>r.json());
        const o=d.observations?.[0];
        if(!o)return null;
        // Use neighborhood name from API if available
        const name=o.neighborhood||o.stationID||s.id;
        const distKm=haversine(LAT,LON,o.lat,o.lon);
        return{...s,name,distKm,obs:o};
      }catch(_){return null;}
    }));

    const valid=obs.filter(Boolean);
    if(!valid.length){grid.innerHTML='<div style="color:var(--muted);font-size:.8rem">Ni dostopnih postaj.</div>';return;}

    const myTemp=_lastTemp??null;
    grid.innerHTML='';
    valid.forEach(s=>{
      const m=s.obs.metric||{};
      const T=m.temp??null;
      const hum=s.obs.humidity??null;
      const wind=m.windSpeed??null;
      const rain=m.precipRate??null;
      const diff=myTemp!=null&&T!=null?T-myTemp:null;
      const diffCol=diff==null?'var(--muted)':diff>0?'var(--red)':'var(--blue)';
      const card=document.createElement('div');
      card.className='sur-card';
      card.innerHTML=
        '<div class="sur-name">'+s.name+'</div>'+
        '<div class="sur-dist">'+(s.distKm!=null?(+s.distKm).toFixed(1)+' km · ':'')+s.id+'</div>'+
        '<div class="sur-temp">'+(T!=null?T.toFixed(1)+'°C':'—')+'</div>'+
        '<div class="sur-meta">'+
          (hum!=null?'💧 '+hum+'%  ':'')+
          (wind!=null?'💨 '+wind.toFixed(0)+' km/h  ':'')+
          (rain!=null&&rain>0?'🌧 '+rain.toFixed(1)+' mm/h':'')+
        '</div>'+
        (diff!=null?'<div class="sur-diff" style="color:'+diffCol+'">'+(diff>0?'+':'')+diff.toFixed(1).replace('.',',')+' °C glede na IREICA1</div>':'');
      grid.appendChild(card);
    });
    renderMicroMap(myTemp,valid).catch(e=>console.warn('MicroMap:',e));
  }catch(e){
    if(grid)grid.innerHTML='<div style="color:var(--muted);font-size:.8rem">WU postaje nedostopne: '+e.message+'</div>';
  }
}
async function initSurroundings(){
  if(_surInit)return;_surInit=true;
  fetchWUNearby();
  fetchWUHistory();
  try{
    const grid=document.getElementById('sur-grid');
    // Fetch current conditions for all nearby locations in parallel
    const results=await Promise.all(NEARBY.map(async loc=>{
      const url='https://api.open-meteo.com/v1/forecast?latitude='+loc.lat+'&longitude='+loc.lon
        +'&current=temperature_2m,apparent_temperature,precipitation,wind_speed_10m,weather_code,relative_humidity_2m'
        +'&timezone=Europe%2FLjubljana';
      const res=await fetch(url);const data=await res.json();
      return{...loc,cur:data.current};
    }));

    // Render station cards
    if(grid){
      grid.innerHTML='';
      const mine=results.find(r=>r.mine);
      results.forEach(r=>{
        const c=r.cur||{};
        const diff=mine&&!r.mine&&c.temperature_2m!=null&&mine.cur?.temperature_2m!=null
          ?(c.temperature_2m-mine.cur.temperature_2m):null;
        const card=document.createElement('div');card.className='sur-card'+(r.mine?' mine':'');
        card.innerHTML=
          '<div class="sur-name">'+(r.mine?'📡 ':'')+r.name+'</div>'+
          '<div class="sur-dist">'+r.note+'</div>'+
          '<div class="sur-temp" style="color:'+(r.mine?'var(--blue)':'var(--text)')+'">'+
            (c.temperature_2m!=null?c.temperature_2m.toFixed(1)+'°C':'—')+
          '</div>'+
          '<div class="sur-meta">'+
            _wmoImg(c.weather_code||0,true,18)+' '+_wmoTxt(c.weather_code||0)+'<br>'+
            (c.relative_humidity_2m!=null?'💧 '+c.relative_humidity_2m+'%  ':'')+
            (c.wind_speed_10m!=null?'💨 '+c.wind_speed_10m.toFixed(0)+' km/h':'')+
          '</div>'+
          (diff!=null?'<div class="sur-diff" style="color:'+(diff>0?'var(--red)':'var(--blue)')+'">'+
            (diff>0?'+':'')+diff.toFixed(1).replace('.',',')+' °C glede na IREICA1</div>':'');
        grid.appendChild(card);
      });
    }

    // Fetch 24h hourly temp for chart comparison
    drawElevationProfile(results); // elevation profile from current temps
    const colors=['#38bdf8','#4ade80','#fbbf24','#f87171','#a78bfa','#67e8f9'];
    const hourlyData=await Promise.all(NEARBY.map(async loc=>{
      const url='https://api.open-meteo.com/v1/forecast?latitude='+loc.lat+'&longitude='+loc.lon
        +'&hourly=temperature_2m&timezone=Europe%2FLjubljana&forecast_days=2&past_days=1';
      const res=await fetch(url);const data=await res.json();
      return{...loc,temps:data.hourly?.temperature_2m||[],times:data.hourly?.time||[]};
    }));
    // Draw comparison chart
    const svg=document.getElementById('sur-chart-svg');
    const leg=document.getElementById('sur-chart-legend');
    if(svg&&hourlyData.length){
      const now=new Date();
      const refIdx=hourlyData[0].times.findIndex(t=>new Date(t)>=new Date(now.getTime()-12*3600000))||0;
      const take=24;
      const VW=900,VH=240,pad={t:20,r:20,b:38,l:36};
      const cw=VW-pad.l-pad.r,ch=VH-pad.t-pad.b;
      const allTemps=hourlyData.flatMap(d=>d.temps.slice(refIdx,refIdx+take));
      const tmin=Math.min(...allTemps.filter(x=>x!=null))-1;
      const tmax=Math.max(...allTemps.filter(x=>x!=null))+1;
      const xS=i=>pad.l+i/(take-1)*cw;
      const yS=v=>pad.t+(1-(v-tmin)/(tmax-tmin))*ch;
      const mk=(tag,attrs,txt)=>{const e=document.createElementNS('http://www.w3.org/2000/svg',tag);Object.entries(attrs).forEach(([k,v])=>e.setAttribute(k,v));if(txt)e.textContent=txt;svg.appendChild(e);return e;};
      svg.innerHTML='';
      for(let i=0;i<=3;i++){const y=pad.t+i/3*ch;mk('line',{x1:pad.l,x2:VW-pad.r,y1:y,y2:y,stroke:CC.grid,'stroke-width':'1'});}
      const labels=[...hourlyData[0].times.slice(refIdx,refIdx+take)];
      labels.forEach((t,i)=>{if(i%4===0){const h=new Date(t).getHours();mk('text',{x:xS(i),y:VH-10,'text-anchor':'middle','font-size':'8',fill:CC.label,'font-family':'JetBrains Mono,monospace'},(h<10?'0':'')+h+':00');}});
      // Now line
      const nowIdx=hourlyData[0].times.slice(refIdx,refIdx+take).findIndex(t=>new Date(t)>=now);
      if(nowIdx>=0)mk('line',{x1:xS(nowIdx),x2:xS(nowIdx),y1:pad.t,y2:VH-pad.b,stroke:'rgba(255,180,0,.5)','stroke-width':'1.5','stroke-dasharray':'4,3'});
      hourlyData.forEach((loc,li)=>{
        const temps=loc.temps.slice(refIdx,refIdx+take);
        const valid=temps.map((v,i)=>v!=null?{x:xS(i),y:yS(v)}:null).filter(Boolean);
        if(valid.length<2)return;
        const pts=temps.map((v,i)=>({x:xS(i),y:v!=null?yS(v):null})).filter(p=>p.y!=null);
        mk('path',{d:smoothPath(pts),fill:'none',stroke:colors[li],'stroke-width':loc.mine?'2.5':'1.5',opacity:loc.mine?'1':'0.7','stroke-dasharray':loc.mine?'':'4,2'});
      });
      if(leg){leg.innerHTML=hourlyData.map((loc,li)=>`<span style="display:inline-flex;align-items:center;gap:.3rem"><span style="width:16px;height:3px;background:${colors[li]};display:inline-block;border-radius:2px"></span>${loc.name}</span>`).join('');}
    }
  }catch(e){
    console.warn('Surroundings:',e);
    _surInit=false; // allow retry on next tab open
    const grid=document.getElementById('sur-grid');
    if(grid&&grid.querySelector('div')&&!grid.querySelector('.sur-card')){
      grid.innerHTML='<div style="color:var(--muted);font-size:.8rem">⚠️ Podatki trenutno niso dosegljivi (Open-Meteo). '
        +'<button onclick="_surInit=false;initSurroundings()" style="background:none;border:1px solid var(--blue);color:var(--blue);border-radius:14px;padding:2px 12px;cursor:pointer;font-size:.72rem;margin-left:.5rem">Poskusi znova</button></div>';
    }
    const elev=document.getElementById('elev-lapse');
    if(elev&&elev.textContent==='Nalaganje…')elev.textContent='Podatki niso dosegljivi.';
  }
}

// ── 24h Sky Strip ──────────────────────────────────────────
function skyColorForHour(hour, wmo, darkMode){
  // Base sky color by hour
  const h=((hour%24)+24)%24;
  let r,g,b;
  if(h<5||h>22){r=2;g=6;b=23;}          // deep night
  else if(h<6){r=15;g=23;b=42;}         // pre-dawn
  else if(h<7){r=120;g=53;b=14;}        // golden AM
  else if(h<8){r=180;g=100;b=30;}       // warm morning
  else if(h<10){r=3;g=105;b=161;}       // fresh morning
  else if(h<17){r=2;g=132;b=199;}       // full day sky
  else if(h<18){r=3;g=105;b=161;}       // afternoon
  else if(h<19.5){r=120;g=53;b=14;}     // golden PM
  else if(h<21){r=30;g=58;b=95;}        // dusk
  else{r=15;g=23;b=42;}                 // night
  // Weather modifier (overcast = darker/greyer)
  const overcast=wmo>=2&&wmo<50?0.55:wmo>=50?0.35:1.0;
  const grey=darkMode?15:140;
  r=Math.round(r*(overcast)+(grey*(1-overcast)));
  g=Math.round(g*(overcast)+(grey*(1-overcast)));
  b=Math.round(b*(overcast)+(grey*(1-overcast)));
  return`rgb(${r},${g},${b})`;
}
function uvToColor(uv){
  if(!uv||uv<1)return'rgba(30,30,30,0)';
  if(uv<3) return`rgba(250,204,21,${Math.min(0.5,uv*0.15)})`;
  if(uv<6) return`rgba(251,146,60,${Math.min(0.6,uv*0.1)})`;
  if(uv<9) return`rgba(239,68,68,${Math.min(0.65,uv*0.08)})`;
  return`rgba(168,85,247,0.7)`;
}

async function fetchAndDrawSkyStrip(){
  try{
    const url='https://api.open-meteo.com/v1/forecast?latitude='+LAT+'&longitude='+LON
      +'&hourly=temperature_2m,precipitation,wind_speed_10m,uv_index,weather_code,apparent_temperature'
      +'&timezone=Europe%2FLjubljana&forecast_days=2&past_hours=1';
    const res=await fetch(url);const data=await res.json();
    const h=data.hourly;if(!h?.time?.length)return;
    const now=new Date();
    // Find current hour index
    const startIdx=Math.max(0,h.time.findIndex(t=>new Date(t)>=now));
    const slice=h.time.slice(startIdx,startIdx+24);
    const hours=slice.map((_,i)=>{
      const idx=startIdx+i;
      const date=new Date(h.time[idx]);
      return{
        hour:date.getHours(),
        label:String(date.getHours()).padStart(2,'0')+':00',
        temp:h.temperature_2m[idx]??0,
        apparent:h.apparent_temperature[idx]??0,
        rain:h.precipitation[idx]??0,
        wind:h.wind_speed_10m[idx]??0,
        uv:h.uv_index[idx]??0,
        wmo:h.weather_code[idx]??0,
        isNow:i===0,
      };
    });
    const rangeEl=document.getElementById('sky-range');
    if(rangeEl)rangeEl.textContent=hours[0]?.label+' – '+hours[hours.length-1]?.label;
    drawSkyStrip(hours);
  }catch(e){
    console.warn('SkyStrip:',e);
    const s=document.getElementById('sky-strip-svg');
    if(s){s.innerHTML='<text x="480" y="64" text-anchor="middle" font-size="11" fill="rgba(128,128,128,.5)" font-family="Inter,sans-serif">Trak neba ni dosegljiv ('+e.message+')</text>';}
  }
}

function drawSkyStrip(hours){
  const svg=document.getElementById('sky-strip-svg');if(!svg||!hours.length)return;
  const VW=960,VH=128;
  const cellW=VW/hours.length;
  const LABEL_H=14, SKY_TOP=LABEL_H, SKY_H=72;
  const UV_Y=SKY_TOP+SKY_H+2, UV_H=8;
  const RAIN_Y=UV_Y+UV_H+2, RAIN_H=14;
  const WIND_Y=RAIN_Y+RAIN_H+2, WIND_H=10;
  const dark=isDark();

  svg.innerHTML='';
  const mk=(tag,attrs,txt)=>{const e=document.createElementNS('http://www.w3.org/2000/svg',tag);Object.entries(attrs).forEach(([k,v])=>e.setAttribute(k,v));if(txt!=null)e.textContent=txt;svg.appendChild(e);return e;};
  const defs=mk('defs',{});

  // ── Sky background cells (smooth gradient between hours)
  hours.forEach((h,i)=>{
    const x=i*cellW;
    const col=skyColorForHour(h.hour,h.wmo,dark);
    const colNext=i<hours.length-1?skyColorForHour(hours[i+1].hour,hours[i+1].wmo,dark):col;
    const gid='sg'+i;
    defs.innerHTML+=`<linearGradient id="${gid}" x1="0" x2="1"><stop offset="0%" stop-color="${col}"/><stop offset="100%" stop-color="${colNext}"/></linearGradient>`;
    mk('rect',{x:x.toFixed(1),y:SKY_TOP,width:(cellW+1).toFixed(1),height:SKY_H,fill:`url(#${gid})`});
  });

  // ── UV band
  hours.forEach((h,i)=>{
    const x=i*cellW;
    mk('rect',{x:x.toFixed(1),y:UV_Y,width:cellW.toFixed(1),height:UV_H,fill:uvToColor(h.uv)});
  });

  // ── Precipitation bars
  const maxRain=Math.max(...hours.map(h=>h.rain),0.5);
  hours.forEach((h,i)=>{
    if(h.rain<0.1)return;
    const bh=Math.max(3,Math.min(RAIN_H,(h.rain/maxRain)*RAIN_H));
    mk('rect',{x:(i*cellW+1.5).toFixed(1),y:(RAIN_Y+RAIN_H-bh).toFixed(1),
      width:(cellW-3).toFixed(1),height:bh.toFixed(1),
      fill:h.wmo>=71?'rgba(147,197,253,0.75)':'rgba(96,165,250,0.75)',rx:'1.5'});
  });

  // ── Wind bars
  const maxWind=Math.max(...hours.map(h=>h.wind),5);
  hours.forEach((h,i)=>{
    if(h.wind<8)return;
    const bh=Math.max(2,Math.min(WIND_H,((h.wind-8)/(maxWind-8))*WIND_H));
    mk('rect',{x:(i*cellW+1.5).toFixed(1),y:(WIND_Y+WIND_H-bh).toFixed(1),
      width:(cellW-3).toFixed(1),height:bh.toFixed(1),
      fill:'rgba(167,139,250,0.7)',rx:'1.5'});
  });

  // ── Temperature line + area
  const temps=hours.map(h=>h.temp);
  const tmin=Math.min(...temps)-1,tmax=Math.max(...temps)+1;
  const tY=t=>SKY_TOP+4+(1-(t-tmin)/(tmax-tmin))*(SKY_H-8);
  const pts=hours.map((h,i)=>({x:i*cellW+cellW/2,y:tY(h.temp)}));
  const tempPath=smoothPath(pts);
  const lastPt=pts[pts.length-1];
  const firstPt=pts[0];
  // Area fill
  const areaId='ta';
  defs.innerHTML+=`<linearGradient id="${areaId}" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="#f87171" stop-opacity="0.25"/><stop offset="100%" stop-color="#f87171" stop-opacity="0"/></linearGradient>`;
  mk('path',{d:`${tempPath} L${lastPt.x},${SKY_TOP+SKY_H} L${firstPt.x},${SKY_TOP+SKY_H} Z`,fill:`url(#${areaId})`});
  mk('path',{d:tempPath,fill:'none',stroke:'#f87171','stroke-width':'2','stroke-linecap':'round'});
  // Temp dots at peaks/troughs
  const maxT=Math.max(...temps),minT=Math.min(...temps);
  const maxIdx=temps.indexOf(maxT),minIdx=temps.indexOf(minT);
  [[maxIdx,maxT,'#f87171',-10],[minIdx,minT,'#38bdf8',14]].forEach(([idx,t,col,dy])=>{
    if(idx<0)return;
    const x=idx*cellW+cellW/2,y=tY(t);
    mk('circle',{cx:x.toFixed(1),cy:y.toFixed(1),r:'4',fill:col,stroke:'white','stroke-width':'1.5'});
    mk('text',{x:x.toFixed(1),y:(y+dy).toFixed(1),'text-anchor':'middle','font-size':'8',fill:col,'font-family':'JetBrains Mono,monospace','font-weight':'600'},t.toFixed(1)+'°');
  });

  // ── Condition icons (every 2h, skip if too many)
  hours.forEach((h,i)=>{
    if(i%2!==0)return;
    const x=i*cellW+cellW;
    const iconY=SKY_TOP+SKY_H*0.55;
    mk('text',{x:x.toFixed(1),y:iconY.toFixed(1),'text-anchor':'middle','font-size':'13',
      'dominant-baseline':'central','font-family':'sans-serif'},_wmoEmoji(h.wmo));
  });

  // ── Apparent temperature mini dots (feels like) — subtle
  hours.forEach((h,i)=>{
    if(Math.abs(h.apparent-h.temp)<1.5)return;
    const x=i*cellW+cellW/2,y=tY(h.apparent);
    mk('circle',{cx:x.toFixed(1),cy:y.toFixed(1),r:'2',fill:'rgba(248,113,113,0.35)'});
  });

  // ── Time labels every 3h
  hours.forEach((h,i)=>{
    if(i%3!==0)return;
    mk('text',{x:(i*cellW+cellW/2).toFixed(1),y:(LABEL_H-2).toFixed(1),'text-anchor':'middle',
      'font-size':'8',fill:dark?'rgba(148,163,184,0.8)':'rgba(71,85,105,0.8)',
      'font-family':'JetBrains Mono,monospace'},h.label);
  });

  // ── "Zdaj" marker
  const nowX=cellW/2;
  mk('line',{x1:nowX.toFixed(1),x2:nowX.toFixed(1),y1:SKY_TOP,y2:VH,
    stroke:'rgba(255,180,0,0.7)','stroke-width':'1.5','stroke-dasharray':'3,3'});
  mk('text',{x:(nowX+3).toFixed(1),y:(SKY_TOP+8).toFixed(1),
    'font-size':'7',fill:'rgba(255,180,0,0.8)','font-family':'JetBrains Mono,monospace'},'zdaj');

  // ── Bottom section labels
  const lbls=[['UV',UV_Y+5],['mm',RAIN_Y+9],['km/h',WIND_Y+7]];
  lbls.forEach(([lbl,y])=>{
    mk('text',{x:(VW-2).toFixed(1),y:y.toFixed(1),'text-anchor':'end',
      'font-size':'6.5',fill:dark?'rgba(148,163,184,0.5)':'rgba(100,116,139,0.5)',
      'font-family':'JetBrains Mono,monospace'},lbl);
  });
}


// ══════════════════════════════════════════════════════════
// ── 1. Ecowitt live data ───────────────────────────────────
// ══════════════════════════════════════════════════════════
async function fetchEcowittCurrent(){
  const grid=document.getElementById('ecw-grid');
  const upd=document.getElementById('ecw-updated');
  if(!grid)return;
  try{
    const res=await fetch(PROXY+'/ecowitt-current');
    const data=await res.json();
    if(data.error==='no_key'){
      grid.innerHTML='<div class="ecw-offline">⚙️ Dodaj Ecowitt app key v worker.js (ecowitt.net → Profile → Application Key)</div>';
      return;
    }
    const d=data.data||{};
    const items=[];
    const inT=d.indoor?.temperature?.value;
    const inH=d.indoor?.humidity?.value;
    if(inT!=null)items.push({icon:'🌡',val:parseFloat(inT).toFixed(1)+'°C',lbl:'Notranja T',col:'var(--text)'});
    if(inH!=null)items.push({icon:'💧',val:parseFloat(inH).toFixed(0)+'%',lbl:'Notranja vlaga',col:'var(--blue)'});
    const co2=d.co2?.co2?.value;
    if(co2!=null){const ppm=Math.round(co2);items.push({icon:'🌬',val:ppm+' ppm',lbl:'CO₂',col:ppm<800?'var(--green)':ppm<1200?'var(--amber)':'var(--red)'});}
    const pm=d.pm25?.pm25?.value??d.pm25_ch1?.pm25?.value;
    if(pm!=null)items.push({icon:'🏭',val:parseFloat(pm).toFixed(0)+' µg',lbl:'PM2.5',col:pm<12?'var(--green)':pm<35?'var(--amber)':'var(--red)'});
    const ltCount=d.lightning?.count?.value??d.lightning_num?.value;
    const ltDist=d.lightning?.distance?.value??d.lightning_dis?.value;
    if(ltCount!=null)items.push({icon:'⚡',val:Math.round(ltCount)+' udarov',lbl:'Strele danes',col:ltCount>0?'var(--amber)':'var(--green)'});
    if(ltDist!=null&&parseFloat(ltDist)<100)items.push({icon:'📍',val:parseFloat(ltDist).toFixed(0)+' km',lbl:'Najbližja strela',col:parseFloat(ltDist)<20?'var(--red)':parseFloat(ltDist)<50?'var(--amber)':'var(--muted)'});
    const soilT=d.soil_ch1?.soiltemp?.value;
    const soilH=d.soil_ch1?.soilmoisture?.value??d.soil_ch1?.humidity?.value;
    if(soilT!=null)items.push({icon:'🌱',val:parseFloat(soilT).toFixed(1)+'°C',lbl:'Temp. tal',col:'var(--green)'});
    if(soilH!=null)items.push({icon:'💦',val:parseFloat(soilH).toFixed(0)+'%',lbl:'Vlaga tal',col:'var(--blue)'});
    if(!items.length){grid.innerHTML='<div class="ecw-offline">Ecowitt: ni senzorjev ali napaka API.</div>';return;}
    grid.innerHTML=items.map(it=>`<div class="ecw-item"><div class="ecw-val" style="color:${it.col}">${it.icon} ${it.val}</div><div class="ecw-lbl">${it.lbl}</div></div>`).join('');
    if(upd)upd.textContent=new Date().toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'});
    updateLightningFromEcowitt(ltCount,ltDist);
    if(ltCount>0){const mc=document.getElementById('mc-list');if(mc&&!mc.querySelector('.lightning-alert')){const div=document.createElement('div');div.className='mc-item mc-item-alert lightning-alert';div.innerHTML='<div class="mc-head"><span class="mc-icon">⚡</span><span class="mc-name">Aktivne strele v okolici</span></div><div class="mc-text">Danes '+Math.round(ltCount)+' udarov'+(ltDist?', najbližja '+parseFloat(ltDist).toFixed(0)+' km stran':'')+'.</div>';mc.prepend(div);}}
  }catch(e){if(grid)grid.innerHTML='<div class="ecw-offline">Ecowitt ni dosegljiv.</div>';console.warn('Ecowitt:',e);}
}

// ══════════════════════════════════════════════════════════
// ── 2. ARSO cross-check & drift detekcija ─────────────────
// ══════════════════════════════════════════════════════════
const ARSO_DRIFT_KEY='arso-drift-v1';
async function fetchARSOComparison(){
  const el=document.getElementById('arso-check-content');
  const ts=document.getElementById('arso-check-time');
  if(!el)return;
  try{
    const res=await fetch(PROXY+'/arso-obs');
    const txt=await res.text();
    const doc=new DOMParser().parseFromString(txt,'application/xml');
    const stations=[...doc.querySelectorAll('metData')];
    let arso=null;
    const tryNames=['Šoštanj','Sostanj','Velenje','Šmartno','Mozirje','Celje'];
    for(const nm of tryNames){arso=stations.find(s=>(s.querySelector('domain_title,domain_longTitle')?.textContent||'').includes(nm));if(arso)break;}
    const getV=(st,sel)=>{const v=parseFloat(st?.querySelector(sel)?.textContent);return isNaN(v)?null:v;};
    const arsoT=getV(arso,'t'),arsoH=getV(arso,'rh'),arsoP=getV(arso,'msl')||getV(arso,'p'),arsoW=getV(arso,'ff_val')||getV(arso,'ff10');
    const arsoName=arso?.querySelector('domain_title')?.textContent||'ARSO';
    const obs=_lastBriefObs||{},m=obs?.metric||{};
    const myT=m.temp??null,myH=obs?.humidity??null,myP=m.pressure??null,myW=m.windSpeed??null;
    if(myT!=null&&arsoT!=null){
      const drifts=JSON.parse(localStorage.getItem(ARSO_DRIFT_KEY)||'[]');
      drifts.push({t:Date.now(),dT:+(myT-arsoT).toFixed(2),dH:myH&&arsoH?+(myH-arsoH).toFixed(1):null});
      if(drifts.length>720)drifts.splice(0,drifts.length-720);
      localStorage.setItem(ARSO_DRIFT_KEY,JSON.stringify(drifts));
    }
    const drifts=JSON.parse(localStorage.getItem(ARSO_DRIFT_KEY)||'[]');
    const r7=drifts.filter(d=>d.t>Date.now()-7*864e5);
    const avgDT=r7.length?+(r7.reduce((s,d)=>s+d.dT,0)/r7.length).toFixed(2):null;
    const avgDH=r7.filter(d=>d.dH!=null).length?+(r7.filter(d=>d.dH!=null).reduce((s,d)=>s+d.dH,0)/r7.filter(d=>d.dH!=null).length).toFixed(1):null;
    const dc=(d,w,b)=>d==null?'':Math.abs(d)<w?'arso-ok':Math.abs(d)<b?'arso-warn':'arso-bad';
    const fv=(v,u)=>v!=null?v.toFixed(1)+u:'—';
    const fd=(d,u)=>d!=null?(d>=0?'+':'')+d.toFixed(1)+u:'—';
    const rows=[
      {p:'🌡 Temperatura',my:fv(myT,'°C'),ref:fv(arsoT,'°C'),d:myT!=null&&arsoT!=null?myT-arsoT:null,w:1,b:2,u:'°C'},
      {p:'💧 Vlaga',my:fv(myH,'%'),ref:fv(arsoH,'%'),d:myH!=null&&arsoH!=null?myH-arsoH:null,w:5,b:10,u:'%'},
      {p:'📊 Tlak',my:fv(myP,' hPa'),ref:fv(arsoP,' hPa'),d:myP!=null&&arsoP!=null?myP-arsoP:null,w:1.5,b:3,u:' hPa'},
      {p:'💨 Veter',my:fv(myW,' km/h'),ref:fv(arsoW,' km/h'),d:null,w:0,b:0,u:' km/h'},
    ];
    el.innerHTML=
      '<div style="font-size:.7rem;color:var(--muted);margin-bottom:.5rem">Primerjava z: <strong style="color:var(--text)">ARSO '+arsoName+'</strong></div>'+
      rows.map(r=>`<div class="arso-diff-row"><div class="arso-diff-param">${r.p}</div><div class="arso-diff-vals"><span class="arso-val-mine">${r.my}</span><span class="arso-val-ref">vs ${r.ref}</span>${r.d!=null?`<span class="arso-val-diff ${dc(r.d,r.w,r.b)}">${fd(r.d,r.u)}</span>`:''}</div></div>`).join('')+
      `<div class="arso-drift-note">`+(avgDT!=null?`<strong>7-dnevni odmik temperature:</strong> IREICA1 je v povprečju za <strong style="color:${Math.abs(avgDT)<1?'var(--green)':Math.abs(avgDT)<2?'var(--amber)':'var(--red)'}">${avgDT>=0?'+':''}${avgDT} °C</strong> ${avgDT>=0?'toplejša':'hladnejša'} od ${arsoName}. `:'Zbiranje odmika temperature … vrni se jutri za trend.')+(avgDH!=null?`Vlaga: ${avgDH>=0?'+':''}${avgDH} %. `:'')+(r7.length?`(${r7.length} meritev)`:'')+'</div>';
    if(ts)ts.textContent=arsoName+' · '+new Date().toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'});
  }catch(e){if(el)el.innerHTML='<div style="color:var(--muted);font-size:.78rem">ARSO primerjava ni dosegljiva.</div>';console.warn('ARSO:',e);}
}

// ══════════════════════════════════════════════════════════
// ── 3. Tekoča vsota padavin glede na normale ───────────────────
// ══════════════════════════════════════════════════════════
function buildPrecipNormals(){
  const grid=document.getElementById('pn-grid');
  const upd=document.getElementById('pn-updated');
  if(!grid)return;
  const stored=JSON.parse(localStorage.getItem(LS_KEY)||'{}');
  const entries=Object.entries(stored).map(([d,v])=>({d,year:+d.slice(0,4),month:+d.slice(5,7),v}));
  if(entries.length<60){grid.innerHTML='<div style="color:var(--muted);font-size:.78rem">Premalo podatkov za izračun norm.</div>';return;}
  const now=new Date(),curYear=now.getFullYear(),curMonth=now.getMonth()+1;
  const dayOfYear=Math.floor((now-new Date(curYear,0,0))/864e5);
  const season=curMonth<=2||curMonth===12?'Zima':curMonth<=5?'Pomlad':curMonth<=8?'Poletje':'Jesen';
  const seasonMonths={Zima:[12,1,2],Pomlad:[3,4,5],Poletje:[6,7,8],Jesen:[9,10,11]};
  const curSM=seasonMonths[season];
  const years=[...new Set(entries.map(e=>e.year))].filter(y=>y<curYear).sort();
  const sum=arr=>arr.reduce((s,e)=>s+(e.v.precipTotal||0),0);
  const curMonTotal=sum(entries.filter(e=>e.year===curYear&&e.month===curMonth));
  // Use XLSX climatological normals as fallback (better than computed)
  const xlsxNorm=(typeof XLSX_KLIMA!=='undefined'?XLSX_KLIMA:[]).find(k=>k.m===curMonth);
  const histMon=years.length>=3?years.map(y=>sum(entries.filter(e=>e.year===y&&e.month===curMonth))).reduce((a,b)=>a+b,0)/years.length:(xlsxNorm?.rain||null);
  const curSeaTotal=sum(entries.filter(e=>season==='Zima'?((e.year===curYear&&[1,2].includes(e.month))||(e.year===curYear-1&&e.month===12)):(e.year===curYear&&curSM.includes(e.month))));
  const histSea=years.length?years.map(y=>sum(entries.filter(e=>season==='Zima'?((e.year===y&&[1,2].includes(e.month))||(e.year===y-1&&e.month===12)):(e.year===y&&curSM.includes(e.month))))).reduce((a,b)=>a+b,0)/years.length:null;
  const curYtd=sum(entries.filter(e=>e.year===curYear));
  const histYtd=years.length?years.map(y=>sum(entries.filter(e=>e.year===y&&Math.floor((new Date(e.d+'T12:00:00')-new Date(y,0,0))/864e5)<=dayOfYear))).reduce((a,b)=>a+b,0)/years.length:null;
  const periods=[
    {lbl:['Jan','Feb','Mar','Apr','Maj','Jun','Jul','Avg','Sep','Okt','Nov','Dec'][curMonth-1],val:curMonTotal,norm:histMon},
    {lbl:season,val:curSeaTotal,norm:histSea},
    {lbl:'Letos (do danes)',val:curYtd,norm:histYtd},
  ];
  grid.innerHTML='';
  periods.forEach(p=>{
    const pct=p.norm&&p.norm>0?Math.round(p.val/p.norm*100):null;
    const cls=pct==null?'':pct>120?'pn-above':pct<80?'pn-below':'pn-normal';
    const barCol=pct>120?'var(--blue)':pct<80?'var(--amber)':'var(--green)';
    const div=document.createElement('div');div.className='pn-item';
    div.innerHTML=`<div class="pn-label">${p.lbl}</div><div class="pn-val ${cls}">${Math.round(p.val)} mm</div><div class="pn-norm">${pct!=null?pct+' % norme ('+Math.round(p.norm)+' mm)':p.norm?'norm. '+Math.round(p.norm)+' mm':'—'}</div><div class="pn-bar-wrap"><div class="pn-bar" style="width:${Math.min(100,pct||0)}%;background:${barCol}"></div></div><div class="pn-caption">${_goalCaption(p,pct,'mm padavin')}</div>`;
    grid.appendChild(div);
  });
  if(upd)upd.textContent=years.length?years[0]+'–'+(curYear-1)+' ('+years.length+' let)':'—';
}

// Human-readable "goal tracker" caption shared by precip + sunshine accumulators
function _goalCaption(p,pct,unit){
  if(pct==null)return'Zbiranje podatkov za primerjavo s podnebno normalo …';
  if(pct>=100)return`Cilj dosežen — ${pct} % dolgoletnega povprečja (${Math.round(p.norm)} ${unit}) za to obdobje.`;
  const missing=Math.max(0,p.norm-p.val);
  return`Trenutno smo pri ${pct} % dolgoletnega povprečja — do cilja manjka še ${missing.toFixed(0)} ${unit}.`;
}

// ══════════════════════════════════════════════════════════
// ── 3b. Tekoča vsota sončnih ur glede na dolgoletno povprečje ──
// (ARSO klimatološke normale 1991–2020, Celje — glej ARSO_NORMALS.sun)
// ══════════════════════════════════════════════════════════
async function buildSunshineNormals(){
  const grid=document.getElementById('sn-grid');
  const upd=document.getElementById('sn-updated');
  if(!grid)return;
  try{
    const now=new Date(),curYear=now.getFullYear(),curMonth=now.getMonth()+1;
    const pad=n=>String(n).padStart(2,'0');
    const season=curMonth<=2||curMonth===12?'Zima':curMonth<=5?'Pomlad':curMonth<=8?'Poletje':'Jesen';
    const seasonMonths={Zima:[12,1,2],Pomlad:[3,4,5],Poletje:[6,7,8],Jesen:[9,10,11]}[season];
    // Fetch range covers season start (may reach into previous year for winter) through today
    const fetchStartYear=curMonth<=2?curYear-1:curYear;
    const fetchStart=fetchStartYear+'-'+(curMonth<=2?'12-01':'01-01');
    const todayStr=curYear+'-'+pad(curMonth)+'-'+pad(now.getDate());
    const url='https://archive-api.open-meteo.com/v1/archive?latitude='+LAT+'&longitude='+LON
      +'&start_date='+fetchStart+'&end_date='+todayStr
      +'&daily=sunshine_duration&timezone=Europe%2FLjubljana';
    const data=await fetch(url).then(r=>r.json());
    const days=data.daily?.time||[];
    const vals=data.daily?.sunshine_duration||[];
    const hoursByDate={};
    days.forEach((d,i)=>{ if(vals[i]!=null) hoursByDate[d]=vals[i]/3600; });
    const sumWhere=pred=>Object.entries(hoursByDate).filter(([d])=>pred(d)).reduce((s,[,v])=>s+v,0);

    const curMonTotal=sumWhere(d=>+d.slice(0,4)===curYear&&+d.slice(5,7)===curMonth);
    const curSeaTotal=season==='Zima'
      ?sumWhere(d=>(+d.slice(0,4)===curYear&&[1,2].includes(+d.slice(5,7)))||(+d.slice(0,4)===curYear-1&&+d.slice(5,7)===12))
      :sumWhere(d=>+d.slice(0,4)===curYear&&seasonMonths.includes(+d.slice(5,7)));
    const curYtd=sumWhere(d=>+d.slice(0,4)===curYear);

    const N=OM_SUN_NORMAL; // index 0=jan … 11=dec — Open-Meteo normala (ista metoda kot tekoči podatki, glej definicijo)
    const histMon=N[curMonth-1];
    const histSea=seasonMonths.reduce((s,m)=>s+N[m-1],0);
    const daysInCurMonth=new Date(curYear,curMonth,0).getDate();
    const monthsBefore=Array.from({length:curMonth-1},(_,i)=>i);
    const histYtd=monthsBefore.reduce((s,i)=>s+N[i],0)+N[curMonth-1]*(now.getDate()/daysInCurMonth);

    const periods=[
      {lbl:['Jan','Feb','Mar','Apr','Maj','Jun','Jul','Avg','Sep','Okt','Nov','Dec'][curMonth-1],val:curMonTotal,norm:histMon},
      {lbl:season,val:curSeaTotal,norm:histSea},
      {lbl:'Letos (do danes)',val:curYtd,norm:histYtd},
    ];
    grid.innerHTML='';
    periods.forEach(p=>{
      const pct=p.norm&&p.norm>0?Math.round(p.val/p.norm*100):null;
      const cls=pct==null?'':pct>110?'pn-above':pct<70?'pn-below':'pn-normal';
      const barCol=pct>110?'var(--amber)':pct<70?'var(--muted)':'var(--green)';
      const div=document.createElement('div');div.className='pn-item';
      div.innerHTML=`<div class="pn-label">${p.lbl}</div><div class="pn-val ${cls}">${Math.round(p.val)} h</div><div class="pn-norm">${pct!=null?pct+' % norme ('+Math.round(p.norm)+' h)':'—'}</div><div class="pn-bar-wrap"><div class="pn-bar" style="width:${Math.min(100,pct||0)}%;background:${barCol}"></div></div><div class="pn-caption">${_goalCaption(p,pct,'ur sonca')}</div>`;
      grid.appendChild(div);
    });
    if(upd)upd.textContent='Open-Meteo normala 1991–2020 (ista metoda)';
  }catch(e){
    console.warn('Sunshine normals:',e);
    grid.innerHTML='<div style="color:var(--muted);font-size:.78rem">Podatki o sončnih urah trenutno niso na voljo.</div>';
  }
}

// ══════════════════════════════════════════════════════════
// ── Dinamičen vremenski background ────────────────────────
// ══════════════════════════════════════════════════════════
const WX_THEMES={
  night:      {bg:'#020617',b:['rgba(30,27,75,.85)','rgba(12,20,50,.75)','rgba(15,23,42,.7)','rgba(49,46,129,.55)'],  p:'star',n:55},
  sunny:      {bg:'#0c2340',b:['rgba(14,165,233,.6)','rgba(56,189,248,.5)','rgba(3,105,161,.65)','rgba(7,89,133,.45)'],p:'mote',n:18},
  hot:        {bg:'#18060a',b:['rgba(239,68,68,.55)','rgba(249,115,22,.6)','rgba(251,191,36,.35)','rgba(220,38,38,.45)'],p:'mote',n:12},
  cloudy:     {bg:'#0f1a2e',b:['rgba(71,85,105,.65)','rgba(51,65,85,.6)','rgba(100,116,139,.5)','rgba(71,85,105,.45)'], p:null,n:0},
  fog:        {bg:'#131e2d',b:['rgba(148,163,184,.5)','rgba(100,116,139,.45)','rgba(148,163,184,.4)','rgba(71,85,105,.35)'],p:'fog',n:7},
  rain:       {bg:'#060f1c',b:['rgba(30,58,95,.75)','rgba(15,23,42,.8)','rgba(37,99,235,.42)','rgba(29,78,216,.4)'],   p:'rain',n:48},
  heavy_rain: {bg:'#040a14',b:['rgba(30,58,95,.85)','rgba(15,23,42,.9)','rgba(37,99,235,.52)','rgba(29,78,216,.48)'],  p:'rain',n:80},
  storm:      {bg:'#04040e',b:['rgba(49,46,129,.8)','rgba(30,27,75,.9)','rgba(67,56,202,.5)','rgba(15,23,42,.95)'],    p:'storm',n:90},
  snow:       {bg:'#060f1c',b:['rgba(30,58,95,.6)','rgba(186,230,253,.25)','rgba(56,189,248,.4)','rgba(14,165,233,.38)'],p:'snow',n:40},
};
const WX_LIGHT_BG={night:'#0f172a',sunny:'#0c3a5e',hot:'#2d1208',cloudy:'#1e293b',fog:'#2d3748',rain:'#0f1a2e',heavy_rain:'#09111f',storm:'#0a0a1f',snow:'#0d1a30'};

let _wxParticles=[],_wxCond='',_lightningTimer=null;

function initBgCanvas(){
  const c=document.getElementById('bg-wx-canvas');if(!c)return;
  const resize=()=>{c.width=window.innerWidth;c.height=window.innerHeight;};
  resize();window.addEventListener('resize',resize,{passive:true});
}

function clearWxParticles(){_wxParticles.forEach(p=>p.remove());_wxParticles=[];}

function spawnWxParticles(type,count){
  const bg=document.getElementById('bg');if(!bg||!type||!count)return;
  for(let i=0;i<count;i++){
    const el=document.createElement('div');
    if(type==='rain'||type==='storm'){
      el.className='wx-rain';
      const len=14+Math.random()*20,spd=0.45+Math.random()*0.55;
      el.style.cssText=`left:${Math.random()*115-7}%;height:${len}px;width:${type==='storm'?1.5:1}px;animation-duration:${spd}s;animation-delay:-${(Math.random()*2).toFixed(2)}s;opacity:${type==='storm'?0.55:0.4}`;
    }else if(type==='snow'){
      el.className='wx-snow';
      const sz=2+Math.random()*4,spd=3.5+Math.random()*5;
      el.style.cssText=`left:${Math.random()*100}%;top:-20px;width:${sz}px;height:${sz}px;animation-duration:${spd}s;animation-delay:-${(Math.random()*7).toFixed(2)}s;opacity:${(0.4+Math.random()*0.35).toFixed(2)}`;
    }else if(type==='star'){
      el.className='wx-star';
      const sz=0.8+Math.random()*1.8,spd=2+Math.random()*4.5;
      el.style.cssText=`left:${Math.random()*100}%;top:${Math.random()*80}%;width:${sz}px;height:${sz}px;animation-duration:${spd}s;animation-delay:-${(Math.random()*6).toFixed(2)}s`;
    }else if(type==='mote'){
      el.className='wx-mote';
      const sz=5+Math.random()*16,spd=4+Math.random()*6;
      const hue=_wxCond==='hot'?`249,115,22`:`56,189,248`;
      el.style.cssText=`left:${Math.random()*100}%;top:${35+Math.random()*60}%;width:${sz}px;height:${sz}px;background:radial-gradient(circle,rgba(${hue},${(0.2+Math.random()*0.2).toFixed(2)}),transparent 70%);animation-duration:${spd}s;animation-delay:-${(Math.random()*7).toFixed(2)}s`;
    }else if(type==='fog'){
      el.className='wx-fog';
      const w=200+Math.random()*320,h=60+Math.random()*110,spd=7+Math.random()*11;
      el.style.cssText=`left:${-15+Math.random()*80}%;top:${5+Math.random()*75}%;width:${w}px;height:${h}px;background:radial-gradient(ellipse,rgba(148,163,184,.18),transparent 70%);animation-duration:${spd}s;animation-delay:-${(Math.random()*12).toFixed(2)}s`;
    }
    bg.appendChild(el);_wxParticles.push(el);
  }
}

function applyWeatherBg(cond){
  if(cond===_wxCond)return;
  _wxCond=cond;
  const dark=isDark();
  const t=WX_THEMES[cond]||WX_THEMES.cloudy;
  const bgEl=document.getElementById('bg');if(!bgEl)return;

  // Base background colour
  bgEl.style.background=dark?t.bg:(WX_LIGHT_BG[cond]||t.bg);

  // Blob colours
  ['b1','b2','b3','b4'].forEach((cls,i)=>{
    const el=bgEl.querySelector('.'+cls);
    if(el)el.style.background=`radial-gradient(circle,${t.b[i]},transparent 70%)`;
  });

  // Particles
  clearWxParticles();
  if(t.p&&t.n>0)spawnWxParticles(t.p,t.n);

  // Storm lightning
  clearTimeout(_lightningTimer);
  if(cond==='storm')scheduleLightning();
}

function scheduleLightning(){
  if(_wxCond!=='storm')return;
  _lightningTimer=setTimeout(()=>{
    const c=document.getElementById('bg-wx-canvas');if(!c||_wxCond!=='storm')return;
    const ctx=c.getContext('2d');if(!ctx)return;
    ctx.clearRect(0,0,c.width,c.height);
    // Draw bolt
    const sx=c.width*0.2+Math.random()*c.width*0.6;
    ctx.save();ctx.strokeStyle='rgba(196,210,255,0.75)';ctx.lineWidth=1.5;
    ctx.shadowColor='#a5b4fc';ctx.shadowBlur=22;ctx.beginPath();ctx.moveTo(sx,0);
    let bx=sx,by=0;
    for(let i=0;i<7;i++){bx+=(Math.random()-.5)*52;by+=c.height/7;ctx.lineTo(bx,by);}
    ctx.stroke();ctx.restore();
    // Fade out
    let a=1;
    const fade=()=>{a-=0.12;ctx.clearRect(0,0,c.width,c.height);
      if(a>0&&_wxCond==='storm'){ctx.save();ctx.globalAlpha=a*0.04;ctx.fillStyle='rgba(200,215,255,1)';ctx.fillRect(0,0,c.width,c.height);ctx.restore();requestAnimationFrame(fade);}
    };
    setTimeout(fade,50);
    scheduleLightning();
  },4000+Math.random()*9000);
}


// ── Animation pause flag (set on visibilitychange) ───────
let _animPaused=false;

// ── Hero canvas particles ─────────────────────────────────
let _heroCtx=null,_heroCanvas=null,_heroParticles=[],_heroAnimId=null,_heroCond='';
function initHeroCanvas(){
  _heroCanvas=document.getElementById('hero-canvas');
  if(!_heroCanvas)return;
  _heroCtx=_heroCanvas.getContext('2d');
  const hero=_heroCanvas.parentElement;
  const resize=()=>{_heroCanvas.width=hero.offsetWidth||460;_heroCanvas.height=hero.offsetHeight||180;};
  resize();
  new ResizeObserver(resize).observe(hero);
  animateHero();
}
function spawnHeroParticles(cond){
  if(!_heroCanvas)return;
  const W=_heroCanvas.width,H=_heroCanvas.height;
  const counts={rain:38,heavy_rain:55,snow:28,storm:45,night:35,sunny:22,hot:25,fog:18,cloudy:12};
  const n=counts[cond]||12;
  _heroParticles=[];
  for(let i=0;i<n;i++)_heroParticles.push(makeHeroP(cond,W,H,true));
}
function makeHeroP(cond,W,H,init=false){
  const r=()=>Math.random();
  if(cond==='rain'||cond==='heavy_rain'||cond==='storm'){
    const speed=cond==='storm'?14+r()*8:7+r()*5;
    return{type:'rain',x:r()*W,y:init?r()*H:-15,vx:cond==='storm'?2.5:1,vy:speed,len:7+r()*11,op:.18+r()*.18};
  }
  if(cond==='snow')return{type:'snow',x:r()*W,y:init?r()*H:-8,vx:(r()-.5)*.4,vy:.7+r()*1.1,r:1.2+r()*2.2,op:.35+r()*.3,ph:r()*Math.PI*2};
  if(cond==='night')return{type:'star',x:r()*W,y:r()*H,r:.6+r()*1.4,op:r(),ph:r()*Math.PI*2};
  if(cond==='sunny'||cond==='hot')return{type:'mote',x:r()*W,y:init?r()*H:H+8,vx:(r()-.5)*.25,vy:-(0.25+r()*.7),r:.8+r()*1.8,op:.12+r()*.15};
  if(cond==='fog')return{type:'wisp',x:r()*W,y:r()*H,vx:.12+r()*.2,w:50+r()*90,h:5+r()*10,op:.03+r()*.04};
  return{type:'wisp',x:r()*W,y:r()*H,vx:.08+r()*.12,w:20+r()*35,h:4+r()*8,op:.02+r()*.03};
}
function animateHero(){
  if(_animPaused){_heroAnimId=null;return;}
  if(!_heroCtx||!_heroCanvas){return;}
  const ctx=_heroCtx,W=_heroCanvas.width,H=_heroCanvas.height,t=performance.now()/1000;
  ctx.clearRect(0,0,W,H);
  const cond=_heroCond;
  _heroParticles.forEach((p,i)=>{
    if(p.type==='star'){
      p.ph+=.025;const op=Math.max(0,p.op*.5+Math.sin(p.ph)*.35);
      ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);
      ctx.fillStyle=`rgba(226,232,240,${op})`;ctx.fill();return;
    }
    if(p.type==='rain'){
      p.x+=p.vx;p.y+=p.vy;
      ctx.beginPath();ctx.moveTo(p.x,p.y);ctx.lineTo(p.x+p.vx*(p.len/p.vy),p.y+p.len);
      ctx.strokeStyle=`rgba(147,197,253,${p.op})`;ctx.lineWidth=.8;ctx.stroke();
      if(p.y>H+22)Object.assign(p,makeHeroP(cond,W,H));return;
    }
    if(p.type==='snow'){
      p.ph+=.02;p.x+=p.vx+Math.sin(p.ph+i*.4)*.25;p.y+=p.vy;
      ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);
      ctx.fillStyle=`rgba(186,230,253,${p.op})`;ctx.fill();
      if(p.y>H+8)Object.assign(p,makeHeroP(cond,W,H));return;
    }
    if(p.type==='mote'){
      p.x+=p.vx;p.y+=p.vy;p.op*=.9985;
      ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);
      ctx.fillStyle=`rgba(253,224,71,${p.op})`;ctx.fill();
      if(p.y<-8||p.op<.012)Object.assign(p,makeHeroP(cond,W,H,true));return;
    }
    if(p.type==='wisp'){
      p.x+=p.vx;if(p.x>W+p.w/2)p.x=-p.w/2;
      ctx.beginPath();ctx.ellipse(p.x,p.y,p.w,p.h,0,0,Math.PI*2);
      ctx.fillStyle=`rgba(203,213,225,${p.op})`;ctx.fill();
    }
  });
  // Replenish
  if(_heroParticles.length<(cond==='rain'||cond==='heavy_rain'?55:cond==='storm'?45:40)){
    _heroParticles.push(makeHeroP(cond,W,H));
  }
  _heroAnimId=requestAnimationFrame(animateHero);
}
function setHeroCond(cond){
  if(cond===_heroCond)return;
  _heroCond=cond;
  spawnHeroParticles(cond);
  const c=document.getElementById('hero-canvas');
  if(c)c.classList.toggle('active',cond!=='cloudy');
}

// ── Mesh gradient canvas ──────────────────────────────────
let _meshCtx=null,_meshCanvas=null,_meshNodes=[],_meshAnimId=null,_meshFrame=0;
let _meshWindAngle=0,_meshWindSpeed=0.5;

const MESH_DEFS=[
  {bx:.12,by:.10,r:.75},{bx:.88,by:.08,r:.72},{bx:.50,by:.18,r:.90},
  {bx:.04,by:.52,r:.68},{bx:.96,by:.48,r:.68},
  {bx:.22,by:.88,r:.65},{bx:.78,by:.90,r:.65},{bx:.50,by:.60,r:.80},
];

// Per-condition mesh palettes  [dark mode rgba strings]
const MESH_PALETTES={
  night:     ['rgba(88,28,235,.32)','rgba(49,46,129,.28)','rgba(109,40,217,.30)','rgba(30,27,75,.25)','rgba(76,29,149,.28)','rgba(17,24,39,.30)','rgba(49,46,129,.22)','rgba(88,28,235,.18)'],
  sunny:     ['rgba(14,165,233,.30)','rgba(3,105,161,.26)','rgba(56,189,248,.22)','rgba(7,89,133,.28)','rgba(2,132,199,.24)','rgba(12,74,110,.30)','rgba(14,165,233,.18)','rgba(56,189,248,.14)'],
  hot:       ['rgba(239,68,68,.32)','rgba(249,115,22,.30)','rgba(245,158,11,.22)','rgba(220,38,38,.26)','rgba(251,146,60,.28)','rgba(180,40,15,.32)','rgba(234,88,12,.20)','rgba(239,68,68,.18)'],
  cloudy:    ['rgba(71,85,105,.25)','rgba(51,65,85,.22)','rgba(100,116,139,.20)','rgba(71,85,105,.18)','rgba(51,65,85,.24)','rgba(30,41,59,.28)','rgba(71,85,105,.16)','rgba(100,116,139,.14)'],
  fog:       ['rgba(148,163,184,.24)','rgba(100,116,139,.22)','rgba(148,163,184,.18)','rgba(71,85,105,.20)','rgba(100,116,139,.24)','rgba(51,65,85,.22)','rgba(148,163,184,.16)','rgba(203,213,225,.14)'],
  rain:      ['rgba(29,78,216,.32)','rgba(37,99,235,.28)','rgba(15,23,42,.35)','rgba(30,58,95,.30)','rgba(29,78,216,.24)','rgba(15,23,42,.38)','rgba(37,99,235,.18)','rgba(29,78,216,.15)'],
  heavy_rain:['rgba(15,23,42,.40)','rgba(29,78,216,.32)','rgba(12,18,35,.38)','rgba(30,58,95,.34)','rgba(15,23,42,.42)','rgba(12,18,35,.40)','rgba(29,78,216,.20)','rgba(15,23,42,.25)'],
  storm:     ['rgba(109,40,217,.38)','rgba(67,20,180,.35)','rgba(139,92,246,.30)','rgba(49,46,129,.40)','rgba(167,139,250,.22)','rgba(30,27,75,.45)','rgba(88,28,235,.28)','rgba(109,40,217,.20)'],
  snow:      ['rgba(14,165,233,.26)','rgba(99,102,241,.22)','rgba(186,230,253,.16)','rgba(2,132,199,.24)','rgba(56,189,248,.18)','rgba(7,89,133,.30)','rgba(14,116,144,.22)','rgba(186,230,253,.12)'],
};
// Dawn/dusk time overrides
function meshTimeOverride(t){
  if(t>=5   &&t<6.5) return ['rgba(194,65,12,.32)','rgba(251,146,60,.28)','rgba(234,88,12,.26)','rgba(180,40,15,.30)','rgba(251,146,60,.22)','rgba(120,30,8,.32)','rgba(220,80,20,.18)','rgba(251,146,60,.15)'];
  if(t>=6.5 &&t<7.5) return ['rgba(180,100,9,.28)','rgba(245,158,11,.25)','rgba(250,204,21,.20)','rgba(161,80,5,.28)','rgba(245,158,11,.22)','rgba(120,60,5,.30)','rgba(180,100,9,.16)','rgba(245,158,11,.12)'];
  if(t>=19  &&t<20.5)return ['rgba(180,100,9,.30)','rgba(245,158,11,.26)','rgba(234,88,12,.24)','rgba(161,80,5,.28)','rgba(251,146,60,.22)','rgba(120,30,8,.32)','rgba(180,100,9,.18)','rgba(245,158,11,.14)'];
  if(t>=20.5&&t<22)  return ['rgba(109,40,217,.28)','rgba(167,139,250,.24)','rgba(88,28,235,.26)','rgba(49,46,129,.30)','rgba(139,92,246,.20)','rgba(30,27,75,.35)','rgba(109,40,217,.18)','rgba(167,139,250,.14)'];
  return null;
}

function _meshDraw(){
  if(_animPaused||!_meshCtx||!_meshCanvas){_meshAnimId=null;return;}
  const ctx=_meshCtx,W=_meshCanvas.width,H=_meshCanvas.height;
  // On touch devices run at ~20 fps instead of ~60 fps to reduce heat
  if(_meshFrame%3!==0&&navigator.maxTouchPoints>0){_meshFrame++;_meshAnimId=requestAnimationFrame(_meshDraw);return;}
  ctx.clearRect(0,0,W,H);
  _meshNodes.forEach(n=>{
    const x=n.x*W,y=n.y*H,r=n.r*Math.max(W,H)*0.85;
    const g=ctx.createRadialGradient(x,y,0,x,y,r);
    g.addColorStop(0,n.color);g.addColorStop(1,'rgba(0,0,0,0)');
    ctx.fillStyle=g;ctx.fillRect(0,0,W,H);
  });
  if(_meshFrame%3===0){
    const spd=_meshWindSpeed*.00006,dx=Math.sin(_meshWindAngle)*spd,dy=-Math.cos(_meshWindAngle)*spd;
    _meshNodes.forEach(n=>{
      n.x+=dx+n.vx;n.y+=dy+n.vy;
      if(n.x<-.15){n.x=-.15;n.vx*=-.85;}if(n.x>1.15){n.x=1.15;n.vx*=-.85;}
      if(n.y<-.15){n.y=-.15;n.vy*=-.85;}if(n.y>1.15){n.y=1.15;n.vy*=-.85;}
    });
  }
  _meshFrame++;
  _meshAnimId=requestAnimationFrame(_meshDraw);
}

function initMeshCanvas(){
  const c=document.getElementById('mesh-canvas');
  if(!c)return;
  _meshCanvas=c;
  _meshCtx=c.getContext('2d');
  c.style.opacity = isDark() ? '1' : '0.35';
  const resize=()=>{c.width=window.innerWidth;c.height=window.innerHeight;};
  resize();
  window.addEventListener('resize',resize);
  _meshNodes=MESH_DEFS.map((d,i)=>({
    x:d.bx,y:d.by,r:d.r,
    vx:(Math.random()-.5)*.00015,vy:(Math.random()-.5)*.00015,
    color:MESH_PALETTES.sunny[i]||'rgba(14,165,233,.2)',
    targetColor:null,
  }));
  _meshDraw();
}

function updateMeshColors(cond,windDir,windSpeed){
  if(!_meshNodes.length)return;
  _meshWindAngle=((windDir??225)*Math.PI)/180;
  _meshWindSpeed=Math.min(windSpeed??5,80);
  const t=new Date().getHours()+new Date().getMinutes()/60;
  const override=meshTimeOverride(t);
  const palette=override||(MESH_PALETTES[cond]||MESH_PALETTES.cloudy);
  _meshNodes.forEach((n,i)=>{n.color=palette[i]||palette[0];});
}

function updateBgFromObs(obs){
  const rain=obs?.metric?.precipRate??0,temp=obs?.metric?.temp??15;
  const wind=obs?.metric?.windSpeed??0,hum=obs?.humidity??70;
  const uv=obs?.uv??0,solar=obs?.solarRadiation??obs?.metric?.solarRadiation??0;
  const hour=new Date().getHours();
  let cond='cloudy';
  if(hour<5||hour>22)             cond='night';
  else if(rain>5)                 cond='heavy_rain';
  else if(rain>0.3)               cond='rain';
  else if(wind>45)                cond='storm';
  else if(temp<0&&rain>0.05)      cond='snow';
  else if(hum>91&&wind<5&&uv<1)  cond='fog';
  else if(temp>27&&uv>3&&rain<.1) cond='hot';
  else{const s=Math.sin(Math.max(0,(hour-6)/12*Math.PI));cond=s>0.1&&solar/s/880<0.35?'cloudy':'sunny';}
  applyWeatherBg(cond);
  // Reduce mesh visibility in light mode so cards stay readable
  if(_meshCanvas) _meshCanvas.style.opacity = isDark() ? '1' : '0.35';
  updateMeshColors(cond,obs?.winddir,wind);
  setHeroCond(cond);
}


function generateWhyWeather(obs){
  const el=document.getElementById('why-text');
  const upd=document.getElementById('why-updated');
  if(!el)return;

  const m=obs.metric||{};
  const T=+(m.temp??15).toFixed(1), Td=+(m.dewpt??T-5).toFixed(1);
  const hum=obs.humidity??70, wind=+(m.windSpeed??0).toFixed(0);
  const pres=+(m.pressure??1013).toFixed(0), rain=+(m.precipRate??0).toFixed(1);
  const dep=+(T-Td).toFixed(1), hour=new Date().getHours();

  // Pressure trend (from rolling history, 3h window)
  const now3h=Date.now()-3*3600000;
  const old=_pressureHistory.find(x=>x.t>=now3h);
  const pTrend=old?+(pres-old.p).toFixed(1):0;

  // ── Blok 1: Tlačni sistem ─────────────────────────────
  let b1='';
  if(pres>1022&&Math.abs(pTrend)<0.8){
    b1=`Nad regijo vlada <em>anticiklon</em> – zračni tlak je visok (${pres} hPa) in stabilen. Zrak se v ozračju počasi poseda, kar preprečuje nastajanje oblakov in padavin.`;
  } else if(pTrend<-2.5){
    b1=`Zračni tlak <em>hitro pada</em> (${pTrend} hPa/3 h) – nezadržno se približuje hladna fronta. Pred nami je občutno poslabšanje vremena.`;
  } else if(pTrend<-1){
    b1=`Zračni tlak <em>postopno pada</em> (${pTrend} hPa/3 h) – z zahoda se počasi približuje ciklon. Vreme bo v prihodnjih urah vse bolj nestanovitno.`;
  } else if(pTrend>1.5){
    b1=`Zračni tlak <em>narašča</em> (+${pTrend} hPa/3 h) – vpliv anticiklona se krepi. Vreme se bo predvidoma izboljšalo.`;
  } else if(pres<1005){
    b1=`Nad regijo se zadržuje območje <em>nizkega zračnega tlaka</em> (${pres} hPa) – ciklon. Zrak se dviga in ohlaja, vlaga v njem pa kondenzira, kar povzroča nastanek oblakov in padavin.`;
  } else if(pres>1018){
    b1=`Visok zračni tlak (${pres} hPa) ohranja <em>stabilne vremenske razmere</em>. Ozračje je umirjeno, brez izrazitih vertikalnih gibanj.`;
  } else {
    b1=`Zračni tlak je v mejah povprečja (${pres} hPa) in brez izrazitih sprememb – prevladuje <em>prehodno stanje</em> med anticiklonom in ciklonom.`;
  }

  // ── Blok 2: Vlaga, zrak, dolinski efekt ──────────────
  let b2='';
  if(dep<1.5&&wind<5){
    b2=`Ker je rosišče le <em>${dep} °C</em> nižje od temperature zraka, veter pa je zelo šibek (${wind} km/h), se ozračje v dolini ne meša. Vlažen nočni zrak se zadržuje pri tleh – nastanek megle je zelo verjeten, še posebej ob reki Savinji.`;
  } else if(dep<3&&hum>80){
    b2=`Zrak je <em>nasičen z vlago</em> (${hum} %, rosišče ${Td} °C). Savinjska dolina zadržuje vlago z reke in travnikov – na hladnih površinah je pričakovati kondenzacijo.`;
  } else if(T<2&&dep<4){
    b2=`Pri temperaturi <em>${T} °C</em> in rosišču ${Td} °C so izpolnjeni pogoji za nastanek <em>slane ali ivja</em>. Mirno ozračje v dolini preprečuje mešanje temperaturnih plasti – nočno ohlajanje je zato izrazitejše kot na okoliških pobočjih.`;
  } else if(wind<5&&pres>1015&&(hour<9||hour>19)){
    b2=`Mirno ozračje (${wind} km/h) in dolinska <em>lega Rečice (366 m n. v.)</em> pogosto privedeta do nastanka <em>temperaturne inverzije</em>: hladnejši in težji zrak se steka v dno kotline, medtem ko je na višjeležečih pobočjih (npr. nad Šoštanjem ali nad Logarsko dolino) topleje.`;
  } else if(rain>0.5){
    b2=`Savinjska dolina je s treh strani obdana z gorami – vlažen zrak v <em>jugozahodnih tokovih</em> se ob pobočjih dviga in ohlaja, vlaga v njem pa kondenzira, kar prinaša tudi do dvakrat več padavin kot na štajerski ravnini.`;
  } else if(hum>70){
    b2=`Reka Savinja in mokrotni travniki prispevajo k <em>višji zračni vlažnosti</em> (${hum} %) v dolini glede na okoliška višjeležeča območja, kar je značilno za zaprte doline.`;
  } else if(wind>25){
    b2=`Močan veter (${wind} km/h) <em>intenzivno premeša</em> ozračje v dolini. Temperaturne razlike med dnom doline in okoliškimi pobočji so v takšnih razmerah minimalne.`;
  } else {
    b2=`Razmerje med temperaturo (${T} °C) in rosiščem (${Td} °C) kaže na <em>razmeroma suh zrak</em> za Savinjsko dolino – to je za omenjeno območje neznačilno.`;
  }

  // ── Blok 3: Napoved za preostanek dneva ──────────────
  let b3='';
  const isAM=hour<13, isPM=hour>=13&&hour<20, isEvening=hour>=20;
  if(dep<2&&wind<5&&pres>1015&&isAM){
    b3=`Čez dan bo <em>sončna toplota postopno razkrojila</em> vlažno zračno plast – megla se navadno dvigne med 9. in 11. uro. Popoldne bo sončno in prijetno.`;
  } else if(pTrend<-2&&rain<0.5){
    b3=`V prihodnjih urah pričakujemo <em>poslabšanje vremena</em> – oblačnost se bo gostila, pojavile se bodo padavine, lokalno pa so možni tudi močnejši sunki vetra.`;
  } else if(pres>1020&&hum<65&&wind<15&&rain<0.1){
    b3=`<em>Stabilne vremenske razmere</em> se bodo nadaljevale do večera. Pred nami je idealen dan za aktivnosti na prostem.`;
  } else if(isEvening&&T<10&&wind<5){
    b3=`Noč bo <em>hladna in mirna</em> – to so idealni pogoji za nastanek <em>jutranje temperaturne inverzije</em>. Na vegetaciji lahko pričakujete ${T-3>0?'roso':'slano'}.`;
  } else if(rain>0.5){
    b3=`Padavine bodo <em>postopno slabele in ponehavale</em> – za natančnejši čas razjasnitve spremljajte radarske slike padavin.`;
  } else if(isPM&&T>22&&hum>60){
    b3=`Popoldne je v Savinjski dolini <em>možna termična konvekcija</em> – nad okoliškimi pobočji se bodo razvile lokalne popoldanske plohe ali nevihte.`;
  } else {
    b3=`Vreme se v prihodnjih urah ne bo bistveno spremenilo.`;
  }

  // Combine into flowing text
  el.innerHTML=b1+' '+b2+' '+b3;
  if(upd)upd.textContent='posod. '+new Date().toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'});
}


const _pressureHistory = [];  // rolling 6h of pressure readings

function analyzeLocalMicroclimate(obs){
  const m=obs.metric||{};
  const T=m.temp??15, Td=m.dewpt??T-5, hum=obs.humidity??70;
  const wind=m.windSpeed??0, pres=m.pressure??1013, rain=m.precipRate??0;
  const hour=new Date().getHours();
  const dep=+(T-Td).toFixed(1);  // rosišče depression

  // Store pressure history (max 12 entries = ~1h at 5min refresh)
  _pressureHistory.push({t:Date.now(),p:pres});
  if(_pressureHistory.length>72)_pressureHistory.shift();

  // Pressure trend over last 3h
  const now3h=Date.now()-3*3600000;
  const old=_pressureHistory.find(x=>x.t>=now3h);
  const pTrend=old?+(pres-old.p).toFixed(1):0;

  const conditions=[];

  // ── 1. Megleni kotel
  if(dep<2&&wind<5&&hum>87){
    const prob=dep<0.8?'zelo verjetna':dep<1.5?'verjetna':'možna';
    conditions.push({
      type:'fog',cls:'mc-item-info',icon:'🌫',name:'Megleni kotel',
      text:`Rosišče je le ${dep} °C pod temperaturo zraka, hitrost vetra pa znaša ${wind.toFixed(0)} km/h. Vlažen zrak se zadržuje v Savinjski dolini – nastanek megle je ${prob}, še posebej ob reki in v nižjih legah.`,
      data:[`T ${T.toFixed(1)}°C`,`Td ${Td.toFixed(1)}°C`,`Dep. ${dep}°C`,`Vlaga ${hum}%`,`V ${wind.toFixed(0)} km/h`],
    });
  }

  // ── 2. Temperaturna inverzija
  if(wind<6&&pres>1018&&rain<0.1&&(hour<10||hour>19)){
    conditions.push({
      type:'inversion',cls:'mc-item-info',icon:'🔄',name:'Temperaturna inverzija',
      text:`Visok zračni tlak (${pres.toFixed(0)} hPa) in mirno ozračje (${wind.toFixed(0)} km/h) ustvarjata idealne pogoje za nastanek temperaturne inverzije. Rečica ob Savinji (366 m n. v.) je v takšnih razmerah pogosto za 2–5 °C hladnejša od višjih leg v okolici Šoštanja ali Velenja.`,
      data:[`Tlak ${pres.toFixed(0)} hPa`,`V ${wind.toFixed(0)} km/h`,`Ura ${hour}:00`],
    });
  }

  // ── 3. Prehod fronte / nevihtni rob
  if(pTrend<-1.5){
    const speed=pTrend<-3?'hitro':'počasi';
    conditions.push({
      type:'front',cls:'mc-item-alert',icon:'⛈',name:'Prihaja fronta',
      text:`Zračni tlak je v zadnjih treh urah ${speed} padel za ${Math.abs(pTrend).toFixed(1)} hPa. Savinjska dolina je ob prehodih hladnih front pogosto tarča močnejših neviht, zato je možna povečana nevarnost toče in močnih vetrovnih sunkov.`,
      data:[`Trend ${pTrend>0?'+':''}${pTrend} hPa/3h`,`Tlak ${pres.toFixed(0)} hPa`],
    });
  } else if(pTrend>1.5){
    conditions.push({
      type:'clearing',cls:'mc-item-good',icon:'🌤',name:'Vremenska razjasnitev',
      text:`Zračni tlak je v zadnjih treh urah narasel za ${pTrend.toFixed(1)} hPa – vpliv anticiklona se krepi. Vreme se bo predvidoma stabiliziralo in izboljšalo.`,
      data:[`Trend +${pTrend} hPa/3h`,`Tlak ${pres.toFixed(0)} hPa`],
    });
  }

  // ── 4. Anticiklonalno stabilno vreme
  if(pres>1022&&wind<12&&hum<60&&rain<0.1&&Math.abs(pTrend)<0.5){
    conditions.push({
      type:'anticyclone',cls:'mc-item-good',icon:'☀️',name:'Anticiklonalno stabilno vreme',
      text:`Zračni tlak znaša ${pres.toFixed(0)} hPa, vlaga je ${hum} %, ozračje pa je mirno – tipične anticiklonalne razmere. Savinjska dolina ima v takšnem vremenu pogosto jasnejše vreme kot višje ležeči predeli, ki jih nerazpujena oblačnost lahko zavije v meglo.`,
      data:[`Tlak ${pres.toFixed(0)} hPa`,`Vlaga ${hum}%`,`V ${wind.toFixed(0)} km/h`],
    });
  }

  // ── 5. Rosa / slana / poledica
  if(T<4&&dep<3){
    const risk=T<-1?{n:'Nevarnost poledice',t:`Temperatura ${T.toFixed(1)} °C ob visoki zračni vlagi prinaša tveganje za nastanek poledice ali slane. Pozor na cestah in mostovih v bližini Savinje!`,c:'mc-item-alert',i:'🧊'}:
               T<1?{n:'Možna slana ali ivje',t:`Temperatura je blizu rosišča, ki se giblje okoli 0 °C. Na travnikih in rastlinah se lahko pojavi slana – izjemna priložnost za makro fotografijo rose in ledenih kristalov.`,c:'mc-item-warn',i:'🌨'}:
                   {n:'Rosa bo padla',t:`Temperatura zraka (${T.toFixed(1)} °C) je blizu rosišča (${Td.toFixed(1)} °C). Pred sončnim vzhodom bodo rastline prekrile rosne kapljice – idealni pogoji za makro fotografijo.`,c:'mc-item-info',i:'💧'};
    conditions.push({type:'dew',cls:risk.c,icon:risk.i,name:risk.n,text:risk.t,
      data:[`T ${T.toFixed(1)}°C`,`Td ${Td.toFixed(1)}°C`,`Dep. ${dep}°C`]});
  }

  // ── 6. Vlažen dolinski zrak (ko ni drugega)
  if(hum>78&&dep<6&&!conditions.find(c=>c.type==='fog')){
    conditions.push({
      type:'moist',cls:'mc-item-info',icon:'💦',name:'Vlažen dolinski zrak',
      text:`Zračna vlaga je visoka (${hum} %), kar je značilno za dno Savinjske doline. Reka in mokrotni travniki stalno vzdržujejo visoko vlažnost, ki je na okoliških pobočjih običajno ne zaznamo.`,
      data:[`Vlaga ${hum}%`,`Td ${Td.toFixed(1)}°C`,`Dep. ${dep}°C`],
    });
  }

  // ── 7. Mrzli dolinski žep (hladnejše od okolice)
  if(wind<4&&rain<0.1&&T<10&&pres>1015){
    conditions.push({
      type:'cold_pool',cls:'mc-item-info',icon:'🌡',name:'Mrzli dolinski žep',
      text:`Zaradi mirnega ozračja in specifične dolinske lege (366 m n. v.) se hladen zrak steka in zbira na dnu doline. Okoliška pobočja in višje ležeči kraji (smeri proti Šoštanju ali Logarski dolini) so v takšnih razmerah praviloma za 2–4 °C toplejši.`,
      data:[`T ${T.toFixed(1)}°C`,`V ${wind.toFixed(0)} km/h`,`Tlak ${pres.toFixed(0)} hPa`],
    });
  }

  // ── 8. Orografske padavine
  if(rain>1&&pres<1010){
    conditions.push({
      type:'orographic',cls:'mc-item-warn',icon:'🌧',name:'Orografske padavine',
      text:`Območje nizkega zračnega tlaka prinaša padavine. Ker je Savinjska dolina izrazito zaprta, vlažni jugozahodni vetrovi trkajo ob gorske pregrade, se ob njih dvigajo in kondenzirajo, to pa ob zahodnih pobočjih prinaša obilne padavine (tudi do dvakrat več kot na štajerski ravnini).`,
      data:[`Dež ${rain.toFixed(1)} mm/h`,`Tlak ${pres.toFixed(0)} hPa`],
    });
  }

  // Render
  const list=document.getElementById('mc-list');
  const upd=document.getElementById('mc-updated');
  if(upd)upd.textContent=new Date().toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'});
  if(!list)return;

  if(!conditions.length){
    list.innerHTML='<div class="mc-none">✓ Razmere so stabilne in v mejah normale – brez posebnosti ali izrazitih mikroklimatskih pojavov.</div>';
    return;
  }

  list.innerHTML='';
  conditions.slice(0,4).forEach(c=>{
    const div=document.createElement('div');
    div.className='mc-item '+c.cls;
    div.innerHTML=
      '<div class="mc-head"><span class="mc-icon">'+c.icon+'</span><span class="mc-name">'+c.name+'</span></div>'+
      '<div class="mc-text">'+c.text+'</div>'+
      '<div class="mc-data">'+c.data.map(d=>'<span class="mc-datum">'+d+'</span>').join('')+'</div>';
    list.appendChild(div);
  });
}


// ══════════════════════════════════════════════════════════
let _mcfForecast=null,_mcfTs=0;
function _mcfDirIn(deg,min,max){
  if(!Number.isFinite(deg))return false;
  const d=((deg%360)+360)%360;
  return min<=max?d>=min&&d<=max:d>=min||d<=max;
}
function _mcfAvg(arr){const a=arr.filter(v=>Number.isFinite(v));return a.length?a.reduce((x,y)=>x+y,0)/a.length:null;}
function _mcfSliceHours(h,from,to){
  const now=new Date(),a=new Date(now.getTime()+from*3600000),b=new Date(now.getTime()+to*3600000);
  return (h.time||[]).map((t,i)=>({t:new Date(t),i})).filter(x=>x.t>=a&&x.t<=b).map(x=>x.i);
}
function _mcfUpcomingNight(h){
  const now=new Date(),end=new Date(now.getTime()+30*3600000);
  return (h.time||[]).map((t,i)=>({d:new Date(t),i})).filter(x=>{
    const hr=x.d.getHours();
    return x.d>=now&&x.d<=end&&(hr>=20||hr<=8);
  }).map(x=>x.i);
}
function _mcfPressureTrend(){
  const presNow=_pressureHistory.at(-1)?.p;
  const old=_pressureHistory.find(x=>x.t>=Date.now()-3*3600000)?.p;
  return presNow!=null&&old!=null?+(presNow-old).toFixed(1):0;
}
async function fetchDailyMicroclimateFingerprint(obs){
  const el=document.getElementById('mcf-content');if(!el||!obs)return;
  try{
    if(!_mcfForecast||Date.now()-_mcfTs>30*60*1000){
      const url='https://api.open-meteo.com/v1/forecast?latitude='+LAT+'&longitude='+LON
        +'&hourly=temperature_2m,dew_point_2m,relative_humidity_2m,wind_speed_10m,wind_direction_10m,wind_gusts_10m,cloud_cover,precipitation,weather_code,cape'
        +'&timezone=Europe%2FLjubljana&forecast_days=2';
      const res=await fetch(url);if(!res.ok)throw new Error('HTTP '+res.status);
      _mcfForecast=(await res.json()).hourly;_mcfTs=Date.now();
    }
    renderDailyMicroclimateFingerprint(obs,_mcfForecast);
  }catch(e){
    console.warn('Microclimate fingerprint:',e);
    el.innerHTML='<div style="color:var(--muted);font-size:.78rem">Mikroklimatski podpis trenutno ni na voljo.</div>';
  }
}
function renderDailyMicroclimateFingerprint(obs,h){
  const el=document.getElementById('mcf-content');if(!el||!h?.time?.length)return;
  const upd=document.getElementById('mcf-updated');
  const m=obs.metric||{},T=m.temp??15,Td=m.dewpt??T-5,hum=obs.humidity??70,wind=m.windSpeed??0,dir=obs.winddir;
  const dep=T-Td,pTrend=_mcfPressureTrend();
  const next6=_mcfSliceHours(h,0,6),next12=_mcfSliceHours(h,0,12),night=_mcfUpcomingNight(h);
  const pick=(name,idxs)=>idxs.map(i=>h[name]?.[i]).filter(v=>Number.isFinite(v));
  const nightTemps=pick('temperature_2m',night),nightWinds=pick('wind_speed_10m',night),nightCloud=pick('cloud_cover',night),nightRain=pick('precipitation',night);
  const dawn=night.filter(i=>{const hr=new Date(h.time[i]).getHours();return hr>=4&&hr<=8;});
  const dawnDep=dawn.map(i=>(h.temperature_2m?.[i]??99)-(h.dew_point_2m?.[i]??-99));
  const dawnWind=pick('wind_speed_10m',dawn),dawnRh=pick('relative_humidity_2m',dawn);
  const gustMax=Math.max(0,...pick('wind_gusts_10m',next12));
  const capeMax=Math.max(0,...pick('cape',next12));
  const rain12=pick('precipitation',next12).reduce((a,b)=>a+b,0);
  const wmoStorm=next12.some(i=>[95,96,99].includes(h.weather_code?.[i]));
  const fcDir=_mcfAvg(pick('wind_direction_10m',next6));
  const fcWind=_mcfAvg(pick('wind_speed_10m',next6))??0;
  const signals=[];
  const add=(type,icon,name,text,score=0)=>signals.push({type,icon,name,text,score});
  const coolingDrop=nightTemps.length?T-Math.min(...nightTemps):0;
  const calmNight=nightWinds.length&&Math.max(...nightWinds)<7&&((_mcfAvg(nightCloud)??100)<55)&&nightRain.reduce((a,b)=>a+b,0)<0.5;
  if(coolingDrop>=5&&calmNight)add('info','🌡','Nočno ohlajanje doline',`Mirno ozračje in majhna oblačnost: dno doline se lahko ponoči ohladi za približno ${coolingDrop.toFixed(1)} °C. Rečica bo predvidoma hladnejša od okoliških višjeležečih pobočij.`,coolingDrop);
  const fogSetup=(dep<3&&hum>82&&wind<8)||((Math.min(...dawnDep,99)<2)&&((_mcfAvg(dawnWind)??99)<6)&&((_mcfAvg(dawnRh)??0)>86));
  if(fogSetup)add('warn','🌫','Pogoji za meglo',`Rosišče je zelo blizu temperature zraka, zračna vlaga znaša ${Math.round(hum)} %, hitrost vetra pa le ${Math.round(wind)} km/h. Ob reki Savinji je zato močno povečana verjetnost nastanka megle ali zadrževanja vlage neposredno nad tlemi.`,80);
  const southChannel=(_mcfDirIn(dir,120,220)&&wind>=10)||(_mcfDirIn(fcDir,120,220)&&fcWind>=10)||(gustMax>=35&&_mcfDirIn(fcDir,120,240));
  if(southChannel)add(gustMax>=50?'alert':'info','💨','Aktiven južni dolinski tok',`Zračni tok južnih do jugovzhodnih smeri se kanalizira po Savinjski dolini. Pričakovani sunki vetra do ${Math.round(gustMax||wind)} km/h lahko lokalno močno prevetrijo in premešajo ozračje v dolini.`,gustMax);
  const stormOutflow=wmoStorm||capeMax>=900&&gustMax>=45||pTrend<-1.5&&capeMax>=500;
  if(stormOutflow)add(gustMax>=70||capeMax>=1500?'alert':'warn','⛈','Nevihtni iztok iz Savinjske doline',`Stopnja nestabilnosti ozračja (CAPE znaša ${Math.round(capeMax)} J/kg) in pričakovani sunki vetra do ${Math.round(gustMax)} km/h nakazujejo možnost močnega nevihtnega piša (iztoka hladnega zraka), ki bo prehodno zapihal po dolini.`,capeMax/20+gustMax);
  if(rain12>=6&&_mcfDirIn(fcDir,180,260))add('warn','🌧','Orografsko ojačanje padavin',`Vlažen južni do jugozahodni zračni tok se bo ob reliefni pregradi Savinjskih Alp prisilno dvigal, kar bo orografsko okrepilo padavine – meteorološki modeli v 12 urah predvidevajo kar ${rain12.toFixed(1)} mm dežja.`,rain12*5);
  if(!signals.length)add('good','✓','Miren dolinski dan',`Brez izrazitih lokalnih posebnosti: veter, zračna vlaga in splošna vremenska napoved ne kažejo na morebitna mikroklimatska odstopanja ali anomalije v dolini.`,1);
  signals.sort((a,b)=>(b.type==='alert')-(a.type==='alert')||b.score-a.score);
  const main=signals[0];
  const kpis=[['Dep.',dep.toFixed(1)+'°C'],['Nočni padec',coolingDrop>0?coolingDrop.toFixed(1)+'°C':'—'],['Sunki 12h',Math.round(gustMax)+' km/h'],['CAPE',Math.round(capeMax)]];
  el.innerHTML='<div><div class="mcf-main"><div class="mcf-icon">'+main.icon+'</div><div><div class="mcf-title">'+main.name+'</div><div class="mcf-text">'+main.text+'</div></div></div><div class="mcf-kpis">'+kpis.map(k=>'<div class="mcf-kpi"><b>'+k[1]+'</b><span>'+k[0]+'</span></div>').join('')+'</div></div><div class="mcf-signals">'+signals.slice(0,4).map(s=>'<div class="mcf-signal '+(s.type==='alert'?'alert':s.type==='warn'?'warn':s.type==='good'?'good':'')+'"><div class="mcf-sig-name"><span>'+s.icon+'</span>'+s.name+'</div><div class="mcf-sig-text">'+s.text+'</div></div>').join('')+'</div>';
  if(upd)upd.textContent='posod. '+new Date().toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'});
}

let _artCtx=null,_artAnim=null,_artCondition='clear',_artParticles=[];
function resizeWeatherArtCanvas(){
  const c=document.getElementById('weather-art-canvas');if(!c)return false;
  const rect=c.getBoundingClientRect();
  const dpr=Math.min(2,window.devicePixelRatio||1);
  const w=Math.max(260,Math.round(rect.width*dpr));
  const h=Math.max(220,Math.round(rect.height*dpr));
  if(c.width!==w||c.height!==h){
    c.width=w;c.height=h;
    return true;
  }
  return false;
}
function initWeatherArt(){
  const c=document.getElementById('weather-art-canvas');if(!c)return;
  resizeWeatherArtCanvas();
  _artCtx=c.getContext('2d');
  if(_artAnim)cancelAnimationFrame(_artAnim);
  _artParticles=[];
  artFrame();
}
function setWeatherArt(obs){
  const rain=obs?.metric?.precipRate??0;
  const temp=obs?.metric?.temp??15;
  const wind=obs?.metric?.windSpeed??0;
  const hum=obs?.humidity??70;
  const uv=obs?.uv??0;
  const solar=obs?.metric?.solarRadiation??obs?.solarRadiation??0;
  const hour=new Date().getHours();

  let cond='sunny';
  if(hour<5||hour>22)              cond='night';
  else if(rain>5)                  cond='heavy_rain';
  else if(rain>0.3)                cond='rain';
  else if(wind>45)                 cond='storm';
  else if(temp<0&&rain>0.05)       cond='snow';
  else if(hum>91&&wind<5&&uv<1)    cond='fog';
  else if(temp>27&&uv>3&&rain<0.1) cond='hot';
  else{
    // Use solar radiation to estimate cloud cover
    const sinH=Math.sin(Math.max(0,(hour-6)/12*Math.PI));
    const expSolar=sinH*880;
    const ratio=expSolar>80?solar/expSolar:1;
    if(ratio<0.35) cond='cloudy';
    else           cond='sunny';
  }

  _artCondition=cond;
  const labels={sunny:'Sončno ☀️',hot:'Vroče 🌡',cloudy:'Oblačno ☁️',fog:'Megla 🌫',rain:'Dež 🌧',heavy_rain:'Plohe 🌧',snow:'Sneg ❄️',storm:'Nevihta ⛈',night:'Noč 🌙'};
  const lbl=document.getElementById('art-label');
  if(lbl)lbl.textContent=labels[cond]||'';
  initWeatherArt();
}
function artFrame(){
  const ctx=_artCtx;if(!ctx)return;
  const c=document.getElementById('weather-art-canvas');
  if(resizeWeatherArtCanvas())_artParticles=[];
  const W=c.width,H=c.height;const dark=isDark();
  ctx.clearRect(0,0,W,H);
  const cond=_artCondition;
  // Background gradient
  const bg=ctx.createLinearGradient(0,0,0,H);
  const bgs={sunny:['#fff7ed','#fef3c7'],hot:['#fef3c7','#fed7aa'],cloudy:['#f1f5f9','#e2e8f0'],fog:['#f8fafc','#e2e8f0'],rain:['#eff6ff','#dbeafe'],heavy_rain:['#dbeafe','#bfdbfe'],snow:['#f0f9ff','#e0f2fe'],storm:['#1e1b4b','#312e81'],night:['#020617','#0f172a']};
  const dc={sunny:['#1e3a5f','#0f2a44'],hot:['#1c1917','#0c0a09'],cloudy:['#1e293b','#0f172a'],fog:['#1e293b','#0f172a'],rain:['#0f172a','#0c1829'],heavy_rain:['#0a0f1c','#060b14'],snow:['#0f172a','#0c1829'],storm:['#020617','#000000'],night:['#020617','#000000']};
  const pair=dark?(dc[cond]||dc.cloudy):(bgs[cond]||bgs.cloudy);
  bg.addColorStop(0,pair[0]);bg.addColorStop(1,pair[1]);
  ctx.fillStyle=bg;ctx.fillRect(0,0,W,H);
  const t=Date.now()/1000;
  if(cond==='sunny'||cond==='hot'){
    // Pulsing sun + rotating rays
    const cx=W*0.15,cy=H/2,r=22+Math.sin(t)*3;
    const g=ctx.createRadialGradient(cx,cy,0,cx,cy,r*3);
    g.addColorStop(0,cond==='hot'?'rgba(251,146,60,.9)':'rgba(251,191,36,.9)');
    g.addColorStop(1,'rgba(251,191,36,0)');
    ctx.beginPath();ctx.arc(cx,cy,r*3,0,Math.PI*2);ctx.fillStyle=g;ctx.fill();
    ctx.beginPath();ctx.arc(cx,cy,r,0,Math.PI*2);ctx.fillStyle=cond==='hot'?'#fb923c':'#fbbf24';ctx.fill();
    for(let i=0;i<12;i++){const a=t*0.3+i*Math.PI/6;const x1=cx+Math.cos(a)*(r+6),y1=cy+Math.sin(a)*(r+6),x2=cx+Math.cos(a)*(r+16+Math.sin(t*2+i)*3),y2=cy+Math.sin(a)*(r+16+Math.sin(t*2+i)*3);ctx.beginPath();ctx.moveTo(x1,y1);ctx.lineTo(x2,y2);ctx.strokeStyle='rgba(251,191,36,0.6)';ctx.lineWidth=2;ctx.stroke();}
    // Floating light particles
    if(_artParticles.length<25)_artParticles.push({x:Math.random()*W,y:Math.random()*H,r:1+Math.random()*2,vx:(Math.random()-0.5)*0.3,vy:-0.2-Math.random()*0.3,a:0.4+Math.random()*0.4});
    _artParticles.forEach(p=>{p.x+=p.vx;p.y+=p.vy;p.a-=0.003;ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fillStyle=`rgba(251,191,36,${p.a})`;ctx.fill();});
    _artParticles=_artParticles.filter(p=>p.a>0);
  } else if(cond==='rain'||cond==='heavy_rain'){
    const count=cond==='heavy_rain'?3:1.2;
    while(_artParticles.length<60*count)_artParticles.push({x:Math.random()*W,y:Math.random()*H,l:6+Math.random()*12,v:4+Math.random()*4,a:0.3+Math.random()*0.5,w:0.8+Math.random()});
    _artParticles.forEach(p=>{p.y+=p.v;p.x+=0.8;if(p.y>H){p.y=-p.l;p.x=Math.random()*W;}ctx.beginPath();ctx.moveTo(p.x,p.y);ctx.lineTo(p.x+p.l*0.2,p.y+p.l);ctx.strokeStyle=`rgba(96,165,250,${p.a})`;ctx.lineWidth=p.w;ctx.stroke();});
  } else if(cond==='snow'){
    while(_artParticles.length<50)_artParticles.push({x:Math.random()*W,y:Math.random()*H,r:1.5+Math.random()*3,v:0.4+Math.random()*0.8,vx:Math.sin(Math.random()*Math.PI*2)*0.3,a:0.5+Math.random()*0.4,phase:Math.random()*Math.PI*2});
    _artParticles.forEach(p=>{p.y+=p.v;p.x+=Math.sin(t*0.5+p.phase)*0.4;if(p.y>H){p.y=-p.r;p.x=Math.random()*W;}ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fillStyle=`rgba(224,242,254,${p.a})`;ctx.fill();});
  } else if(cond==='storm'){
    if(Math.random()<0.015){
      // Lightning bolt
      const sx=W*0.2+Math.random()*W*0.6,sy=0;
      ctx.beginPath();ctx.moveTo(sx,sy);
      let cx=sx,cy=sy;
      for(let i=0;i<6;i++){cx+=(Math.random()-0.5)*40;cy+=H/6;ctx.lineTo(cx,cy);}
      ctx.strokeStyle='rgba(253,224,71,0.9)';ctx.lineWidth=2;ctx.stroke();
      ctx.shadowColor='#fde047';ctx.shadowBlur=20;ctx.stroke();ctx.shadowBlur=0;
    }
    // Rain in storm
    while(_artParticles.length<80)_artParticles.push({x:Math.random()*W,y:Math.random()*H,l:10,v:7,a:0.4});
    _artParticles.forEach(p=>{p.y+=p.v;p.x+=2;if(p.y>H){p.y=-10;p.x=Math.random()*W;}ctx.beginPath();ctx.moveTo(p.x,p.y);ctx.lineTo(p.x+2,p.y+p.l);ctx.strokeStyle=`rgba(148,163,184,${p.a})`;ctx.lineWidth=1;ctx.stroke();});
  } else if(cond==='fog'){
    // Drifting fog layers
    for(let i=0;i<3;i++){const g2=ctx.createLinearGradient(0,0,W,0);const offset=(t*0.03*(i+1))%1;g2.addColorStop((offset)%1,`rgba(148,163,184,0)`);g2.addColorStop((offset+0.3)%1,`rgba(148,163,184,${0.06*(i+1)})`);g2.addColorStop((offset+0.6)%1,`rgba(148,163,184,${0.03*(i+1)})`);g2.addColorStop((offset+1)%1,`rgba(148,163,184,0)`);ctx.fillStyle=g2;ctx.fillRect(0,H/3*i,W,H/3);}
  } else if(cond==='night'){
    // Stars
    if(_artParticles.length===0){for(let i=0;i<80;i++)_artParticles.push({x:Math.random()*W,y:Math.random()*H,r:Math.random()*1.5,phase:Math.random()*Math.PI*2,twinkle:0.3+Math.random()*0.4});}
    _artParticles.forEach(p=>{const a=p.twinkle+Math.sin(t*2+p.phase)*0.15;ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fillStyle=`rgba(226,232,240,${a})`;ctx.fill();});
    // Moon
    const mx=W*0.8,my=H*0.3;const mg=ctx.createRadialGradient(mx,my,0,mx,my,28);mg.addColorStop(0,'rgba(241,245,249,0.9)');mg.addColorStop(1,'rgba(241,245,249,0)');ctx.beginPath();ctx.arc(mx,my,28,0,Math.PI*2);ctx.fillStyle=mg;ctx.fill();
    ctx.beginPath();ctx.arc(mx,my,16,0,Math.PI*2);ctx.fillStyle='rgba(241,245,249,0.85)';ctx.fill();
  } else { // cloudy
    for(let i=0;i<2;i++){const blobX=(t*12*(i+1)+i*W/2)%W,blobY=H*0.3+i*H*0.25;const bg2=ctx.createRadialGradient(blobX,blobY,0,blobX,blobY,80);bg2.addColorStop(0,dark?'rgba(51,65,85,0.4)':'rgba(148,163,184,0.25)');bg2.addColorStop(1,'rgba(148,163,184,0)');ctx.fillStyle=bg2;ctx.beginPath();ctx.ellipse(blobX,blobY,90,50,0,0,Math.PI*2);ctx.fill();}
  }
  _artAnim=requestAnimationFrame(artFrame);
}

// ══════════════════════════════════════════════════════════
// ── Starfield — jasna noč ───────────────────────────────────
// ══════════════════════════════════════════════════════════
let _sfCanvas=null,_sfCtx=null,_sfAnim=null,_sfActive=false,_sfPrev=0;
let _sfStars=[],_sfShooting=[],_sfNextShoot=0;

function _sfGenStars(W,H){
  _sfStars=[];
  // Tiny background stars
  for(let i=0;i<320;i++){
    const warm=Math.random()<0.08,cool=Math.random()<0.12;
    _sfStars.push({x:Math.random()*W,y:Math.random()*H*0.92,
      r:0.25+Math.random()*0.55,
      a:0.2+Math.random()*0.45,tw:0.06+Math.random()*0.16,
      fr:0.3+Math.random()*1.8,ph:Math.random()*Math.PI*2,
      c:warm?[255,225,180]:cool?[180,210,255]:[225,235,255]});
  }
  // Medium stars
  for(let i=0;i<95;i++){
    const warm=Math.random()<0.1,cool=Math.random()<0.18;
    _sfStars.push({x:Math.random()*W,y:Math.random()*H*0.88,
      r:0.65+Math.random()*0.85,
      a:0.45+Math.random()*0.35,tw:0.1+Math.random()*0.28,
      fr:0.15+Math.random()*0.85,ph:Math.random()*Math.PI*2,
      c:warm?[255,215,160]:cool?[160,200,255]:[238,245,255]});
  }
  // Bright stars with glow halo
  for(let i=0;i<18;i++){
    const cool=Math.random()<0.3;
    _sfStars.push({x:Math.random()*W,y:Math.random()*H*0.82,
      r:1.5+Math.random()*1.3,
      a:0.78+Math.random()*0.18,tw:0.05+Math.random()*0.1,
      fr:0.08+Math.random()*0.35,ph:Math.random()*Math.PI*2,
      c:cool?[140,185,255]:[248,253,255],glow:true});
  }
}

function _sfMoon(ctx,W,H){
  const mx=W*0.81,my=H*0.12,mr=W<500?16:22;
  // Atmospheric halo
  const h=ctx.createRadialGradient(mx,my,mr,mx,my,mr*5);
  h.addColorStop(0,'rgba(210,228,255,0.13)');h.addColorStop(1,'rgba(210,228,255,0)');
  ctx.beginPath();ctx.arc(mx,my,mr*5,0,Math.PI*2);ctx.fillStyle=h;ctx.fill();
  // Disc
  ctx.beginPath();ctx.arc(mx,my,mr,0,Math.PI*2);
  ctx.fillStyle='rgba(240,248,255,0.87)';ctx.fill();
  // Subtle limb darkening
  const ld=ctx.createRadialGradient(mx-mr*0.25,my-mr*0.15,mr*0.1,mx,my,mr);
  ld.addColorStop(0,'rgba(255,255,255,0)');ld.addColorStop(1,'rgba(8,14,38,0.18)');
  ctx.beginPath();ctx.arc(mx,my,mr,0,Math.PI*2);ctx.fillStyle=ld;ctx.fill();
}

function _sfFrame(ts){
  if(_animPaused){_sfAnim=null;return;}
  if(!_sfActive){_sfAnim=null;return;}
  const dt=_sfPrev?(ts-_sfPrev)/1000:0.016;_sfPrev=ts;
  const c=_sfCanvas,ctx=_sfCtx,W=c.width,H=c.height,t=ts/1000;
  ctx.clearRect(0,0,W,H);

  // Deep sky gradient
  const sky=ctx.createLinearGradient(0,0,0,H);
  sky.addColorStop(0,'#000005');sky.addColorStop(0.35,'#010910');
  sky.addColorStop(0.7,'#030e1e');sky.addColorStop(1,'#071428');
  ctx.fillStyle=sky;ctx.fillRect(0,0,W,H);

  // Milky Way — soft diagonal band
  ctx.save();ctx.translate(W*0.42,H*0.46);ctx.rotate(0.55);
  const mw=ctx.createLinearGradient(-W*0.9,0,W*0.9,0);
  mw.addColorStop(0,'rgba(140,165,220,0)');mw.addColorStop(0.3,'rgba(140,165,220,0)');
  mw.addColorStop(0.42,'rgba(148,173,228,0.044)');mw.addColorStop(0.5,'rgba(162,188,238,0.072)');
  mw.addColorStop(0.58,'rgba(148,173,228,0.044)');mw.addColorStop(0.7,'rgba(140,165,220,0)');
  mw.addColorStop(1,'rgba(140,165,220,0)');
  ctx.fillStyle=mw;ctx.fillRect(-W,-H*0.75,W*2,H*1.5);
  // Secondary wider band
  const mw2=ctx.createLinearGradient(-W*0.9,0,W*0.9,0);
  mw2.addColorStop(0,'rgba(130,155,210,0)');mw2.addColorStop(0.25,'rgba(130,155,210,0)');
  mw2.addColorStop(0.38,'rgba(138,163,218,0.022)');mw2.addColorStop(0.5,'rgba(145,170,225,0.036)');
  mw2.addColorStop(0.62,'rgba(138,163,218,0.022)');mw2.addColorStop(0.75,'rgba(130,155,210,0)');
  mw2.addColorStop(1,'rgba(130,155,210,0)');
  ctx.fillStyle=mw2;ctx.fillRect(-W,-H,W*2,H*2);
  ctx.restore();

  // Stars
  for(const s of _sfStars){
    const a=Math.min(1,Math.max(0,s.a+Math.sin(t*s.fr+s.ph)*s.tw));
    const [r,g,b]=s.c;
    if(s.glow){
      const gl=ctx.createRadialGradient(s.x,s.y,0,s.x,s.y,s.r*5.5);
      gl.addColorStop(0,`rgba(${r},${g},${b},${a.toFixed(2)})`);
      gl.addColorStop(0.3,`rgba(${r},${g},${b},${(a*0.22).toFixed(2)})`);
      gl.addColorStop(1,'rgba(0,0,0,0)');
      ctx.beginPath();ctx.arc(s.x,s.y,s.r*5.5,0,Math.PI*2);ctx.fillStyle=gl;ctx.fill();
    }
    ctx.beginPath();ctx.arc(s.x,s.y,s.r,0,Math.PI*2);
    ctx.fillStyle=`rgba(${r},${g},${b},${a.toFixed(2)})`;ctx.fill();
  }

  // Moon
  _sfMoon(ctx,W,H);

  // Shooting stars
  if(ts>_sfNextShoot){
    _sfNextShoot=ts+(28000+Math.random()*85000);
    const sx=W*(0.12+Math.random()*0.6),sy=H*(0.03+Math.random()*0.2);
    _sfShooting.push({x:sx,y:sy,dx:W*(0.1+Math.random()*0.08),dy:H*(0.04+Math.random()*0.04),dur:0.45+Math.random()*0.35,t:0});
  }
  _sfShooting=_sfShooting.filter(s=>{
    s.t+=dt;if(s.t>=s.dur)return false;
    const p=s.t/s.dur,al=p<0.2?p/0.2:Math.max(0,1-(p-0.2)/0.8);
    const x1=s.x+s.dx*p,y1=s.y+s.dy*p,x0=x1-s.dx*0.18,y0=y1-s.dy*0.18;
    const sg=ctx.createLinearGradient(x0,y0,x1,y1);
    sg.addColorStop(0,'rgba(255,255,255,0)');
    sg.addColorStop(1,`rgba(255,255,255,${(al*0.9).toFixed(2)})`);
    ctx.beginPath();ctx.moveTo(x0,y0);ctx.lineTo(x1,y1);
    ctx.strokeStyle=sg;ctx.lineWidth=1.5;ctx.stroke();
    return true;
  });

  _sfAnim=requestAnimationFrame(_sfFrame);
}

function showStarfield(show){
  if(!_sfCanvas){
    _sfCanvas=document.getElementById('starfield-canvas');
    if(!_sfCanvas)return;
    _sfCtx=_sfCanvas.getContext('2d');
    const resize=()=>{
      _sfCanvas.width=window.innerWidth;_sfCanvas.height=window.innerHeight;
      _sfGenStars(_sfCanvas.width,_sfCanvas.height);
    };
    resize();
    window.addEventListener('resize',resize,{passive:true});
  }
  if(show===_sfActive)return;
  _sfActive=show;
  _sfCanvas.style.opacity=show?'1':'0';
  if(show&&!_sfAnim){_sfPrev=0;_sfNextShoot=performance.now()+10000;_sfAnim=requestAnimationFrame(_sfFrame);}
}

// ══════════════════════════════════════════════════════════
// ── Soundscape Generator ────────────────────────────────────
// ══════════════════════════════════════════════════════════
let _scPlaying=false,_scNodes=null;

function _scDesc(obs){
  if(!obs)return'';
  const m=obs.metric,wind=m.windSpeed||0,pres=m.pressure||1013,precip=m.precipRate||0;
  const parts=[];
  if(precip>=5)parts.push('močan dež');
  else if(precip>=1)parts.push('dež');
  else if(precip>0)parts.push('rosenje');
  if(wind<3)parts.push('brezvetrje');
  else if(wind<15)parts.push('lahek veter');
  else if(wind<30)parts.push('zmeren veter');
  else if(wind<50)parts.push('močan veter');
  else parts.push('nevihta');
  if(pres>1025)parts.push('visok tlak');
  else if(pres<1000)parts.push('nizek tlak');
  const h=new Date().getHours();
  if(h>=22||h<5)parts.push('noč');
  else if(h<9)parts.push('jutro');
  else if(h<18)parts.push('dan');
  else parts.push('večer');
  return parts.join(' · ');
}

async function _soundscapeInit(){
  const T=window.Tone;if(!T)return;
  await T.start();
  T.getContext().resume();

  // Master chain: masterVol → reverb → destination
  const reverb=new T.Reverb({decay:5,preDelay:0.08,wet:0.35}).toDestination();
  const masterVol=new T.Volume(-4).connect(reverb);

  // ── Wind layer: pink noise → bandpass filter → tremolo → vol ──
  const windNoise=new T.Noise('pink').start();
  const windFilter=new T.Filter({type:'bandpass',frequency:500,Q:0.9});
  const windTrem=new T.Tremolo({frequency:0.4,depth:0.15}).start();
  const windVol=new T.Volume(-38);
  windNoise.chain(windFilter,windTrem,windVol,masterVol);

  // ── Drone layer: 3 oscillators → gain → vol (pressure → pitch) ──
  const droneA=new T.Oscillator({type:'sine',frequency:55}).start();
  const droneB=new T.Oscillator({type:'sine',frequency:82.5}).start();
  const droneC=new T.Oscillator({type:'triangle',frequency:110}).start();
  const droneMix=new T.Gain(0.33);
  droneA.connect(droneMix);droneB.connect(droneMix);droneC.connect(droneMix);
  const droneVol=new T.Volume(-22);
  droneMix.connect(droneVol);droneVol.connect(masterVol);

  // ── Rain layer: white noise → highpass → vol ──
  const rainNoise=new T.Noise('white').start();
  const rainFilter=new T.Filter({type:'highpass',frequency:3800,Q:0.7});
  const rainVol=new T.Volume(-60);
  rainNoise.chain(rainFilter,rainVol,masterVol);

  // ── Pressure whistle: high sine for falling pressure tension ──
  const whistleOsc=new T.Oscillator({type:'sine',frequency:440}).start();
  const whistleVol=new T.Volume(-60);
  whistleOsc.connect(whistleVol);whistleVol.connect(masterVol);

  _scNodes={reverb,masterVol,windNoise,windFilter,windTrem,windVol,
            droneA,droneB,droneC,droneMix,droneVol,
            rainNoise,rainFilter,rainVol,
            whistleOsc,whistleVol};
}

function updateSoundscape(obs){
  if(!_scPlaying||!_scNodes||!obs)return;
  const m=obs.metric;
  const wind=m.windSpeed||0;
  const pres=m.pressure||1013;
  const hum=obs.humidity||60;
  const precip=m.precipRate||0;
  const {windVol,windFilter,windTrem,reverb,droneA,droneB,droneC,droneVol,rainVol,whistleOsc,whistleVol}=_scNodes;

  // Wind → noise volume & filter cutoff
  const windDb=wind<2?-42:Math.max(-10,-42+wind*0.48);
  windVol.volume.rampTo(windDb,3);
  windFilter.frequency.rampTo(Math.min(3200,200+wind*38),4);
  windTrem.depth.rampTo(Math.min(0.45,0.05+wind/100),5);

  // Pressure → drone base pitch (975hPa→38Hz, 1040hPa→90Hz)
  const baseFreq=Math.max(30,Math.min(95,38+((pres-975)/65)*52));
  droneA.frequency.rampTo(baseFreq,8);
  droneB.frequency.rampTo(baseFreq*1.5,8);
  droneC.frequency.rampTo(baseFreq*2,8);
  // Drone louder under low pressure
  const droneDb=pres<1000?-14:pres>1025?-28:-20;
  droneVol.volume.rampTo(droneDb,6);

  // Humidity → reverb wetness
  reverb.wet.rampTo(Math.min(0.65,0.08+(hum-30)/110),4);

  // Rain
  rainVol.volume.rampTo(precip<=0?-60:precip<0.5?-36:precip<2?-24:precip<6?-16:-10,2);

  // Pressure whistle: only audible when pressure is very low & falling
  const whistleDb=pres<998?Math.max(-22,-60+(998-pres)*2.5):-60;
  whistleOsc.frequency.rampTo(200+Math.max(0,1013-pres)*3.5,10);
  whistleVol.volume.rampTo(whistleDb,5);

  // Update UI label
  const desc=document.getElementById('sc-desc');
  if(desc)desc.textContent=_scDesc(obs);
}

async function toggleSoundscape(){
  const btn=document.getElementById('sc-btn');
  const lbl=document.getElementById('sc-btn-lbl');
  const desc=document.getElementById('sc-desc');
  if(_scPlaying){
    _scPlaying=false;
    if(_scNodes){
      try{window.Tone?.getTransport()?.stop();}catch(e){}
      Object.values(_scNodes).forEach(n=>{try{n.dispose();}catch(e){}});
      _scNodes=null;
    }
    btn.classList.remove('sc-on');
    lbl.textContent='Poslušaj vreme';
    if(desc)desc.textContent='';
  }else{
    btn.classList.add('sc-on');
    lbl.textContent='Inicializiram…';
    if(!window.Tone){
      if(desc)desc.textContent='Tone.js se nalaga…';
      try{ await _loadScript('https://unpkg.com/tone@14/build/Tone.js'); }catch(e){
        btn.classList.remove('sc-on');lbl.textContent='Poslušaj vreme';
        if(desc)desc.textContent='Napaka pri nalaganju Tone.js';
        return;
      }
    }
    if(desc)desc.textContent='';
    try{
      await _soundscapeInit();
      _scPlaying=true;
      lbl.textContent='V živo';
      if(_lastBriefObs)updateSoundscape(_lastBriefObs);
      else if(desc)desc.textContent='Čakam na podatke…';
    }catch(e){
      btn.classList.remove('sc-on');
      lbl.textContent='Poslušaj vreme';
      if(desc)desc.textContent='Napaka: '+e.message;
      _scPlaying=false;_scNodes=null;
    }
  }
}

// ══════════════════════════════════════════════════════════
// ── AI dnevni fotobriefing ─────────────────────────────────
// ══════════════════════════════════════════════════════════
let _lastBriefObs=null;
async function fetchAIBrief(force=false){
  const today=new Date().toDateString();
  const cached=localStorage.getItem('ai-brief-v1');
  const cachedData=cached?JSON.parse(cached):null;
  if(!force&&cachedData?.date===today&&cachedData?.text){
    showAIBrief(cachedData.text,cachedData.date,cachedData.source||'cache');return;
  }
  const briefEl=document.getElementById('ai-brief-text');
  if(briefEl)briefEl.textContent='Generiram brief…';
  try{
    const obs=_lastBriefObs||{};const m=obs?.metric||{};
    const pt=calcPhotoTimes()||{};
    const gddEl=document.getElementById('pheno-gdd-total');
    const gdd=gddEl?parseInt(gddEl.textContent)||0:0;
    const phenoPhases=['Pozna zima','Zgodnja pomlad (leska)','Pomlad (cvetlice)','Zgodnje poletje (metulji)','Poletje (kačji pastirji)','Pozno poletje (pajki)','Jesen'];
    const phenoIdx=gdd<50?0:gdd<120?1:gdd<300?2:gdd<500?3:gdd<700?4:gdd<900?5:6;
    const moon=calcMoon();
    const payload={
      temp:(m.temp??15).toFixed(1),hum:obs.humidity??70,wind:(m.windSpeed??0).toFixed(0),rain:(m.precipRate??0).toFixed(1),
      cond:document.getElementById('cond-label')?.textContent||'—',
      gdd,phenoPhase:phenoPhases[phenoIdx],
      goldAM:pt.goldAM||'—',goldPM:pt.goldPM||'—',sunrise:pt.sunrise||'—',sunset:pt.sunset||'—',
      moon:moon.phase,moonIllum:moon.illum,
      timeStr:new Date().toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'}),
    };
    const res=await fetch(PROXY+'/ai-brief',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)});
    const data=await res.json();
    if(data.error==='no_key'){
      // Fallback: rule-based brief
      const brief=generateRuleBasedBrief(payload);
      localStorage.setItem('ai-brief-v1',JSON.stringify({date:today,text:brief,source:'rule'}));
      showAIBrief(brief,today,'Lokalni generator');
    }else if(data.brief){
      localStorage.setItem('ai-brief-v1',JSON.stringify({date:today,text:data.brief,source:'Claude AI'}));
      showAIBrief(data.brief,today,'Claude AI');
    }
  }catch(e){
    const brief=generateRuleBasedBrief({});
    showAIBrief(brief,today,'Lokalni generator');
  }
}
function showAIBrief(text,date,source){
  const el=document.getElementById('ai-brief-text');if(el)el.textContent=text;
  const meta=document.getElementById('ai-brief-meta');
  if(meta)meta.textContent=source+' · '+new Date(date||Date.now()).toLocaleDateString('sl',{weekday:'long',day:'numeric',month:'long'});
  const bd=document.getElementById('brief-date');
  if(bd)bd.textContent=source;
}
function generateRuleBasedBrief(p){
  const gdd=p.gdd||0,T=parseFloat(p.temp||15),rain=parseFloat(p.rain||0);
  const h=new Date().getHours();
  const subjects=gdd<120?'lesko in teloh':gdd<300?'spomladanske cvetlice in prve čebele':gdd<500?'metulje in hrošče':gdd<700?'kačje pastirje in kobilice':'pajke in jesenske cvetlice';
  const time=h<9?p.goldAM?`Danes je zlata ura ob ${p.goldAM} — izvrsten čas za makro!`:'Jutranjo roso ujemi zgodaj.':h>18&&p.goldPM?`Večerna zlata ura ob ${p.goldPM} se bliža.`:'';
  const loc=gdd<300?'gozdnem robu nad Rečico ali ob potoku':gdd<600?'mokrotnih travnikih ob Savinji':'bregovih Savinje ali visokem travišču';
  const cond=rain>0?'Po dežju so rastline mokre — idealno za kapljice.':`Pri ${T}°C je aktivnost ${T>=18?'žuželk odlična':'žuželk zmerna — išči zavetišče'}.`;
  return `${time} Danes so aktivni ${subjects}. Najboljša lokacija: ${loc}. ${cond} Luna (${p.moon||'—'}, ${p.moonIllum||0}%) vpliva na nočne subjekte.`;
}

// ══════════════════════════════════════════════════════════
// ── Mikroklimatski odtis ─────────────────────────────────
// ══════════════════════════════════════════════════════════
async function buildFingerprint(){
  const grid=document.getElementById('fp-grid');
  const sub=document.getElementById('fp-subtitle');
  const narr=document.getElementById('fp-narrative');
  if(!grid)return;
  const stored=JSON.parse(localStorage.getItem(LS_KEY)||'{}');
  const entries=Object.entries(stored).map(([d,v])=>({d,v}));
  if(entries.length<90){if(sub)sub.textContent='Premalo podatkov (potrebnih vsaj 90 dni)';return;}
  // Compute fingerprint metrics
  const withT=entries.filter(e=>e.v.tempAvg!=null);
  const withR=entries.filter(e=>e.v.precipTotal!=null);
  // Fog days (humidity proxy: days where temp low and likely foggy)
  const winterLowTemp=entries.filter(e=>{const m=new Date(e.d+'T12:00:00').getMonth();return (m<=2||m>=10)&&(e.v.tempAvg??99)<5&&(e.v.humidityAvg??0)>85;}).length;
  const fogDaysPerYear=withT.length>0?Math.round(winterLowTemp/(withT.length/365)):0;
  // Temperature inversions (approx: very cold night vs mild day)
  const inversions=withT.filter(e=>(e.v.tempLow??99)<2&&(e.v.tempHigh??0)>8).length;
  const invPerYear=Math.round(inversions/(withT.length/365));
  // Annual precipitation
  const years=new Set(entries.map(e=>e.d.slice(0,4)));
  const annualPrecip=years.size>0?[...years].map(y=>entries.filter(e=>e.d.startsWith(y)).reduce((s,e)=>s+(e.v.precipTotal||0),0)):[];
  const avgPrecip=annualPrecip.length?Math.round(annualPrecip.reduce((a,b)=>a+b,0)/annualPrecip.length):0;
  // Frost days per year
  const frostTotal=withT.filter(e=>(e.v.tempLow??99)<=0).length;
  const frostPerYear=Math.round(frostTotal/(withT.length/365));
  // Rainy days per year
  const rainyTotal=withR.filter(e=>e.v.precipTotal>1).length;
  const rainyPerYear=Math.round(rainyTotal/(withR.length/365));
  // Max single-day rain
  const maxRain=withR.reduce((m,e)=>e.v.precipTotal>m?e.v.precipTotal:m,0);
  // Summer heat days (avg ≥ 20°C)
  const heatDays=Math.round(withT.filter(e=>(e.v.tempAvg??0)>=20).length/(withT.length/365));
  const stats=[
    {icon:'🌡',n:withT.length?(withT.reduce((s,e)=>s+e.v.tempAvg,0)/withT.length).toFixed(1)+'°C':'—',l:'Povp. temperatura',bar:null,desc:'Letno povprečje za Rečico ob Savinji'},
    {icon:'🌧',n:avgPrecip+' mm',l:'Letne padavine',bar:avgPrecip/1800,col:'#60a5fa',desc:'Savinjska dolina je med mokrejšimi v SLO'},
    {icon:'☔',n:rainyPerYear+' dni',l:'Deževnih dni/leto',bar:rainyPerYear/150,col:'#38bdf8',desc:'Dni z >1mm padavin'},
    {icon:'❄️',n:frostPerYear+' dni',l:'Zmrzali/leto',bar:frostPerYear/60,col:'#7dd3fc',desc:'Nočne temperature ≤0°C'},
    {icon:'☀️',n:heatDays+' dni',l:'Poletnih dni/leto',bar:heatDays/80,col:'#fbbf24',desc:'Dnevi z povp. temp ≥20°C'},
    {icon:'🌊',n:maxRain.toFixed(0)+' mm',l:'Rekordni dan',bar:Math.min(1,maxRain/100),col:'#f87171',desc:'Maksimalne dnevne padavine'},
    {icon:'🌫',n:'~'+fogDaysPerYear+' dni',l:'Megleni dni/leto',bar:Math.min(1,fogDaysPerYear/80),col:'#94a3b8',desc:'Nizka temp + visoka vlaga (ocena)'},
    {icon:'🔄',n:'~'+invPerYear+' dni',l:'Temp. inverzij/leto',bar:Math.min(1,invPerYear/50),col:'#a78bfa',desc:'Hladne noči z toplimi dnevi — dolinski učinek'},
  ];
  if(sub)sub.textContent='Analiza '+entries.length+' dni meritev ('+[...years].sort()[0]+'–'+[...years].sort().pop()+')';
  grid.innerHTML=stats.map(st=>`<div class="fp-item"><div class="fp-val">${st.n}</div><div class="fp-lbl">${st.icon} ${st.l}</div>${st.bar!=null?`<div class="fp-bar"><div class="fp-bar-fill" style="width:${Math.round(st.bar*100)}%;background:${st.col||'var(--blue)'}"></div></div>`:''}${st.desc?`<div class="fp-desc">${st.desc}</div>`:''}</div>`).join('');
  // Narrative
  if(narr){
    const warm=avgPrecip>1300?'nadpovprečno mokra':'normalno vlažna';
    narr.textContent=`Postaja IREICA1 na Rečici ob Savinji (366 m n. m.) ima tipično mikroklimatsko sliko savinjske doline: ${frostPerYear} zmrzalnih noči letno, ${rainyPerYear} deževnih dni in ${fogDaysPerYear} meglenih dni — dolina je ${warm} v primerjavi z regijskim povprečjem. Temperaturne inverzije (~${invPerYear} dni/leto) so pogost pojav jeseni in pozimi, ko hladen zrak zaide v dolino. Savinjska regija velja za eno padavinsko bogatejših v Sloveniji, kar potrjuje povprečje ${avgPrecip} mm/leto.`;
  }
}


