function checkAIPredAccuracy(currentTemp){
  try{
    if(currentTemp==null)return;
    const raw=localStorage.getItem(AI_PRED_LOG_KEY);
    if(!raw)return;
    const{preds}=JSON.parse(raw);
    const now=Date.now();
    const match=preds.find(p=>Math.abs(p.t-now)<45*60000);
    if(!match)return;
    const err=Math.abs(currentTemp-match.v);
    const el=document.getElementById('ai-pred-acc');
    if(el)el.textContent='±'+err.toFixed(1)+'°C';
  }catch(e){}
}

