// ══════════════════════════════════════════════════════════
// ── INNOVATIVE AI FEATURES ───────────────────────────────
//   1) Event nowcast (megla / slana / nevihta)
//   2) Verjetnostna pahljača (ansambel) + skill semafor
//   3) Analogni dnevi (k-NN nad sezonskim arhivom)
// ══════════════════════════════════════════════════════════
let _aiLastHW=null,_aiAnalogCache=null,_aiNowFc=null;
const AI_ANALOG_KEY='wx-ai-analog-v1';
const AI_SKILL_KEY='wx-ai-skill-v1';

function _dewpoint(t,rh){
  if(t==null||rh==null||rh<=0)return null;
  const a=17.625,b=243.04,g=Math.log(rh/100)+a*t/(b+t);
  return b*g/(a-g);
}
function _clamp01(x){return x<0?0:x>1?1:x;}

// ── Orchestrator — runs all three innovative features ─────
async function aiRunInnovations(hw,temps,obs){
  try{ await aiFetchNowcastForecast(); }catch(e){ console.warn('AI nowcast fc:',e); }
  try{ aiEventNowcast(); }catch(e){ console.warn('AI event:',e); }
  try{ await aiAnalogDays(obs); }catch(e){ console.warn('AI analog:',e); }
  try{ aiFanChart(hw,temps); }catch(e){ console.warn('AI fan:',e); }
  try{ aiLogEnsemblePreds(hw); }catch(e){ console.warn('AI log:',e); }
  try{ aiRenderSkill(); }catch(e){ console.warn('AI skill:',e); }
}

// ── Richer hourly forecast (humidity, dewpoint, cloud, cape) ──
async function aiFetchNowcastForecast(){
  if(_aiNowFc&&Date.now()-_aiNowFc.ts<20*60000)return _aiNowFc;
  const url=`https://api.open-meteo.com/v1/forecast?latitude=${LAT}&longitude=${LON}`+
    `&hourly=temperature_2m,relative_humidity_2m,dew_point_2m,cloud_cover,wind_speed_10m,wind_gusts_10m,precipitation_probability,weather_code,cape`+
    `&timezone=Europe%2FLjubljana&forecast_days=2`;
  const r=await fetch(url);
  if(!r.ok)throw new Error('forecast '+r.status);
  const d=await r.json();const h=d.hourly;if(!h)throw new Error('no hourly');
  const now=Date.now();
  const rows=h.time.map((t,i)=>({
    t:new Date(t).getTime(),
    temp:h.temperature_2m?.[i],rh:h.relative_humidity_2m?.[i],td:h.dew_point_2m?.[i],
    cloud:h.cloud_cover?.[i],wind:h.wind_speed_10m?.[i],gust:h.wind_gusts_10m?.[i],
    prob:h.precipitation_probability?.[i]??0,wmo:h.weather_code?.[i]??0,cape:h.cape?.[i]??0
  })).filter(x=>x.t>=now-3600000);
  _aiNowFc={ts:Date.now(),rows};
  return _aiNowFc;
}

// ══ 1) EVENT NOWCAST ═════════════════════════════════════
function aiEventNowcast(){
  const grid=document.getElementById('ai-event-grid');if(!grid)return;
  const rng=document.getElementById('ai-event-range');
  const rows=(_aiNowFc?.rows||[]).slice(0,9);
  if(rows.length<2){grid.innerHTML='<div style="grid-column:1/-1;color:var(--muted);font-size:.78rem;padding:.5rem 0">Napoved trenutno ni dosegljiva.</div>';return;}
  const fmtH=ts=>String(new Date(ts).getHours()).padStart(2,'0')+':00';
  const fog=[],frost=[],storm=[];
  rows.forEach(r=>{
    const hh=new Date(r.t).getHours();const isNight=hh>=21||hh<=6;
    const td=r.td!=null?r.td:_dewpoint(r.temp,r.rh);
    const spread=(r.temp!=null&&td!=null)?r.temp-td:99;
    // FOG: small dew spread + high RH + calm; night boost; OM fog codes override
    let pf=_clamp01((2.2-spread)/2.2)*_clamp01(((r.rh??0)-88)/12)*_clamp01((14-(r.wind??0))/14);
    if(isNight)pf=_clamp01(pf*1.25+0.05);
    if(r.wmo>=45&&r.wmo<=48)pf=Math.max(pf,0.85);
    fog.push(pf);
    // FROST: near/below 0 air temp; clear sky + calm = radiative; dewpoint sub-zero
    let pr=0;
    if(r.temp!=null&&r.temp<=4){
      const tFac=_clamp01((4-r.temp)/6.5);
      const clearFac=_clamp01((100-(r.cloud??100))/70);
      const calmFac=_clamp01((12-(r.wind??0))/12);
      const dryFac=td!=null?_clamp01((1-td)/4):.5;
      pr=_clamp01(tFac*(0.45+0.55*clearFac*calmFac)*(0.6+0.4*dryFac));
      if(r.temp<=0)pr=Math.max(pr,_clamp01(0.6+(0-r.temp)/8));
    }
    frost.push(pr);
    // STORM: thunder codes + CAPE + precip probability
    const thunder=(r.wmo>=95&&r.wmo<=99)?1:0;
    const capeFac=_clamp01(((r.cape??0)-300)/2200);
    const probFac=_clamp01((r.prob-30)/70);
    let ps=_clamp01(Math.max(thunder?0.7:0,capeFac*0.55+probFac*0.35+capeFac*probFac*0.4));
    if(thunder)ps=Math.max(ps,0.8);
    storm.push(ps);
  });
  const peak=arr=>{let mi=0;arr.forEach((v,i)=>{if(v>arr[mi])mi=i;});return{p:arr[mi],i:mi};};
  const defs=[
    {name:'Megla',  icon:'🌫️',col:'#94a3b8',arr:fog,  onset:'Radiacijska meglica / megla'},
    {name:'Slana',  icon:'❄️', col:'#60a5fa',arr:frost,onset:'Slana ob jasnem, mirnem vremenu'},
    {name:'Nevihta',icon:'⛈️', col:'#f59e0b',arr:storm,onset:'Nevihtni potencial (CAPE)'},
  ];
  grid.innerHTML=defs.map(d=>{
    const pk=peak(d.arr);const pct=Math.round(pk.p*100);const hot=pct>=55;
    const R=22,C=2*Math.PI*R,off=C*(1-pk.p);
    const whenStr=pct>=15?`vrh ob ${fmtH(rows[pk.i].t)} (+${pk.i} h)`:'—';
    const level=pct>=70?'visoko':pct>=45?'zmerno':pct>=20?'nizko':'zanemarljivo';
    return `<div class="ai-event-card${hot?' hot':''}" style="--ev-col:${d.col}">
      <div class="ai-event-icon">${d.icon}</div>
      <div class="ai-event-name">${d.name}</div>
      <svg class="ai-event-ring" width="58" height="58" viewBox="0 0 58 58">
        <circle cx="29" cy="29" r="${R}" fill="none" stroke="var(--rain-track)" stroke-width="5"/>
        <circle cx="29" cy="29" r="${R}" fill="none" stroke="${d.col}" stroke-width="5" stroke-linecap="round" stroke-dasharray="${C.toFixed(1)}" stroke-dashoffset="${off.toFixed(1)}" transform="rotate(-90 29 29)"/>
        <text x="29" y="29" text-anchor="middle" dominant-baseline="central" font-family="JetBrains Mono,monospace" font-size="13" fill="var(--text)">${pct}%</text>
      </svg>
      <div class="ai-event-when">${pct>=15?d.onset:'ni izrazitega tveganja'}</div>
      <div class="ai-event-when">${whenStr}</div>
      <div class="ai-event-tag">${level}</div>
    </div>`;
  }).join('');
  if(rng)rng.textContent=`okno ${fmtH(rows[0].t)}–${fmtH(rows[rows.length-1].t)}`;
}

// ══ 2) PROBABILISTIC FAN CHART ═══════════════════════════
function aiFanChart(hw,temps){
  const svg=document.getElementById('ai-fan-svg');if(!svg||!temps?.length)return;
  const FAN_H=24;               // chart horizon
  const MODEL_H=AI_OUT_LEN;     // HW/Analog max horizon
  const PAST_H=12;              // hours of history to show
  const now=new Date(),nowMs=now.getTime(),hourNow=now.getHours();
  const lastT=temps[temps.length-1];
  if(lastT==null){svg.innerHTML='<text x="440" y="95" text-anchor="middle" font-size="12" fill="rgba(128,128,128,.4)" font-family="Inter,sans-serif">Ni podatka o trenutni temperaturi.</text>';return;}
  const seasonal=hw?.seasonal||null;

  // Past actual station data (last PAST_H hours)
  const actualPast=(_hourlyObs||[])
    .map(o=>({t:new Date((o.obsTimeLocal||'').replace(' ','T')).getTime(),v:o.metric?.temp??null}))
    .filter(d=>d.v!=null&&isFinite(d.t)&&d.t>=nowMs-PAST_H*3600000&&d.t<=nowMs)
    .sort((a,b)=>a.t-b.t);

  // Per-hour stats for future (h=1..FAN_H)
  const hwPreds=_aiLstmPredictions?.preds||[];
  const omRows=_aiNowFc?.rows||[];
  const analogOk=_aiAnalogCache?.projection?.length>=MODEL_H&&_aiAnalogCache.ts&&Date.now()-_aiAnalogCache.ts<3600000&&_aiAnalogCache.projection.every(v=>v!=null);
  const stats=[];
  const memberNames=new Set();
  for(let h=1;h<=FAN_H;h++){
    const targetMs=nowMs+h*3600000;
    const vals=[];
    if(h<=MODEL_H&&hwPreds[h-1]!=null){vals.push(hwPreds[h-1]);memberNames.add('HW');}
    const r=omRows.reduce((b,x)=>Math.abs(x.t-targetMs)<Math.abs((b?.t??Infinity)-targetMs)?x:b,null);
    if(r&&r.temp!=null){vals.push(r.temp);memberNames.add('Open-Meteo');}
    if(seasonal){const pv=lastT+(seasonal[(hourNow+h)%24]-seasonal[hourNow%24]);vals.push(pv);memberNames.add('Perzistenca + klima');}
    if(h<=MODEL_H&&analogOk){vals.push(_aiAnalogCache.projection[h-1]);memberNames.add('Analogni dnevi');}
    if(!vals.length){stats.push(null);continue;}
    const mean=vals.reduce((s,v)=>s+v,0)/vals.length;
    const sd=vals.length>1?Math.sqrt(vals.reduce((s,v)=>s+(v-mean)**2,0)/vals.length):0;
    const sigma=(Math.max(sd,0.3)+0.15*h)*(vals.length<2?0.7:1);
    stats.push({h,mean,p10:mean-1.2816*sigma,p90:mean+1.2816*sigma,sigma});
  }
  const validStats=stats.filter(Boolean);
  if(!validStats.length){svg.innerHTML='<text x="440" y="95" text-anchor="middle" font-size="12" fill="rgba(128,128,128,.4)" font-family="Inter,sans-serif">Premalo veljavnih podatkov za pahljačo.</text>';return;}

  // SVG layout
  const VW=880,VH=190,pl=40,pr=15,pt=12,pb=28;
  const tMin=nowMs-PAST_H*3600000,tMax=nowMs+FAN_H*3600000,tSpan=tMax-tMin;
  const mapXt=t=>pl+(t-tMin)/tSpan*(VW-pl-pr);
  const mapXh=h=>mapXt(nowMs+h*3600000);
  const nowX=mapXt(nowMs);

  // Temperature range
  const allVals=[lastT,...actualPast.map(d=>d.v),...validStats.map(s=>s.p10),...validStats.map(s=>s.p90)].filter(v=>v!=null&&isFinite(v));
  const rawMin=Math.min(...allVals),rawMax=Math.max(...allVals);
  const spread=rawMax-rawMin;
  const minT=rawMin-(spread<0.5?1:0.5),maxT=rawMax+(spread<0.5?1:0.5);
  const mapY=v=>{const d=maxT-minT;return d<0.01?(pt+(VH-pt-pb)/2):pt+(1-(v-minT)/d)*(VH-pt-pb);};
  const ok=p=>p&&isFinite(p[0])&&isFinite(p[1]);

  let html='';

  // Grid lines
  const step=Math.max(1,Math.ceil((maxT-minT)/4));
  for(let t=Math.ceil(minT/step)*step;t<=maxT;t+=step){const y=mapY(t).toFixed(1);html+=`<line x1="${pl}" x2="${VW-pr}" y1="${y}" y2="${y}" stroke="var(--border)" stroke-width="0.5"/><text x="${pl-4}" y="${y}" text-anchor="end" font-size="8" fill="var(--muted)" font-family="JetBrains Mono,monospace" dominant-baseline="middle">${t.toFixed(0)}°</text>`;}

  // "zdaj" divider
  html+=`<line x1="${nowX.toFixed(1)}" x2="${nowX.toFixed(1)}" y1="${pt}" y2="${VH-pb}" stroke="rgba(255,255,255,.18)" stroke-width="1" stroke-dasharray="3,3"/>`;
  html+=`<text x="${(nowX+4).toFixed(1)}" y="${pt+8}" font-size="8" fill="var(--muted)" font-family="JetBrains Mono,monospace">zdaj</text>`;

  // Fan band (P10–P90)
  const upper=[[nowX,mapY(lastT)],...stats.map(s=>s?[mapXh(s.h),mapY(s.p90)]:null)].filter(ok);
  const lower=[...stats.map(s=>s?[mapXh(s.h),mapY(s.p10)]:null).filter(ok).reverse(),[nowX,mapY(lastT)]].filter(ok);
  const bandPts=[...upper,...lower].map(p=>`${p[0].toFixed(1)},${p[1].toFixed(1)}`).join(' ');
  if(bandPts)html+=`<polygon points="${bandPts}" fill="rgba(124,58,237,.18)" stroke="none"/>`;

  // Median line (future)
  const medPts=[[nowX,mapY(lastT)],...stats.map(s=>s?[mapXh(s.h),mapY(s.mean)]:null)].filter(ok).map(p=>`${p[0].toFixed(1)},${p[1].toFixed(1)}`).join(' ');
  if(medPts)html+=`<polyline points="${medPts}" fill="none" stroke="#a78bfa" stroke-width="2" stroke-linejoin="round"/>`;

  // Median dots (smaller after MODEL_H where fewer members)
  stats.forEach(s=>{if(!s)return;const cx=mapXh(s.h),cy=mapY(s.mean);if(isFinite(cx)&&isFinite(cy))html+=`<circle cx="${cx.toFixed(1)}" cy="${cy.toFixed(1)}" r="${s.h<=MODEL_H?2.5:1.8}" fill="#a78bfa"/>`;});

  // Actual station line (green)
  const actPoints=[...actualPast.map(d=>[mapXt(d.t),mapY(d.v)]),[nowX,mapY(lastT)]].filter(ok);
  if(actPoints.length>1)html+=`<polyline points="${actPoints.map(p=>`${p[0].toFixed(1)},${p[1].toFixed(1)}`).join(' ')}" fill="none" stroke="#4ade80" stroke-width="2" stroke-linejoin="round"/>`;

  // Time axis labels
  for(let h=-PAST_H;h<=FAN_H;h+=3){
    if(h===0)continue;
    const x=mapXh(h),label=h<0?`-${Math.abs(h)}h`:`+${h}h`;
    html+=`<text x="${x.toFixed(1)}" y="${VH-8}" text-anchor="middle" font-size="7.5" fill="var(--muted)" font-family="JetBrains Mono,monospace">${label}</text>`;
  }

  svg.innerHTML=html;

  const rng=document.getElementById('ai-fan-range');
  const widest=validStats[validStats.length-1];
  if(rng)rng.textContent=`Zadnjih ${PAST_H} ur + napoved za ${FAN_H} ur · ±${(1.2816*widest.sigma).toFixed(1)} °C pri +${FAN_H} h`;
  const mem=document.getElementById('ai-fan-members');
  if(mem)mem.textContent=`${memberNames.size} članov: ${[...memberNames].join(' · ')}`;
}

// ── Skill scoreboard: local model vs Open-Meteo ──────────
function _skillLoad(){try{return JSON.parse(localStorage.getItem(AI_SKILL_KEY))||{pending:[],local:{s:0,n:0},om:{s:0,n:0}};}catch(e){return{pending:[],local:{s:0,n:0},om:{s:0,n:0}};}}
function _skillSave(s){try{localStorage.setItem(AI_SKILL_KEY,JSON.stringify(s));}catch(e){}}
function aiLogEnsemblePreds(hw){
  const curT=_lastBriefObs?.metric?.temp;
  const st=_skillLoad();const now=Date.now();
  if(curT!=null){
    st.pending=st.pending.filter(p=>{
      if(Math.abs(p.target-now)<40*60000){
        if(p.local!=null){st.local.s+=Math.abs(p.local-curT);st.local.n++;}
        if(p.om!=null){st.om.s+=Math.abs(p.om-curT);st.om.n++;}
        return false;
      }
      return p.target>now-3*3600000;
    });
  }
  const localPreds=_aiLstmPredictions?.preds||hw?.preds||[];
  const omRows=_aiNowFc?.rows||[];
  for(let h=1;h<=AI_OUT_LEN;h++){
    const target=now+h*3600000;
    if(st.pending.some(p=>Math.abs(p.target-target)<40*60000))continue;
    const r=omRows.reduce((b,x)=>Math.abs(x.t-target)<Math.abs((b?.t||Infinity)-target)?x:b,null);
    st.pending.push({target,local:localPreds[h-1]??null,om:(r&&r.temp!=null)?r.temp:null});
  }
  if(st.pending.length>60)st.pending=st.pending.slice(-60);
  _skillSave(st);
}
function aiRenderSkill(){
  const body=document.getElementById('ai-skill-body');if(!body)return;
  const st=_skillLoad();
  const lMae=st.local.n?st.local.s/st.local.n:null;
  const oMae=st.om.n?st.om.s/st.om.n:null;
  const minN=Math.min(st.local.n,st.om.n);
  if(minN<3||lMae==null||oMae==null){
    body.innerHTML=`<div style="color:var(--muted);font-size:.74rem;line-height:1.5">Zbiram preverjene napovedi … (${minN}/3 ujemanj). Vsako uro se napoved samodejno primerja z dejansko izmerjeno temperaturo na postaji.</div>`;
    return;
  }
  const worst=Math.max(lMae,oMae,0.1);
  const localWins=lMae<oMae;
  const bar=(name,emoji,mae,col)=>`<div class="ai-skill-row"><div class="ai-skill-name">${emoji} ${name}</div><div class="ai-skill-bar-bg"><div class="ai-skill-bar" style="width:${Math.round(mae/worst*100)}%;background:${col}"></div></div><div class="ai-skill-mae">${mae.toFixed(2)}°</div></div>`;
  const pct=oMae>0?Math.round(Math.abs(lMae-oMae)/oMae*100):0;
  body.innerHTML=
    bar('Lokalni (HW)','🤖',lMae,localWins?'#34d399':'#a78bfa')+
    bar('Open-Meteo','🌐',oMae,localWins?'#a78bfa':'#34d399')+
    `<div class="ai-skill-verdict">${pct<5
      ? `⚖️ <b>Izenačeno</b> – modela sta praktično enako natančna (${minN} preverjenih napovedi).`
      : localWins
      ? `🏆 <b>Lokalni model vodi</b> – povprečna napaka je za ${pct} % manjša kot pri modelu Open-Meteo (${minN} preverjenih napovedi).`
      : `🌐 <b>Open-Meteo vodi</b> za ${pct} % (${minN} preverjenih napovedi). Lokalni model se bo z več zbranimi podatki sčasoma izboljšal.`}</div>`;
}

// ══ 3) ANALOG DAYS (k-NN) ════════════════════════════════
async function aiFetchAnalogArchive(){
  const dayKey=_localDateStr(new Date());
  try{const c=JSON.parse(localStorage.getItem(AI_ANALOG_KEY));if(c&&c.day===dayKey&&c.rows?.length)return c.rows;}catch(e){}
  const today=new Date(),rows=[];
  for(const y of [1,2,3]){
    const center=new Date(today);center.setFullYear(today.getFullYear()-y);
    const start=new Date(center.getTime()-30*864e5);
    let end=new Date(center.getTime()+30*864e5);
    const maxEnd=new Date(Date.now()-6*864e5);
    if(end>maxEnd)end=maxEnd;
    if(end<=start)continue;
    const sd=start.toISOString().slice(0,10),ed=end.toISOString().slice(0,10);
    const url=`https://archive-api.open-meteo.com/v1/archive?latitude=${LAT}&longitude=${LON}`+
      `&start_date=${sd}&end_date=${ed}`+
      `&hourly=temperature_2m,relative_humidity_2m,wind_speed_10m,precipitation,surface_pressure`+
      `&timezone=Europe%2FLjubljana`;
    try{
      const r=await fetch(url);if(!r.ok)continue;const d=await r.json();const h=d.hourly;if(!h)continue;
      h.time.forEach((t,i)=>{
        const T=h.temperature_2m?.[i];if(T==null)return;
        rows.push({t,T,rh:h.relative_humidity_2m?.[i]??null,w:h.wind_speed_10m?.[i]??null,r:h.precipitation?.[i]??0,p:h.surface_pressure?.[i]??null});
      });
    }catch(e){}
  }
  try{localStorage.setItem(AI_ANALOG_KEY,JSON.stringify({day:dayKey,rows}));}catch(e){}
  return rows;
}
async function aiAnalogDays(obs){
  const sumEl=document.getElementById('ai-analog-summary');
  const listEl=document.getElementById('ai-analog-list');
  const rngEl=document.getElementById('ai-analog-range');
  if(!sumEl)return;
  const recent=(obs||[]).slice(-4);
  const cur=recent[recent.length-1];if(!cur){return;}
  const cm=cur.metric||{};
  const curT=cm.temp??cm.tempAvg,curRH=cur.humidity??cm.humidityAvg,curW=cm.windSpeed??cm.windspeedAvg,curP=cm.pressure;
  if(curT==null){sumEl.innerHTML='<div style="color:var(--muted);font-size:.78rem">Ni dovolj lokalnih podatkov za analogni izračun.</div>';return;}
  const t3=recent.length>=4?recent[0].metric?.temp:null;
  const p3=recent.length>=4?recent[0].metric?.pressure:null;
  const dT3=(curT!=null&&t3!=null)?curT-t3:0;
  const dP3=(curP!=null&&p3!=null)?curP-p3:0;
  const rows=await aiFetchAnalogArchive();
  if(!rows||rows.length<100){sumEl.innerHTML='<div style="color:var(--muted);font-size:.78rem">Arhiv trenutno ni dosegljiv za analogni izračun.</div>';return;}
  const recs=rows.map(r=>{const dt=new Date(r.t);return{...r,dt,hour:dt.getHours()};});
  const byTime=new Map();recs.forEach(r=>byTime.set(r.dt.getTime(),r));
  const W={T:1/6,P:1/8,RH:1/18,Wind:1/10,dT:1/3,dP:1/4};
  const hourNow=new Date().getHours();
  const cand=[];
  recs.forEach(r=>{
    if(r.T==null)return;
    let dh=Math.abs(r.hour-hourNow);if(dh>12)dh=24-dh;
    if(dh>2)return;
    const prev=byTime.get(r.dt.getTime()-3*3600000);
    const rdT=prev&&prev.T!=null?r.T-prev.T:0;
    const rdP=prev&&prev.p!=null&&r.p!=null?r.p-prev.p:0;
    let dist=((r.T-curT)*W.T)**2;
    if(r.p!=null&&curP!=null)dist+=((r.p-curP)*W.P)**2;
    if(r.rh!=null&&curRH!=null)dist+=((r.rh-curRH)*W.RH)**2;
    if(r.w!=null&&curW!=null)dist+=((r.w-curW)*W.Wind)**2;
    dist+=((rdT-dT3)*W.dT)**2+((rdP-dP3)*W.dP)**2+dh*0.04;
    cand.push({r,dist});
  });
  if(cand.length<5){sumEl.innerHTML='<div style="color:var(--muted);font-size:.78rem">Premalo primerljivih analogov.</div>';return;}
  cand.sort((a,b)=>a.dist-b.dist);
  const K=Math.min(25,cand.length);const knn=cand.slice(0,K);
  const proj=new Array(AI_OUT_LEN).fill(0),projN=new Array(AI_OUT_LEN).fill(0);
  let rainSumAll=0,rainCnt=0;
  knn.forEach(c=>{
    let anyRain=0;
    for(let h=1;h<=AI_OUT_LEN;h++){
      const fut=byTime.get(c.r.dt.getTime()+h*3600000);
      if(fut&&fut.T!=null){proj[h-1]+=(fut.T-c.r.T);projN[h-1]++;}
      if(fut)anyRain+=fut.r||0;
    }
    rainSumAll+=anyRain;rainCnt++;
  });
  const projection=proj.map((s,h)=>projN[h]?curT+s/projN[h]:null);
  const avgRain=rainCnt?rainSumAll/rainCnt:0;
  const sim=dist=>Math.max(0,Math.round((1-Math.min(1,dist/3))*100));
  const bestSim=sim(knn[0].dist);
  const endT=projection[projection.length-1];
  const trendTxt=endT!=null?(endT-curT>0.8?`ogrelo na ~${endT.toFixed(0)} °C`:endT-curT<-0.8?`ohladilo na ~${endT.toFixed(0)} °C`:`ostalo okrog ${endT.toFixed(0)} °C`):'—';
  const rainTxt=avgRain>=1.5?` z dežjem (povp. ~${avgRain.toFixed(1)} mm)`:avgRain>=0.3?' z rahlimi padavinami':' brez izrazitih padavin';
  sumEl.innerHTML=`<div class="ai-analog-match">${bestSim}%</div><div class="ai-analog-headline">Najboljše ujemanje s preteklostjo. V <b>${K}</b> najbolj podobnih primerih se je v naslednjih 6 urah vreme ${trendTxt}${rainTxt}.</div>`;
  const seen=new Set(),top=[];
  for(const c of knn){const ds=c.r.dt.toISOString().slice(0,10);if(seen.has(ds))continue;seen.add(ds);top.push(c);if(top.length>=3)break;}
  const fmtDay=dt=>dt.toLocaleDateString('sl',{day:'numeric',month:'short',year:'numeric'});
  if(listEl)listEl.innerHTML=top.map(c=>{
    let endFut=null,rainSum=0;
    for(let h=1;h<=AI_OUT_LEN;h++){const f=byTime.get(c.r.dt.getTime()+h*3600000);if(f){if(f.T!=null)endFut=f.T;rainSum+=f.r||0;}}
    const dTxt=endFut!=null?`${c.r.T.toFixed(0)} °C → <b>${endFut.toFixed(0)} °C</b>`:`${c.r.T.toFixed(0)} °C`;
    const rTxt=rainSum>=0.3?` · 🌧 ${rainSum.toFixed(1)}mm`:'';
    return `<div class="ai-analog-card"><div class="ai-analog-date">${fmtDay(c.r.dt)}</div><div class="ai-analog-sim">ujemanje ${sim(c.dist)}% · ${String(c.r.hour).padStart(2,'0')}:00</div><div class="ai-analog-then">Naslednjih 6 h: ${dTxt}${rTxt}</div></div>`;
  }).join('');
  if(rngEl)rngEl.textContent=`${recs.length} ur · k=${K}`;
  _aiAnalogCache={projection,ts:Date.now()};
}

// ══════════════════════════════════════════════════════════
// ── SENSOR DIAGNOSTICS & CALIBRATION ─────────────────────
// ══════════════════════════════════════════════════════════
const METAR_KEY='wx-metar-v1';
let _metarData=null,_metarFetchTime=0,_aeModel=null,_aeNorm=null;
// One-time cleanup: remove bogus dP entries caused by inHg→hPa double-conversion bug
(()=>{try{const log=JSON.parse(localStorage.getItem(METAR_KEY)||'[]');const clean=log.filter(d=>d.dP==null||Math.abs(d.dP)<100);if(clean.length!==log.length)localStorage.setItem(METAR_KEY,JSON.stringify(clean));}catch(_){}})();

// ── METAR fetch (LJLJ = Ljubljana/Brnik) ─────────────────
async function fetchMETAR(){
  if(_metarData&&Date.now()-_metarFetchTime<30*60*1000)return _metarData;
  try{
    const r=await fetch(PROXY+'/metar?ids=LJLJ&hours=2',{cache:'no-store'});
    const arr=await r.json();
    if(!arr||!arr.length)throw new Error('Empty METAR');
    const m=arr[0];
    _metarData={
      station:'LJLJ',
      time:m.obsTime||m.reportTime||null,
      temp_c:m.temp,
      dewp_c:m.dewp,
      wind_kt:m.wspd,
      wind_dir:m.wdir,
      altim:m.altim,  // hPa for ICAO/European airports (FAA API returns hPa for non-US stations)
      vis:m.visib,
      wxString:m.wxString||'',
      rawText:m.rawOb||'',
      press_hpa:m.altim?+(+m.altim).toFixed(1):null,
    };
    _metarFetchTime=Date.now();
    // Store for calibration log
    const obs=_lastBriefObs?.metric||{};
    const myT=obs.temp??null;
    const myH=_lastBriefObs?.humidity??null;
    const myP=obs.pressure??null;
    if(myT!=null&&_metarData.temp_c!=null){
      const log=JSON.parse(localStorage.getItem(METAR_KEY)||'[]');
      log.push({t:Date.now(),dT:+(myT-_metarData.temp_c).toFixed(2),
        dH:myH&&_metarData.dewp_c!=null?+(myH-(100-5/3*(_metarData.temp_c-_metarData.dewp_c))).toFixed(1):null,
        dP:myP&&_metarData.press_hpa?+(myP-_metarData.press_hpa).toFixed(1):null});
      if(log.length>360)log.splice(0,log.length-360);
      localStorage.setItem(METAR_KEY,JSON.stringify(log));
    }
    return _metarData;
  }catch(e){console.warn('METAR:',e);return null;}
}

function renderMETAR(){
  const body=document.getElementById('metar-body');
  const upd=document.getElementById('metar-updated');
  if(!body)return;
  const md=_metarData;
  if(!md){body.innerHTML='<div class="clim-loading">METAR LJLJ ni dosegljiv. Preverite internetno povezavo.</div>';return;}
  const obs=_lastBriefObs?.metric||{};
  const myT=obs.temp??null,myH=_lastBriefObs?.humidity??null,myP=obs.pressure??null;
  const myW=obs.windSpeed??null;
  const fmtD=(v,u,warn,bad)=>{if(v==null)return'';const cls=Math.abs(v)>bad?'md-bad':Math.abs(v)>warn?'md-warn':'md-ok';const s=v>=0?'+':'';return`<span class="metar-delta ${cls}">${s}${v.toFixed(1)}${u}</span>`;};
  const dT=myT!=null&&md.temp_c!=null?myT-md.temp_c:null;
  const dP=myP!=null&&md.press_hpa?myP-md.press_hpa:null;
  // Estimated RH from METAR Td: RH ≈ 100 - 5/3*(T-Td)
  const metarRH=md.temp_c!=null&&md.dewp_c!=null?Math.round(100-5/3*(md.temp_c-md.dewp_c)):null;
  const dH=myH!=null&&metarRH!=null?myH-metarRH:null;
  const metarKmh=md.wind_kt!=null?+(md.wind_kt*1.852).toFixed(0):null;
  body.innerHTML=
    `<div class="metar-grid">
      <div class="metar-cell"><div class="metar-cell-val">${md.temp_c!=null?md.temp_c.toFixed(1)+'°C':'—'}</div><div class="metar-cell-lbl">METAR T</div>${dT!=null?fmtD(dT,'°C',1.5,3):''}</div>
      <div class="metar-cell"><div class="metar-cell-val">${md.dewp_c!=null?md.dewp_c.toFixed(1)+'°C':'—'}</div><div class="metar-cell-lbl">Rosišče LJLJ</div></div>
      <div class="metar-cell"><div class="metar-cell-val">${metarRH!=null?metarRH+'%':'—'}</div><div class="metar-cell-lbl">Vlaga (est.)</div>${dH!=null?fmtD(dH,'%',8,15):''}</div>
      <div class="metar-cell"><div class="metar-cell-val">${md.press_hpa??'—'} hPa</div><div class="metar-cell-lbl">QNH→hPa</div>${dP!=null?fmtD(dP,' hPa',2,5):''}</div>
      <div class="metar-cell"><div class="metar-cell-val">${metarKmh!=null?metarKmh+' km/h':'—'}</div><div class="metar-cell-lbl">Veter LJLJ</div></div>
      <div class="metar-cell"><div class="metar-cell-val">${md.wxString||'CAVOK'}</div><div class="metar-cell-lbl">Vreme LJLJ</div></div>
    </div>`+
    `<div style="font-size:.67rem;color:var(--muted);font-family:'JetBrains Mono',monospace;margin-top:.35rem;line-height:1.5">RAW: ${md.rawText||'—'}</div>`;
  if(upd)upd.textContent=md.time?new Date(md.time*1000||md.time).toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'})+'h LJLJ':'LJLJ';
}

// ── Anomaly scoring ───────────────────────────────────────
function runAnomalyScoring(){
  const body=document.getElementById('aq-body');
  const badge=document.getElementById('aq-score-badge');
  if(!body)return;
  const obs=_lastBriefObs||{},m=obs?.metric||{};
  const hourly=_hourlyObs||[];
  const T=m.temp??null,H=obs.humidity??null,P=m.pressure??null;
  const W=m.windSpeed??0,G=m.windGust??W,solar=m.solarRadiation??0;
  const WD=m.winddir??null;
  const rain=m.precipRate??0;
  // Get recent hourly arrays
  const recentH=hourly.slice(-6);
  const recentTemps=recentH.map(o=>o.metric?.temp).filter(v=>v!=null);
  const recentHums=recentH.map(o=>o.humidity).filter(v=>v!=null);
  const recentWD=hourly.slice(-10).map(o=>o.metric?.winddir??o.metric?.windDirection).filter(v=>v!=null);
  const sensors=[];

  // 1. Temperature sensor
  let tScore=100,tIssues=[];
  if(T!=null){
    // Solar heating: high solar + temp unusually high vs dew point spread
    const Td=H!=null?(T-(100-H)/5):null;
    const dpd=Td!=null?T-Td:null;
    if(solar>600&&dpd!=null&&dpd>12&&(new Date().getHours()>=10)&&(new Date().getHours()<=15)){tScore-=25;tIssues.push('Možno solarno segrevanje senzorja (solar='+Math.round(solar)+'W/m², DPD='+dpd.toFixed(1)+'°C)');}
    // Rapid change
    if(recentTemps.length>=3){const chg=Math.abs(recentTemps[recentTemps.length-1]-recentTemps[0]);if(chg>6)tIssues.push('Hitra sprememba T: '+chg.toFixed(1)+'°C/'+recentTemps.length+'h');}
    // Vs METAR
    if(_metarData?.temp_c!=null){const d=Math.abs(T-_metarData.temp_c);if(d>5){tScore-=20;tIssues.push('Velik odmik od METAR LJLJ: '+d.toFixed(1)+'°C');}else if(d>3){tScore-=10;}}
  }else{tScore=0;tIssues.push('Ni podatka o temperaturi');}
  sensors.push({icon:'🌡️',name:'Temperatura',score:tScore,issues:tIssues,unit:'°C',val:T!=null?T.toFixed(1)+'°C':'—'});

  // 2. Humidity sensor
  let hScore=100,hIssues=[];
  if(H!=null){
    // Stuck values
    if(recentHums.length>=4){const uniq=new Set(recentHums.map(v=>Math.round(v))).size;if(uniq===1){hScore-=35;hIssues.push('Senzor se zdi zagozdjen ('+recentHums.length+' enakih vrednosti)');}else if(uniq===2){hScore-=15;}}
    // Always 100%
    if(H>=100&&recentHums.filter(v=>v>=99).length===recentHums.length&&recentHums.length>=3){hScore-=20;hIssues.push('Vlaga 100% dlje časa — možna kondenzacija ali saturacija senzorja');}
    // Cross-check with T: T-Td spread inconsistency
    if(T!=null){const Td=T-(100-H)/5;if(H>90&&T>25){hScore-=10;hIssues.push('Visoka vlaga pri visoki T — nenavadna kombinacija');}}
  }else{hScore=0;hIssues.push('Ni podatka o vlagi');}
  sensors.push({icon:'💧',name:'Vlažnost',score:hScore,issues:hIssues,unit:'%',val:H!=null?Math.round(H)+'%':'—'});

  // 3. Rain gauge
  let rScore=100,rIssues=[];
  const storeToday=_insStore()[_localDateStr(new Date())];
  const todayRain=storeToday?.precipTotal??0;
  if(_metarData?.wxString?.match(/-RA|-SH|TS|DZ/)&&todayRain<0.2&&rain<0.1){
    rScore-=30;rIssues.push('METAR poroča padavine ('+(_metarData.wxString)+'), a postaja meri 0mm — možno zamašena/zamrznjena žlica');
  }
  if(rain>80){rScore-=25;rIssues.push('Ekstremna intenziteta '+rain.toFixed(1)+'mm/h — preverite');}
  sensors.push({icon:'🌧️',name:'Dežemer',score:rScore,issues:rIssues,unit:'mm',val:todayRain.toFixed(1)+'mm danes'});

  // 4. Wind vane
  let wvScore=100,wvIssues=[];
  if(recentWD.length>=5){
    const stuck=recentWD.every(d=>Math.abs(d-(recentWD[0]??0))<5);
    if(stuck&&recentWD.length>=5){wvScore-=40;wvIssues.push('Smer vetra zagozdjena pri '+Math.round(recentWD[0])+'° — preveri anemometer');}
    const allNorth=recentWD.every(d=>d<5||d>355);
    if(allNorth){wvScore-=35;wvIssues.push('Smer vedno 0°/360° — tipična okvara smernega kazalca');}
    if(G>0&&W>0){const ti=G/W;if(ti<1.05&&W>5){wvScore-=15;wvIssues.push('Sunek = povprečje — možno zagozdena anemometrska lopatica');}}
  }else wvIssues.push('Premalo urnih podatkov za analizo smeri');
  sensors.push({icon:'🌬️',name:'Vetromer & smer',score:wvScore,issues:wvIssues,unit:'km/h',val:W.toFixed(0)+'/'+G.toFixed(0)+' km/h'});

  // 5. Pressure sensor
  let pScore=100,pIssues=[];
  if(P!=null){
    if(_metarData?.press_hpa){const d=Math.abs(P-_metarData.press_hpa);if(d>6){pScore-=30;pIssues.push('Odmik od METAR QNH: '+d.toFixed(1)+' hPa — možen drift senzorja');}else if(d>3){pScore-=15;pIssues.push('Zmeren odmik od METAR QNH: '+d.toFixed(1)+' hPa');}}
    const pt=typeof pressureTrend3h==='function'?pressureTrend3h():null;
    if(pt!=null&&Math.abs(pt)>8){pScore-=20;pIssues.push('Ekstremno hitra sprememba tlaka: '+pt.toFixed(1)+' hPa/3h');}
  }else{pScore=0;pIssues.push('Ni podatka o tlaku');}
  sensors.push({icon:'📊',name:'Tlak',score:pScore,issues:pIssues,unit:'hPa',val:P!=null?P.toFixed(1)+' hPa':'—'});

  // 6. Solar radiation
  let sScore=100,sIssues=[];
  const hr=new Date().getHours();
  if(solar>1100){sScore-=25;sIssues.push('Solarno sevanje '+Math.round(solar)+' W/m² presega atmosferski maksimum (~1100)');}
  if((hr<5||hr>21)&&solar>50){sScore-=35;sIssues.push('Solarno sevanje ponoči/zvečer '+Math.round(solar)+' W/m² — napaka senzorja ali odboj');}
  sensors.push({icon:'☀️',name:'Solarno sevanje',score:sScore,issues:sIssues,unit:'W/m²',val:Math.round(solar)+' W/m²'});

  const overallScore=Math.round(sensors.reduce((s,x)=>s+x.score,0)/sensors.length);
  if(badge)badge.textContent='Skupna kakovost: '+overallScore+'%';

  body.innerHTML=sensors.map(s=>{
    const cls=s.score>=85?'aq-ok':s.score>=60?'aq-warn':'aq-bad';
    const label=s.score>=85?'OK':s.score>=60?'OPOZORILO':'NAPAKA';
    const detail=s.issues.length?s.issues.join(' · '):s.name+' senzor deluje normalno.';
    return`<div class="aq-sensor ${cls}">
      <div class="aq-sensor-left">
        <div class="aq-sensor-name">${s.icon} ${s.name} <span style="color:var(--muted);font-weight:400;font-size:.72rem">${s.val}</span></div>
        <div class="aq-sensor-detail">${detail}</div>
      </div>
      <div class="aq-score-wrap">
        <div class="aq-score">${s.score}%</div>
        <span class="aq-badge">${label}</span>
      </div>
    </div>`;
  }).join('');

  // Autoencoder anomaly note
  const aeNote=document.getElementById('aq-ae-note');
  if(aeNote&&_aeModel){
    aeNote.innerHTML='<strong style="color:var(--text)">Autoencoder:</strong> Model naložen — rekonstrukcijska napaka <span id="ae-recon-err">izračunam…</span>. Visoka napaka = anomalija.';
    // Run AE inference
    setTimeout(()=>runAEAnomaly(sensors),200);
  }else if(aeNote){
    aeNote.innerHTML='<strong style="color:var(--text)">Autoencoder — detekcija odmika:</strong> Dostopno po učenju modela LSTM v zavihku AI napoved.';
  }
}

// ── Autoencoder anomaly inference ────────────────────────
async function runAEAnomaly(sensors){
  if(!_aeModel||!_aiNorm)return;
  try{
    const obs=_lastBriefObs||{},m=obs?.metric||{};
    const T=m.temp??15,H=obs.humidity??65,W=m.windSpeed??0,rain=m.precipRate??0,P=m.pressure??1013;
    const now=new Date(),hr=now.getHours(),doy=Math.floor((now-new Date(now.getFullYear(),0,0))/864e5);
    const feat=[T,H,W,rain,P,Math.sin(2*Math.PI*hr/24),Math.cos(2*Math.PI*hr/24),Math.sin(2*Math.PI*doy/365)];
    const normFeat=feat.map((v,i)=>{const r=_aiNorm.maxs[i]-_aiNorm.mins[i];return r>0?(v-_aiNorm.mins[i])/r:0;});
    const inputT=tf.tensor2d([normFeat],[1,8]);
    const reconT=_aeModel.predict(inputT);
    const recon=Array.from(await reconT.data());
    inputT.dispose();reconT.dispose();
    const mse=normFeat.reduce((s,v,i)=>s+(v-recon[i])**2,0)/normFeat.length;
    const el=document.getElementById('ae-recon-err');
    if(el){
      const cls=mse<0.01?'#4ade80':mse<0.05?'var(--amber)':'#f87171';
      const lbl=mse<0.01?'normalno':mse<0.05?'rahlo zvišana':'ANOMALIJA';
      el.innerHTML=`<strong style="color:${cls}">${mse.toFixed(5)} (${lbl})</strong>`;
    }
  }catch(e){console.warn('AE inference:',e);}
}

// ── Build & train autoencoder (reuses tf from LSTM) ───────
async function buildAndTrainAE(){
  if(typeof tf==='undefined'||typeof tf.sequential!=='function')return;
  const raw=aiExtractFeatures(_hourlyObs||[]);
  if(raw.length<20)return;
  const normData=aiNormalize(raw,_aiNorm||aiComputeNorm(raw));
  if(!_aiNorm)_aiNorm=aiComputeNorm(raw);
  const model=tf.sequential();
  model.add(tf.layers.dense({units:16,activation:'relu',inputShape:[AI_N_FEAT]}));
  model.add(tf.layers.dense({units:8,activation:'relu'}));
  model.add(tf.layers.dense({units:4,activation:'relu'}));  // bottleneck
  model.add(tf.layers.dense({units:8,activation:'relu'}));
  model.add(tf.layers.dense({units:16,activation:'relu'}));
  model.add(tf.layers.dense({units:AI_N_FEAT,activation:'linear'}));
  model.compile({optimizer:tf.train.adam(0.002),loss:'meanSquaredError'});
  const xT=tf.tensor2d(normData);
  await model.fit(xT,xT,{epochs:40,batchSize:16,shuffle:true,verbose:0});
  xT.dispose();
  _aeModel=model;
  const note=document.getElementById('aq-ae-note');
  if(note)note.innerHTML='<strong style="color:var(--text)">Autoencoder naučen</strong> ('+raw.length+' vzorcev, 40 epoh). Osvežujem diagnostiko…';
  setTimeout(()=>runAnomalyScoring(),300);
}

// ── Statistical t-test ────────────────────────────────────
function tTest1Sample(samples){
  const n=samples.length;
  if(n<1)return{t:0,p:1,sig:false,mean:0,se:0,std:0,n};
  const mean=samples.reduce((a,b)=>a+b,0)/n;
  if(n<2)return{t:0,p:1,sig:false,mean:+mean.toFixed(3),se:0,std:0,n};
  const std=Math.sqrt(samples.reduce((s,x)=>s+(x-mean)**2,0)/(n-1));
  const se=std/Math.sqrt(n);
  const t=se>0?mean/se:0;
  const at=Math.abs(t);
  const p=at>4?0.0001:at>3.29?0.001:at>2.58?0.01:at>1.96?0.05:at>1.65?0.1:0.2;
  return{t,p,sig:at>2.0,mean:+mean.toFixed(3),se:+se.toFixed(3),std:+std.toFixed(3),n,at};
}

function renderCalibration(){
  const body=document.getElementById('cal-body');
  const badge=document.getElementById('cal-samples-badge');
  if(!body)return;
  // dnevnik odmikov ARSO
  const arsoDrifts=JSON.parse(localStorage.getItem(ARSO_DRIFT_KEY)||'[]').filter(d=>d.t>Date.now()-14*864e5);
  // METAR drift log
  const metarDrifts=JSON.parse(localStorage.getItem(METAR_KEY)||'[]').filter(d=>d.t>Date.now()-14*864e5);
  const combined=[...arsoDrifts,...metarDrifts];
  if(badge)badge.textContent=combined.length+' meritev (14 dni)';
  if(combined.length<1){body.innerHTML='<div class="clim-loading">Zbira se podatke za kalibracijo. Odprite ta zavihek še nekajkrat čez dan.</div>';return;}
  const lowData=combined.length<5;
  // Temperature calibration
  const tSamples=[...arsoDrifts.map(d=>d.dT),...metarDrifts.map(d=>d.dT)].filter(v=>v!=null);
  const hSamples=[...arsoDrifts.map(d=>d.dH),...metarDrifts.map(d=>d.dH)].filter(v=>v!=null);
  const pSamples=metarDrifts.map(d=>d.dP).filter(v=>v!=null);
  const tTest=tTest1Sample(tSamples);
  const hTest=tTest1Sample(hSamples);
  const pTest=tTest1Sample(pSamples);
  const fmtCard=(label,unit,test,icon,hint)=>{
    const sigClass=test.sig?'cal-card-sig':'';
    const sigLabel=test.n<2?'PREMALO PODATKOV':test.sig?'STATISTIČNO SIGNIFIKANTNO':'BREZ KOREKCIJE';
    const sigCls=test.n<2?'cal-sig-no':test.sig?'cal-sig-yes':'cal-sig-no';
    const ci95=test.se>0?(test.se*1.96).toFixed(3):null;
    const rec=test.n<2
      ?`Preliminarni odmik: <b style="color:var(--text)">${test.mean>=0?'+':''}${test.mean.toFixed(2)}${unit}</b>. Statistični test zahteva n≥2.`
      :test.sig?`Predlagana korekcija: <b style="color:var(--text)">${test.mean>=0?'+':''}${test.mean.toFixed(2)}${unit}</b> (95% CI: ±${ci95}${unit})`:`Odmik postaje ni statistično signifikanten. Senzor je v kalibraciji.`;
    const stat=test.n<2?`n=${test.n} · samo povprečje`:`n=${test.n} · t=${test.t.toFixed(2)} · p≈${test.p} · σ=${test.std}${unit}`;
    return`<div class="cal-card ${sigClass}">
      <div class="cal-label">${icon} ${label}</div>
      <div class="cal-offset">${test.mean>=0?'+':''}${test.mean.toFixed(2)}<span style="font-size:.8rem;color:var(--muted)">${unit}</span></div>
      <div class="cal-stat">${stat}</div>
      <span class="cal-sig-badge ${sigCls}">${sigLabel}</span>
      <div style="font-size:.67rem;color:var(--muted);margin-top:.4rem;line-height:1.4">${rec}<br><span style="opacity:.7">${hint}</span></div>
    </div>`;
  };
  const lowDataNote=lowData?`<div style="font-size:.7rem;color:var(--warning,#f59e0b);margin-bottom:.75rem;padding:.4rem .6rem;border:1px solid currentColor;border-radius:6px;opacity:.85">⚠ Malo podatkov (n=${combined.length}/5) — rezultati so preliminarni. Natančnost se izboljša z več meritvami.</div>`:'';
  body.innerHTML= lowDataNote+
    fmtCard('Temperatura','°C',tTest,'🌡️','Primerjano z ARSO + METAR LJLJ.')+
    fmtCard('Vlažnost','%',hTest,'💧','Vlaga METAR izračunana iz T in Td.')+
    (pSamples.length>=2?fmtCard('Tlak','hPa',pTest,'📊','QNH → hPa + nadmorska korekcija.'):
    '<div class="cal-card"><div class="cal-label">📊 Tlak</div><div class="cal-stat">Premalo METAR primerjav.</div></div>');
}

async function initSensorDiag(){
  // Reveal the diagnostics section by moving into AI tab
  const host=document.getElementById('tab-ai-diag');
  const aiTab=document.getElementById('tab-ai');
  if(host&&aiTab&&host.style.display==='none'){
    host.style.display='';
    aiTab.appendChild(host);
  }
  // Fetch METAR
  await fetchMETAR();
  renderMETAR();
  runAnomalyScoring();
  renderCalibration();
  // Train AE if LSTM already trained and TF available
  if(typeof tf!=='undefined'&&typeof tf.sequential==='function'&&_aiNorm){
    setTimeout(buildAndTrainAE,500);
  }
}

// ══════════════════════════════════════════════════════════
// ── DATA ASSIMILATION — Kalman / 3D-Var / O-B ─────────────
// ══════════════════════════════════════════════════════════
const KF_KEY='wx-kf-state-v1';
const OB_KEY='wx-ob-log-v1';
let _daInit=false;

// ── Scalar Kalman filter helper ───────────────────────────
// Single prediction-update cycle for one scalar state variable
function kfPredict(x,P,Q){return{x,P:P+Q};}
function kfUpdate(x,P,obs,R){
  const K=P/(P+R);           // Kalman gain
  const x_new=x+K*(obs-x);  // updated estimate
  const P_new=(1-K)*P;       // updated covariance
  return{x:x_new,P:P_new,K};
}
// Fuse multiple observations sequentially (optimal with independent obs)
function kfFuseObs(x0,P0,observations){
  let x=x0,P=P0;
  const gains=[];
  observations.forEach(o=>{
    if(o.value==null)return;
    const r=kfUpdate(x,P,o.value,o.sigma*o.sigma);
    x=r.x;P=r.P;gains.push({name:o.name,K:r.K,value:o.value,sigma:o.sigma});
  });
  return{x,P,uncertainty:Math.sqrt(P),gains};
}

// Persistent Kalman state storage
function kfLoadState(){
  try{return JSON.parse(localStorage.getItem(KF_KEY)||'{}');}catch(e){return{};}
}
function kfSaveState(state){
  try{localStorage.setItem(KF_KEY,JSON.stringify(state));}catch(e){}
}

// ── Run Kalman filter ─────────────────────────────────────
async function runKalmanFilter(){
  const saved=kfLoadState();
  const obs=_lastBriefObs||{},m=obs?.metric||{};
  const now=Date.now();
  const dt_h=saved.ts?Math.min(3,(now-saved.ts)/3600000):1;

  // Station observations
  const T_sta=m.temp??null,H_sta=obs.humidity??null,P_sta=m.pressure??null;

  // Open-Meteo background (from existing SC fetch or direct)
  const omH=_scData?.temperature_2m;
  const ci=omH?(()=>{const times=(_scData?.time||[]).map(t=>new Date(t));let ci=times.findIndex(t=>t>=new Date())-1;return Math.max(0,ci);})():null;
  const T_om=ci!=null?(_scData?.temperature_2m?.[ci]??null):null;
  const H_om=ci!=null?(_scData?.relative_humidity_2m?.[ci]??null):null;

  // METAR (already fetched)
  const T_metar=_metarData?.temp_c??null;
  const H_metar=_metarData?.dewp_c!=null?Math.round(100-5/3*(_metarData.temp_c-_metarData.dewp_c)):null;
  const P_metar=_metarData?.press_hpa??null;

  // Process noise per hour (how much state drifts: σ² per hour)
  const Q={T:0.4,H:4,P:0.2};
  // Observation error variances (σ²):
  const R={T_sta:0.09,T_om:2.25,T_metar:0.64,  // 0.3°C, 1.5°C, 0.8°C
           H_sta:4,   H_om:25,   H_metar:16,
           P_sta:0.09,P_metar:1};

  // Initial state from station if no saved state
  const xT_0=saved.T?.x??(T_sta??T_om??15);
  const xH_0=saved.H?.x??(H_sta??H_om??65);
  const xP_0=saved.P?.x??(P_sta??P_metar??1013);
  const PT_0=saved.T?.P??4,PH_0=saved.H?.P??100,PP_0=saved.P?.P??9;

  // Predict step
  const predT=kfPredict(xT_0,PT_0,Q.T*dt_h);
  const predH=kfPredict(xH_0,PH_0,Q.H*dt_h);
  const predP=kfPredict(xP_0,PP_0,Q.P*dt_h);

  // Update with all available observations
  const fusedT=kfFuseObs(predT.x,predT.P,[
    {name:'Postaja',value:T_sta,sigma:Math.sqrt(R.T_sta)},
    {name:'Open-Meteo',value:T_om,sigma:Math.sqrt(R.T_om)},
    {name:'METAR LJLJ',value:T_metar,sigma:Math.sqrt(R.T_metar)},
  ]);
  const fusedH=kfFuseObs(predH.x,predH.P,[
    {name:'Postaja',value:H_sta,sigma:Math.sqrt(R.H_sta)},
    {name:'Open-Meteo',value:H_om,sigma:Math.sqrt(R.H_om)},
  ]);
  const fusedP=kfFuseObs(predP.x,predP.P,[
    {name:'Postaja',value:P_sta,sigma:Math.sqrt(R.P_sta)},
    {name:'METAR LJLJ',value:P_metar,sigma:Math.sqrt(R.P_metar)},
  ]);

  // Save state
  kfSaveState({T:{x:fusedT.x,P:fusedT.P},H:{x:fusedH.x,P:fusedH.P},P:{x:fusedP.x,P:fusedP.P},ts:now});

  // Render
  const g=id=>document.getElementById(id);
  const fmtV=(v,dec)=>v!=null?v.toFixed(dec):'—';
  if(g('kf-t'))g('kf-t').textContent=fmtV(fusedT.x,1);
  if(g('kf-t-unc'))g('kf-t-unc').textContent=fmtV(fusedT.uncertainty,2);
  if(g('kf-t-gain'))g('kf-t-gain').style.width=((fusedT.gains[0]?.K||0)*100).toFixed(0)+'%';
  if(g('kf-h'))g('kf-h').textContent=fmtV(fusedH.x,0);
  if(g('kf-h-unc'))g('kf-h-unc').textContent=fmtV(fusedH.uncertainty,1);
  if(g('kf-h-gain'))g('kf-h-gain').style.width=((fusedH.gains[0]?.K||0)*100).toFixed(0)+'%';
  if(g('kf-p'))g('kf-p').textContent=fmtV(fusedP.x,1);
  if(g('kf-p-unc'))g('kf-p-unc').textContent=fmtV(fusedP.uncertainty,2);
  if(g('kf-p-gain'))g('kf-p-gain').style.width=((fusedP.gains[0]?.K||0)*100).toFixed(0)+'%';

  const srcDiv=g('kf-sources');
  if(srcDiv){
    const allGains=[...fusedT.gains.map(g=>({...g,var:'T',unit:'°C'})),...fusedH.gains.map(g=>({...g,var:'H',unit:'%'})),...fusedP.gains.map(g=>({...g,var:'P',unit:' hPa'}))];
    const byName={};
    allGains.forEach(g=>{if(!byName[g.name])byName[g.name]={name:g.name,items:[]};byName[g.name].items.push(g);});
    srcDiv.innerHTML=Object.values(byName).map(src=>{
      const avgK=src.items.reduce((s,i)=>s+i.K,0)/src.items.length;
      const vals=src.items.map(i=>`${i.var}:${i.value!=null?i.value.toFixed(1):'—'}${i.unit}`).join(' · ');
      const colW=Math.round(avgK*100);
      const col=avgK>0.7?'#4ade80':avgK>0.4?'var(--amber)':'var(--blue)';
      return`<div class="kf-src"><span class="kf-src-name">${src.name}</span><span class="kf-src-sigma">σ: ±${src.items[0].sigma.toFixed(1)}</span><span class="kf-src-val">${vals.split(' · ')[0].split(':')[1]}</span><div class="kf-src-bar"><div class="kf-src-fill" style="width:${colW}%;background:${col};height:100%"></div></div><span style="font-size:.62rem;color:var(--muted);width:36px;flex-shrink:0">K=${(avgK).toFixed(2)}</span></div>`;
    }).join('');
  }
  if(g('kf-updated'))g('kf-updated').textContent=`±σ T:${fusedT.uncertainty.toFixed(2)}°C  H:${fusedH.uncertainty.toFixed(1)}%  P:${fusedP.uncertainty.toFixed(2)}hPa`;
}

// ── 3D-Var analysis ───────────────────────────────────────
async function buildThreeDVar(){
  const svg=document.getElementById('var3d-svg');
  const rng=document.getElementById('var3d-range');
  if(!svg)return;
  svg.innerHTML='<text x="300" y="150" text-anchor="middle" font-size="11" fill="rgba(128,128,128,.3)" font-family="Inter,sans-serif">Nalaganje ozadja …</text>';

  // Grid: 6×4 points over Slovenia approx.
  // Lat: 45.5, 46.0, 46.5, 47.0  Lon: 13.5, 14.5, 15.5, 16.0, 16.5
  const lats=[45.5,46.0,46.5,47.0];
  const lons=[13.5,14.2,15.0,15.8,16.5,17.0];
  const latStr=lats.join(',');
  const lonStr=lons.join(',');

  try{
    const url=`https://api.open-meteo.com/v1/forecast?latitude=${latStr}&longitude=${lonStr}&current=temperature_2m&timezone=Europe%2FLjubljana`;
    const r=await fetch(url);const d=await r.json();

    // Extract background temperatures (may be returned as array or single)
    const bkgTemps=[];
    if(Array.isArray(d)){d.forEach(pt=>bkgTemps.push(pt.current?.temperature_2m??15));}
    else{bkgTemps.push(d.current?.temperature_2m??15);}
    // Fill to grid size if needed
    while(bkgTemps.length<lats.length*lons.length)bkgTemps.push(bkgTemps[bkgTemps.length-1]??15);

    // Our observation
    const T_obs=(_lastBriefObs?.metric?.temp)??15;
    const obs_lat=LAT,obs_lon=LON;
    const sigma_B=1.2,sigma_obs=0.3,L_km=80; // correlation length

    // Apply 3D-Var analysis increment at each grid point
    const analysis=lats.flatMap((lat,li)=>lons.map((lon,loi)=>{
      const idx=li*lons.length+loi;
      const xb=bkgTemps[idx]??15;
      // Distance from our station to this grid point
      const dLat=(lat-obs_lat)*111.0,dLon=(lon-obs_lon)*111.0*Math.cos(obs_lat*Math.PI/180);
      const d_km=Math.sqrt(dLat*dLat+dLon*dLon);
      // Gaussian background error correlation
      const rho=Math.exp(-(d_km*d_km)/(2*L_km*L_km));
      // Analysis increment: Δx = B·Hᵀ(H·B·Hᵀ+R)⁻¹·(y-Hxb)
      const S=sigma_B**2+sigma_obs**2;
      const gain=sigma_B**2*rho/S;
      const innov=T_obs-xb;
      const xa=xb+gain*innov;
      return{lat,lon,xb,xa,increment:xa-xb};
    }));

    // Draw SVG
    const W=600,VH=300,pl=30,pr=30,pt=20,pb=30;
    const latMin=Math.min(...lats)-0.3,latMax=Math.max(...lats)+0.3;
    const lonMin=Math.min(...lons)-0.3,lonMax=Math.max(...lons)+0.3;
    const mapX=lon=>pl+(lon-lonMin)/(lonMax-lonMin)*(W-pl-pr);
    const mapY=lat=>pt+(1-(lat-latMin)/(latMax-latMin))*(VH-pt-pb);
    const allXa=analysis.map(a=>a.xa);
    const minT=Math.min(...allXa)-0.5,maxT=Math.max(...allXa)+0.5;

    // Color scale: blue→cyan→yellow→orange→red
    const tempColor=t=>{
      const p=Math.max(0,Math.min(1,(t-minT)/(maxT-minT)));
      const stops=[[30,64,175],[37,99,235],[147,197,253],[253,224,71],[249,115,22],[220,38,38]];
      const seg=p*(stops.length-1),i=Math.min(stops.length-2,Math.floor(seg)),f=seg-i;
      const c=stops[i].map((v,j)=>Math.round(v+(stops[i+1][j]-v)*f));
      return`rgb(${c.join(',')})`;
    };

    const cellW=(W-pl-pr)/lons.length,cellH=(VH-pt-pb)/lats.length;
    let html='';
    analysis.forEach(a=>{
      const x=mapX(a.lon)-cellW/2,y=mapY(a.lat)-cellH/2;
      html+=`<rect x="${x.toFixed(1)}" y="${y.toFixed(1)}" width="${cellW.toFixed(1)}" height="${cellH.toFixed(1)}" fill="${tempColor(a.xa)}" opacity="0.85"/>`;
      html+=`<text x="${(x+cellW/2).toFixed(1)}" y="${(y+cellH/2+4).toFixed(1)}" text-anchor="middle" font-size="9" font-family="JetBrains Mono,monospace" fill="rgba(255,255,255,.85)" font-weight="500">${a.xa.toFixed(1)}</text>`;
      // Show increment as +/- overlay
      if(Math.abs(a.increment)>0.05){const c=a.increment>0?'#fde68a':'#93c5fd';html+=`<text x="${(x+cellW/2).toFixed(1)}" y="${(y+cellH/2+14).toFixed(1)}" text-anchor="middle" font-size="7" font-family="JetBrains Mono,monospace" fill="${c}">${a.increment>0?'+':''}${a.increment.toFixed(2)}</text>`;}
    });
    // Station marker
    const sx=mapX(obs_lon),sy=mapY(obs_lat);
    html+=`<circle cx="${sx.toFixed(1)}" cy="${sy.toFixed(1)}" r="8" fill="white" stroke="#1d4ed8" stroke-width="2.5"/>`;
    html+=`<text x="${sx.toFixed(1)}" y="${(sy-12).toFixed(1)}" text-anchor="middle" font-size="9" fill="white" font-weight="700" font-family="Inter,sans-serif">IREICA1</text>`;
    html+=`<text x="${sx.toFixed(1)}" y="${(sy-2).toFixed(1)}" text-anchor="middle" font-size="8" fill="#1d4ed8" font-weight="700" font-family="JetBrains Mono,monospace">${(_lastBriefObs?.metric?.temp??'—').toString().slice(0,4)}</text>`;
    // Lat/lon axis labels
    lons.forEach((lon,i)=>html+=`<text x="${mapX(lon).toFixed(1)}" y="${VH-8}" text-anchor="middle" font-size="8" fill="var(--muted)" font-family="JetBrains Mono,monospace">${lon.toFixed(1)}°E</text>`);
    lats.forEach((lat,i)=>html+=`<text x="${pl-4}" y="${mapY(lat).toFixed(1)}" text-anchor="end" dominant-baseline="middle" font-size="8" fill="var(--muted)" font-family="JetBrains Mono,monospace">${lat.toFixed(1)}°N</text>`);
    svg.innerHTML=html;
    if(rng)rng.textContent=`Analiza: T_obs=${(_lastBriefObs?.metric?.temp??'—').toString().slice(0,4)}°C · L = 80 km · σ_B = 1,2 °C`;
  }catch(e){
    svg.innerHTML=`<text x="300" y="150" text-anchor="middle" font-size="11" fill="rgba(128,128,128,.4)" font-family="Inter,sans-serif">3D-Var API ni dosegljiv.</text>`;
    console.warn('3D-Var:',e);
  }
}

// ── O-B tracking ──────────────────────────────────────────
function updateOBLog(){
  const obs=_lastBriefObs?.metric||{};
  const T_sta=obs.temp??null;
  if(T_sta==null)return;
  // NWP first-guess: Open-Meteo current hour temperature
  const ci=_scData?.temperature_2m?((()=>{const times=(_scData.time||[]).map(t=>new Date(t));let i=times.findIndex(t=>t>=new Date())-1;return Math.max(0,i);})()):-1;
  const T_om=ci>=0?(_scData?.temperature_2m?.[ci]??null):null;
  const T_metar=_metarData?.temp_c??null;
  if(T_om==null&&T_metar==null)return;
  const log=JSON.parse(localStorage.getItem(OB_KEY)||'[]');
  log.push({t:Date.now(),T_sta,T_om,T_metar,ob_om:T_om!=null?+(T_sta-T_om).toFixed(2):null,ob_metar:T_metar!=null?+(T_sta-T_metar).toFixed(2):null});
  // Keep 30 days
  const cutoff=Date.now()-30*864e5;
  const trimmed=log.filter(e=>e.t>cutoff);
  if(trimmed.length>720)trimmed.splice(0,trimmed.length-720);
  try{localStorage.setItem(OB_KEY,JSON.stringify(trimmed));}catch(e){}
}

function renderOBTracking(){
  const stats=document.getElementById('ob-stats');
  const svgEl=document.getElementById('ob-svg');
  const badge=document.getElementById('ob-count-badge');
  if(!stats||!svgEl)return;
  const log=JSON.parse(localStorage.getItem(OB_KEY)||'[]').filter(e=>e.ob_om!=null);
  if(!badge){}else badge.textContent=log.length+' opazovanj';
  if(log.length<3){stats.innerHTML='<div class="clim-loading" style="grid-column:1/-1">Zbiranje O-B statistik… potrebno vsaj 3 meritvi z Open-Meteo podatki.</div>';svgEl.innerHTML='';return;}

  const obs=log.map(e=>e.ob_om);
  const n=obs.length;
  const mean=+(obs.reduce((a,b)=>a+b,0)/n).toFixed(3);
  const std=+(Math.sqrt(obs.reduce((s,x)=>s+(x-mean)**2,0)/(n-1))).toFixed(3);
  const latest=obs[obs.length-1].toFixed(2);
  // Autocorrelation lag-1
  const ac1=n>5?+(obs.slice(0,-1).reduce((s,v,i)=>(s+(v-mean)*(obs[i+1]-mean)),0)/((n-1)*std**2||1)).toFixed(2):null;
  // Bias class
  const biasClass=Math.abs(mean)<0.3?'ob-bias-good':Math.abs(mean)<0.8?'ob-bias-warn':'ob-bias-bad';
  const biasTxt=Math.abs(mean)<0.3?'Brez biasa':Math.abs(mean)<0.8?'Zmeren bias':'⚠️ Sistematičen bias';

  stats.innerHTML=[
    {v:mean+'°C',l:'Srednji O-B',c:biasClass},
    {v:'±'+std+'°C',l:'Std odmik',c:''},
    {v:latest+'°C',l:'Zadnji O-B',c:obs[obs.length-1]>0?'ob-bias-bad':obs[obs.length-1]<-0.3?'ob-bias-warn':'ob-bias-good'},
    {v:ac1!=null?ac1:'—',l:'Lag-1 avtokor.',c:''},
  ].map(s=>`<div class="ob-stat"><div class="ob-stat-val ${s.c}">${s.v}</div><div class="ob-stat-lbl">${s.l}</div></div>`).join('');

  // Draw O-B time series
  const VW=880,VH=130,pl=42,pr=15,pt=8,pb=28;
  const times=log.map(e=>e.t);
  const minT2=Math.min(...times),maxT2=Math.max(...times);
  const minV=Math.min(...obs,-1),maxV=Math.max(...obs,1);
  const mapX=t=>pl+(t-minT2)/Math.max(1,maxT2-minT2)*(VW-pl-pr);
  const mapY=v=>pt+(1-(v-minV)/(maxV-minV||1))*(VH-pt-pb);
  const zy=mapY(0).toFixed(1);
  let h=`<line x1="${pl}" x2="${VW-pr}" y1="${zy}" y2="${zy}" stroke="rgba(255,255,255,.15)" stroke-width="1"/>`;
  // Mean line
  const my=mapY(mean).toFixed(1);
  h+=`<line x1="${pl}" x2="${VW-pr}" y1="${my}" y2="${my}" stroke="${Math.abs(mean)<0.3?'#4ade80':'#fbbf24'}" stroke-width="1" stroke-dasharray="5,3" opacity="0.6"/>`;
  // Y axis
  [minV,0,mean,maxV].forEach(v=>{const y=mapY(v).toFixed(1);h+=`<text x="${pl-4}" y="${y}" text-anchor="end" font-size="8" fill="var(--muted)" font-family="JetBrains Mono,monospace" dominant-baseline="middle">${v.toFixed(1)}</text>`;});
  // Colored area under curve
  const ptsPoly=log.map(e=>`${mapX(e.t).toFixed(1)},${mapY(e.ob_om).toFixed(1)}`);
  h+=`<polygon points="${mapX(minT2)},${zy} ${ptsPoly.join(' ')} ${mapX(maxT2)},${zy}" fill="${mean>0?'rgba(248,113,113,.12)':'rgba(96,165,250,.12)'}"/>`;
  // Line
  h+=`<polyline points="${ptsPoly.join(' ')}" fill="none" stroke="${mean>0.3?'#f87171':mean<-0.3?'#60a5fa':'#4ade80'}" stroke-width="1.8" stroke-linejoin="round"/>`;
  // X axis dates (every ~10 points)
  const step=Math.max(1,Math.floor(log.length/6));
  log.filter((_,i)=>i%step===0).forEach(e=>{h+=`<text x="${mapX(e.t).toFixed(1)}" y="${VH-5}" text-anchor="middle" font-size="8" fill="var(--muted)" font-family="JetBrains Mono,monospace">${new Date(e.t).toLocaleDateString('sl',{day:'numeric',month:'short'})}</text>`;});
  h+=`<text x="${pl+5}" y="${pt+12}" font-size="9" fill="var(--muted)" font-family="Inter,sans-serif">${biasTxt}</text>`;
  svgEl.innerHTML=h;
}

async function initDA(){
  if(!_daInit){
    _daInit=true;
    // Inject DA cards into analysis tab
    const host=document.getElementById('tab-da-host');
    const analysisTab=document.getElementById('tab-analysis');
    if(host&&analysisTab&&host.style.display==='none'){
      host.style.display='';
      analysisTab.appendChild(host);
    }
  }
  // Run all three
  updateOBLog();
  try{await runKalmanFilter();}catch(e){console.warn('KF:',e);}
  try{await buildThreeDVar();}catch(e){console.warn('3DVar:',e);}
  renderOBTracking();
}

