// ── ARSO postaje vzdolž Savinje ───────────────────────────
async function fetchArsoStations(){
  const el=document.getElementById('arso-stations-body');
  const upd=document.getElementById('arso-stations-updated');
  if(!el)return;
  try{
    const ctrl=new AbortController();const tid=setTimeout(()=>ctrl.abort(),8000);
    const r=await fetch(PROXY+'/arso-water',{signal:ctrl.signal}).finally(()=>clearTimeout(tid));
    if(!r.ok)throw new Error('HTTP '+r.status);
    const d=await r.json();
    const stations=d.stations||[];
    if(!stations.length){el.innerHTML='<div class="clim-loading" style="color:var(--muted)">Podatki ARSO postaj trenutno nedostopni</div>';return;}
    const T=_RIVER_THRESHOLDS;
    let html='<div class="arso-stations">';
    for(const st of stations){
      const p=st.properties||{};
      const name=(p.postaja||p.name||p.station||'ARSO').replace(/\s*\(.*?\)/g,'').trim();
      const h=p.vodostaj!=null?p.vodostaj:(p.h!=null?p.h:'—');
      const q=p.pretok!=null?p.pretok:(p.q!=null?p.q:null);
      const tw=p.temperatura??p.TW??p.tw??p.T??null;
      const coords=st.geometry?.coordinates;
      const reka=(p.reka||p.river||'Savinja');
      let pillCls='normal',pillTxt='Normalen';
      if(q!=null){
        if(q>=T.alarm){pillCls='alarm';pillTxt='Alarm';}
        else if(q>=T.warning){pillCls='warning';pillTxt='Opozorilo';}
        else if(q>=T.raised){pillCls='raised';pillTxt='Povečan';}
      }
      const twCol=tw!=null?(Number(tw)<10?'var(--blue)':Number(tw)<18?'#34d399':'#fbbf24'):'';
      html+=`<div class="arso-st">`+
        `<div class="arso-st-name" title="${name}">${name}</div>`+
        `<div class="arso-st-row"><span class="arso-st-val" style="color:var(--blue)">${h!=='—'?Number(h).toFixed(0):h}</span><span class="arso-st-unit">cm</span></div>`+
        (q!=null?`<div class="arso-st-row"><span class="arso-st-val" style="color:var(--cyan)">${Number(q).toFixed(1)}</span><span class="arso-st-unit">m³/s</span></div>`:'')+
        (tw!=null?`<div class="arso-st-row"><span class="arso-st-val" style="color:${twCol}">${Number(tw).toFixed(1)}</span><span class="arso-st-unit">°C vode</span></div>`:'')+
        `<div><span class="arso-st-pill ${pillCls}">${pillTxt}</span></div>`+
        `</div>`;
    }
    html+='</div>';
    el.innerHTML=html;
    if(upd)upd.textContent='ARSO · '+new Date().toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'});
  }catch(e){
    if(el)el.innerHTML='<div class="clim-loading" style="color:var(--muted)">ARSO postaje začasno nedostopne</div>';
  }
}

// ── Temperatura vode Savinje ──────────────────────────────
async function fetchWaterTemp(){
  const el=document.getElementById('water-temp-body');
  const upd=document.getElementById('water-temp-updated');
  if(!el)return;
  try{
    const ctrl=new AbortController();const tid=setTimeout(()=>ctrl.abort(),8000);
    const r=await fetch(PROXY+'/arso-water',{signal:ctrl.signal}).finally(()=>clearTimeout(tid));
    if(!r.ok)throw new Error('HTTP '+r.status);
    const d=await r.json();
    const stations=d.stations||[];
    const stationTemps=[];
    for(const st of stations){
      const p=st.properties||{};
      const name=(p.postaja||p.name||p.station||'ARSO').replace(/\s*\(.*?\)/g,'').trim();
      const temp=p.temperatura??p.TW??p.tw??p.T??null;
      if(temp!=null)stationTemps.push({name,temp:Number(temp)});
    }
    if(stationTemps.length){_renderWaterTemp(stationTemps,null,upd);return;}
    // Fallback: ocena temperature vode iz trenutne temperature zraka
    // T_voda ≈ 0.75 * T_zrak + 2 °C (empirična formula za alpske reke)
    const omUrl='https://api.open-meteo.com/v1/forecast?latitude='+LAT+'&longitude='+LON
      +'&current=temperature_2m&timezone=Europe%2FLjubljana';
    const om=await fetch(omUrl).then(r2=>r2.json());
    const tAir=om?.current?.temperature_2m;
    if(tAir!=null){
      const est=Math.max(0.5,Math.min(28,tAir*0.75+2));
      _renderWaterTemp([],est,upd);
    }else{
      el.innerHTML='<div class="clim-loading" style="color:var(--muted)">Podatki o temperaturi vode trenutno niso dosegljivi</div>';
      if(upd)upd.textContent='ARSO · ni podatkov';
    }
  }catch(e){
    if(el)el.innerHTML='<div class="clim-loading" style="color:var(--muted)">Temperatura vode začasno nedostopna</div>';
  }
}

function _renderWaterTemp(stationTemps,fallbackTemp,upd){
  const el=document.getElementById('water-temp-body');if(!el)return;
  const isArso=stationTemps.length>0;
  const temp=isArso?stationTemps[0].temp:fallbackTemp;
  const tempCol=temp<5?'#93c5fd':temp<10?'#60a5fa':temp<18?'#34d399':temp<24?'#fbbf24':'#f87171';
  const statusLbl=temp<5?'Zelo hladna':temp<10?'Hladna':temp<18?'Prijetna':temp<24?'Topla':'Vroča';
  const pillCls=temp<10?'normal':temp<18?'normal':temp<24?'raised':'alarm';
  let html='<div style="display:flex;gap:1.5rem;align-items:flex-start;flex-wrap:wrap">';
  html+=`<div style="text-align:center;min-width:90px">`;
  html+=`<div style="font-family:'JetBrains Mono',monospace;font-size:2.6rem;font-weight:500;color:${tempCol};line-height:1">${temp.toFixed(1)}</div>`;
  html+=`<div style="font-size:.9rem;color:var(--muted);margin-top:.05rem">°C</div>`;
  html+=`<div style="margin-top:.35rem"><span class="arso-st-pill ${pillCls}">${statusLbl}</span></div>`;
  html+=`</div>`;
  html+=`<div style="flex:1;min-width:200px">`;
  if(isArso){
    html+=`<div style="font-size:.68rem;color:var(--muted);text-transform:uppercase;letter-spacing:.06em;margin-bottom:.4rem">Postaje vzdolž Savinje</div>`;
    for(const {name,temp:t} of stationTemps){
      const c=t<10?'#60a5fa':t<18?'#34d399':'#fbbf24';
      html+=`<div style="display:flex;justify-content:space-between;font-size:.8rem;margin-bottom:.25rem">`;
      html+=`<span style="color:var(--text)">${name}</span>`;
      html+=`<span style="font-family:'JetBrains Mono',monospace;color:${c};font-weight:600">${t.toFixed(1)} °C</span>`;
      html+=`</div>`;
    }
    if(upd)upd.textContent='ARSO · '+new Date().toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'});
  }else{
    html+=`<div style="font-size:.75rem;color:var(--muted);line-height:1.65">Direktni podatki ARSO o temperaturi vode niso dosegljivi.<br>Prikazana je ocena iz temperature zraka (T<sub>voda</sub> ≈ 0,75 · T<sub>zrak</sub> + 2 °C).</div>`;
    if(upd)upd.textContent='Open-Meteo (ocena) · '+new Date().toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'});
  }
  const swim=temp>=18&&temp<=26,fish=temp>=8&&temp<=20;
  if(swim||fish){
    html+=`<div style="margin-top:.6rem;padding:.35rem .6rem;background:rgba(52,211,153,.08);border:1px solid rgba(52,211,153,.2);border-radius:7px;font-size:.68rem;color:var(--muted)">`;
    if(swim)html+=`🏊 Primerno za kopanje`;
    if(swim&&fish)html+=' · ';
    if(fish)html+=`🎣 Ugodne razmere za ribolov`;
    html+=`</div>`;
  }
  html+=`</div></div>`;
  el.innerHTML=html;
}

// ── Vlaga v tleh — 4 globine ─────────────────────────────
async function fetchSoilDepths(){
  const el=document.getElementById('soil-depths-body');
  if(!el)return;
  try{
    const url='https://api.open-meteo.com/v1/forecast?latitude='+LAT+'&longitude='+LON
      +'&hourly=soil_moisture_0_to_1cm,soil_moisture_1_to_3cm,soil_moisture_3_to_9cm,soil_moisture_9_to_27cm'
      +'&forecast_hours=1&timezone=Europe%2FLjubljana';
    const h=(await fetch(url).then(r=>r.json())).hourly;
    if(!h?.soil_moisture_0_to_1cm)throw new Error('no data');
    const layers=[
      {lbl:'0 – 1 cm', key:'soil_moisture_0_to_1cm', dry:.05, wet:.35},
      {lbl:'1 – 3 cm', key:'soil_moisture_1_to_3cm', dry:.06, wet:.38},
      {lbl:'3 – 9 cm', key:'soil_moisture_3_to_9cm', dry:.07, wet:.40},
      {lbl:'9 – 27 cm',key:'soil_moisture_9_to_27cm',dry:.08, wet:.42},
    ];
    const colForVal=(v,dry,wet)=>{
      const pct=(v-dry)/Math.max(wet-dry,0.01);
      if(pct<0.2)return'#f59e0b';
      if(pct<0.5)return'#34d399';
      if(pct<0.8)return'#60a5fa';
      return'#818cf8';
    };
    const statusFor=(v,dry,wet)=>{
      const pct=(v-dry)/Math.max(wet-dry,0.01);
      if(pct<0.15)return'Suho';if(pct<0.45)return'Zmerno';if(pct<0.75)return'Mokro';return'Zasičeno';
    };
    let html='<div class="soil-depths">';
    for(const L of layers){
      const v=h[L.key]?.[0];
      if(v==null)continue;
      const pct=Math.min(100,Math.max(0,((v-L.dry)/(L.wet-L.dry))*100));
      const col=colForVal(v,L.dry,L.wet);
      const st=statusFor(v,L.dry,L.wet);
      html+=`<div class="soil-row">`+
        `<div class="soil-lbl">${L.lbl}</div>`+
        `<div class="soil-bar-bg"><div class="soil-bar-fill" style="width:${pct.toFixed(1)}%;background:${col}"></div></div>`+
        `<div class="soil-val" style="color:${col}">${st}</div>`+
        `</div>`;
    }
    html+=`</div><div style="font-size:.64rem;color:var(--muted);margin-top:.6rem">Volumetrična vlažnost tal · <span style="color:#f59e0b">■</span> Suho &nbsp;<span style="color:#34d399">■</span> Zmerno &nbsp;<span style="color:#60a5fa">■</span> Mokro &nbsp;<span style="color:#818cf8">■</span> Zasičeno</div>`;
    el.innerHTML=html;
  }catch(e){
    if(el)el.innerHTML='<div class="clim-loading" style="color:var(--muted)">Vlaga v tleh začasno nedostopna</div>';
  }
}

// ── Zgodovinski poplavni dogodki Savinje ─────────────────
function renderFloodHistory(){
  const el=document.getElementById('flood-history-body');
  if(!el)return;
  const events=[
    {date:'Nov 1990',q:820, col:'#f87171',desc:'Poplave Savinje — ena prvih večjih po vojni, škoda po celotni dolini'},
    {date:'Okt 1998',q:950, col:'#f87171',desc:'Katastrofalne poplave Zgornje Savinjske doline, škoda >100 mio DEM'},
    {date:'Nov 2000',q:680, col:'#fb923c',desc:'Hude poplave, prelitje nasipov pri Letušu in Nazarjah'},
    {date:'Sep 2007',q:420, col:'#fbbf24',desc:'Poplave po dolgotrajnih padavinah, lokalne evakuacije'},
    {date:'Nov 2012',q:310, col:'#fbbf24',desc:'Povečan pretok, opozorilo ARSO — ni večjih škod'},
    {date:'Avg 2023',q:1100,col:'#ef4444',desc:'Katastrofalne poplave — zgodovinski rekord Savinje, škoda >500 mio €'},
  ];
  const maxQ=Math.max(...events.map(e=>e.q));
  let html='<div class="flood-history">';
  for(const ev of events.slice().reverse()){
    const barW=Math.round((ev.q/maxQ)*100);
    html+=`<div class="flood-ev">`+
      `<div class="flood-ev-date">${ev.date}</div>`+
      `<div class="flood-ev-info">${ev.desc}<div class="flood-ev-bar" style="width:${barW}%;color:${ev.col}"></div></div>`+
      `<div class="flood-ev-q" style="color:${ev.col}">${ev.q} <span style="font-size:.62rem;font-weight:400;color:var(--muted)">m³/s</span></div>`+
      `</div>`;
  }
  const curQ=_RIVER_THRESHOLDS.normal;
  html+=`</div><div style="font-size:.64rem;color:var(--muted);margin-top:.75rem">Pretoki so ocenjeni maksimumi pri merilni postaji Letuš (GloFAS / ARSO). Vir: ARSO, MOP, URSZR.</div>`;
  el.innerHTML=html;
}

// ── ARSO klimatološke normale 1991–2020 — Celje (0014) ────
// Vir: ARSO, Klimatološke normale za obdobje 1991–2020
const ARSO_NORMALS={
  station:'Celje',stationId:'0014',lat:46.238,lon:15.225,elev:241,period:'1991–2020',
  // indeks 0=jan … 11=dec
  temp:  [0.8,3.2,7.6,12.4,17.1,20.3,22.1,21.7,16.2,10.8,5.1,1.5],  // srednja T (°C)
  tmax:  [3.8,6.7,12.0,17.4,22.4,25.9,27.7,27.3,21.7,15.4,8.3,4.3], // srednji Tmax
  tmin:  [-2.2,-0.3,3.2,7.5,11.8,14.7,16.5,16.1,10.7,6.2,1.9,-1.3], // srednji Tmin
  precip:[56,51,77,93,102,120,107,108,103,111,106,77],               // mesečne padavine (mm)
  sun:   [68,95,145,171,208,229,253,236,185,125,67,54],              // sončne ure
};

// ── Open-Meteo referenčna normala sončnih ur 1991–2020 (Rečica, ista lokacija) ──
// Open-Meteov "sunshine_duration" (prag 120 W/m² na modelirani/reanalizirani
// kratkovalovni sevalnosti) sistematično prešteje več sonca kot ARSO-jeva
// heliografska meritev (razlika je tu ~70 % — letni seštevek te normale je
// 3102 h proti ARSO-jevih 1836 h za Celje). Ker "letos do danes" prihaja iz
// istega Open-Meteo vira/metode, ga primerjamo s to normalo (izračunano iz
// istih 30 let arhiva za iste koordinate) — ne z ARSO normalo — da odstotek
// odraža resnično odstopanje od povprečja in ne razlike med metodama meritve.
const OM_SUN_NORMAL=[165.3,187.4,255.4,297.5,341.6,351.0,373.3,346.2,266.6,214.2,153.0,150.2];
const SL_MON_SHORT=['Jan','Feb','Mar','Apr','Maj','Jun','Jul','Avg','Sep','Okt','Nov','Dec'];

function buildArsoNormals(curMonthT, curMonthR){
  const el=document.getElementById('norm-body');if(!el)return;
  const N=ARSO_NORMALS;
  const curM=new Date().getMonth(); // 0-based

  // ── SVG climatogram ────────────────────────────────────────
  const W=600,H=200,PL=42,PR=48,PT=18,PB=34;
  const CW=W-PL-PR,CH=H-PT-PB;
  const barW=Math.floor(CW/12)-2;
  const maxP=Math.max(...N.precip,1);
  const minT=Math.min(...N.tmin,-5),maxT=Math.max(...N.tmax,25);
  const Ty=t=>PT+CH-(t-minT)/(maxT-minT)*CH;
  const Py=p=>PT+CH-p/maxP*CH;

  // Precipitation bars
  let bars='';
  N.precip.forEach((p,i)=>{
    const x=PL+i*(CW/12)+1;
    const bh=p/maxP*CH;
    const isCur=i===curM;
    const fill=isCur?'rgba(96,165,250,.85)':'rgba(96,165,250,.38)';
    const stroke=isCur?'rgba(96,165,250,1)':'none';
    bars+=`<rect x="${x.toFixed(1)}" y="${(PT+CH-bh).toFixed(1)}" width="${barW}" height="${bh.toFixed(1)}" fill="${fill}" stroke="${stroke}" stroke-width="1" rx="3"><title>${SL_MON_SHORT[i]}: ${p} mm padavin</title></rect>`;
    // Precip label on hover (value inside bar if tall enough)
    if(bh>20)bars+=`<text x="${(x+barW/2).toFixed(1)}" y="${(PT+CH-bh+13).toFixed(1)}" font-size="8.5" fill="${isCur?'#fff':'rgba(96,165,250,.8)'}" text-anchor="middle" font-family="JetBrains Mono,monospace">${p}</text>`;
  });

  // Temperature line (mean)
  const tPts=N.temp.map((t,i)=>[(PL+i*(CW/12)+barW/2+1).toFixed(1),Ty(t).toFixed(1)]);
  const tPath='M '+tPts.map(p=>p.join(',')).join(' L ');
  // Area fill under temp line
  const tArea='M '+tPts[0][0]+','+PT+' L '+tPts.map(p=>p.join(',')).join(' L ')+' L '+tPts[11][0]+','+PT+' Z';

  // Current month marker (circle on temp line)
  const [cx,cy]=tPts[curM];
  const curCircle=`<circle cx="${cx}" cy="${cy}" r="5" fill="#f97316" stroke="white" stroke-width="2"/>`;

  // Axes
  // Temp axis (left): ticks at 0, 5, 10, 15, 20 °C
  let yTicks='';
  [-5,0,5,10,15,20,25].filter(v=>v>=minT&&v<=maxT).forEach(v=>{
    const y=Ty(v).toFixed(1);
    yTicks+=`<line x1="${PL}" y1="${y}" x2="${W-PR}" y2="${y}" stroke="rgba(128,128,128,.1)" stroke-width="1"/>`;
    yTicks+=`<text x="${(PL-4).toFixed(1)}" y="${(+y+3.5).toFixed(1)}" font-size="8.5" fill="rgba(128,128,128,.55)" text-anchor="end" font-family="JetBrains Mono,monospace">${v}°</text>`;
  });
  // Precip axis (right): ticks at 0, 50, 100, 150
  [0,50,100,150].filter(v=>v<=maxP+20).forEach(v=>{
    const y=(PT+CH-v/maxP*CH).toFixed(1);
    yTicks+=`<text x="${(W-PR+5).toFixed(1)}" y="${(+y+3.5).toFixed(1)}" font-size="8.5" fill="rgba(96,165,250,.6)" text-anchor="start" font-family="JetBrains Mono,monospace">${v}</text>`;
  });
  // Month labels
  let xLabels='';
  SL_MON_SHORT.forEach((m,i)=>{
    const x=(PL+i*(CW/12)+barW/2+1).toFixed(1);
    const isCur=i===curM;
    xLabels+=`<text x="${x}" y="${(H-5).toFixed(1)}" font-size="${isCur?9.5:8.5}" fill="${isCur?'var(--text)':'rgba(128,128,128,.65)'}" text-anchor="middle" font-family="Inter,sans-serif" font-weight="${isCur?700:400}">${m}</text>`;
  });
  // Axis labels
  const axisLbls=
    `<text x="${(PL-34).toFixed(1)}" y="${(PT+CH/2).toFixed(1)}" font-size="8" fill="rgba(249,115,22,.7)" transform="rotate(-90,${(PL-34).toFixed(1)},${(PT+CH/2).toFixed(1)})" text-anchor="middle" font-family="Inter,sans-serif">Temp (°C)</text>`+
    `<text x="${(W-PR+38).toFixed(1)}" y="${(PT+CH/2).toFixed(1)}" font-size="8" fill="rgba(96,165,250,.7)" transform="rotate(90,${(W-PR+38).toFixed(1)},${(PT+CH/2).toFixed(1)})" text-anchor="middle" font-family="Inter,sans-serif">Padavine (mm)</text>`;

  const svg=
    `<svg class="norm-chart-svg" viewBox="0 0 ${W} ${H}" height="${H}" xmlns="http://www.w3.org/2000/svg">`+
    `<defs><linearGradient id="tAreaGrad" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="rgba(249,115,22,.18)"/><stop offset="100%" stop-color="rgba(249,115,22,.02)"/></linearGradient></defs>`+
    yTicks+bars+
    `<path d="${tArea}" fill="url(#tAreaGrad)"/>`+
    `<path d="${tPath}" fill="none" stroke="#f97316" stroke-width="2.2" stroke-linejoin="round"/>`+
    curCircle+xLabels+axisLbls+
    `</svg>`;

  // ── Annual KPIs ─────────────────────────────────────────────
  const annualT=(N.temp.reduce((s,v)=>s+v,0)/12).toFixed(1);
  const annualP=N.precip.reduce((s,v)=>s+v,0);
  const annualSun=N.sun.reduce((s,v)=>s+v,0);
  const kpis=
    '<div class="norm-kpi-row">'+
    `<div class="norm-kpi"><div class="norm-kpi-val">${annualT}°C</div><div class="norm-kpi-lbl">Povpr. letna T</div></div>`+
    `<div class="norm-kpi"><div class="norm-kpi-val">${annualP} mm</div><div class="norm-kpi-lbl">Letne padavine</div></div>`+
    `<div class="norm-kpi"><div class="norm-kpi-val">${annualSun} h</div><div class="norm-kpi-lbl">Sončne ure / leto</div></div>`+
    `<div class="norm-kpi"><div class="norm-kpi-val">${N.elev} m</div><div class="norm-kpi-lbl">Nadmorska višina</div></div>`+
    '</div>';

  // ── Current month anomaly ───────────────────────────────────
  let anomHtml='';
  const normT=N.temp[curM], normP=N.precip[curM];
  const mName=new Date().toLocaleDateString('sl',{month:'long'});
  if(curMonthT!=null||curMonthR!=null){
    const dT=curMonthT!=null?curMonthT-normT:null;
    const dP=curMonthR!=null?curMonthR-normP:null;
    const dPpct=curMonthR!=null?((curMonthR-normP)/normP*100):null;
    const Tcls=dT==null?'neutral':Math.abs(dT)<0.5?'neutral':dT>0?'pos':'neg';
    const Pcls=dP==null?'neutral':Math.abs(dPpct)<8?'neutral':dP>0?'neg':'pos'; // more precip = blue
    anomHtml=
      '<div class="norm-anom">'+
      `<div class="norm-anom-title">${mName} – anomalija glede na normalo ${N.period}</div>`+
      '<div class="norm-anom-row">'+
      (curMonthT!=null?
        `<div class="norm-anom-item"><div class="norm-anom-val">${curMonthT.toFixed(1)}°C<span class="norm-delta ${Tcls}">${dT>=0?'+':''}${dT.toFixed(1)}°</span></div><div class="norm-anom-lbl">Srednja T (normala ${normT.toFixed(1).replace('.',',')} °C)</div></div>`:'')  +
      (curMonthR!=null?
        `<div class="norm-anom-item"><div class="norm-anom-val">${curMonthR.toFixed(0)} mm<span class="norm-delta ${Pcls}">${dP>=0?'+':''}${dP.toFixed(0)} mm</span></div><div class="norm-anom-lbl">Padavine (normala ${normP} mm)</div></div>`:'')  +
      '</div>'+
      '</div>';
  } else {
    anomHtml=`<div class="norm-anom"><div class="norm-anom-title">${mName} – normala ${N.period}</div>`+
      `<div class="norm-anom-row">`+
      `<div class="norm-anom-item"><div class="norm-anom-val">${normT.toFixed(1)}°C</div><div class="norm-anom-lbl">Srednja T (normala)</div></div>`+
      `<div class="norm-anom-item"><div class="norm-anom-val">${normP} mm</div><div class="norm-anom-lbl">Padavine (normala)</div></div>`+
      `</div></div>`;
  }

  // ── Altitude note ───────────────────────────────────────────
  const elevDiff=366-N.elev; // Rečica 366m vs Celje 241m
  const tCorr=(elevDiff*0.0065).toFixed(1);
  const altNote=`<div class="norm-alt-note">Rečica ob Savinji (366 m n. v.) leži ${elevDiff} m višje od Celja – termični popravek znaša ≈ −${tCorr.replace('.',',')} °C. Normale veljajo za Celje, zato lokalno pričakujte nekoliko nižje temperature in podoben padavinski režim. · <a href="https://meteo.arso.gov.si/met/sl/climate/tables/climate-normals/" target="_blank" rel="noopener" style="color:var(--blue)">ARSO vir</a></div>`;

  el.innerHTML=
    '<div class="norm-chart-wrap">'+svg+'</div>'+
    '<div style="display:flex;gap:.5rem;flex-wrap:wrap;font-size:.65rem;color:var(--muted);margin-bottom:.75rem">'+
    '<span><span style="display:inline-block;width:14px;height:8px;background:rgba(96,165,250,.55);border-radius:2px;vertical-align:middle;margin-right:3px"></span>Padavine (mm) ↗ desna os</span>'+
    '<span><span style="display:inline-block;width:16px;height:2.5px;background:#f97316;border-radius:2px;vertical-align:middle;margin-right:3px"></span>Srednja T (°C) ↖ leva os</span>'+
    '<span style="background:rgba(249,115,22,.15);border-radius:50%;width:9px;height:9px;display:inline-block;vertical-align:middle;margin-right:3px;border:1.5px solid #f97316"></span><span>Ta mesec</span>'+
    '</div>'+
    kpis+anomHtml+altNote;
}


// ══════════════════════════════════════════════════════════
// ── PVGIS Solar Potential — EU JRC ────────────────────────
// ══════════════════════════════════════════════════════════
const _PVGIS_CACHE_KEY='wx-pvgis-v1';

async function fetchPVGIS(){
  const el=document.getElementById('pvgis-body');if(!el)return;
  try{
    const c=JSON.parse(localStorage.getItem(_PVGIS_CACHE_KEY)||'null');
    if(c&&Date.now()-c.ts<7*864e5){renderPVGIS(c.data);return;}
  }catch(_){}
  try{
    const url=PROXY+'/pvgis';
    const data=await fetch(url).then(r=>r.json());
    try{localStorage.setItem(_PVGIS_CACHE_KEY,JSON.stringify({ts:Date.now(),data}));}catch(_){}
    renderPVGIS(data);
    const src=document.getElementById('pvgis-src');
    if(src)src.textContent='PVGIS-SARAH3 · EU JRC · '+new Date().toLocaleDateString('sl');
  }catch(e){
    el.innerHTML='<div style="color:var(--muted);font-size:.78rem">Podatki PVGIS niso dosegljivi.</div>';
    console.warn('PVGIS:',e);
  }
}

function renderPVGIS(data){
  const el=document.getElementById('pvgis-body');if(!el)return;
  const monthly=data?.outputs?.monthly?.fixed||[];
  const totals=data?.outputs?.totals?.fixed||{};
  if(!monthly.length){el.innerHTML='<div style="color:var(--muted);font-size:.78rem">Ni podatkov.</div>';return;}
  const vals=monthly.map(m=>+(m.H_h||0));
  const maxV=Math.max(...vals,0.01);
  const MN=['J','F','M','A','M','J','J','A','S','O','N','D'];
  const MNF=['Januar','Februar','Marec','April','Maj','Junij','Julij','Avgust','September','Oktober','November','December'];
  const cur=new Date().getMonth();
  const bars=vals.map((v,i)=>{
    const h=Math.max(6,(v/maxV)*64);
    const col=i===cur?'var(--amber)':'var(--blue)';
    return '<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:2px">'
      +'<div style="font-size:.52rem;color:var(--muted)">'+v.toFixed(1)+'</div>'
      +'<div style="height:'+h+'px;width:100%;max-width:26px;background:'+col+';border-radius:3px 3px 0 0;opacity:'+(i===cur?1:.6)+'" title="'+MN[i]+': '+v.toFixed(2)+' kWh/m²/dan"></div>'
      +'<div style="font-size:.58rem;color:var(--muted)">'+MN[i]+'</div>'
      +'</div>';
  }).join('');
  const annTot=totals.H_h!=null?Math.round(totals.H_h*365):Math.round(vals.reduce((a,b)=>a+b,0)*30.44);
  const optAng=totals.optimal_angle!=null?totals.optimal_angle+'°':'—';
  const bestM=MNF[vals.indexOf(Math.max(...vals))];
  el.innerHTML=
    '<div style="display:flex;gap:1.5rem;margin-bottom:.65rem;flex-wrap:wrap">'
    +'<div><div style="font-size:.63rem;color:var(--muted);text-transform:uppercase;letter-spacing:.07em;margin-bottom:.1rem">Letno obsevanje</div>'
    +'<div style="font-family:\'JetBrains Mono\',monospace;font-size:1.1rem;color:var(--amber)">'+annTot+' <span style="font-size:.68rem;color:var(--muted)">kWh/m²</span></div></div>'
    +'<div><div style="font-size:.63rem;color:var(--muted);text-transform:uppercase;letter-spacing:.07em;margin-bottom:.1rem">Optimalni naklon</div>'
    +'<div style="font-family:\'JetBrains Mono\',monospace;font-size:1.1rem">'+optAng+'</div></div>'
    +'<div><div style="font-size:.63rem;color:var(--muted);text-transform:uppercase;letter-spacing:.07em;margin-bottom:.1rem">Najboljši mesec</div>'
    +'<div style="font-family:\'JetBrains Mono\',monospace;font-size:1.1rem">'+bestM+'</div></div>'
    +'</div>'
    +'<div style="display:flex;gap:2px;align-items:flex-end;height:80px">'+bars+'</div>'
    +'<div style="font-size:.63rem;color:var(--muted);margin-top:.45rem">Globalno horizontalno obsevanje H_h (kWh/m²/dan) · PVGIS-SARAH3 · EU Joint Research Centre</div>';
}


// ══════════════════════════════════════════════════════════
// ── Fire Weather Index (FWI) — kanadska/EFFIS metodologija ─
// ══════════════════════════════════════════════════════════
const _FWI_CACHE_KEY='wx-fwi-v1';

function _calcOneDayFWI(prev,T,H,W,r,month){
  H=Math.max(1,Math.min(H,99));W=Math.max(0,W);r=Math.max(0,r);
  const F0=prev.ffmc??85,P0=prev.dmc??6,D0=prev.dc??15;
  // FFMC
  const mo=147.2*(101-F0)/(59.5+F0);
  let mR=mo;
  if(r>0.5){
    const rf=r-0.5;
    let mr=mo+42.5*rf*Math.exp(-100/(251-mo))*(1-Math.exp(-6.93/rf));
    if(mo>150)mr+=0.0015*Math.pow(mo-150,2)*Math.sqrt(rf);
    mR=Math.min(mr,250);
  }
  const Ed=0.942*Math.pow(H,0.679)+11*Math.exp((H-100)/10)+0.18*(21.1-T)*(1-Math.exp(-0.115*H));
  const Ew=0.618*Math.pow(H,0.753)+10*Math.exp((H-100)/10)+0.18*(21.1-T)*(1-Math.exp(-0.115*H));
  let m1;
  if(mR>Ed){const kd=0.424*(1-Math.pow(H/100,1.7))+0.0694*Math.sqrt(W)*(1-Math.pow(H/100,8));m1=Ed+(mR-Ed)*Math.exp(-2.303*kd);}
  else if(mR<Ew){const kw=0.424*(1-Math.pow((100-H)/100,1.7))+0.0694*Math.sqrt(W)*(1-Math.pow((100-H)/100,8));m1=Ew-(Ew-mR)*Math.exp(-2.303*kw);}
  else{m1=mR;}
  const ffmc=59.5*(250-m1)/(147.2+m1);
  // DMC
  let Pr=P0;
  if(r>1.5){
    const re=0.92*r-1.27;
    const Mo=20+Math.exp(5.6348-P0/43.43);
    const b=P0<=33?100/(0.5+0.3*P0):P0<=65?14-1.3*Math.log(P0):6.2*Math.log(P0)-17.2;
    const Mr=Mo+1000*re/(48.77+b*re);
    Pr=Math.max(244.72-43.43*Math.log(Mr-20),0);
  }
  const Le=[6.5,7.5,9.0,12.8,13.9,13.9,12.4,10.9,9.4,8.0,7.0,6.0][month];
  const K=1.894*(T+1.1)*(100-H)*Le*1e-6;
  const dmc=Math.max(Pr+100*K,0);
  // DC
  let Dr=D0;
  if(r>2.8){const rd=0.83*r-1.27;const Qo=800*Math.exp(-D0/400);const Qr=Qo+3.937*rd;Dr=Math.max(400*Math.log(800/Qr),0);}
  const Lf=[-1.6,-1.6,-1.6,0.9,3.8,5.8,6.4,5.0,2.4,0.4,-1.6,-1.6][month];
  const dc=Math.max(Dr+Math.max(0,0.36*(T+2.8)+Lf)/2,0);
  // ISI
  const fW=Math.exp(0.05039*W);
  const mF=147.2*(101-ffmc)/(59.5+ffmc);
  const fF=91.9*Math.exp(-0.1386*mF)*(1+Math.pow(mF,5.31)/4.93e7);
  const isi=0.208*fW*fF;
  // BUI
  const bui=dmc<=0.4*dc?0.8*dmc*dc/(dmc+0.4*dc):dmc-(1-0.8*dc/(dmc+0.4*dc))*(0.92+Math.pow(0.0114*dmc,1.7));
  // FWI
  const fD=bui<=80?0.626*Math.pow(Math.max(bui,0),0.809)+2:1000/(25+108.64*Math.exp(-0.023*bui));
  const B=0.1*isi*fD;
  const fwi=B>1?Math.exp(2.72*Math.pow(0.434*Math.log(B),0.647)):B;
  return{ffmc,dmc,dc,isi,bui,fwi:Math.max(0,fwi)};
}

function _fwiClass(v){
  if(v<5.2)return{label:'Nizka',col:'#22c55e'};
  if(v<11.2)return{label:'Zmerna',col:'#84cc16'};
  if(v<21.3)return{label:'Visoka',col:'#f59e0b'};
  if(v<38.0)return{label:'Zelo visoka',col:'#ef4444'};
  return{label:'Ekstremna',col:'#7c3aed'};
}

async function fetchFireWeather(){
  const el=document.getElementById('fwi-body');if(!el)return;
  try{
    const c=JSON.parse(localStorage.getItem(_FWI_CACHE_KEY)||'null');
    if(c&&Date.now()-c.ts<3*3600000){renderFireWeather(c.days);return;}
  }catch(_){}
  try{
    const url='https://api.open-meteo.com/v1/forecast?latitude='+LAT+'&longitude='+LON
      +'&daily=temperature_2m_max,relative_humidity_2m_min,windspeed_10m_max,precipitation_sum'
      +'&forecast_days=7&past_days=7&timezone=Europe%2FLjubljana';
    const data=await fetch(url).then(r=>r.json());
    const d=data.daily;
    if(!d?.time?.length)throw new Error('no data');
    let prev={ffmc:85,dmc:6,dc:15};
    const days=d.time.map((date,i)=>{
      const T=d.temperature_2m_max[i]??20;
      const H=d.relative_humidity_2m_min[i]??50;
      const W=d.windspeed_10m_max[i]??0;
      const r=d.precipitation_sum[i]??0;
      const month=new Date(date).getMonth();
      const res=_calcOneDayFWI(prev,T,H,W,r,month);
      prev=res;return{date,...res};
    });
    try{localStorage.setItem(_FWI_CACHE_KEY,JSON.stringify({ts:Date.now(),days}));}catch(_){}
    renderFireWeather(days);
    const upd=document.getElementById('fwi-updated');
    if(upd)upd.textContent='EFFIS metodologija · '+new Date().toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'});
  }catch(e){
    el.innerHTML='<div style="color:var(--muted);font-size:.78rem">Podatki FWI niso na voljo.</div>';
    console.warn('FWI:',e);
  }
}

function renderFireWeather(days){
  const el=document.getElementById('fwi-body');if(!el||!days?.length)return;
  const today=_localDateStr(new Date());
  const ti=days.findIndex(d=>d.date===today);
  const td=ti>=0?days[ti]:days[Math.min(7,days.length-1)];
  const cls=_fwiClass(td.fwi);
  const maxF=Math.max(...days.map(d=>d.fwi),5);
  const DN=['Ned','Pon','Tor','Sre','Čet','Pet','Sob'];
  const bars=days.map(d=>{
    const h=Math.max(4,(d.fwi/maxF)*64);
    const c=_fwiClass(d.fwi);
    const isTd=d.date===today;
    const dn=DN[new Date(d.date).getDay()];
    return '<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:2px">'
      +'<div style="height:'+h+'px;width:100%;max-width:20px;background:'+c.col+';border-radius:3px 3px 0 0;opacity:'+(isTd?1:.58)+';'+(isTd?'outline:2px solid var(--text);outline-offset:1px':'')+'" title="'+d.date+': FWI '+d.fwi.toFixed(1)+' ('+c.label+')"></div>'
      +'<div style="font-size:.53rem;color:var(--muted)">'+dn+'</div>'
      +'</div>';
  }).join('');
  el.innerHTML=
    '<div style="display:flex;align-items:center;gap:1rem;margin-bottom:.65rem;flex-wrap:wrap">'
    +'<div style="text-align:center;min-width:3.5rem">'
    +'<div style="font-family:\'JetBrains Mono\',monospace;font-size:2rem;font-weight:700;color:'+cls.col+';line-height:1.1">'+td.fwi.toFixed(1)+'</div>'
    +'<div style="font-size:.58rem;color:var(--muted);margin-top:.1rem">FWI danes</div>'
    +'</div>'
    +'<div style="flex:1">'
    +'<div style="display:inline-block;padding:.25rem .75rem;background:'+cls.col+'22;border:1px solid '+cls.col+';border-radius:20px;color:'+cls.col+';font-size:.76rem;font-weight:600;margin-bottom:.3rem">'+cls.label+'</div>'
    +'<div style="font-size:.7rem;color:var(--muted)">ISI: '+td.isi.toFixed(1)+' · BUI: '+td.bui.toFixed(0)+' · FFMC: '+td.ffmc.toFixed(0)+'</div>'
    +'</div></div>'
    +'<div style="display:flex;gap:3px;align-items:flex-end;height:74px">'+bars+'</div>'
    +'<div style="font-size:.63rem;color:var(--muted);margin-top:.45rem">Kanadska metodologija FWI (EFFIS/GWIS) · Open-Meteo · 7 dni nazaj + 7-dnevna napoved</div>';
}

// ══════════════════════════════════════════════════════════
// ── ENSO / El Niño monitor — NOAA CPC ONI ─────────────────
// ══════════════════════════════════════════════════════════
const _ENSO_CACHE='wx-enso-v1';

async function fetchENSO(){
  const el=document.getElementById('enso-body');if(!el)return;
  try{
    const c=JSON.parse(localStorage.getItem(_ENSO_CACHE)||'null');
    if(c&&Date.now()-c.ts<86400000){renderENSO(c.data);return;}
  }catch(_){}
  try{
    const r=await fetch(PROXY+'/enso');
    if(!r.ok)throw new Error('HTTP '+r.status);
    const data=await r.json();
    if(!Array.isArray(data)||!data.length)throw new Error('no data');
    try{localStorage.setItem(_ENSO_CACHE,JSON.stringify({ts:Date.now(),data}));}catch(_){}
    renderENSO(data);
    const src=document.getElementById('enso-src');
    if(src)src.textContent='NOAA CPC · ONI · '+new Date().toLocaleDateString('sl');
  }catch(e){
    el.innerHTML='<div style="color:var(--muted);font-size:.78rem">Podatki ENSO niso dosegljivi.</div>';
    console.warn('ENSO:',e);
  }
}

function renderENSO(data){
  const el=document.getElementById('enso-body');if(!el||!data?.length)return;
  const last=data[data.length-1];
  const oni=last.a;
  const phase=oni>=2?'Zelo močen El Niño':oni>=1.5?'Močen El Niño':oni>=1?'Zmeren El Niño':oni>=0.5?'Šibek El Niño':oni<=-2?'Zelo močna La Niña':oni<=-1.5?'Močna La Niña':oni<=-1?'Zmerna La Niña':oni<=-0.5?'Šibka La Niña':'Nevtralna faza';
  const phaseCol=oni>=0.5?'var(--amber)':oni<=-0.5?'var(--blue)':'var(--muted)';
  const phaseEmoji=oni>=0.5?'🔴':oni<=-0.5?'🔵':'⚪';
  const latestSeas=last.s+' '+last.y;

  const kpi=`<div style="display:flex;gap:.75rem;flex-wrap:wrap;margin-bottom:1rem;align-items:center">
    <div style="background:var(--fc-bg);border:1px solid var(--fc-border);border-radius:12px;padding:.55rem 1rem">
      <div style="font-family:'JetBrains Mono',monospace;font-size:1.4rem;font-weight:300;color:${phaseCol}">${oni>=0?'+':''}${oni.toFixed(2)}</div>
      <div style="font-size:.62rem;text-transform:uppercase;letter-spacing:.08em;color:var(--muted);margin-top:.1rem">ONI · ${latestSeas}</div>
    </div>
    <div style="background:var(--fc-bg);border:1px solid var(--fc-border);border-radius:12px;padding:.55rem 1rem;flex:1;min-width:140px">
      <div style="font-size:.92rem;font-weight:600;color:${phaseCol}">${phaseEmoji} ${phase}</div>
      <div style="font-size:.62rem;text-transform:uppercase;letter-spacing:.08em;color:var(--muted);margin-top:.1rem">Trenutna faza ENSO</div>
    </div>
  </div>`;

  const W=880,H=160,mL=36,mR=8,mT=16,mB=28;
  const cW=W-mL-mR,cH=H-mT-mB;
  const maxAbs=Math.max(2.5,...data.map(d=>Math.abs(d.a)));
  const yZ=mT+cH/2;
  const yS=v=>yZ-(v/maxAbs)*(cH/2);
  const bW=Math.max(2,Math.floor(cW/data.length)-1);

  let gridLines='',bars='',labels='';
  [-2,-1,-0.5,0,0.5,1,2].forEach(v=>{
    const y=yS(v).toFixed(1);
    const dash=Math.abs(v)===0.5?'4,3':'';
    const col=v===0?'rgba(255,255,255,.15)':'rgba(255,255,255,.06)';
    gridLines+=`<line x1="${mL}" x2="${W-mR}" y1="${y}" y2="${y}" stroke="${col}" stroke-width="${v===0?1:.5}"${dash?` stroke-dasharray="${dash}"`:''}/>`
    gridLines+=`<text x="${mL-3}" y="${(+y+3.5).toFixed(0)}" font-size="8" text-anchor="end" fill="var(--muted)" font-family="'JetBrains Mono',monospace">${v>0?'+':''}${v}</text>`;
  });

  let lastYear=null;
  data.forEach((d,i)=>{
    const x=mL+i*(cW/data.length);
    const barH=Math.abs((d.a/maxAbs)*(cH/2));
    const y0=d.a>=0?yS(d.a):yZ;
    const intensity=Math.min(1,Math.abs(d.a)/2);
    const col=d.a>=0.5?`rgba(251,146,60,${0.45+intensity*0.55})`:d.a<=-0.5?`rgba(96,165,250,${0.45+intensity*0.55})`:'rgba(148,163,184,.35)';
    bars+=`<rect x="${x.toFixed(1)}" y="${y0.toFixed(1)}" width="${bW}" height="${Math.max(1,barH).toFixed(1)}" fill="${col}" rx="1"><title>${d.s} ${d.y}: ${d.a>=0?'+':''}${d.a.toFixed(2)}</title></rect>`;
    if(d.s==='DJF'&&d.y!==lastYear){
      lastYear=d.y;
      labels+=`<text x="${(x+bW/2).toFixed(0)}" y="${H-mB+13}" font-size="8.5" text-anchor="middle" fill="var(--muted)" font-family="Inter,sans-serif">${d.y}</text>`;
    }
  });

  const svg=`<div class="chart-svg-wrap"><svg class="chart-svg" viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg">
    ${gridLines}${bars}${labels}
    <text x="${W-mR}" y="${mT-4}" font-size="8" text-anchor="end" fill="rgba(251,146,60,.8)" font-family="Inter,sans-serif">🔴 El Niño ≥ +0,5</text>
    <text x="${W-mR-110}" y="${mT-4}" font-size="8" text-anchor="end" fill="rgba(96,165,250,.8)" font-family="Inter,sans-serif">🔵 La Niña ≤ −0,5</text>
  </svg></div>`;

  el.innerHTML=kpi+svg+'<div style="font-size:.63rem;color:var(--muted);margin-top:.4rem;text-align:right">ONI = 3-mesečno drseče povprečje temperaturne anomalije morske gladine (SST) v regiji Niño 3.4 · Vir: NOAA Climate Prediction Center</div>';
}

function initClimate(){
  if(_climInit)return;_climInit=true;
  try{buildArsoNormals(null,null);}catch(e){console.error('arso-norm',e);}
  fetchCMIP6();
  fetchPVGIS();
  fetchENSO();
  try{fetchNASASolar();}catch(e){console.error('nasa-solar',e);}
  try{fetchNASABaselines();}catch(e){console.error('nasa-baselines',e);}
  try{renderClimateTwin();}catch(e){console.error('twin',e);}
  try{buildWrapped();}catch(e){console.error('wrapped',e);}
  try{buildGrowingSeason();}catch(e){console.error('gs',e);}
  try{buildSpells();}catch(e){console.error('spells',e);}
  try{renderDriftEngine();}catch(e){console.error('drift',e);}
  try{buildAgroPulse();}catch(e){console.error('pulse',e);}
}
function refreshClimate(){
  if(!_climInit)return;
  try{renderClimateTwin();buildWrapped();buildGrowingSeason();buildSpells();}catch(e){}
  try{renderDriftEngine();}catch(e){}
  try{buildAgroPulse();}catch(e){}
}
// ══════════════════════════════════════════════════════════
// ── 1. MICROCLIMATE DRIFT ENGINE ──────────────────────────
// ══════════════════════════════════════════════════════════
function renderDriftEngine(){
  const body=document.getElementById('drift-body');
  const range=document.getElementById('drift-range');
  if(!body)return;
  const drifts=JSON.parse(localStorage.getItem(ARSO_DRIFT_KEY)||'[]');
  if(drifts.length<6){const card=document.getElementById('drift-card');if(card)card.style.display='none';return;}
  // Enrich with hour info
  const rich=drifts.map(d=>({...d,hour:new Date(d.t).getHours(),month:new Date(d.t).getMonth()}));
  // KPIs
  const r24=rich.filter(d=>d.t>Date.now()-864e5);
  const r7=rich.filter(d=>d.t>Date.now()-7*864e5);
  const avg=arr=>arr.length?arr.reduce((s,v)=>s+v,0)/arr.length:null;
  const avgDT24=avg(r24.map(d=>d.dT));
  const avgDT7=avg(r7.map(d=>d.dT));
  const avgDH7=avg(r7.filter(d=>d.dH!=null).map(d=>d.dH));
  // Night vs day drift (night = 21-6, day = 9-18)
  const night=rich.filter(d=>(d.hour>=21||d.hour<=6)&&d.t>Date.now()-30*864e5);
  const daytime=rich.filter(d=>(d.hour>=9&&d.hour<=18)&&d.t>Date.now()-30*864e5);
  const nightDT=avg(night.map(d=>d.dT));
  const dayDT=avg(daytime.map(d=>d.dT));
  const fmtD=(v,u='°C')=>v==null?'—':(v>=0?'+':'')+v.toFixed(1)+u;
  const cls=(v)=>v==null?'':v<-0.5?'drift-cold':v>0.5?'drift-warm':'';
  // Frost pocket analysis
  let frostPocketTxt='';
  if(nightDT!=null&&nightDT<-1)frostPocketTxt=`<b style="color:var(--blue)">Zaznano mrazišče!</b> Ponoči je za ${nightDT.toFixed(1).replace('.',',')} °C hladneje kot na referenčni postaji. Lokalna topografija ujame hladen zrak.`;
  else if(nightDT!=null&&nightDT<-0.3)frostPocketTxt=`Šibek učinek mrazišča: ponoči je za ${nightDT.toFixed(1).replace('.',',')} °C hladneje.`;
  // Hourly drift profile SVG (0-23h)
  const hourlyDT=Array.from({length:24},(_,h)=>{
    const pts=rich.filter(d=>d.hour===h&&d.t>Date.now()-30*864e5).map(d=>d.dT);
    return pts.length?avg(pts):null;
  });
  const validHours=hourlyDT.filter(v=>v!=null);
  const minDT=validHours.length?Math.min(...validHours,-1.5):-2;
  const maxDT=validHours.length?Math.max(...validHours,1.5):2;
  const W=840,H=80,pl=30,pr=10,pt=8,pb=24;
  const yw=H-pt-pb,xw=W-pl-pr;
  const mapY=v=>pt+(1-(v-minDT)/(maxDT-minDT))*yw;
  let svg=`<svg viewBox="0 0 ${W} ${H}" style="display:block;width:100%;min-width:${W}px" xmlns="http://www.w3.org/2000/svg">`;
  // Zero line
  const zy=mapY(0).toFixed(1);
  svg+=`<line x1="${pl}" x2="${W-pr}" y1="${zy}" y2="${zy}" stroke="var(--border)" stroke-width="0.8" stroke-dasharray="4,3"/>`;
  svg+=`<text x="${pl-3}" y="${zy}" text-anchor="end" font-size="8" fill="var(--muted)" font-family="JetBrains Mono,monospace" dominant-baseline="middle">0</text>`;
  // Area fill
  let areaPts=`${pl},${pt+yw}`;
  hourlyDT.forEach((v,h)=>{
    const x=pl+(h/23)*xw;
    const y=v!=null?mapY(v):mapY(0);
    areaPts+=` ${x.toFixed(1)},${y.toFixed(1)}`;
  });
  areaPts+=` ${W-pr},${pt+yw}`;
  svg+=`<polygon points="${areaPts}" fill="var(--blue)" opacity="0.12"/>`;
  // Line
  const pts=hourlyDT.map((v,h)=>v!=null?`${(pl+(h/23)*xw).toFixed(1)},${mapY(v).toFixed(1)}`:null).filter(Boolean);
  if(pts.length)svg+=`<polyline points="${pts.join(' ')}" fill="none" stroke="var(--blue)" stroke-width="1.8" stroke-linejoin="round"/>`;
  // Hour labels
  [0,6,12,18,23].forEach(h=>{
    svg+=`<text x="${(pl+(h/23)*xw).toFixed(1)}" y="${H-4}" text-anchor="middle" font-size="8" fill="var(--muted)" font-family="JetBrains Mono,monospace">${String(h).padStart(2,'0')}:00</text>`;
  });
  svg+=`<text x="${pl-3}" y="${mapY(maxDT).toFixed(1)}" text-anchor="end" font-size="8" fill="var(--red)" font-family="JetBrains Mono,monospace" dominant-baseline="middle">${maxDT>0?'+':''}${maxDT.toFixed(1)}</text>`;
  svg+='</svg>';
  body.innerHTML=
    `<div class="drift-kpi-row">`+
    `<div class="drift-kpi"><div class="drift-kpi-val ${cls(avgDT24)}">${fmtD(avgDT24)}</div><div class="drift-kpi-lbl">Odmik T (24 h)</div></div>`+
    `<div class="drift-kpi"><div class="drift-kpi-val ${cls(avgDT7)}">${fmtD(avgDT7)}</div><div class="drift-kpi-lbl">Odmik T (7 d)</div></div>`+
    (avgDH7!=null?`<div class="drift-kpi"><div class="drift-kpi-val ${avgDH7>3?'drift-humid':avgDH7<-3?'drift-dry':''}">${fmtD(avgDH7,'%')}</div><div class="drift-kpi-lbl">Odmik vlage (7 d)</div></div>`+
    `<div class="drift-kpi"><div class="drift-kpi-val drift-cold">${fmtD(nightDT)}</div><div class="drift-kpi-lbl">Nočni odmik</div></div>`+
    `<div class="drift-kpi"><div class="drift-kpi-val drift-warm">${fmtD(dayDT)}</div><div class="drift-kpi-lbl">Dnevni odmik</div></div>`:'')+'</div>'+
    `<div class="drift-chart-wrap">${svg}</div>`+
    (frostPocketTxt?`<div class="csub" style="margin-top:.6rem">❄️ ${frostPocketTxt}</div>`:'<div class="csub" style="margin-top:.6rem">Nočni in dnevni odmik: ponoči <b style="color:var(--text)">${fmtD(nightDT)}</b>, podnevi <b style="color:var(--text)">${fmtD(dayDT)}</b>. Zbiranje podatkov za sezonski vzorec …</div>')+
    `<div style="font-size:.67rem;color:var(--muted);margin-top:.4rem">${rich.length} meritev · ${Math.round((rich[rich.length-1].t-rich[0].t)/3600000)} h zajema · referenca: ARSO</div>`;
  if(range)range.textContent=`${rich.length} meritev · ${r7.length} zadnjih 7 dni`;
}

