// ── 2. AGROMETEOROLOGICAL PULSE PREDICTOR ─────────────────
// ══════════════════════════════════════════════════════════
// GDD events for Savinja valley — biologically meaningful thresholds
const PULSE_EVENTS=[
  {icon:'🦋',name:'Prvi metulji',base:5,threshold:40,color:'var(--amber)',
   note:'Topli dnevi prebudijo prve dnevne metulje.',cond:null},
  {icon:'🌸',name:'Regrat v cvetu',base:5,threshold:55,color:'#fb923c',
   note:'Idealen čas za makrofotografijo cvetov.',cond:null},
  {icon:'🍄',name:'Mavrahi (smrčki) – vrhunec sezone',base:5,threshold:85,color:'var(--green)',
   note:'Optimalno pri Tmin > 5 °C in ≥ 15 mm dežja v zadnjih 14 dneh.',
   cond:s=>s.recentRain>=15&&s.tminOk},
  {icon:'🐝',name:'Čebelja aktivnost',base:5,threshold:100,color:'var(--amber)',
   note:'Čebele začnejo intenzivno zbirati cvetni prah.',cond:null},
  {icon:'🌺',name:'Cvetenje jablan',base:10,threshold:50,color:'#f9a8d4',
   note:'Ključni fenološki mejnik. V tem oknu je nujna zaščita pred pozebo.',cond:null},
  {icon:'🦗',name:'Kobilice in murni',base:5,threshold:300,color:'var(--green)',
   note:'Začetek aktivnosti pojočih žuželk (kobilic in murnov) – ravninski predeli v dolini.',cond:null},
  {icon:'🐉',name:'Prvi kačji pastirji',base:5,threshold:160,color:'var(--cyan)',
   note:'Odrasli osebki se pojavijo ob vodah v Savinjski dolini.',cond:null},
  {icon:'🔥',name:'Kresnice – vrhunec',base:10,threshold:420,color:'var(--amber)',
   note:'Idealen čas za makrofotografijo kresnic. Pogoj: nočna T > 15 °C.',
   cond:s=>s.nightTempOk},
  {icon:'🍇',name:'Zorenje grozdja',base:10,threshold:900,color:'var(--purple)',
   note:'Veraison (začetek zorenja) – sprememba barve jagod. Pomembno za vinogradnike.',cond:null},
  {icon:'🕷️',name:'Pajčevine – vrhunec sezone',base:5,threshold:520,color:'var(--muted)',
   note:'Jesenski vrhunec aktivnosti pajkov. Rosne jutranje pajčevine so idealne za makrofotografijo!',cond:null},
  {icon:'🍂',name:'Jesenske gobe (jurčki)',base:10,threshold:800,color:'var(--amber)',
   note:'Rast jurčkov in lisičk po prvem jesenskem dežju.',
   cond:s=>s.recentRain>=20},
];

let _pulseForcast=null;
async function buildAgroPulse(){
  const body=document.getElementById('agro-pulse-body');
  const badge=document.getElementById('pulse-gdd-badge');
  if(!body)return;
  const store=_insStore();
  const yr=new Date().getFullYear();
  // Calculate GDD5 and GDD10 from Jan 1 to today
  let gdd5=0,gdd10=0;
  const today=_localDateStr(new Date());
  for(let d=new Date(`${yr}-01-01`);d.toISOString().slice(0,10)<=today;d.setDate(d.getDate()+1)){
    const k=d.toISOString().slice(0,10);
    const r=store[k];
    if(r){
      const avg=(r.tempHigh!=null&&r.tempLow!=null)?(r.tempHigh+r.tempLow)/2:(r.tempAvg??null);
      if(avg!=null){gdd5+=Math.max(0,avg-5);gdd10+=Math.max(0,avg-10);}
    }
  }
  if(badge)badge.textContent=`GDD5: ${Math.round(gdd5)} · GDD10: ${Math.round(gdd10)}`;
  // Recent rain (last 14 days) and night temp check
  let recentRain=0,nightTempOk=false,tminOk=false;
  for(let i=0;i<14;i++){const d=new Date();d.setDate(d.getDate()-i);const k=_localDateStr(d);const r=store[k];if(r){recentRain+=(r.precipTotal||0);if((r.tempLow??0)>5)tminOk=true;}}
  const curObs=_lastBriefObs?.metric||{};
  nightTempOk=(curObs.temp??0)>15;
  const state={recentRain,nightTempOk,tminOk};
  // Forecast daily GDD additions (use 5 days Open-Meteo + fallback from historical average)
  let fcDailyGDD5=2,fcDailyGDD10=0.8; // fallback seasonal average
  try{
    if(!_pulseForcast||Date.now()-_pulseForcast.t>3*3600*1000){
      const r=await fetch(`https://api.open-meteo.com/v1/forecast?latitude=${LAT}&longitude=${LON}&daily=temperature_2m_max,temperature_2m_min&timezone=Europe%2FLjubljana&forecast_days=7`);
      const d=await r.json();
      if(d.daily?.temperature_2m_max?.length){
        const g5=d.daily.temperature_2m_max.map((mx,i)=>Math.max(0,((mx+(d.daily.temperature_2m_min[i]||mx-8))/2)-5));
        const g10=d.daily.temperature_2m_max.map((mx,i)=>Math.max(0,((mx+(d.daily.temperature_2m_min[i]||mx-8))/2)-10));
        fcDailyGDD5=g5.reduce((a,b)=>a+b,0)/g5.length;
        fcDailyGDD10=g10.reduce((a,b)=>a+b,0)/g10.length;
        _pulseForcast={t:Date.now(),g5:fcDailyGDD5,g10:fcDailyGDD10};
      }
    }else{fcDailyGDD5=_pulseForcast.g5;fcDailyGDD10=_pulseForcast.g10;}
  }catch(e){}
  body.innerHTML='<div class="pulse-list">'+PULSE_EVENTS.map(ev=>{
    const gdd=ev.base===5?gdd5:gdd10;
    const daily=ev.base===5?fcDailyGDD5:fcDailyGDD10;
    const pct=Math.min(100,Math.round(gdd/ev.threshold*100));
    const condMet=ev.cond?ev.cond(state):true;
    const done=gdd>=ev.threshold;
    const daysLeft=!done&&daily>0?Math.ceil((ev.threshold-gdd)/daily):0;
    const etaTxt=done?'DOSEŽENO':daysLeft<=0?'kmalu':daysLeft<=7?`čez ~${daysLeft} dni`:`čez ~${daysLeft} dni`;
    const isActive=done&&condMet;
    return `<div class="pulse-item${isActive?' pulse-active':''}" style="--pi-accent:${ev.color}">
      <div class="pulse-header">
        <span class="pulse-icon">${ev.icon}</span>
        <span class="pulse-name">${ev.name}${isActive?'<span class="pulse-now">ZDAJ ✓</span>':''}</span>
        <span class="pulse-eta">${etaTxt}</span>
      </div>
      <div class="pulse-bar-bg"><div class="pulse-bar-fill" style="width:${pct}%;background:${ev.color}"></div></div>
      <div class="pulse-note">${Math.round(gdd)} / ${ev.threshold} GDD${ev.base} (${pct}%)${done&&!condMet?' – ⚠️ pogoji niso optimalni':''} · ${ev.note}</div>
    </div>`;
  }).join('')+'</div>';
}

// ══════════════════════════════════════════════════════════
// ── 3. WIND FINGERPRINT ENGINE ────────────────────────────
// ══════════════════════════════════════════════════════════
function buildWindFingerprint(){
  const body=document.getElementById('fp-body');
  if(!body)return;
  const store=_insStore();
  const keys=Object.keys(store).sort();
  if(keys.length<60){body.innerHTML='<div class="clim-loading">Premalo podatkov za analizo vzorcev.</div>';return;}
  // Live station data
  const obs=_lastBriefObs||{},m=obs?.metric||{};
  const curP=m.pressure??null;
  const curPTrend=typeof pressureTrend3h==='function'?pressureTrend3h():null;
  const curT=m.temp??null;
  const curW=m.windSpeed??0;
  const curH=obs?.humidity??null;
  // Historical storm precursors: scan for significant events
  // Event: next-day rain > 12mm or current wind > 50 km/h
  const events=[];
  for(let i=2;i<keys.length-1;i++){
    const nextDay=store[keys[i+1]];
    const curDay=store[keys[i]];
    const prevDay=store[keys[i-1]];
    const prevPrevDay=store[keys[i-2]];
    if(!nextDay||!curDay||!prevDay)continue;
    const bigRain=(nextDay.precipTotal??0)>12;
    const bigWind=(nextDay.windspeedHigh??0)>50;
    if(bigRain||bigWind){
      // Collect pre-event signature: temp drop, wind rise
      const tDrop=(curDay.tempAvg??15)-(prevPrevDay?.tempAvg??15);
      const wRise=(curDay.windspeedHigh??0)-(prevDay.windspeedHigh??0);
      events.push({tDrop,wRise,rain:nextDay.precipTotal??0,wind:nextDay.windspeedHigh??0});
    }
  }
  // Build average pre-storm signature
  const avgSig=events.length?{
    tDrop:events.reduce((s,e)=>s+e.tDrop,0)/events.length,
    wRise:events.reduce((s,e)=>s+e.wRise,0)/events.length,
    n:events.length,
    avgRain:events.reduce((s,e)=>s+e.rain,0)/events.length,
    avgWind:events.reduce((s,e)=>s+e.wind,0)/events.length,
  }:null;
  // Current conditions score
  // Pressure fingerprinting (primary signal)
  let score=0,signals=[];
  if(curPTrend!=null){
    if(curPTrend<-4){score+=40;signals.push(`Hiter padec tlaka (${curPTrend.toFixed(1)} hPa/3h)`);}
    else if(curPTrend<-2){score+=20;signals.push(`Zmeren padec tlaka (${curPTrend.toFixed(1)} hPa/3h)`);}
    else if(curPTrend<-1){score+=8;signals.push(`Blag padec tlaka`);}
  }
  if(curP!=null&&curP<1000){score+=12;signals.push(`Nizek tlak (${curP.toFixed(0)} hPa)`);}
  if(curH!=null&&curH>78){score+=10;signals.push(`Visoka vlaga (${Math.round(curH)}%)`);}
  if(curW>25){score+=10;signals.push(`Okrepljen veter (${Math.round(curW)} km/h)`);}
  // Compare with historical storm signatures
  if(avgSig){
    const recentStore=JSON.parse(localStorage.getItem(LS_KEY)||'{}');
    const tod=_localDateStr(new Date());
    const yes=_localDateStr(new Date(Date.now()-864e5));
    const todRec=recentStore[tod],yesRec=recentStore[yes];
    if(todRec&&yesRec){
      const tD=(todRec.tempAvg??0)-(yesRec.tempAvg??0);
      const wR=(todRec.windspeedHigh??0)-(yesRec.windspeedHigh??0);
      // How closely does today match the avg pre-storm signature?
      if(Math.sign(tD)===Math.sign(avgSig.tDrop)&&Math.abs(tD)>1){score+=8;signals.push(`Temp. trend ujema prenevihno signaturo`);}
      if(wR>5){score+=8;signals.push(`Okrepitev vetra ujema prenevihno signaturo`);}
    }
  }
  let alertClass,alertTitle,alertDesc;
  if(score>=45){alertClass='fp-warn';alertTitle='⚠️ Nevihta/poslabšanje verjetno';alertDesc='Kombinacija signalov močno kaže na bližajoče poslabšanje v naslednjih 12–24 urah.';}
  else if(score>=22){alertClass='fp-watch';alertTitle='👁 Pozor — znaki nestabilnosti';alertDesc='Zaznan en ali več signalov, ki so v preteklosti predhodili poslabšanju. Spremljaj.';}
  else{alertClass='fp-none';alertTitle='✅ Brez alarma';alertDesc='Trenutni vzorec tlaka, vetra in vlage ne kaže na bližajoče poslabšanje.';}
  const histTxt=avgSig?`Na podlagi ${avgSig.n} analiziranih nevihtnih dogodkov (2019–danes): povprečno poslabšanje prinaša <b style="color:var(--text)">${avgSig.avgRain.toFixed(0)} mm</b> padavin in sunke do <b style="color:var(--text)">${avgSig.avgWind.toFixed(0)} km/h</b>. Karakteristično: T pada za <b style="color:var(--text)">${avgSig.tDrop.toFixed(1)}°C</b> in veter naraste za <b style="color:var(--text)">${avgSig.wRise.toFixed(0)} km/h</b> v 48h pred dogodkom.`:'Analiza vzorcev se gradi z rastočo bazo podatkov.';
  body.innerHTML=
    `<div class="fp-alert ${alertClass}"><div class="fp-alert-title">${alertTitle}</div>`+
    `<div class="fp-alert-sub">${alertDesc}${signals.length?' Aktivni signali: '+signals.join(', ')+'.'  :''}</div></div>`+
    `<div class="fp-metrics">`+
    `<div class="fp-metric"><div class="fp-metric-val">${curPTrend!=null?(curPTrend>=0?'+':'')+curPTrend.toFixed(1)+' hPa':'—'}</div><div class="fp-metric-lbl">Tlak 3h trend</div></div>`+
    `<div class="fp-metric"><div class="fp-metric-val">${curP!=null?curP.toFixed(0)+' hPa':'—'}</div><div class="fp-metric-lbl">Absolutni tlak</div></div>`+
    `<div class="fp-metric"><div class="fp-metric-val">${curH!=null?Math.round(curH)+'%':'—'}</div><div class="fp-metric-lbl">Vlažnost</div></div>`+
    `<div class="fp-metric"><div class="fp-metric-val">${curW>0?Math.round(curW)+' km/h':'—'}</div><div class="fp-metric-lbl">Veter</div></div>`+
    `</div><div class="fp-history">${histTxt}</div>`;
}


// ══════════════════════════════════════════════════════════
// ── ADVANCED STORM CHASER VISUALIZATIONS ──────────────────
// ══════════════════════════════════════════════════════════

// Moist adiabatic lapse rate (°C/km) — simplified Tetens
function _malr(T){
  const Tk=T+273.15,L=2.501e6,Rv=461.5,cp=1004,eps=0.622;
  const es=6.112*Math.exp(17.67*T/(T+243.5));
  const rs=eps*es/(1013.25-es);
  return 9.8*(1+L*rs/(Rv*Tk))/(1+L*L*rs/(cp*Rv*Tk*Tk));
}
// Standard atmosphere height from pressure (m)
function _stH(p){return 44330*(1-Math.pow(p/1013.25,0.1903));}
// Dewpoint from T(°C) and RH(%)
function _dp(T,rh){const a=17.625,b=243.04,g=Math.log(Math.max(1,rh)/100)+a*T/(b+T);return b*g/(a-g);}
// Lift parcel from (T0,Td0,p0) to p1 — dry then moist adiabatic
function _liftP(T0,Td0,p0,p1){
  const H_lcl=125*(T0-Td0),H0=_stH(p0),H1=_stH(p1);
  const Tlcl=T0-9.8*H_lcl/1000,Hlcl=H0+H_lcl;
  if(H1<=Hlcl)return T0-9.8*(H1-H0)/1000;
  let Tc=Tlcl,Hc=Hlcl,step=200;
  while(Hc<H1-step){Tc-=_malr(Tc)*step/1000;Hc+=step;}
  Tc-=_malr(Tc)*(H1-Hc)/1000;
  return Tc;
}

// ── 1. HODOGRAPH ─────────────────────────────────────────
function drawAdvHodograph(d,ci){
  const svg=document.getElementById('hodo-svg');
  const info=document.getElementById('hodo-info');
  const stats=document.getElementById('hodo-stats');
  if(!svg)return;
  const g=id=>document.getElementById(id);
  const obs=_lastBriefObs?.metric||{};
  const ws10=(obs.windSpeed??0),wd10=(obs.winddir??obs.windDirection??0);
  const toUV=(spd,dir)=>[spd*Math.sin(dir*Math.PI/180),-spd*Math.cos(dir*Math.PI/180)];
  const levels=[
    {label:'Sfc',spd:ws10,dir:wd10,col:'#f87171'},
    {label:'850',spd:(d.wind_speed_850hPa?.[ci]??0)*1.852,dir:d.wind_direction_850hPa?.[ci]??wd10,col:'#fb923c'},
    {label:'700',spd:(d.wind_speed_700hPa?.[ci]??0)*1.852,dir:d.wind_direction_700hPa?.[ci]??wd10,col:'#a78bfa'},
    {label:'500',spd:(d.wind_speed_500hPa?.[ci]??0)*1.852,dir:d.wind_direction_500hPa?.[ci]??wd10,col:'#67e8f9'},
    {label:'300',spd:(d.wind_speed_300hPa?.[ci]??0)*1.852,dir:d.wind_direction_300hPa?.[ci]??wd10,col:'#4ade80'},
  ];
  const W=280,cx=W/2,cy=W/2,R=120;
  const maxSpd=Math.max(...levels.map(l=>l.spd),20);
  const sc=R/maxSpd;
  const mapU=u=>cx+u*sc, mapV=v=>cy+v*sc;
  let h='';
  // Rings
  [20,40,60,80,100].filter(r=>r<=maxSpd+20).forEach(r=>{
    h+=`<circle cx="${cx}" cy="${cy}" r="${(r*sc).toFixed(1)}" fill="none" stroke="rgba(255,255,255,.1)" stroke-width="0.7"/>`;
    h+=`<text x="${cx+r*sc+2}" y="${cy}" font-size="7.5" fill="rgba(255,255,255,.25)" font-family="monospace">${r}</text>`;
  });
  // Axes
  h+=`<line x1="${cx}" x2="${cx}" y1="${cy-R-12}" y2="${cy+R+12}" stroke="rgba(255,255,255,.12)" stroke-width="0.5"/>`;
  h+=`<line x1="${cx-R-12}" x2="${cx+R+12}" y1="${cy}" y2="${cy}" stroke="rgba(255,255,255,.12)" stroke-width="0.5"/>`;
  [['N',cx,cy-R-15],['S',cx,cy+R+18],['E',cx+R+12,cy+4],['W',cx-R-12,cy+4]].forEach(([l,x,y])=>
    h+=`<text x="${x}" y="${y}" text-anchor="middle" font-size="9" fill="rgba(255,255,255,.35)" font-family="sans-serif">${l}</text>`);
  // Hodograph line
  const pts=levels.map(l=>{const[u,v]=toUV(l.spd,l.dir);return{u,v,col:l.col,label:l.label,spd:l.spd,dir:l.dir};});
  const segCol=['#fb923c','#a78bfa','#67e8f9','#4ade80'];
  for(let i=1;i<pts.length;i++){
    h+=`<line x1="${mapU(pts[i-1].u).toFixed(1)}" y1="${mapV(pts[i-1].v).toFixed(1)}" x2="${mapU(pts[i].u).toFixed(1)}" y2="${mapV(pts[i].v).toFixed(1)}" stroke="${segCol[i-1]}" stroke-width="2.5" stroke-linecap="round"/>`;
  }
  pts.forEach(p=>{
    const x=mapU(p.u),y=mapV(p.v);
    h+=`<circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="5" fill="${p.col}" stroke="rgba(0,0,0,.4)" stroke-width="1.5"/>`;
    h+=`<text x="${(x+7).toFixed(1)}" y="${(y-4).toFixed(1)}" font-size="8.5" fill="${p.col}" font-family="monospace" font-weight="600">${p.label}</text>`;
  });
  svg.innerHTML=h;
  // Shear and veering analysis
  const sfc=pts[0],h500=pts[3]||pts[2];
  const shear0_6=Math.sqrt((h500.u-sfc.u)**2+(h500.v-sfc.v)**2).toFixed(0);
  const dDir=(pts[pts.length-1].dir-pts[0].dir+360)%360;
  const veering=dDir<180;
  const veeringTxt=veering?'↻ Veering (topla adveksija)':'↺ Backing (hladna adveksija)';
  if(stats)stats.innerHTML=`<b style="color:var(--text)">Shear 0–6 km:</b> ${shear0_6} km/h<br><b style="color:var(--text)">Rotacija:</b> ${veeringTxt}<br><b style="color:var(--text)">Sfc smer:</b> ${Math.round(sfc.dir)}° @ ${sfc.spd.toFixed(0)} km/h<br><b style="color:var(--text)">500 hPa:</b> ${Math.round((pts[3]||pts[2]).dir)}° @ ${(pts[3]||pts[2]).spd.toFixed(0)} km/h`;
  if(info)info.textContent=`0–6km shear: ${shear0_6} km/h · ${veering?'Veering':'Backing'}`;
}

// ── 2. SKEW-T ────────────────────────────────────────────
function drawSkewT(d,ci){
  const svg=document.getElementById('skewt-svg');
  const info=document.getElementById('skewt-info');
  if(!svg)return;
  const obs=_lastBriefObs?.metric||{};
  const T_sfc=obs.temp??15,H_sfc=_lastBriefObs?.humidity??65;
  const Td_sfc=_dp(T_sfc,H_sfc);
  const levels=[
    {p:1013,T:T_sfc,Td:Td_sfc},
    {p:925,T:d.temperature_925hPa?.[ci]??T_sfc-5,Td:_dp(d.temperature_925hPa?.[ci]??T_sfc-5,d.relative_humidity_925hPa?.[ci]??H_sfc)},
    {p:850,T:d.temperature_850hPa?.[ci]??T_sfc-9,Td:_dp(d.temperature_850hPa?.[ci]??T_sfc-9,d.relative_humidity_850hPa?.[ci]??60)},
    {p:700,T:d.temperature_700hPa?.[ci]??T_sfc-18,Td:_dp(d.temperature_700hPa?.[ci]??T_sfc-18,d.relative_humidity_700hPa?.[ci]??50)},
    {p:500,T:d.temperature_500hPa?.[ci]??T_sfc-32,Td:_dp(d.temperature_500hPa?.[ci]??T_sfc-32,30)},
    {p:300,T:d.temperature_300hPa?.[ci]??T_sfc-55,Td:null},
  ];
  const VW=600,VH=380,pl=52,pr=25,pt=15,pb=30;
  const pLevels=[1050,925,850,700,600,500,400,300];
  const lp=p=>Math.log(p),lp0=lp(1050),lp1=lp(280);
  const mapY=p=>pt+(lp(p)-lp0)/(lp1-lp0)*(VH-pt-pb);
  const Tmin=-40,Tmax=40,skew=0.8;
  const mapX=(T,p)=>pl+(T-Tmin)/(Tmax-Tmin)*(VW-pl-pr)+skew*(1050-p)/100;
  let h='';
  // Isobars
  pLevels.forEach(p=>{
    const y=mapY(p).toFixed(1);
    h+=`<line x1="${pl}" x2="${VW-pr}" y1="${y}" y2="${y}" stroke="rgba(255,255,255,.08)" stroke-width="0.7"/>`;
    h+=`<text x="${pl-4}" y="${y}" text-anchor="end" font-size="9" fill="rgba(255,255,255,.35)" font-family="monospace" dominant-baseline="middle">${p}</text>`;
  });
  // Dry adiabats
  for(let theta=-30;theta<=70;theta+=10){
    const pts=pLevels.map(p=>{const T=(theta+273.15)*Math.pow(p/1000,0.286)-273.15;return`${mapX(T,p).toFixed(1)},${mapY(p).toFixed(1)}`;}).join(' ');
    h+=`<polyline points="${pts}" fill="none" stroke="rgba(234,179,8,.18)" stroke-width="0.6"/>`;
  }
  // Moist adiabats
  [-10,0,10,20,30].forEach(Ts=>{
    let Tc=Ts,pc=1000,maPts=[];
    while(pc>=300){maPts.push(`${mapX(Tc,pc).toFixed(1)},${mapY(pc).toFixed(1)}`);Tc-=_malr(Tc)*(_stH(pc-50)-_stH(pc))/1000;pc-=50;}
    h+=`<polyline points="${maPts.join(' ')}" fill="none" stroke="rgba(34,197,94,.18)" stroke-width="0.6"/>`;
  });
  // Isotherms
  for(let T=Tmin;T<=Tmax;T+=10){
    const pts=pLevels.map(p=>`${mapX(T,p).toFixed(1)},${mapY(p).toFixed(1)}`).join(' ');
    h+=`<polyline points="${pts}" fill="none" stroke="rgba(255,255,255,.06)" stroke-width="0.5" stroke-dasharray="4,4"/>`;
    h+=`<text x="${mapX(T,1050).toFixed(1)}" y="${VH-pb+12}" text-anchor="middle" font-size="8.5" fill="rgba(255,255,255,.3)" font-family="monospace">${T}°</text>`;
  }
  // Zero isotherm
  h+=`<polyline points="${pLevels.map(p=>`${mapX(0,p).toFixed(1)},${mapY(p).toFixed(1)}`).join(' ')}" fill="none" stroke="rgba(96,165,250,.35)" stroke-width="1.2"/>`;
  // CAPE / CIN shading
  const parT=levels.map(l=>({p:l.p,T:_liftP(T_sfc,Td_sfc,1013,l.p)}));
  for(let i=1;i<levels.length;i++){
    const e1=levels[i-1],e2=levels[i],pa1=parT[i-1],pa2=parT[i];
    const poly=[`${mapX(e1.T,e1.p).toFixed(1)},${mapY(e1.p).toFixed(1)}`,`${mapX(e2.T,e2.p).toFixed(1)},${mapY(e2.p).toFixed(1)}`,`${mapX(pa2.T,pa2.p).toFixed(1)},${mapY(pa2.p).toFixed(1)}`,`${mapX(pa1.T,pa1.p).toFixed(1)},${mapY(pa1.p).toFixed(1)}`].join(' ');
    if(pa1.T>e1.T||pa2.T>e2.T)h+=`<polygon points="${poly}" fill="rgba(248,113,113,.25)"/>`;
    else if(pa1.T<e1.T&&pa2.T<e2.T)h+=`<polygon points="${poly}" fill="rgba(167,139,250,.15)"/>`;
  }
  // Env T
  h+=`<polyline points="${levels.map(l=>`${mapX(l.T,l.p).toFixed(1)},${mapY(l.p).toFixed(1)}`).join(' ')}" fill="none" stroke="#60a5fa" stroke-width="2.5" stroke-linejoin="round"/>`;
  // Dewpoint
  h+=`<polyline points="${levels.filter(l=>l.Td!=null).map(l=>`${mapX(l.Td,l.p).toFixed(1)},${mapY(l.p).toFixed(1)}`).join(' ')}" fill="none" stroke="#67e8f9" stroke-width="2" stroke-dasharray="6,3" stroke-linejoin="round"/>`;
  // Parcel
  h+=`<polyline points="${parT.map(p=>`${mapX(p.T,p.p).toFixed(1)},${mapY(p.p).toFixed(1)}`).join(' ')}" fill="none" stroke="#f87171" stroke-width="2" stroke-dasharray="5,2" stroke-linejoin="round"/>`;
  // LCL
  const H_lcl=125*(T_sfc-Td_sfc),p_lcl=1013.25*Math.pow(1-H_lcl/44330,5.2561);
  if(p_lcl>300&&p_lcl<1013){const lclY=mapY(p_lcl).toFixed(1);h+=`<line x1="${pl}" x2="${VW-pr}" y1="${lclY}" y2="${lclY}" stroke="#60a5fa" stroke-width="1" stroke-dasharray="3,3" opacity="0.5"/>`;h+=`<text x="${VW-pr+2}" y="${lclY}" font-size="8.5" fill="#60a5fa" dominant-baseline="middle">LCL</text>`;}
  svg.innerHTML=h;
  if(info)info.textContent=`T=${T_sfc.toFixed(1)}°C · Td=${Td_sfc.toFixed(1)}°C · LCL≈${Math.round(H_lcl)}m`;
}

// ── 3. PHASE-SPACE T × DPD ───────────────────────────────
function drawPhaseSpace(){
  const svg=document.getElementById('phase-svg');
  const info=document.getElementById('phase-info');
  if(!svg)return;
  const hourly=_hourlyObs||[];
  const pts=hourly.filter(o=>o.metric?.temp!=null&&o.humidity!=null).map((o,i)=>{
    const T=o.metric.temp,Td=_dp(T,o.humidity),DPD=Math.max(0,T-Td),P=o.metric.pressure??1013;
    return{T,DPD,P,i};
  });
  if(pts.length<8){svg.innerHTML='<text x="350" y="155" text-anchor="middle" font-size="11" fill="rgba(255,255,255,.2)" font-family="sans-serif">Premalo urnih podatkov (min 8h)</text>';return;}
  const VW=700,VH=300,pl=50,pr=20,pt=15,pb=38;
  const allT=pts.map(p=>p.T),allD=pts.map(p=>p.DPD),allP=pts.map(p=>p.P);
  const minT=Math.min(...allT)-2,maxT=Math.max(...allT)+2;
  const maxDPD=Math.max(...allD)+2,minP=Math.min(...allP),maxP=Math.max(...allP);
  const mapX=T=>pl+(T-minT)/(maxT-minT)*(VW-pl-pr);
  const mapY=d=>pt+(1-d/maxDPD)*(VH-pt-pb);
  const pSize=P=>2+4*(P-minP)/Math.max(1,maxP-minP);
  const tCol=(i,n)=>{const f=i/Math.max(1,n-1);const r=Math.round(167+(75-167)*f),g2=Math.round(139+(222-139)*f),b=Math.round(250+(128-250)*f);return`rgb(${r},${g2},${b})`;};
  let h='';
  // Grid
  const tStep=Math.ceil((maxT-minT)/6);
  for(let t=Math.ceil(minT/tStep)*tStep;t<=maxT;t+=tStep){const x=mapX(t).toFixed(1);h+=`<line x1="${x}" x2="${x}" y1="${pt}" y2="${VH-pb}" stroke="rgba(255,255,255,.07)" stroke-width="0.5"/>`;h+=`<text x="${x}" y="${VH-pb+13}" text-anchor="middle" font-size="8.5" fill="rgba(255,255,255,.3)" font-family="monospace">${t.toFixed(0)}°C</text>`;}
  const dStep=Math.ceil(maxDPD/5);
  for(let d=0;d<=maxDPD;d+=dStep){const y=mapY(d).toFixed(1);h+=`<line x1="${pl}" x2="${VW-pr}" y1="${y}" y2="${y}" stroke="rgba(255,255,255,.07)" stroke-width="0.5"/>`;h+=`<text x="${pl-4}" y="${y}" text-anchor="end" font-size="8.5" fill="rgba(255,255,255,.3)" font-family="monospace" dominant-baseline="middle">${d.toFixed(0)}°</text>`;}
  // Regime labels
  h+=`<text x="${mapX(maxT-3).toFixed(1)}" y="${mapY(1).toFixed(1)}" font-size="8.5" fill="rgba(251,146,60,.45)" font-family="sans-serif" text-anchor="end">Fen/sušno</text>`;
  h+=`<text x="${mapX(minT+3).toFixed(1)}" y="${mapY(2.5).toFixed(1)}" font-size="8.5" fill="rgba(96,165,250,.45)" font-family="sans-serif">Polarna/vlažna</text>`;
  // Axis labels
  h+=`<text x="${VW/2}" y="${VH-2}" text-anchor="middle" font-size="9" fill="rgba(255,255,255,.35)" font-family="sans-serif">Temperatura (°C)</text>`;
  // Trajectory + points
  const linePts=pts.map(p=>`${mapX(p.T).toFixed(1)},${mapY(p.DPD).toFixed(1)}`).join(' ');
  h+=`<polyline points="${linePts}" fill="none" stroke="rgba(167,139,250,.2)" stroke-width="1"/>`;
  pts.forEach((p,i)=>{h+=`<circle cx="${mapX(p.T).toFixed(1)}" cy="${mapY(p.DPD).toFixed(1)}" r="${pSize(p.P).toFixed(1)}" fill="${tCol(i,pts.length)}" opacity="0.8"/>`;});
  // Latest
  const last=pts[pts.length-1];
  h+=`<circle cx="${mapX(last.T).toFixed(1)}" cy="${mapY(last.DPD).toFixed(1)}" r="7" fill="#4ade80" stroke="rgba(0,0,0,.4)" stroke-width="2"/>`;
  svg.innerHTML=h;
  const foehn=last.T>18&&last.DPD<3,coldFront=pts.length>3&&(pts[pts.length-1].T-pts[pts.length-4].T)<-3;
  if(info)info.textContent=`${pts.length}h · T=${last.T.toFixed(1)}°C DPD=${last.DPD.toFixed(1)}°C${foehn?' · 🌬 Fen?':''}${coldFront?' · 🌨 Fronta?':''}`;
}

// ── 4. FFT PERIODOGRAM ───────────────────────────────────
function _fft(re,im){
  const n=re.length;let j=0;
  for(let i=1;i<n;i++){let bit=n>>1;for(;j&bit;bit>>=1)j^=bit;j^=bit;if(i<j){[re[i],re[j]]=[re[j],re[i]];[im[i],im[j]]=[im[j],im[i]];}}
  for(let len=2;len<=n;len<<=1){const ang=-2*Math.PI/len,wR=Math.cos(ang),wI=Math.sin(ang);for(let i=0;i<n;i+=len){let cR=1,cI=0;for(let k=0;k<len/2;k++){const uR=re[i+k],uI=im[i+k],vR=re[i+k+len/2]*cR-im[i+k+len/2]*cI,vI=re[i+k+len/2]*cI+im[i+k+len/2]*cR;re[i+k]=uR+vR;im[i+k]=uI+vI;re[i+k+len/2]=uR-vR;im[i+k+len/2]=uI-vI;const nR=cR*wR-cI*wI;cI=cR*wI+cI*wR;cR=nR;}}}
}
function drawFFTPeriodogram(){
  const svg=document.getElementById('fft-svg');
  const info=document.getElementById('fft-info');
  if(!svg)return;
  const hourly=_hourlyObs||[];
  const pressures=hourly.map(o=>o.metric?.pressure).filter(v=>v!=null&&v>900&&v<1100);
  if(pressures.length<32){svg.innerHTML='<text x="440" y="105" text-anchor="middle" font-size="11" fill="rgba(255,255,255,.2)" font-family="sans-serif">Premalo tlačnih podatkov (min 32h)</text>';return;}
  // Pad to next power of 2
  let N=1;while(N<pressures.length)N<<=1;
  const re=new Float64Array(N),im=new Float64Array(N);
  const mean=pressures.reduce((s,v)=>s+v,0)/pressures.length;
  const n2=pressures.length,slope=(pressures[n2-1]-pressures[0])/(n2-1);
  // Detrend + Hann window
  pressures.forEach((v,i)=>{re[i]=(v-mean-slope*i)*(0.5-0.5*Math.cos(2*Math.PI*i/(n2-1)));});
  _fft(re,im);
  // Power (one-sided), period in hours
  const power=[];
  for(let k=1;k<=N/2;k++)power.push({k,pow:re[k]*re[k]+im[k]*im[k],period:N/k});
  const maxP=Math.max(...power.map(p=>p.pow));
  power.forEach(p=>p.norm=p.pow/maxP);
  const filtered=power.filter(p=>p.period>=1&&p.period<=240);
  const VW=880,VH=200,pl=42,pr=20,pt=15,pb=38;
  const periods=filtered.map(p=>p.period);
  const minLP=Math.log10(Math.max(1,Math.min(...periods))),maxLP=Math.log10(Math.max(...periods));
  const mapX=T=>pl+(Math.log10(T)-minLP)/(maxLP-minLP)*(VW-pl-pr);
  const mapY=v=>pt+(1-v)*(VH-pt-pb);
  let h='';
  // Key period grid lines
  [1,2,4,6,12,24,48,72,120,168].forEach(p=>{if(p<Math.pow(10,minLP)||p>Math.pow(10,maxLP))return;const x=mapX(p).toFixed(1);h+=`<line x1="${x}" x2="${x}" y1="${pt}" y2="${VH-pb}" stroke="rgba(255,255,255,.08)" stroke-width="0.5"/>`;h+=`<text x="${x}" y="${VH-pb+13}" text-anchor="middle" font-size="8.5" fill="rgba(255,255,255,.3)" font-family="monospace">${p<24?p+'h':p/24+'d'}</text>`;});
  // Power bars coloured by period category
  filtered.forEach(p=>{const x=mapX(p.period),barH=p.norm*(VH-pt-pb);const col=p.period>23.5&&p.period<24.5?'#fbbf24':p.period>11.5&&p.period<12.5?'#a78bfa':p.period>47&&p.period<120?'#60a5fa':p.period<7?'#4ade80':'rgba(148,163,184,.4)';h+=`<rect x="${(x-.8).toFixed(1)}" y="${(VH-pb-barH).toFixed(1)}" width="1.6" height="${barH.toFixed(1)}" fill="${col}" opacity="0.85"/>`;});
  // Top-5 peaks
  const peaks=[];for(let i=1;i<filtered.length-1;i++){if(filtered[i].norm>filtered[i-1].norm&&filtered[i].norm>filtered[i+1].norm)peaks.push(filtered[i]);}
  peaks.sort((a,b)=>b.norm-a.norm).slice(0,5).forEach(p=>{
    const lbl=p.period>23&&p.period<25?'24h':p.period>11.5&&p.period<12.5?'12h':p.period>47&&p.period<73?`${(p.period/24).toFixed(1)}d`:`${p.period.toFixed(1)}h`;
    const x=mapX(p.period),y=mapY(p.norm);
    h+=`<line x1="${x.toFixed(1)}" x2="${x.toFixed(1)}" y1="${(y-4).toFixed(1)}" y2="${(y-20).toFixed(1)}" stroke="rgba(255,255,255,.3)" stroke-width="0.8"/>`;
    h+=`<text x="${x.toFixed(1)}" y="${(y-23).toFixed(1)}" text-anchor="middle" font-size="8.5" fill="white" font-family="sans-serif">${lbl}</text>`;
  });
  svg.innerHTML=h;
  const dom=peaks[0];
  if(info)info.textContent=`${pressures.length} urnih točk · N=${N} · dominanta: ${dom?dom.period.toFixed(1)+'h':'—'}`;
}

// Called from renderStormChaser to update all viz
function updateAdvViz(d,ci){
  try{drawAdvHodograph(d,ci);}catch(e){console.warn('Hodo:',e);}
  try{drawSkewT(d,ci);}catch(e){console.warn('SkewT:',e);}
  try{drawPhaseSpace();}catch(e){console.warn('Phase:',e);}
  try{drawFFTPeriodogram();}catch(e){console.warn('FFT:',e);}
}

function initStormChaser(){
  if(!_scInit){_scInit=true;}
  fetchStormChaser();
  try{fetchSloStormMap();}catch(e){console.error('slomap',e);}
  try{buildWindFingerprint();}catch(e){console.error('fp',e);}
  try{buildTurbulenceIndex();}catch(e){console.error('turb',e);}
}
