// ── Visitor counter ───────────────────────────────────────
async function initVisitorCounter(){
  const ftYear=document.getElementById('ft-year');
  if(ftYear)ftYear.textContent=new Date().getFullYear();
  const el=document.getElementById('vc-num');
  const wrap=document.getElementById('visitor-counter');
  if(!el)return;
  try{
    const ctrl=new AbortController();const tid=setTimeout(()=>ctrl.abort(),5000);
    const r=await fetch('https://ibanezar.goatcounter.com/counter//.json',{signal:ctrl.signal}).finally(()=>clearTimeout(tid));
    if(r.ok){
      const d=await r.json();
      const n=parseInt((d.count??'').replace(/\s/g,''),10);
      if(!isNaN(n)){el.textContent=n.toLocaleString('sl');wrap?.classList.add('loaded');return;}
    }
  }catch(_){}
  if(wrap)wrap.style.display='none';
}

async function init(){
  // ── Synchronous setup (no network) — each call guarded so a crash in one
  // widget (e.g. canvas unavailable in Facebook IAB) never blocks fetchCurrent.
  try{applyStationOnThisDay();}catch(_){}
  try{applyMoon();}catch(_){}
  try{applyMonthlySummary();}catch(_){}
  try{applyYearRecords();}catch(_){}
  try{renderPastDays();}catch(_){}
  try{applyPhotographyWidget(null);}catch(_){}
  try{initBgCanvas();}catch(_){}
  try{applyWeatherBg('night');}catch(_){}
  try{initNotifBtn();}catch(_){}
  try{initNotifHint();}catch(_){}
  try{initMeshCanvas();}catch(_){}
  try{initHeroCanvas();}catch(_){}
  try{autoLoadHistoryFile();}catch(_){}
  setTimeout(()=>{try{initWeatherArt();setWeatherArt(_lastBriefObs||{});}catch(_){}},150);
  try{loadThresholds();}catch(_){} // restore user alert thresholds from localStorage
  try{_fcSliderInit();}catch(_){}
  // ── Wave 1: critical for the initial visible tab ──
  await Promise.all([fetchCurrent(),fetchHourly()]);
  autoAccentCards();
  fetchAIForecast(); // non-blocking — populates forecast tab card

  // ── Wave 2: forecast tab content (~0.8 s after wave 1) ──
  setTimeout(()=>{
    fetchTextForecast();
    fetchForecastExtras();
    fetchAndDrawSkyStrip();
    fetchComingUp();
  },800);

  // ── Wave 3: secondary widgets (2.5 s) ──
  setTimeout(()=>{
    fetchAirQuality();
    fetchAgrometeo();
    fetchClimateComparison();
    fetchFogForecast();
    fetchEcowittCurrent();
    initInsights();
    initVisitorCounter();
    checkSmartNotifications();
    loadBlogTicker();
  },2500);

  // ── Wave 3.5: precip nowcast (4 s) ──
  setTimeout(fetchPrecipNowcast,4000);

  // ── Wave 4: lowest priority (6 s) ──
  setTimeout(()=>{
    fetchSevereWeather();
    fetchMeteoalarm();
    fetchGoogleAlerts();
    fetchPollen();
    fetchAIBrief();
    connectLightning();
    buildPrecipNormals();
    buildSunshineNormals();
    applyPheno();
  },6000);
}

