// ── NASA POWER — Climate Baselines ─────────────────────────
// ══════════════════════════════════════════════════════════
const _NASA_CLIM_CACHE_KEY='wx-nasa-clim-v1';

async function fetchNASABaselines(){
  const el=document.getElementById('nasa-clim-body');if(!el)return;
  try{
    const c=JSON.parse(localStorage.getItem(_NASA_CLIM_CACHE_KEY)||'null');
    if(c&&Date.now()-c.ts<4*3600000){renderNASABaselines(c.data);return;}
  }catch(_){}
  try{
    const r=await fetch(PROXY+'/nasa-power?type=baselines');
    if(!r.ok)throw new Error('HTTP '+r.status);
    const data=await r.json();
    try{localStorage.setItem(_NASA_CLIM_CACHE_KEY,JSON.stringify({ts:Date.now(),data}));}catch(_){}
    renderNASABaselines(data);
    const src=document.getElementById('nasa-clim-src');
    if(src)src.textContent='NASA POWER · MERRA-2 · '+new Date().toLocaleDateString('sl');
  }catch(e){
    el.innerHTML='<div style="color:var(--muted);font-size:.78rem">Podatki NASA POWER Baselines niso dosegljivi.</div>';
    console.warn('nasa-clim:',e);
  }
}

function renderNASABaselines(data){
  const el=document.getElementById('nasa-clim-body');if(!el||!data?.length)return;
  const p=data[0]?.properties?.parameter;
  if(!p){el.innerHTML='<div style="color:var(--muted);font-size:.78rem">Ni podatkov.</div>';return;}
  const t2m=CLIM_KEYS.map(k=>{const v=p.T2M?.[k];return(v==null||v===-999)?null:v;});
  const tmax=CLIM_KEYS.map(k=>{const v=p.T2M_MAX?.[k];return(v==null||v===-999)?null:v;});
  const tmin=CLIM_KEYS.map(k=>{const v=p.T2M_MIN?.[k];return(v==null||v===-999)?null:v;});
  const prec=CLIM_KEYS.map(k=>{const v=p.PRECTOTCORR?.[k];return(v==null||v===-999)?null:v;});

  // Temperature chart
  const W=880,HT=200,mL=45,mR=15,mT=18,mB=35;
  const cW=W-mL-mR,cHT=HT-mT-mB;
  const allT=[...tmax,...t2m,...tmin].filter(v=>v!=null);
  const minT=Math.floor(Math.min(...allT)-1),maxT=Math.ceil(Math.max(...allT)+1);
  const yT=v=>mT+cHT-(v-minT)/(maxT-minT)*cHT;

  let tGrid='';
  const tTicks=5;
  for(let i=0;i<=tTicks;i++){
    const v=minT+(maxT-minT)*i/tTicks;
    const y=yT(v);
    tGrid+=`<line x1="${mL}" y1="${y.toFixed(1)}" x2="${W-mR}" y2="${y.toFixed(1)}" stroke="var(--fc-border)" stroke-width="0.5"/>`;
    tGrid+=`<text x="${(mL-4)}" y="${(y+3.5).toFixed(1)}" font-size="9" text-anchor="end" fill="var(--muted)" font-family="'JetBrains Mono',monospace">${v.toFixed(0)}</text>`;
  }
  // Zero line
  if(minT<0&&maxT>0){
    const y0=yT(0);
    tGrid+=`<line x1="${mL}" y1="${y0.toFixed(1)}" x2="${W-mR}" y2="${y0.toFixed(1)}" stroke="var(--muted)" stroke-width="1" stroke-dasharray="3,2" opacity="0.6"/>`;
  }

  // Tmax area fill
  let tmaxPts=[],tminPts=[],t2mPts=[];
  for(let i=0;i<12;i++){
    const cx=mL+(i+0.5)*(cW/12);
    if(tmax[i]!=null)tmaxPts.push(`${cx.toFixed(1)},${yT(tmax[i]).toFixed(1)}`);
    if(t2m[i]!=null)t2mPts.push(`${cx.toFixed(1)},${yT(t2m[i]).toFixed(1)}`);
    if(tmin[i]!=null)tminPts.push(`${cx.toFixed(1)},${yT(tmin[i]).toFixed(1)}`);
    tGrid+=`<text x="${cx.toFixed(1)}" y="${(HT-mB+14).toFixed(0)}" font-size="9" text-anchor="middle" fill="var(--muted)" font-family="Inter,sans-serif">${SL_MON[i]}</text>`;
  }
  // Area between tmax and tmin
  const allXY=[...tmax.map((v,i)=>v!=null?`${(mL+(i+0.5)*(cW/12)).toFixed(1)},${yT(v).toFixed(1)}`:null).filter(Boolean),
    ...[...tmin].reverse().map((v,i,a)=>{const ri=11-i;return tmin[ri]!=null?`${(mL+(ri+0.5)*(cW/12)).toFixed(1)},${yT(tmin[ri]).toFixed(1)}`:null}).filter(Boolean)];
  const tmaxArea=allXY.length?`<polygon points="${allXY.join(' ')}" fill="var(--red)" opacity="0.12"/>`:
    '';
  const yLabel=`<text x="11" y="${(mT+cHT/2).toFixed(0)}" font-size="9" text-anchor="middle" fill="var(--muted)" font-family="Inter,sans-serif" transform="rotate(-90,11,${(mT+cHT/2).toFixed(0)})">°C</text>`;
  const tLegend=`<line x1="${mL+4}" y1="${HT-mB-12}" x2="${mL+16}" y2="${HT-mB-12}" stroke="var(--red)" stroke-width="2"/><text x="${mL+19}" y="${HT-mB-8}" font-size="9" fill="var(--muted)" font-family="Inter,sans-serif">Tmax</text>`+
    `<line x1="${mL+58}" y1="${HT-mB-12}" x2="${mL+70}" y2="${HT-mB-12}" stroke="var(--muted)" stroke-width="1.5"/><text x="${mL+73}" y="${HT-mB-8}" font-size="9" fill="var(--muted)" font-family="Inter,sans-serif">Tsred</text>`+
    `<line x1="${mL+116}" y1="${HT-mB-12}" x2="${mL+128}" y2="${HT-mB-12}" stroke="var(--blue)" stroke-width="2"/><text x="${mL+131}" y="${HT-mB-8}" font-size="9" fill="var(--muted)" font-family="Inter,sans-serif">Tmin</text>`;
  const svgT=`<div style="overflow-x:auto"><svg viewBox="0 0 ${W} ${HT}" style="display:block;width:100%;min-width:${W}px" xmlns="http://www.w3.org/2000/svg">${tGrid}${tmaxArea}<polyline points="${tmaxPts.join(' ')}" fill="none" stroke="var(--red)" stroke-width="1.8"/><polyline points="${t2mPts.join(' ')}" fill="none" stroke="var(--muted)" stroke-width="1.5"/><polyline points="${tminPts.join(' ')}" fill="none" stroke="var(--blue)" stroke-width="1.8"/>${yLabel}${tLegend}</svg></div>`;

  // Precipitation chart
  const HP=140,cHP=HP-mT-mB;
  const maxP=Math.max(...prec.filter(v=>v!=null),1);
  const yP=v=>mT+cHP-v/maxP*cHP;
  let pGrid='',pBars='';
  const pTicks=3;
  for(let i=0;i<=pTicks;i++){
    const v=maxP*i/pTicks;
    const y=yP(v);
    pGrid+=`<line x1="${mL}" y1="${y.toFixed(1)}" x2="${W-mR}" y2="${y.toFixed(1)}" stroke="var(--fc-border)" stroke-width="0.5"/>`;
    pGrid+=`<text x="${(mL-4)}" y="${(y+3.5).toFixed(1)}" font-size="9" text-anchor="end" fill="var(--muted)" font-family="'JetBrains Mono',monospace">${v.toFixed(0)}</text>`;
  }
  const pbW=Math.floor((cW/12)*0.6);
  for(let i=0;i<12;i++){
    const cx=mL+(i+0.5)*(cW/12);
    if(prec[i]!=null){
      const bh=prec[i]/maxP*cHP;
      pBars+=`<rect x="${(cx-pbW/2).toFixed(1)}" y="${yP(prec[i]).toFixed(1)}" width="${pbW}" height="${bh.toFixed(1)}" fill="var(--blue)" opacity="0.7" rx="2"><title>${SL_MON[i]}: ${prec[i].toFixed(1)} mm</title></rect>`;
    }
    pGrid+=`<text x="${cx.toFixed(1)}" y="${(HP-mB+14).toFixed(0)}" font-size="9" text-anchor="middle" fill="var(--muted)" font-family="Inter,sans-serif">${SL_MON[i]}</text>`;
  }
  const pYLabel=`<text x="11" y="${(mT+cHP/2).toFixed(0)}" font-size="9" text-anchor="middle" fill="var(--muted)" font-family="Inter,sans-serif" transform="rotate(-90,11,${(mT+cHP/2).toFixed(0)})">mm/mesec</text>`;
  const svgP=`<div style="overflow-x:auto"><svg viewBox="0 0 ${W} ${HP}" style="display:block;width:100%;min-width:${W}px" xmlns="http://www.w3.org/2000/svg">${pGrid}${pBars}${pYLabel}</svg></div>`;

  const note=`<div style="font-size:.67rem;color:var(--muted);margin-top:.5rem">🛸 Satelitski podatki NASA POWER (1994–2023) · za primerjavo z normalami ARSO (1991–2020) zgoraj</div>`;
  const src=`<div class="nasa-src">NASA POWER · Reanaliza MERRA-2 · kalibrirano za lokacijo</div>`;
  el.innerHTML=svgT+svgP+note+src;
}

