const _NASA_AGRO_CACHE_KEY='wx-nasa-agro-v1';
const _DAYS_IN_MON=[31,28,31,30,31,30,31,31,30,31,30,31];

async function fetchNASAAgro(){
  const el=document.getElementById('nasa-agro-body');if(!el)return;
  try{
    const c=JSON.parse(localStorage.getItem(_NASA_AGRO_CACHE_KEY)||'null');
    if(c&&Date.now()-c.ts<4*3600000){renderNASAAgro(c.data);return;}
  }catch(_){}
  try{
    const r=await fetch(PROXY+'/nasa-power?type=agro');
    if(!r.ok)throw new Error('HTTP '+r.status);
    const data=await r.json();
    try{localStorage.setItem(_NASA_AGRO_CACHE_KEY,JSON.stringify({ts:Date.now(),data}));}catch(_){}
    renderNASAAgro(data);
    const src=document.getElementById('nasa-agro-src');
    if(src)src.textContent='NASA POWER · AG · '+new Date().toLocaleDateString('sl');
  }catch(e){
    el.innerHTML='<div style="color:var(--muted);font-size:.78rem">Podatki NASA POWER Agro niso dosegljivi.</div>';
    console.warn('nasa-agro:',e);
  }
}

function renderNASAAgro(data){
  const el=document.getElementById('nasa-agro-body');if(!el||!data?.length)return;
  const p=data[0]?.properties?.parameter;
  if(!p){el.innerHTML='<div style="color:var(--muted);font-size:.78rem">Ni podatkov.</div>';return;}
  const evpt=CLIM_KEYS.map((k,i)=>{const v=p.EVPTRNS?.[k];return(v==null||v===-999)?null:v*_DAYS_IN_MON[i];});
  const par=CLIM_KEYS.map(k=>{const v=p.ALLSKY_SFC_PAR_TOT?.[k];return(v==null||v===-999)?null:v;});
  const frost=CLIM_KEYS.map(k=>{const v=p.FROST_DAYS?.[k];return(v==null||v===-999)?null:v;});

  const annET=p.EVPTRNS?.ANN;
  const annFrost=p.FROST_DAYS?.ANN;
  const julPAR=par[6];

  const kpi=`<div class="nasa-kpi-row">
    <div class="nasa-kpi"><div class="nasa-kpi-val">${annET!=null&&annET!==-999?(annET*365).toFixed(0):'—'} <span style="font-size:.7rem;color:var(--muted)">mm</span></div><div class="nasa-kpi-lbl">Letna ET</div></div>
    <div class="nasa-kpi"><div class="nasa-kpi-val">${annFrost!=null&&annFrost!==-999?Math.round(annFrost):'—'} <span style="font-size:.7rem;color:var(--muted)">dni</span></div><div class="nasa-kpi-lbl">Dni s pozebo</div></div>
    <div class="nasa-kpi"><div class="nasa-kpi-val">${julPAR!=null?julPAR.toFixed(1):'—'} <span style="font-size:.7rem;color:var(--muted)">W/m²</span></div><div class="nasa-kpi-lbl">PAR julij</div></div>
  </div>`;

  function miniChart(vals,color,yLabel,H){
    const W=880,mL=45,mR=15,mT=12,mB=30;
    const cW=W-mL-mR,cH=H-mT-mB;
    const allV=vals.filter(v=>v!=null);
    const maxV=Math.max(...allV,0.01);
    const bW=Math.floor((cW/12)*0.6);
    let inner='';
    const ticks=3;
    for(let i=0;i<=ticks;i++){
      const v=maxV*i/ticks;
      const y=mT+cH-v/maxV*cH;
      inner+=`<line x1="${mL}" y1="${y.toFixed(1)}" x2="${W-mR}" y2="${y.toFixed(1)}" stroke="var(--fc-border)" stroke-width="0.5"/>`;
      inner+=`<text x="${(mL-4)}" y="${(y+3.5).toFixed(1)}" font-size="8" text-anchor="end" fill="var(--muted)" font-family="'JetBrains Mono',monospace">${v.toFixed(v<10?1:0)}</text>`;
    }
    for(let i=0;i<12;i++){
      const cx=mL+(i+0.5)*(cW/12);
      if(vals[i]!=null){
        const bh=vals[i]/maxV*cH;
        inner+=`<rect x="${(cx-bW/2).toFixed(1)}" y="${(mT+cH-bh).toFixed(1)}" width="${bW}" height="${bh.toFixed(1)}" fill="${color}" opacity="0.78" rx="2"><title>${SL_MON[i]}: ${vals[i].toFixed(1)}</title></rect>`;
      }
      inner+=`<text x="${cx.toFixed(1)}" y="${(H-mB+12).toFixed(0)}" font-size="8" text-anchor="middle" fill="var(--muted)" font-family="Inter,sans-serif">${SL_MON[i]}</text>`;
    }
    inner+=`<text x="10" y="${(mT+cH/2).toFixed(0)}" font-size="8" text-anchor="middle" fill="var(--muted)" font-family="Inter,sans-serif" transform="rotate(-90,10,${(mT+cH/2).toFixed(0)})">${yLabel}</text>`;
    return `<div style="overflow-x:auto"><svg viewBox="0 0 ${W} ${H}" style="display:block;width:100%;min-width:${W}px" xmlns="http://www.w3.org/2000/svg">${inner}</svg></div>`;
  }

  const s1=`<div class="nasa-section-lbl">Evapotranspiracija (ET₀)</div>`+miniChart(evpt,'var(--green)','mm',120);
  const s2=`<div class="nasa-section-lbl">Dni s pozebo (Tmin &lt; 0 °C)</div>`+miniChart(frost,'var(--blue)','dni',120);
  const s3=`<div class="nasa-section-lbl">Fotosintetsko aktivno sevanje (PAR)</div>`+miniChart(par,'var(--amber)','W/m²',120);
  const src=`<div class="nasa-src">NASA POWER · satelitski + modelski podatki · klimatološko povprečje 1994–2023</div>`;
  el.innerHTML=kpi+s1+s2+s3+src;
}

// ═══ PADALCI ══════════════════════════════════════════════
let _padalciInit=false,_padalciCache=null,_padalciCacheT=0;

async function initPadalci(){
  if(_padalciInit)return; _padalciInit=true;
  try{
    const now=Date.now();
    if(!_padalciCache||now-_padalciCacheT>3600000){
      const url='https://api.open-meteo.com/v1/forecast?latitude='+LAT+'&longitude='+LON
        +'&hourly=boundary_layer_height,cape,lifted_index,wind_speed_10m,wind_speed_80m,'
        +'wind_direction_10m,wind_direction_80m,precipitation_probability,precipitation,'
        +'is_day,temperature_2m,dew_point_2m'
        +'&daily=temperature_2m_max,precipitation_sum,wind_speed_10m_max,wind_gusts_10m_max,'
        +'sunshine_duration,weather_code'
        +'&timezone=Europe%2FLjubljana&forecast_days=7';
      _padalciCache=await fetch(url).then(r=>r.json());
      _padalciCacheT=now;
    }
    _buildPadalciKPIs(_padalciCache);
    _buildPadalciFlyWindow(_padalciCache);
    _buildPadalciBLChart(_padalciCache);
    _buildPadalciDailyFc(_padalciCache);
    _buildPadalciSuit(_padalciCache);
  }catch(e){console.error('initPadalci',e);}
}

// Flyability score 0–100 for a single hour
function _flyScore(windKmh,precipProb,cape,blH,isDay){
  if(!isDay)return -1; // night
  if(precipProb>70)return 0;
  if(windKmh>45)return 0;
  let s=100;
  if(windKmh>35)s-=50;
  else if(windKmh>25)s-=30;
  else if(windKmh>18)s-=15;
  if(cape>2000)s-=50;
  else if(cape>1000)s-=30;
  else if(cape>500)s-=15;
  if(precipProb>50)s-=35;
  else if(precipProb>30)s-=20;
  else if(precipProb>15)s-=10;
  if(blH<200)s-=25;
  else if(blH<500)s-=10;
  else if(blH>1500)s+=5;
  return Math.max(0,Math.min(100,s));
}

function _flyLabel(score){
  if(score<0)return{cls:'fly-night',txt:'•',bl:''};
  if(score>=70)return{cls:'fly-go',txt:'FLY',col:'rgba(20,83,45,.9)'};
  if(score>=40)return{cls:'fly-maybe',txt:'MAY',col:'rgba(92,45,3,.9)'};
  return{cls:'fly-no',txt:'NO',col:null};
}

function _buildPadalciKPIs(d){
  const el=document.getElementById('fly-kpis');if(!el)return;
  const h=d.hourly||{};
  const today=_localDateStr(new Date());
  // Collect today's daytime hours
  const todayIdxs=[];
  (h.time||[]).forEach((t,i)=>{if(t.startsWith(today)&&h.is_day?.[i])todayIdxs.push(i);});
  const blVals=todayIdxs.map(i=>h.boundary_layer_height?.[i]??0).filter(v=>v>0);
  const capeVals=todayIdxs.map(i=>h.cape?.[i]??0);
  const windVals=todayIdxs.map(i=>h.wind_speed_10m?.[i]??0);
  const maxBL=blVals.length?Math.round(Math.max(...blVals)):null;
  const maxCAPE=capeVals.length?Math.round(Math.max(...capeVals)):null;
  const maxWind=windVals.length?Math.round(Math.max(...windVals)):null;
  const flyHours=todayIdxs.filter(i=>_flyScore(h.wind_speed_10m?.[i]??0,h.precipitation_probability?.[i]??0,h.cape?.[i]??0,h.boundary_layer_height?.[i]??0,h.is_day?.[i])>=70).length;
  const kpis=[
    {val:maxBL!=null?maxBL+' m':'—',lbl:'Maks. višina BL',sub:'konvektivni strop',col:maxBL!=null&&maxBL>1500?'var(--green)':maxBL!=null&&maxBL<400?'var(--muted)':null},
    {val:flyHours>0?flyHours+' h':'0 h',lbl:'Ure letenja',sub:'ocena ≥ 70, danes',col:flyHours>=4?'var(--green)':flyHours>=2?'var(--amber)':flyHours>0?'var(--muted)':'var(--red)'},
    {val:maxCAPE!=null?maxCAPE+' J/kg':'—',lbl:'Maks. CAPE',sub:maxCAPE!=null&&maxCAPE>1000?'⚠️ nevihtno':maxCAPE!=null&&maxCAPE>500?'pozor':'ok',col:maxCAPE!=null&&maxCAPE>1000?'var(--red)':maxCAPE!=null&&maxCAPE>500?'var(--amber)':null},
    {val:maxWind!=null?maxWind+' km/h':'—',lbl:'Maks. veter',sub:'površina danes',col:maxWind!=null&&maxWind>30?'var(--red)':maxWind!=null&&maxWind>20?'var(--amber)':null},
  ];
  el.innerHTML=kpis.map(k=>`<div class="fly-kpi"><div class="fly-kpi-val"${k.col?` style="color:${k.col}"`:''}>${k.val}</div><div class="fly-kpi-lbl">${k.lbl}</div><div class="fly-kpi-sub">${k.sub}</div></div>`).join('');
}

function _buildPadalciFlyWindow(d){
  const el=document.getElementById('fly-window-body');if(!el)return;
  const h=d.hourly||{};
  const today=_localDateStr(new Date());
  // 6:00–20:00 = 15 slots
  const slots=[];
  (h.time||[]).forEach((t,i)=>{
    if(!t.startsWith(today))return;
    const hr=parseInt(t.slice(11,13));
    if(hr<6||hr>20)return;
    const wind=h.wind_speed_10m?.[i]??0;
    const precip=h.precipitation_probability?.[i]??0;
    const cape=h.cape?.[i]??0;
    const bl=h.boundary_layer_height?.[i]??0;
    const isDay=h.is_day?.[i]??0;
    const score=_flyScore(wind,precip,cape,bl,isDay);
    slots.push({hr,score,bl:Math.round(bl),wind:Math.round(wind),precip});
  });
  if(!slots.length){el.innerHTML='<div style="color:var(--muted)">Ni podatkov za danes</div>';return;}
  let slotsHtml='';
  slots.forEach(s=>{
    const {cls,txt}=_flyLabel(s.score);
    const midTxt=s.score<0?'—':s.score>=40&&s.bl>0?s.bl+'m':txt;
    const windTxt=s.score>=0?'💨'+s.wind:'';
    slotsHtml+=`<div class="fly-slot ${cls}">
      <div class="fly-slot-time">${s.hr}h</div>
      <div class="fly-slot-bl">${midTxt}</div>
      <div class="fly-slot-wind">${windTxt}</div>
    </div>`;
  });
  const html=`<div class="fly-scroll"><div class="fly-slots">${slotsHtml}</div></div>
  <div style="display:flex;gap:1rem;margin-top:.6rem;font-size:.65rem;flex-wrap:wrap">
    <span><span style="display:inline-block;width:10px;height:10px;border-radius:2px;background:rgba(74,222,128,.65);margin-right:3px;vertical-align:middle"></span>LETENJE ≥ 70 · višina BL</span>
    <span><span style="display:inline-block;width:10px;height:10px;border-radius:2px;background:rgba(251,191,36,.6);margin-right:3px;vertical-align:middle"></span>Mejno 40–69</span>
    <span><span style="display:inline-block;width:10px;height:10px;border-radius:2px;background:rgba(248,113,113,.35);margin-right:3px;vertical-align:middle"></span>Brez letenja &lt; 40</span>
  </div>`;
  el.innerHTML=html;
}

function _buildPadalciBLChart(d){
  const chartEl=document.getElementById('fly-bl-chart');
  const legEl=document.getElementById('fly-bl-legend');
  if(!chartEl)return;
  const h=d.hourly||{};
  const today=_localDateStr(new Date());
  const pts=[];
  (h.time||[]).forEach((t,i)=>{
    if(!t.startsWith(today))return;
    const hr=parseInt(t.slice(11,13));
    if(hr<5||hr>21)return;
    pts.push({hr,bl:h.boundary_layer_height?.[i]??0,wind:h.wind_speed_10m?.[i]??0,cape:h.cape?.[i]??0});
  });
  if(!pts.length){chartEl.innerHTML='<div style="color:var(--muted);font-size:.75rem">Ni podatkov</div>';return;}
  const W=880,H=100,pad={l:40,r:10,t:10,b:20};
  const cW=W-pad.l-pad.r,cH=H-pad.t-pad.b;
  const maxBL=4000;
  const xScale=i=>(pad.l+i*(cW/(pts.length-1)));
  const yScale=v=>(pad.t+cH-(v/maxBL)*cH);
  // Fill under curve
  let pathD=`M${xScale(0)},${yScale(0)}`;
  pts.forEach((p,i)=>{pathD+=` L${xScale(i)},${yScale(p.bl)}`;});
  pathD+=` L${xScale(pts.length-1)},${H-pad.b} L${xScale(0)},${H-pad.b} Z`;
  // Line
  let lineD=`M${xScale(0)},${yScale(pts[0].bl)}`;
  pts.forEach((p,i)=>{if(i>0)lineD+=` L${xScale(i)},${yScale(p.bl)}`;});
  // Ref lines
  const refs=[{h:500,lbl:'500 m · min',col:'#fbbf24'},{h:1500,lbl:'1500 m · XC',col:'#4ade80'}];
  let svg=`<svg viewBox="0 0 ${W} ${H}" class="fly-bl-svg">`;
  svg+=`<defs><linearGradient id="blGrad" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="var(--blue)" stop-opacity=".35"/><stop offset="100%" stop-color="var(--blue)" stop-opacity=".05"/></linearGradient></defs>`;
  svg+=`<path d="${pathD}" fill="url(#blGrad)"/>`;
  refs.forEach(r=>{
    const y=yScale(r.h);
    svg+=`<line x1="${pad.l}" y1="${y}" x2="${W-pad.r}" y2="${y}" stroke="${r.col}" stroke-width="1" stroke-dasharray="5,3" opacity=".7"/>`;
    svg+=`<text x="${W-pad.r-2}" y="${y-2}" font-size="7" fill="${r.col}" text-anchor="end">${r.lbl}</text>`;
  });
  [0,1000,2000,3000,4000].forEach(v=>{
    const y=yScale(v);
    svg+=`<text x="${pad.l-3}" y="${y+3}" font-size="7" fill="var(--muted)" text-anchor="end">${v}</text>`;
    svg+=`<line x1="${pad.l}" y1="${y}" x2="${pad.l+2}" y2="${y}" stroke="var(--muted)" stroke-width="1"/>`;
  });
  svg+=`<path d="${lineD}" fill="none" stroke="var(--blue)" stroke-width="2" stroke-linejoin="round"/>`;
  pts.forEach((p,i)=>{
    const x=xScale(i),y=yScale(p.bl);
    const score=_flyScore(p.wind,0,p.cape,p.bl,1);
    const dotCol=score>=70?'#4ade80':score>=40?'#fbbf24':'#f87171';
    svg+=`<circle cx="${x}" cy="${y}" r="3" fill="${dotCol}" stroke="var(--card-bg)" stroke-width="1"/>`;
    if(i%2===0)svg+=`<text x="${x}" y="${H-3}" font-size="7" fill="var(--muted)" text-anchor="middle">${p.hr}h</text>`;
  });
  svg+='</svg>';
  chartEl.innerHTML=svg;
  if(legEl)legEl.innerHTML=`<span style="color:var(--blue)">— BL višina (m)</span>`
    +refs.map(r=>`<span><svg width="14" height="2"><line x1="0" y1="1" x2="14" y2="1" stroke="${r.col}" stroke-width="1.5" stroke-dasharray="4,2"/></svg>${r.lbl}</span>`).join('');
}

function _buildPadalciDailyFc(d){
  const el=document.getElementById('fly-daily-body');if(!el)return;
  const h=d.hourly||{},dd=d.daily||{};
  const n=Math.min(7,(dd.time||[]).length);
  const days=['Ned','Pon','Tor','Sre','Čet','Pet','Sob'];
  let html='';
  for(let di=0;di<n;di++){
    const date=dd.time[di];
    const dt=new Date(date); const dn=days[dt.getDay()];
    // Collect daytime hours for this date
    const idxs=[];
    (h.time||[]).forEach((t,i)=>{if(t.startsWith(date)&&h.is_day?.[i])idxs.push(i);});
    const scores=idxs.map(i=>_flyScore(h.wind_speed_10m?.[i]??0,h.precipitation_probability?.[i]??0,h.cape?.[i]??0,h.boundary_layer_height?.[i]??0,1));
    const maxScore=scores.length?Math.max(...scores):0;
    const flyHrs=scores.filter(s=>s>=70).length;
    const badge=maxScore>=70?'🟢':maxScore>=40?'🟡':'🔴';
    const scoreLabel=maxScore>=70?'Leti':maxScore>=40?'Meja':'Ne';
    const tmax=dd.temperature_2m_max?.[di]!=null?Math.round(dd.temperature_2m_max[di])+'°':'—';
    const precip=dd.precipitation_sum?.[di]!=null?dd.precipitation_sum[di].toFixed(0)+'mm':'—';
    const sun=dd.sunshine_duration?.[di]!=null?Math.round(dd.sunshine_duration[di]/3600)+'h':'—';
    html+=`<div class="fly-day">
      <div class="fly-day-name">${dn}</div>
      <div class="fly-day-badge">${badge}</div>
      <div class="fly-day-score" style="color:${maxScore>=70?'var(--green)':maxScore>=40?'var(--amber)':'var(--red)'}">${scoreLabel}</div>
      <div class="fly-day-sub">${flyHrs>0?flyHrs+'h fly':'—'}<br>${tmax}<br>🌧 ${precip}<br>☀️ ${sun}</div>
    </div>`;
  }
  el.innerHTML=html;
}
// ═══ end PADALCI ══════════════════════════════════════════

// ═══ MORJE ════════════════════════════════════════════════
const SEA_LAT=45.514,SEA_LON=13.601; // Portorož
let _morjeInit=false,_morjeCache=null,_morjeCacheT=0;

async function initMorje(){
  if(_morjeInit)return; _morjeInit=true;
  try{
    const now=Date.now();
    if(!_morjeCache||now-_morjeCacheT>3600000){
      const [fc,marine]=await Promise.all([
        fetch(`https://api.open-meteo.com/v1/forecast?latitude=${SEA_LAT}&longitude=${SEA_LON}&daily=weather_code,temperature_2m_max,temperature_2m_min,precipitation_sum,wind_speed_10m_max,wind_gusts_10m_max,wind_direction_10m_dominant,uv_index_max&current=temperature_2m,wind_speed_10m,wind_direction_10m,wind_gusts_10m,weather_code&timezone=Europe%2FLjubljana&forecast_days=7`).then(r=>r.json()),
        fetch(`https://marine-api.open-meteo.com/v1/marine?latitude=${SEA_LAT}&longitude=${SEA_LON}&current=wave_height,wave_direction,wave_period,wind_wave_height,swell_wave_height,sea_surface_temperature&daily=wave_height_max,wave_period_max,sea_surface_temperature_mean&timezone=Europe%2FLjubljana&forecast_days=7`).then(r=>r.json()),
      ]);
      _morjeCache={fc,marine}; _morjeCacheT=now;
    }
    _buildMorjeKPIs(_morjeCache);
    _buildMorjeMarine(_morjeCache);
    _buildMorjeFc(_morjeCache);
    _buildMorjeWind(_morjeCache);
    _buildMorjeSuit(_morjeCache);
  }catch(e){console.error('initMorje',e);}
}

function _seaStateLabel(h){
  if(h<0.1)return'mirno';if(h<0.5)return'rahlo';if(h<1.25)return'zmerno valovito';
  if(h<2.5)return'razburkano';return'hudo razburkano';
}

// ═══ OCEANOLOGIJA ══════════════════════════════════════════
// Historical SST climatology for the Slovenian Adriatic coast (Portorož)
const OCN_SST_AVG=[9.5,9.0,10.5,13.5,18.0,22.5,25.5,26.5,24.0,19.5,15.0,11.5];

let _ocnInit=false,_ocnCache=null,_ocnCacheT=0;
async function initOceanologija(){
  if(_ocnInit)return; _ocnInit=true;
  try{
    const now=Date.now();
    if(!_ocnCache||now-_ocnCacheT>3600000){
      _ocnCache=await fetch(
        `https://marine-api.open-meteo.com/v1/marine?latitude=${SEA_LAT}&longitude=${SEA_LON}`+
        `&current=wave_height,wave_direction,wave_period,wind_wave_height,swell_wave_height,swell_wave_direction,swell_wave_period,sea_surface_temperature,ocean_current_velocity,ocean_current_direction`+
        `&hourly=wave_height,wave_direction,swell_wave_height,sea_surface_temperature,ocean_current_velocity,ocean_current_direction`+
        `&daily=wave_height_max,wave_period_max,sea_surface_temperature_mean`+
        `&past_days=30&forecast_days=7&timezone=Europe%2FLjubljana`
      ).then(r=>r.json());
      _ocnCacheT=now;
    }
    _buildOcnKPIs(_ocnCache);
    _buildOcnSSTChart(_ocnCache);
    _buildOcnWaveChart(_ocnCache);
    _buildOcnWaveRose(_ocnCache);
    _buildOcnCurrents(_ocnCache);
    _buildOcnTides(_ocnCache);
    _buildOcnEcology(_ocnCache);
    _buildOcnClimate(_ocnCache);
  }catch(e){console.error('initOceanologija',e);}
}

function _buildOcnKPIs(m){
  const el=document.getElementById('ocn-kpis');if(!el)return;
  const c=m.current||{};
  const vel=c.ocean_current_velocity!=null?(c.ocean_current_velocity*100).toFixed(0)+' cm/s':'—';
  const kpis=[
    {val:c.sea_surface_temperature!=null?c.sea_surface_temperature.toFixed(1)+' °C':'—',lbl:'Temp. morja',sub:'površinska (SST)'},
    {val:c.wave_height!=null?c.wave_height.toFixed(2)+' m':'—',lbl:'Valovanje',sub:c.wave_height!=null?_seaStateLabel(c.wave_height):'—'},
    {val:c.swell_wave_height!=null?c.swell_wave_height.toFixed(2)+' m':'—',lbl:'Mrtvo valovanje',sub:'mrtvi valovi (swell)'},
    {val:c.wave_period!=null?c.wave_period.toFixed(1)+' s':'—',lbl:'Perioda valovanja',sub:'sekund'},
    {val:vel,lbl:'Morski tok',sub:c.ocean_current_direction!=null?_windDirLabel(c.ocean_current_direction):'—'},
    {val:c.wave_direction!=null?_windDirLabel(c.wave_direction):'—',lbl:'Smer valovanja',sub:c.wave_direction!=null?c.wave_direction.toFixed(0)+'°':'—'},
  ];
  el.innerHTML=kpis.map(k=>`<div class="ocn-kpi"><div class="ocn-kpi-val">${k.val}</div><div class="ocn-kpi-lbl">${k.lbl}</div><div class="ocn-kpi-sub">${k.sub}</div></div>`).join('');
}

function _buildOcnSSTChart(m){
  const el=document.getElementById('ocn-sst-wrap');if(!el)return;
  const h=m.hourly||{};
  const times=h.time||[];
  const ssts=h.sea_surface_temperature||[];
  // Aggregate to daily mean
  const dailyMap={};
  times.forEach((t,i)=>{
    const d=t.slice(0,10);
    if(ssts[i]!=null){
      if(!dailyMap[d]){dailyMap[d]={sum:0,n:0};}
      dailyMap[d].sum+=ssts[i];dailyMap[d].n++;
    }
  });
  const dates=Object.keys(dailyMap).sort();
  if(!dates.length){el.innerHTML='<div style="color:var(--muted);font-size:.75rem">Ni podatkov</div>';return;}
  const vals=dates.map(d=>dailyMap[d].sum/dailyMap[d].n);
  const todayStr=_localDateStr(new Date());
  const todayIdx=dates.indexOf(todayStr);

  const W=880,H=160,pad={l:38,r:10,t:14,b:24};
  const cW=W-pad.l-pad.r,cH=H-pad.t-pad.b;
  const valid=vals.filter(v=>v!=null);
  const vmin=Math.floor(Math.min(...valid)-0.5),vmax=Math.ceil(Math.max(...valid)+0.5);
  const xS=i=>pad.l+i*(cW/Math.max(dates.length-1,1));
  const yS=v=>pad.t+cH-(v-vmin)/(vmax-vmin)*cH;

  let pathPast='',pathFuture='',firstFut=true;
  dates.forEach((d,i)=>{
    const v=vals[i];if(v==null)return;
    const x=xS(i),y=yS(v);
    if(i<=(todayIdx>=0?todayIdx:i)){
      pathPast+=(pathPast?'L':'M')+x+','+y;
    }
    if(i>=(todayIdx>=0?todayIdx:dates.length)){
      if(firstFut&&todayIdx>=0){pathFuture='M'+xS(todayIdx)+','+yS(vals[todayIdx]||v);firstFut=false;}
      else if(firstFut){pathFuture='M'+x+','+y;firstFut=false;}
      pathFuture+='L'+x+','+y;
    }
  });

  const mon=new Date().getMonth();
  const climAvg=OCN_SST_AVG[mon];
  const avgY=yS(climAvg);
  const todayX=todayIdx>=0?xS(todayIdx):null;
  const step=vmax-vmin>8?2:1;

  // Area fill under past line
  const fillPath=pathPast?pathPast+' L'+xS(Math.min(todayIdx>=0?todayIdx:dates.length-1,dates.length-1))+','+yS(vmin)+' L'+xS(0)+','+yS(vmin)+' Z':'';

  let svg=`<svg class="chart-svg" viewBox="0 0 ${W} ${H}" height="${H}" style="overflow:visible">`;
  svg+=`<defs><linearGradient id="sst-fill" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="var(--cyan)" stop-opacity="0.18"/><stop offset="100%" stop-color="var(--cyan)" stop-opacity="0.02"/></linearGradient></defs>`;
  for(let v=Math.ceil(vmin);v<=vmax;v+=step){
    const y=yS(v);
    svg+=`<line x1="${pad.l}" y1="${y}" x2="${W-pad.r}" y2="${y}" stroke="var(--border)" stroke-width="1"/>`;
    svg+=`<text x="${pad.l-4}" y="${y+4}" font-size="9.5" fill="var(--muted)" text-anchor="end" font-family="JetBrains Mono,monospace">${v}°</text>`;
  }
  if(avgY>=pad.t&&avgY<=H-pad.b){
    svg+=`<line x1="${pad.l}" y1="${avgY}" x2="${W-pad.r}" y2="${avgY}" stroke="var(--amber)" stroke-width="1.5" stroke-dasharray="5,3" opacity=".6"/>`;
    svg+=`<text x="${W-pad.r}" y="${avgY-3}" font-size="8.5" fill="var(--amber)" text-anchor="end" opacity=".8">povp. ${climAvg} °C</text>`;
  }
  if(todayX!=null)svg+=`<line x1="${todayX}" y1="${pad.t}" x2="${todayX}" y2="${H-pad.b}" stroke="var(--muted)" stroke-width="1" stroke-dasharray="3,2" opacity=".45"/>`;
  if(fillPath)svg+=`<path d="${fillPath}" fill="url(#sst-fill)"/>`;
  if(pathPast)svg+=`<path d="${pathPast}" fill="none" stroke="var(--cyan)" stroke-width="2.5" stroke-linejoin="round" stroke-linecap="round"/>`;
  if(pathFuture)svg+=`<path d="${pathFuture}" fill="none" stroke="var(--cyan)" stroke-width="1.5" stroke-dasharray="5,3" stroke-linejoin="round" opacity=".65"/>`;
  // Month labels
  let lastMon='';
  const monNames=['jan','feb','mar','apr','maj','jun','jul','avg','sep','okt','nov','dec'];
  dates.forEach((d,i)=>{
    const mo=d.slice(5,7);
    if(mo!==lastMon){lastMon=mo;svg+=`<text x="${xS(i)}" y="${H-2}" font-size="9.5" fill="var(--muted)" text-anchor="middle" font-family="JetBrains Mono,monospace">${monNames[parseInt(mo,10)-1]}</text>`;}
  });
  // Crosshair elements (hidden until hover/touch)
  svg+=`<line id="ocn-sst-xline" x1="0" y1="${pad.t}" x2="0" y2="${H-pad.b}" stroke="var(--muted)" stroke-width="1" stroke-dasharray="3,2" opacity="0" style="pointer-events:none"/>`;
  svg+=`<line id="ocn-sst-yline" x1="${pad.l}" y1="0" x2="${W-pad.r}" y2="0" stroke="var(--muted)" stroke-width="1" stroke-dasharray="3,2" opacity="0" style="pointer-events:none"/>`;
  svg+=`<circle id="ocn-sst-dot" cx="0" cy="0" r="5" fill="var(--cyan)" stroke="white" stroke-width="2" opacity="0" style="pointer-events:none"/>`;
  svg+=`<rect id="ocn-sst-hit" x="${pad.l}" y="${pad.t}" width="${cW}" height="${cH}" fill="transparent"/>`;
  svg+='</svg>';
  el.innerHTML='<div class="chart-svg-wrap">'+svg+'</div>';
  const leg=document.getElementById('ocn-sst-leg');
  if(leg)leg.innerHTML='<span>—— izmerjena SST</span><span style="opacity:.6">- - - napoved</span><span style="color:var(--amber)">— — klimatol. povprečje</span>';

  // Attach crosshair interaction
  const svgEl=el.querySelector('svg');
  const xLine=document.getElementById('ocn-sst-xline');
  const yLine=document.getElementById('ocn-sst-yline');
  const dot=document.getElementById('ocn-sst-dot');
  const tip=document.getElementById('chart-tip');
  function _sstPointer(clientX,clientY){
    const r=svgEl.getBoundingClientRect(),vb=svgEl.viewBox.baseVal;
    const svgX=(clientX-r.left)/r.width*vb.width;
    const idx=Math.max(0,Math.min(dates.length-1,Math.round((svgX-pad.l)/cW*(dates.length-1))));
    const v=vals[idx];if(v==null)return;
    const px=xS(idx),py=yS(v);
    xLine.setAttribute('x1',px);xLine.setAttribute('x2',px);xLine.setAttribute('opacity','0.6');
    yLine.setAttribute('y1',py);yLine.setAttribute('y2',py);yLine.setAttribute('opacity','0.4');
    dot.setAttribute('cx',px);dot.setAttribute('cy',py);dot.setAttribute('opacity','1');
    const dt=new Date(dates[idx]);
    tip.innerHTML='<span style="color:var(--cyan);font-weight:600">'+v.toFixed(1)+' °C</span>&ensp;'+dt.getDate()+'. '+monNames[dt.getMonth()]+' '+dt.getFullYear();
    tip.style.opacity='1';tip.style.left=(clientX+14)+'px';tip.style.top=(clientY-28)+'px';
  }
  function _sstHide(){xLine.setAttribute('opacity','0');yLine.setAttribute('opacity','0');dot.setAttribute('opacity','0');tip.style.opacity='0';}
  svgEl.addEventListener('mousemove',e=>_sstPointer(e.clientX,e.clientY));
  svgEl.addEventListener('mouseleave',_sstHide);
  svgEl.addEventListener('touchmove',e=>{const t=e.touches[0];_sstPointer(t.clientX,t.clientY);},{passive:true});
  svgEl.addEventListener('touchend',_sstHide);
}

function _buildOcnWaveChart(m){
  const el=document.getElementById('ocn-wave-wrap');if(!el)return;
  const d=m.daily||{};
  const times=d.time||[];
  if(!times.length){el.innerHTML='<div style="color:var(--muted);font-size:.75rem">Ni podatkov</div>';return;}
  const today=_localDateStr(new Date());
  let start=times.findIndex(t=>t>=today);
  if(start<0)start=Math.max(0,times.length-7);
  const n=Math.min(7,times.length-start);
  const fcT=times.slice(start,start+n);
  const wh=(d.wave_height_max||[]).slice(start,start+n);
  const days=['Ned','Pon','Tor','Sre','Čet','Pet','Sob'];

  const W=880,H=80,pL=28,pR=8,pT=6,pB=18;
  const cW=W-pL-pR,cH=H-pT-pB;
  const maxW=Math.max(0.5,...wh.filter(v=>v!=null))*1.15;
  const bW=Math.floor(cW/n)-4;

  let svg=`<svg class="chart-svg" viewBox="0 0 ${W} ${H}">`;
  [0,maxW/2,maxW].forEach(v=>{
    const y=pT+cH-(v/maxW)*cH;
    svg+=`<text x="${pL-3}" y="${y+3}" font-size="7" fill="var(--muted)" text-anchor="end">${v.toFixed(1)}</text>`;
  });
  fcT.forEach((t,i)=>{
    const x=pL+i*(cW/n)+2;
    const v=wh[i]??0;
    const bH=Math.max(2,(v/maxW)*cH);
    const bY=pT+cH-bH;
    const col=v<0.3?'var(--green)':v<0.6?'var(--cyan)':v<1.0?'var(--amber)':v<1.5?'#fb923c':'var(--red)';
    svg+=`<rect x="${x}" y="${bY}" width="${bW}" height="${bH}" fill="${col}" rx="2" opacity=".78"/>`;
    svg+=`<text x="${x+bW/2}" y="${H-1}" font-size="7.5" fill="var(--muted)" text-anchor="middle">${days[new Date(t).getDay()]}</text>`;
    if(v>0)svg+=`<text x="${x+bW/2}" y="${bY-2}" font-size="7" fill="var(--text)" text-anchor="middle">${v.toFixed(1)}</text>`;
  });
  svg+='</svg>';
  el.innerHTML='<div class="chart-svg-wrap">'+svg+'</div>';
  const leg=document.getElementById('ocn-wave-leg');
  if(leg)leg.innerHTML='<span style="color:var(--green)">▮ mirno &lt; 0,3 m</span><span style="color:var(--cyan)">▮ rahlo &lt; 0,6 m</span><span style="color:var(--amber)">▮ zmerno &lt; 1 m</span><span style="color:#fb923c">▮ razburkano &lt; 1,5 m</span><span style="color:var(--red)">▮ hudo</span>';
}

function _buildOcnWaveRose(m){
  const el=document.getElementById('ocn-rose-wrap');if(!el)return;
  const h=m.hourly||{};
  const dirs=h.wave_direction||[];
  const whs=h.wave_height||[];
  const cutMs=Date.now()-7*24*3600000;
  const futMs=Date.now()+7*24*3600000;
  const bins=new Array(8).fill(0);
  (h.time||[]).forEach((t,i)=>{
    const ms=new Date(t).getTime();
    if(ms<cutMs||ms>futMs)return;
    const dir=dirs[i];if(dir==null)return;
    bins[Math.round(dir/45)%8]+=(whs[i]??0.1);
  });
  const maxB=Math.max(...bins,0.1);
  const labels=['S','SV','V','JV','J','JZ','Z','SZ'];
  const cols=['var(--cyan)','var(--cyan)','var(--amber)','var(--amber)','var(--blue)','var(--blue)','var(--muted)','var(--muted)'];
  const sz=130,cx=65,cy=65,maxR=48;
  let svg=`<svg viewBox="0 0 ${sz} ${sz}" style="width:130px;height:130px">`;
  [1/3,2/3,1].forEach(f=>{svg+=`<circle cx="${cx}" cy="${cy}" r="${maxR*f}" fill="none" stroke="var(--border)" stroke-width="1"/>`;});
  [0,45,90,135].forEach(a=>{
    const r=a*Math.PI/180;
    svg+=`<line x1="${cx+Math.sin(r)*maxR}" y1="${cy-Math.cos(r)*maxR}" x2="${cx-Math.sin(r)*maxR}" y2="${cy+Math.cos(r)*maxR}" stroke="var(--border)" stroke-width="1"/>`;
  });
  bins.forEach((cnt,i)=>{
    if(!cnt)return;
    const r=(cnt/maxB)*maxR;
    const a0=(i*45-22.5)*Math.PI/180,a1=(i*45+22.5)*Math.PI/180;
    const x0=cx+Math.sin(a0)*r,y0=cy-Math.cos(a0)*r;
    const x1=cx+Math.sin(a1)*r,y1=cy-Math.cos(a1)*r;
    svg+=`<path d="M${cx},${cy}L${x0},${y0}A${r},${r},0,0,1,${x1},${y1}Z" fill="${cols[i]}" opacity=".7"/>`;
  });
  labels.forEach((lbl,i)=>{
    const rad=i*45*Math.PI/180;
    const lx=cx+Math.sin(rad)*(maxR+11),ly=cy-Math.cos(rad)*(maxR+11);
    svg+=`<text x="${lx}" y="${ly+3}" font-size="8" fill="var(--muted)" text-anchor="middle" dominant-baseline="middle">${lbl}</text>`;
  });
  svg+='</svg>';
  el.innerHTML=svg;
}

function _buildOcnCurrents(m){
  const el=document.getElementById('ocn-currents');if(!el)return;
  const c=m.current||{};
  const vel=c.ocean_current_velocity!=null?c.ocean_current_velocity*100:null;
  const dir=c.ocean_current_direction;
  const velLbl=vel==null?'—':vel<5?'šibek':vel<15?'zmeren':vel<30?'močan':'zelo močan';
  const bCls=vel==null?'ocn-badge-ok':vel<15?'ocn-badge-ok':vel<30?'ocn-badge-warn':'ocn-badge-bad';
  const arrowSvg=dir!=null?`<svg viewBox="0 0 24 24" width="40" height="40" style="transform:rotate(${dir}deg);display:block;margin:.1rem auto .3rem"><polygon points="12,2 16,20 12,15 8,20" fill="var(--cyan)" opacity=".85"/></svg>`:`<div style="font-size:1.6rem;text-align:center;margin:.2rem 0">—</div>`;
  el.innerHTML=`<div style="text-align:center">
    ${arrowSvg}
    <div style="font-size:1.0rem;font-weight:700;color:var(--text);font-family:'JetBrains Mono',monospace">${vel!=null?vel.toFixed(0)+' cm/s':'—'}</div>
    <div style="font-size:.62rem;color:var(--muted);margin:.1rem 0">${dir!=null?_windDirLabel(dir)+' ('+dir.toFixed(0)+'°)':'—'}</div>
    <span class="ocn-badge ${bCls}">${velLbl}</span>
  </div>
  <div style="font-size:.68rem;color:var(--muted);line-height:1.55;margin-top:.55rem">
    V Jadranskem morju prevladujejo šibki geostrofski tokovi (5–20 cm/s). Ob burji nastane površinski odklon (drift) proti jugovzhodu, ob jugu pa proti severozahodu. Vzdolžni jadranski tok ob obali le redko preseže hitrost 50 cm/s.
  </div>`;
}

function _buildOcnTides(m){
  const el=document.getElementById('ocn-tides');if(!el)return;
  // Harmonic tidal prediction for Koper (approximate)
  // Constituents: [amplitude_m, angular_speed_deg/h, V0_deg, kappa_deg]
  // Source: IHO/published harmonic constants for Northern Adriatic (Koper)
  const J2000=Date.UTC(2000,0,1);
  function _tH(ms){
    const t=(ms-J2000)/3600000;
    const C=[[0.21,28.9841,254.0,334.0],[0.10,30.0000,0.0,353.0],[0.07,15.0411,100.0,200.0],[0.03,13.9430,214.0,178.0]];
    let h=0.35;
    for(const [A,sig,V0,kap] of C)h+=A*Math.cos((sig*t+V0-kap)*Math.PI/180);
    return h;
  }
  const now=Date.now();
  // 25 points: -12h to +12h
  const pts=Array.from({length:25},(_,i)=>({ms:now+(i-12)*3600000,h:_tH(now+(i-12)*3600000)}));
  const allH=pts.map(p=>p.h);
  const tmin=Math.min(...allH),tmax=Math.max(...allH);
  const range=(tmax-tmin).toFixed(2);
  // High/low water events in next 24h
  const next24=Array.from({length:25},(_,i)=>({ms:now+i*3600000,h:_tH(now+i*3600000)}));
  const events=[];
  for(let i=1;i<next24.length-1;i++){
    const prev=next24[i-1].h,cur=next24[i].h,nxt=next24[i+1].h;
    if(cur>prev&&cur>nxt){const d=new Date(next24[i].ms);events.push({type:'V',h:cur,lbl:d.getHours().toString().padStart(2,'0')+':'+d.getMinutes().toString().padStart(2,'0')});}
    else if(cur<prev&&cur<nxt){const d=new Date(next24[i].ms);events.push({type:'N',h:cur,lbl:d.getHours().toString().padStart(2,'0')+':'+d.getMinutes().toString().padStart(2,'0')});}
  }
  const moonIllum=_moonIllum(new Date());
  const tidalType=moonIllum<0.1||moonIllum>0.9?'Živa plima (sizigijska plima – ščip / mlaj)':moonIllum>0.4&&moonIllum<0.6?'Mrtva plima (kvadraturna plima – prvi / zadnji krajec)':'Vmesna plima';

  // SVG chart
  const W=880,H=80,pL=30,pR=8,pT=8,pB=18;
  const cW=W-pL-pR,cH=H-pT-pB;
  const vmax2=Math.max(0.85,tmax+0.05);
  const xS=i=>pL+i*(cW/(pts.length-1));
  const yS=v=>pT+cH-(v/vmax2)*cH;
  let path='';
  pts.forEach((p,i)=>{path+=(i?'L':'M')+xS(i)+','+yS(p.h);});
  const fill=path+`L${xS(pts.length-1)},${H-pB}L${xS(0)},${H-pB}Z`;
  const nowX=xS(12);

  let svg=`<svg class="chart-svg" viewBox="0 0 ${W} ${H}">`;
  [0,0.2,0.4,0.6,0.8].forEach(v=>{
    if(v>vmax2)return;
    const y=yS(v);
    svg+=`<line x1="${pL}" y1="${y}" x2="${W-pR}" y2="${y}" stroke="var(--border)" stroke-width="1"/>`;
    svg+=`<text x="${pL-3}" y="${y+3}" font-size="7" fill="var(--muted)" text-anchor="end">${v.toFixed(1)}</text>`;
  });
  svg+=`<path d="${fill}" fill="var(--cyan)" opacity=".12"/>`;
  svg+=`<path d="${path}" fill="none" stroke="var(--cyan)" stroke-width="2"/>`;
  svg+=`<line x1="${nowX}" y1="${pT}" x2="${nowX}" y2="${H-pB}" stroke="var(--amber)" stroke-width="1.5" stroke-dasharray="3,2"/>`;
  svg+=`<text x="${nowX}" y="${pT}" font-size="7" fill="var(--amber)" text-anchor="middle" dominant-baseline="hanging">zdaj</text>`;
  [-12,-6,0,6,12].forEach(h=>{
    const d=new Date(now+h*3600000);
    svg+=`<text x="${xS(h+12)}" y="${H-1}" font-size="7.5" fill="var(--muted)" text-anchor="middle">${d.getHours().toString().padStart(2,'0')}:00</text>`;
  });
  svg+='</svg>';

  const evHtml=events.slice(0,4).map(e=>`<div class="ocn-row"><span style="color:var(--muted)">${e.type==='V'?'🔺 Plima (visoka voda)':'🔻 Oseka (nizka voda)'}</span><b>${e.lbl} &nbsp;·&nbsp; ${e.h.toFixed(2)} m</b></div>`).join('');
  el.innerHTML=`<div class="chart-svg-wrap">${svg}</div><div style="margin-top:.5rem">${evHtml}
    <div class="ocn-row"><span style="color:var(--muted)">Amplituda plimovanja</span><b>${range} m</b></div>
    <div class="ocn-row"><span style="color:var(--muted)">Tip plimovanja</span><b>${tidalType}</b></div>
    <div style="font-size:.65rem;color:var(--muted);margin-top:.4rem;line-height:1.5">Za Koper je značilno mikroplimovanje (amplituda do ~0,7 m). Prikaz temelji na harmonskem modelu (M2 + S2 + K1 + O1) in je izključno <em>informativne</em> narave. Za natančne pomorske napovedi spremljajte uradne podatke agencije <a href="https://meteo.arso.gov.si/met/sl/sea/" target="_blank" style="color:var(--blue)">ARSO</a>.</div>
  </div>`;
}

function _buildOcnEcology(m){
  const el=document.getElementById('ocn-ecology');if(!el)return;
  const c=m.current||{};
  const sst=c.sea_surface_temperature;
  const wave=c.wave_height??0;
  const mon=new Date().getMonth();
  // Jellyfish (Pelagia noctiluca / Rhizostoma pulmo)
  let jfRisk='nizka',jfCls='ocn-badge-ok',jfDesc='Meduz je malo (redke)';
  if(sst!=null){
    if(sst>=24||(sst>=21&&mon>=6&&mon<=8)){jfRisk='visoka';jfCls='ocn-badge-bad';jfDesc='Sezona mesečink (Pelagia noctiluca)';}
    else if(sst>=19||(mon>=5&&mon<=9)){jfRisk='zmerna';jfCls='ocn-badge-warn';jfDesc='Možen pojav posameznih meduz';}
  } else if(mon>=6&&mon<=8){jfRisk='zmerna';jfCls='ocn-badge-warn';jfDesc='Letna sezona meduz';}
  // HAB (Harmful Algal Bloom)
  let habRisk='nizko',habCls='ocn-badge-ok',habDesc='Brez indikatorjev';
  if(sst!=null&&sst>=24&&wave<0.3){habRisk='povišano';habCls='ocn-badge-warn';habDesc='Visoka SST + mirno = stratifikacija';}
  else if(sst!=null&&sst>=26){habRisk='zmerno';habCls='ocn-badge-warn';habDesc='Visoka SST';}
  // Secchi depth (water transparency estimate)
  const secchi=wave<0.2?'6–10 m':wave<0.5?'4–7 m':wave<1.0?'2–4 m':'1–2 m';
  const secchiDesc=wave<0.2?'mirno morje':wave<0.5?'rahlo valovito':wave<1.0?'zmerno valovito':'razburkano';
  // Estimated salinity (seasonal Northern Adriatic)
  const salEst=[37.5,37.3,37.0,37.2,37.5,38.0,38.3,38.4,38.2,37.9,37.6,37.5];
  // Posidonia oceanica health (static contextual)
  const posDesc=sst!=null&&sst>28?'stres (T > 28 °C)':sst!=null&&sst<10?'mirovanje (T < 10 °C)':'dobri pogoji';
  const cards=[
    {ic:'🪼',t:'Meduze (Pelagia)',v:`<span class="ocn-badge ${jfCls}">${jfRisk}</span>`,d:jfDesc},
    {ic:'🌿',t:'Cvetenje alg (HAB)',v:`<span class="ocn-badge ${habCls}">${habRisk}</span>`,d:habDesc},
    {ic:'👁',t:'Prosojnost morja (Secchi)',v:secchi,d:secchiDesc},
    {ic:'🧂',t:'Slanost (ocena)',v:salEst[mon].toFixed(1)+' ‰',d:'severni Jadran'},
    {ic:'🌱',t:'Pozejdonka (Posidonia oceanica)',v:posDesc,d:'morska trava'},
    {ic:'⚗️',t:'pH morja',v:'~8,10',d:'povprečje (−0,002/leto)'},
  ];
  el.innerHTML=cards.map(cd=>`<div class="ocn-eco-card"><div class="ocn-eco-ttl">${cd.ic} ${cd.t}</div><div class="ocn-eco-val">${cd.v}</div><div class="ocn-eco-sub">${cd.d}</div></div>`).join('');
}

function _buildOcnClimate(m){
  const el=document.getElementById('ocn-climate');if(!el)return;
  const h=m.hourly||{};
  const today=_localDateStr(new Date());
  // Current month SSTs for anomaly
  const monthSsts=(h.sea_surface_temperature||[]).filter((v,i)=>v!=null&&(h.time||[])[i]?.startsWith(today.slice(0,7)));
  const mon=new Date().getMonth();
  const climAvg=OCN_SST_AVG[mon];
  const curSST=monthSsts.length?+(monthSsts.reduce((a,b)=>a+b,0)/monthSsts.length).toFixed(1):null;
  const anomaly=curSST!=null?+(curSST-climAvg).toFixed(1):null;
  const months=['jan','feb','mar','apr','maj','jun','jul','avg','sep','okt','nov','dec'];

  // Monthly SST bar chart
  const W=880,H=55,pL=24,pR=8,pT=4,pB=14;
  const cW=W-pL-pR,cH=H-pT-pB;
  const minT=7,maxT=28;
  const bW=Math.floor(cW/12)-2;
  let svg=`<svg class="chart-svg" viewBox="0 0 ${W} ${H}" style="margin-bottom:.5rem">`;
  OCN_SST_AVG.forEach((t,i)=>{
    const x=pL+i*(cW/12)+1;
    const bH=Math.max(2,(t-minT)/(maxT-minT)*cH);
    const bY=pT+cH-bH;
    const col=t<14?'var(--blue)':t<20?'var(--cyan)':t<24?'var(--green)':'var(--amber)';
    svg+=`<rect x="${x}" y="${bY}" width="${bW}" height="${bH}" fill="${i===mon?'var(--amber)':col}" rx="1.5" opacity="${i===mon?1:.6}"/>`;
    svg+=`<text x="${x+bW/2}" y="${H-1}" font-size="7" fill="var(--muted)" text-anchor="middle">${months[i]}</text>`;
    svg+=`<text x="${x+bW/2}" y="${bY-2}" font-size="7" fill="${i===mon?'var(--text)':'var(--muted)'}" text-anchor="middle">${t}</text>`;
  });
  svg+='</svg>';

  const anomCol=anomaly==null?'var(--muted)':anomaly>0.5?'var(--red)':anomaly>0?'var(--amber)':anomaly<-0.5?'var(--blue)':'var(--green)';
  const anomStr=anomaly!=null?(anomaly>=0?'+':'')+anomaly+' °C':'—';
  el.innerHTML=`<div class="chart-svg-wrap">${svg}</div>
    <div class="ocn-row" style="font-size:.75rem"><span style="color:var(--muted)">Klimatološko povprečje (${months[mon]})</span><b>${climAvg} °C</b></div>
    <div class="ocn-row" style="font-size:.75rem"><span style="color:var(--muted)">Izmerjena SST (mesečno povprečje)</span><b>${curSST!=null?curSST+' °C':'—'}</b></div>
    <div class="ocn-row" style="font-size:.75rem"><span style="color:var(--muted)">Anomalija SST</span><b style="color:${anomCol}">${anomStr}</b></div>
    <div style="font-size:.7rem;color:var(--muted);margin-top:.65rem;line-height:1.6">
      <b style="color:var(--text)">Zakisanost Jadranskega morja:</b> Morje absorbira CO₂ iz ozračja, kar znižuje njegov pH. Od predindustrijske dobe se je vrednost pH znižala za ~0,1 enote (z 8,2 na ~8,1). Letni trend upadanja znaša −0,002 enote pH/leto. Vpliv na školjke, korale in celoten morski ekosistem je znaten.
    </div>
    <div style="font-size:.7rem;color:var(--muted);margin-top:.35rem;line-height:1.6">
      <b style="color:var(--text)">Dvig morske gladine:</b> Gladina severnega Jadrana se dviguje za ~3 mm/leto (vir: Copernicus). Koper: relativni dvig morske gladine od leta 1900 znaša ~15 cm. Poplavljanje morja (pojav »acqua alta«) je vse pogostejše.
    </div>`;
}
// ═══ end OCEANOLOGIJA ══════════════════════════════════════

// ═══ KAKOVOST ZRAKA ════════════════════════════════════════
let _zrakInit=false,_zrakCache=null,_zrakCacheT=0;
async function initZrak(){
  if(_zrakInit)return; _zrakInit=true;
  try{
    const now=Date.now();
    if(!_zrakCache||now-_zrakCacheT>3600000){
      _zrakCache=await fetch(
        `https://air-quality-api.open-meteo.com/v1/air-quality?latitude=${LAT}&longitude=${LON}`+
        `&hourly=pm10,pm2_5,carbon_monoxide,nitrogen_dioxide,sulphur_dioxide,ozone,`+
        `european_aqi,european_aqi_pm2_5,european_aqi_pm10,european_aqi_nitrogen_dioxide,european_aqi_ozone,`+
        `alder_pollen,birch_pollen,grass_pollen,mugwort_pollen,ragweed_pollen,dust,ammonia`+
        `&timezone=Europe%2FLjubljana&past_days=1&forecast_days=5&domains=cams_europe`
      ).then(r=>r.json());
      _zrakCacheT=now;
    }
    _buildAqAQI(_zrakCache);
    _buildAqKPIs(_zrakCache);
    _buildAqChart(_zrakCache);
    _buildAqPollutants(_zrakCache);
    _buildAqPollen(_zrakCache);
    _buildAqHealth(_zrakCache);
  }catch(e){console.error('initZrak',e);}
}

function _aqNowIdx(times){
  const nowStr=new Date().toISOString().slice(0,13);
  const i=(times||[]).findIndex(t=>t.slice(0,13)===nowStr);
  return i>=0?i:null;
}
function _aqClass(aqi){
  if(aqi==null)return{cls:'suit-fair',lvl:'—',col:'var(--muted)',ic:'🌫️'};
  if(aqi<=20)return{cls:'suit-excellent',lvl:'ODLIČNO',col:'#4ade80',ic:'😊'};
  if(aqi<=40)return{cls:'suit-good',lvl:'DOBRO',col:'#a3e635',ic:'🙂'};
  if(aqi<=60)return{cls:'suit-fair',lvl:'ZMERNO',col:'#fbbf24',ic:'😐'};
  if(aqi<=80)return{cls:'suit-poor',lvl:'SLABO',col:'#fb923c',ic:'😷'};
  if(aqi<=100)return{cls:'suit-bad',lvl:'ZELO SLABO',col:'#f87171',ic:'🤧'};
  return{cls:'suit-bad',lvl:'NEVZDRŽNO',col:'#c084fc',ic:'⛔'};
}
function _aqLvl(aqi){
  if(aqi==null)return'—';
  if(aqi<=20)return'odlično';if(aqi<=40)return'dobro';if(aqi<=60)return'zmerno';
  if(aqi<=80)return'slabo';if(aqi<=100)return'zelo slabo';return'nevzdržno';
}

function _buildAqAQI(d){
  const card=document.getElementById('aq-aqi-card');if(!card)return;
  const h=d.hourly||{};
  const ni=_aqNowIdx(h.time);
  const get=k=>ni!=null?h[k]?.[ni]:null;
  const aqi=get('european_aqi');
  const cls=_aqClass(aqi);
  card.className=`card sc-risk-card ${cls.cls}`;
  const pct=aqi!=null?Math.min(100,aqi):0;
  const desc=aqi==null?'Nalagam podatke…':
    aqi<=20?'Zrak je čist. Ni omejitev za dejavnosti na prostem.':
    aqi<=40?'Zrak je sprejemljiv. Možni so blagi vplivi na zelo občutljive posameznike.':
    aqi<=60?'Občutljive skupine (astmatiki, srčni bolniki, starejši in otroci) naj omejijo dolgotrajnejše aktivnosti na prostem.':
    aqi<=80?'Večina ljudi lahko občuti vpliv na zdravje. Zmanjšajte fizične napore na prostem.':
    aqi<=100?'Resni vplivi na zdravje. Omejite čas zadrževanja na prostem.':
    'Zdravstveni alarm – izogibajte se bivanju na prostem.';
  const factors=[
    {l:'PM2,5 AQI',v:get('european_aqi_pm2_5')??'—',d:_aqLvl(get('european_aqi_pm2_5'))},
    {l:'PM10 AQI',v:get('european_aqi_pm10')??'—',d:_aqLvl(get('european_aqi_pm10'))},
    {l:'NO₂ AQI',v:get('european_aqi_nitrogen_dioxide')??'—',d:_aqLvl(get('european_aqi_nitrogen_dioxide'))},
    {l:'O₃ AQI',v:get('european_aqi_ozone')??'—',d:_aqLvl(get('european_aqi_ozone'))},
  ];
  card.innerHTML=`<div class="sc-risk-head">
    <span class="sc-risk-icon">${cls.ic}</span>
    <div class="sc-risk-text">
      <div class="clabel" style="margin:0">🌫️ Kakovost zraka – Rečica ob Savinji (EU AQI)</div>
      <div class="sc-risk-level" style="color:${cls.col}">${cls.lvl}</div>
      <div class="sc-risk-desc">${desc}</div>
    </div>
    <div class="sc-risk-gauge">
      <div class="sc-risk-pct">${aqi!=null?aqi:'—'}</div>
      <div class="sc-risk-bar"><div class="sc-risk-fill" style="width:${pct}%;background:${cls.col}"></div></div>
      <div class="sc-risk-gauge-lbl">EU AQI</div>
    </div>
  </div>
  <div class="sc-risk-factors">${factors.map(f=>`<div class="sc-risk-factor"><small>${f.l}</small><b>${f.v}</b><span>${f.d}</span></div>`).join('')}</div>`;
}

function _buildAqKPIs(d){
  const el=document.getElementById('aq-kpis');if(!el)return;
  const h=d.hourly||{};
  const ni=_aqNowIdx(h.time);
  const get=k=>ni!=null?h[k]?.[ni]:null;
  const pollenKeys=['grass_pollen','birch_pollen','alder_pollen','mugwort_pollen','ragweed_pollen'];
  const pollenLbls={grass_pollen:'Trave',birch_pollen:'Breza',alder_pollen:'Jelša',mugwort_pollen:'Pelin',ragweed_pollen:'Ambrozija'};
  let domPollen='—',domVal=0;
  pollenKeys.forEach(k=>{const v=get(k);if(v!=null&&v>domVal){domVal=v;domPollen=pollenLbls[k];}});
  const pm25=get('pm2_5'),pm10=get('pm10'),o3=get('ozone'),no2=get('nitrogen_dioxide');
  const kpis=[
    {val:pm25!=null?pm25.toFixed(1)+' µg':'—',lbl:'PM2,5',sub:pm25==null?'—':pm25<5?'odlično':pm25<15?'dobro':pm25<25?'zmerno':'slabo'},
    {val:pm10!=null?pm10.toFixed(0)+' µg':'—',lbl:'PM10',sub:pm10==null?'—':pm10<20?'dobro':pm10<45?'zmerno':'slabo'},
    {val:o3!=null?o3.toFixed(0)+' µg':'—',lbl:'Ozon O₃',sub:o3==null?'—':o3<60?'dobro':o3<100?'zmerno':'slabo'},
    {val:no2!=null?no2.toFixed(0)+' µg':'—',lbl:'NO₂',sub:no2==null?'—':no2<20?'dobro':no2<40?'zmerno':'slabo'},
    {val:domVal>0.5?Math.round(domVal)+' delcev/m³':'nizka',lbl:'Cvetni prah',sub:domVal>0.5?domPollen:'—'},
  ];
  el.innerHTML=kpis.map(k=>`<div class="aq-kpi"><div class="aq-kpi-val">${k.val}</div><div class="aq-kpi-lbl">${k.lbl}</div><div class="aq-kpi-sub">${k.sub}</div></div>`).join('');
}

function _buildAqChart(d){
  const el=document.getElementById('aq-chart-wrap');if(!el)return;
  const h=d.hourly||{};
  const times=h.time||[];
  const aqis=h.european_aqi||[];
  if(!times.length){el.innerHTML='<div style="color:var(--muted);font-size:.75rem">Ni podatkov</div>';return;}
  const now=Date.now();
  const wStart=now-24*3600000,wEnd=now+24*3600000;
  const pts=[];
  times.forEach((t,i)=>{
    const ms=new Date(t).getTime();
    if(ms>=wStart&&ms<=wEnd)pts.push({ms,v:aqis[i]});
  });
  if(!pts.length){el.innerHTML='<div style="color:var(--muted);font-size:.75rem">Ni podatkov v oknu 48h</div>';return;}
  const W=880,H=80,pL=28,pR=8,pT=8,pB=18;
  const cW=W-pL-pR,cH=H-pT-pB;
  const vmax=Math.max(100,...pts.map(p=>p.v??0));
  const xS=ms=>pL+(ms-wStart)/(wEnd-wStart)*cW;
  const yS=v=>pT+cH-(v/vmax)*cH;
  const nowX=xS(now);
  let svg=`<svg class="chart-svg" viewBox="0 0 ${W} ${H}">`;
  // AQI zone backgrounds
  [[0,20,'rgba(74,222,128,.09)'],[20,40,'rgba(163,230,53,.09)'],[40,60,'rgba(251,191,36,.10)'],[60,80,'rgba(249,115,22,.11)'],[80,Math.max(101,vmax),'rgba(248,113,113,.13)']].forEach(([a,b,col])=>{
    if(a>=vmax)return;
    const y1=yS(Math.min(b,vmax)),y2=yS(a);
    svg+=`<rect x="${pL}" y="${y1}" width="${cW}" height="${y2-y1}" fill="${col}"/>`;
  });
  // Grid + labels
  [20,40,60,80,100].forEach(v=>{
    if(v>vmax)return;
    const y=yS(v);
    svg+=`<line x1="${pL}" y1="${y}" x2="${W-pR}" y2="${y}" stroke="var(--border)" stroke-width="1"/>`;
    svg+=`<text x="${pL-2}" y="${y+3}" font-size="7" fill="var(--muted)" text-anchor="end">${v}</text>`;
  });
  // AQI line
  let path='';
  pts.forEach(p=>{if(p.v==null)return;path+=(path?'L':'M')+xS(p.ms)+','+yS(p.v);});
  if(path)svg+=`<path d="${path}" fill="none" stroke="var(--cyan)" stroke-width="2" stroke-linejoin="round"/>`;
  // Now marker
  svg+=`<line x1="${nowX}" y1="${pT}" x2="${nowX}" y2="${H-pB}" stroke="var(--amber)" stroke-width="1.5" stroke-dasharray="3,2"/>`;
  svg+=`<text x="${nowX}" y="${pT}" font-size="7" fill="var(--amber)" text-anchor="middle" dominant-baseline="hanging">zdaj</text>`;
  // X labels every 6h
  for(let off=-24;off<=24;off+=6){
    const dt=new Date(now+off*3600000);
    svg+=`<text x="${xS(now+off*3600000)}" y="${H-1}" font-size="7.5" fill="var(--muted)" text-anchor="middle">${dt.getHours().toString().padStart(2,'0')}:00</text>`;
  }
  svg+='</svg>';
  el.innerHTML='<div class="chart-svg-wrap">'+svg+'</div>';
}

function _buildAqPollutants(d){
  const el=document.getElementById('aq-pollutants');if(!el)return;
  const h=d.hourly||{};
  const ni=_aqNowIdx(h.time);
  const get=k=>ni!=null?h[k]?.[ni]:null;
  const co=get('carbon_monoxide');
  const rows=[
    {lbl:'PM2,5',val:get('pm2_5'),unit:'µg/m³',lim:25,note:'Dnevna meja: WHO 15 µg/m³ / EU 25 µg/m³'},
    {lbl:'PM10',val:get('pm10'),unit:'µg/m³',lim:50,note:'Dnevna meja EU: 50 µg/m³'},
    {lbl:'Ozon O₃',val:get('ozone'),unit:'µg/m³',lim:120,note:'8-urna meja EU: 120 µg/m³'},
    {lbl:'NO₂',val:get('nitrogen_dioxide'),unit:'µg/m³',lim:200,note:'Urna meja EU: 200 µg/m³'},
    {lbl:'SO₂',val:get('sulphur_dioxide'),unit:'µg/m³',lim:350,note:'Urna meja EU: 350 µg/m³'},
    {lbl:'CO',val:co!=null?co/1000:null,unit:'mg/m³',lim:10,note:'8-urna meja EU: 10 mg/m³'},
    {lbl:'Prah (dust)',val:get('dust'),unit:'µg/m³',lim:null,note:'Saharski prah + lokalni viri'},
    {lbl:'NH₃',val:get('ammonia'),unit:'µg/m³',lim:null,note:'Kmetijsko onesnaževalo'},
  ];
  el.innerHTML=rows.map(r=>{
    const v=r.val;
    const disp=v!=null?(v<10?v.toFixed(1):v.toFixed(0))+' '+r.unit:'—';
    const pct=v!=null&&r.lim?Math.min(100,(v/r.lim)*100):null;
    const barCol=pct==null?'var(--muted)':pct<33?'var(--green)':pct<66?'var(--amber)':pct<100?'#fb923c':'var(--red)';
    return `<div style="display:flex;gap:.5rem;align-items:center;padding:.25rem 0;border-bottom:1px solid var(--border);font-size:.74rem;flex-wrap:wrap">
      <span style="color:var(--muted);width:82px;flex-shrink:0">${r.lbl}</span>
      <b style="width:78px;flex-shrink:0">${disp}</b>
      <div style="flex:1;min-width:80px">${pct!=null?`<div class="aq-bar-wrap" style="margin:.1rem 0"><div class="aq-bar-fill" style="width:${pct.toFixed(0)}%;background:${barCol}"></div></div>`:''}</div>
      <span style="font-size:.62rem;color:var(--muted);min-width:100px">${r.note}</span>
    </div>`;
  }).join('');
}

function _buildAqPollen(d){
  const el=document.getElementById('aq-pollen-wrap');if(!el)return;
  const h=d.hourly||{};
  const times=h.time||[];
  const today=new Date();
  const days=Array.from({length:5},(_,i)=>{const dt=new Date(today);dt.setDate(dt.getDate()+i);return _localDateStr(dt);});
  const wdays=['Ned','Pon','Tor','Sre','Čet','Pet','Sob'];
  const dayLbls=days.map((d,i)=>i===0?'Danes':i===1?'Jutri':wdays[new Date(d).getDay()]);
  const types=[
    {key:'grass_pollen',   lbl:'🌾 Trave',     th:[10,50,200]},
    {key:'birch_pollen',   lbl:'🌳 Breza',     th:[10,100,1000]},
    {key:'alder_pollen',   lbl:'🌲 Jelša',     th:[10,100,1000]},
    {key:'mugwort_pollen', lbl:'🌿 Pelin',     th:[10,100,300]},
    {key:'ragweed_pollen', lbl:'🌺 Ambrozija', th:[10,50,200]},
  ];
  const dailyMax=(key,dateStr)=>{
    let mx=null;
    times.forEach((t,i)=>{if(t.startsWith(dateStr)){const v=h[key]?.[i];if(v!=null)mx=mx==null?v:Math.max(mx,v);}});
    return mx;
  };
  const riskCls=(v,th)=>{
    if(v==null||v<0.5)return'aq-poll-na';
    if(v<th[0])return'aq-poll-good';
    if(v<th[1])return'aq-poll-fair';
    if(v<th[2])return'aq-poll-mod';
    return'aq-poll-poor';
  };
  const riskTxt=(v,th)=>{
    if(v==null||v<0.5)return'—';
    if(v<th[0])return'nizka';
    if(v<th[1])return'zmerna';
    if(v<th[2])return'visoka';
    return'zelo visoka';
  };
  // Grid: label col + 5 day cols
  const cols=`repeat(${5+1},1fr)`;
  let html=`<div class="aq-poll-grid" style="grid-template-columns:auto ${Array(5).fill('1fr').join(' ')}">`;
  // Header
  html+=`<div class="aq-poll-head" style="text-align:left">Vrsta</div>`;
  dayLbls.forEach(l=>html+=`<div class="aq-poll-head">${l}</div>`);
  // Rows
  types.forEach(tp=>{
    html+=`<div class="aq-poll-lbl">${tp.lbl}</div>`;
    days.forEach(dt=>{
      const v=dailyMax(tp.key,dt);
      html+=`<div class="aq-poll-cell ${riskCls(v,tp.th)}">${riskTxt(v,tp.th)}</div>`;
    });
  });
  html+='</div>';
  html+=`<div style="font-size:.63rem;color:var(--muted);margin-top:.4rem;line-height:1.5">Vrednosti predstavljajo dnevne maksimume v delcih/m³. Vir podatkov: Copernicus CAMS Europe. Sezonska razpoložljivost podatkov je odvisna od biološke aktivnosti rastlin.</div>`;
  el.innerHTML=html;
}

function _buildAqHealth(d){
  const el=document.getElementById('aq-health');if(!el)return;
  const h=d.hourly||{};
  const ni=_aqNowIdx(h.time);
  const get=k=>ni!=null?h[k]?.[ni]:null;
  const aqi=get('european_aqi');
  const maxPollen=Math.max(get('grass_pollen')??0,get('birch_pollen')??0,get('ragweed_pollen')??0,get('mugwort_pollen')??0);
  const items=[];
  if(aqi!=null){
    if(aqi<=20)items.push({ic:'✅',txt:'Kakovost zraka je odlična. Ni omejitev za dejavnosti na prostem.'});
    else if(aqi<=40)items.push({ic:'🟡',txt:'Sprejemljiva kakovost zraka. Zelo občutljivi (npr. s hudo astmo) naj se izogibajo večjim naporom.'});
    else if(aqi<=60){
      items.push({ic:'🟠',txt:'<b>Občutljive skupine</b> (astmatiki, srčni bolniki, starejši in otroci) – omejite dolgotrajnejšo fizično aktivnost na prostem.'});
      items.push({ic:'💊',txt:'Astmatiki naj imajo ob sebi inhalator.'});
    }else if(aqi<=80){
      items.push({ic:'🔴',txt:'<b>Vsakdo</b> lahko začuti vpliv na zdravje. Zmanjšajte fizične napore na prostem.'});
      items.push({ic:'🚪',txt:'Zaprite okna in vrata – preprečite vstop onesnaženega zraka v bivalne prostore.'});
    }else{
      items.push({ic:'🚨',txt:'<b>Zdravstveni alarm!</b> Izogibajte se zunanjim aktivnostim. Če morate ven, nosite zaščitno masko N95/FFP2.'});
      items.push({ic:'🚪',txt:'Zaprite okna. Priporoča se uporaba čistilnika zraka s HEPA-filtrom.'});
    }
  }
  if(maxPollen>200)items.push({ic:'🤧',txt:'<b>Zelo visoka koncentracija cvetnega prahu.</b> Alergiki: vzemite antihistaminike, ostanite v zaprtih prostorih in filtrirajte zrak. Po prihodu od zunaj se oprhajte in preoblecite.'});
  else if(maxPollen>50)items.push({ic:'🤧',txt:'<b>Visoka koncentracija cvetnega prahu.</b> Alergiki naj redno jemljejo antihistaminike. Izogibajte se travnatim območjem. Dom prezračujte zgodaj zjutraj ali neposredno po dežju.'});
  else if(maxPollen>10)items.push({ic:'😤',txt:'<b>Zmerna koncentracija cvetnega prahu.</b> Bodite pozorni na morebitne simptome. Ob sunkovitem vetru se koncentracija v zraku močno poveča.'});
  if(!items.length)items.push({ic:'😊',txt:'Ni posebnih priporočil. Uživajte na svežem zraku!'});
  items.push({ic:'🪟',txt:'Dom prezračujte zgodaj zjutraj do 6. ure (nižje koncentracije prizemnega ozona) in po dežju (izpiranje delcev iz ozračja). Med prometnimi konicami (med 7. in 9. uro ter 15. in 18. uro) se prezračevanje odsvetuje.'});
  el.innerHTML=items.map(it=>`<div class="aq-health-item"><span style="font-size:1.05rem;flex-shrink:0;margin-top:.05rem">${it.ic}</span><span>${it.txt}</span></div>`).join('');
}
