function _windDirLabel(deg){
  const dirs=['S','SSV','SV','VSV','V','VJV','JV','JJV','J','JJZ','JZ','ZJZ','Z','ZSZ','SZ','SSZ'];
  return dirs[Math.round(deg/22.5)%16];
}

function _buildMorjeKPIs({fc,marine}){
  const el=document.getElementById('sea-kpis'); if(!el)return;
  const c=marine.current||{},cf=fc.current||{};
  const wh=c.wave_height??null,sst=c.sea_surface_temperature??null;
  const uv=fc.daily?.uv_index_max?.[0]??null;
  const kpis=[
    {val:wh!=null?wh.toFixed(1)+' m':'—',lbl:'Valovanje',sub:wh!=null?_seaStateLabel(wh):'—'},
    {val:c.wave_period!=null?c.wave_period.toFixed(0)+' s':'—',lbl:'Obdobje vala',sub:'sekunde'},
    {val:sst!=null?sst.toFixed(1)+' °C':'—',lbl:'Temp. morja',sub:'površina'},
    {val:cf.wind_speed_10m!=null?Math.round(cf.wind_speed_10m)+' km/h':'—',lbl:'Veter',sub:cf.wind_direction_10m!=null?_windDirLabel(cf.wind_direction_10m):'—'},
    {val:uv!=null?uv.toFixed(1):'—',lbl:'Maks. UV',sub:uv!=null?(uv>7?'visok':uv>3?'zmeren':'nizek'):'—'},
    {val:cf.temperature_2m!=null?cf.temperature_2m.toFixed(0)+' °C':'—',lbl:'T zraka',sub:'Portorož'},
  ];
  el.innerHTML=kpis.map(k=>`<div class="sea-kpi"><div class="sea-kpi-val">${k.val}</div><div class="sea-kpi-lbl">${k.lbl}</div><div class="sea-kpi-sub">${k.sub}</div></div>`).join('');
}

function _buildMorjeMarine({marine}){
  const el=document.getElementById('sea-marine-body'); if(!el)return;
  const c=marine.current||{};
  const rows=[
    ['🌊 Skupna višina valov',c.wave_height!=null?c.wave_height.toFixed(2)+' m':'—'],
    ['🌊 Vetrni valovi',c.wind_wave_height!=null?c.wind_wave_height.toFixed(2)+' m':'—'],
    ['🌊 Valovanje (swell)',c.swell_wave_height!=null?c.swell_wave_height.toFixed(2)+' m':'—'],
    ['⏱ Obdobje vala',c.wave_period!=null?c.wave_period.toFixed(1)+' s':'—'],
    ['🧭 Smer valovanja',c.wave_direction!=null?c.wave_direction.toFixed(0)+'° ('+_windDirLabel(c.wave_direction)+')':'—'],
    ['🌡 Temp. morja',c.sea_surface_temperature!=null?c.sea_surface_temperature.toFixed(1)+' °C':'—'],
  ];
  // Wave height bar
  const maxH=4, pct=Math.min(100,((c.wave_height??0)/maxH)*100);
  const lbl=_seaStateLabel(c.wave_height??0);
  el.innerHTML=`<div style="margin-bottom:.6rem">
    <div style="font-size:.7rem;color:var(--muted);margin-bottom:.2rem">Stanje morja: <b style="color:var(--text)">${lbl}</b> · ${c.wave_height!=null?c.wave_height.toFixed(2)+' m':'—'}</div>
    <div class="sea-state-bar"><div class="sea-state-fill" style="width:${pct}%"></div></div>
  </div>`+
  rows.map(([l,v])=>`<div style="display:flex;justify-content:space-between;padding:.18rem 0;border-bottom:1px solid var(--border);font-size:.75rem"><span style="color:var(--muted)">${l}</span><b>${v}</b></div>`).join('');
}

function _buildMorjeFc({fc,marine}){
  const el=document.getElementById('sea-fc-body'); if(!el)return;
  const d=fc.daily||{};
  const dm=marine.daily||{};
  const days=['Ned','Pon','Tor','Sre','Čet','Pet','Sob'];
  const n=Math.min(7,(d.time||[]).length);
  let html='<div class="sea-fc-row">';
  for(let i=0;i<n;i++){
    const dt=new Date(d.time[i]); const dn=days[dt.getDay()];
    const wmo=d.weather_code?.[i]??0;
    const tmax=d.temperature_2m_max?.[i]!=null?Math.round(d.temperature_2m_max[i])+'°':'—';
    const tmin=d.temperature_2m_min?.[i]!=null?Math.round(d.temperature_2m_min[i])+'°':'—';
    const wh=dm.wave_height_max?.[i]!=null?dm.wave_height_max[i].toFixed(1)+' m':'—';
    const rain=d.precipitation_sum?.[i]!=null?d.precipitation_sum[i].toFixed(0):'0';
    const wind=d.wind_gusts_10m_max?.[i]!=null?Math.round(d.wind_gusts_10m_max[i])+' km/h':'—';
    html+=`<div class="sea-fc-day">
      <div class="sea-fc-name">${dn}</div>
      <div class="sea-fc-icon">${_wmoImg(wmo,true,28)}</div>
      <div class="sea-fc-t">${tmax}/${tmin}</div>
      <div class="sea-fc-sub">🌊 ${wh}<br>💨 ${wind}<br>🌧 ${rain}mm</div>
    </div>`;
  }
  html+='</div>';
  el.innerHTML=html;
}

function _buildMorjeWind({fc}){
  const el=document.getElementById('sea-wind-body'); if(!el)return;
  const d=fc.daily||{};
  const n=Math.min(7,(d.time||[]).length);
  const days=['Ned','Pon','Tor','Sre','Čet','Pet','Sob'];
  // Classify each day: Bora (NE: 30-80°), Jugo (SE-S: 110-180°), ostalo
  let html='<table class="sea-wind-table"><thead><tr><th>Dan</th><th>Hitrost</th><th>Sunki</th><th>Smer</th><th>Tip</th></tr></thead><tbody>';
  for(let i=0;i<n;i++){
    const dt=new Date(d.time[i]); const dn=days[dt.getDay()];
    const spd=d.wind_speed_10m_max?.[i]!=null?Math.round(d.wind_speed_10m_max[i]):'—';
    const gust=d.wind_gusts_10m_max?.[i]!=null?Math.round(d.wind_gusts_10m_max[i]):'—';
    const dir=d.wind_direction_10m_dominant?.[i];
    const dirLbl=dir!=null?_windDirLabel(dir):'—';
    let type='ostali vetrovi',cls='sea-ostalo';
    if(dir!=null){
      if(dir>=30&&dir<=80){type='Burja';cls='sea-bora';}
      else if(dir>=110&&dir<=190){type='Jugo';cls='sea-jugo';}
    }
    html+=`<tr><td>${dn}</td><td>${spd} km/h</td><td>${gust} km/h</td><td>${dirLbl}</td><td><span class="sea-wind-type ${cls}">${type}</span></td></tr>`;
  }
  html+='</tbody></table>';
  html+=`<div style="margin-top:.65rem;font-size:.7rem;color:var(--muted);line-height:1.6">
    <b style="color:var(--blue)">Burja</b> — hladen SV veter (30–80°), sunkovit, suh. Tipičen za zimo in pomlad, hitrost do 200 km/h v izjemnih razmerah.<br>
    <b style="color:var(--amber)">Jugo</b> — topel JV veter (110–190°), vlaži, prinaša visoke valove. Pogost pred in med atlantskimi cikloni.
  </div>`;
  el.innerHTML=html;
}

// ══════════════════════════════════════════════════════════
// ── SUITABILITY CARDS (sea / mountains / paragliding) ─────
// ══════════════════════════════════════════════════════════
// Suitability level (higher = better)
function _suitClass(pct){
  if(pct>=80)return{cls:'suit-excellent',lvl:'ODLIČNO',col:'#4ade80'};
  if(pct>=60)return{cls:'suit-good',lvl:'DOBRO',col:'#a3e635'};
  if(pct>=40)return{cls:'suit-fair',lvl:'ZMERNO',col:'#fbbf24'};
  if(pct>=20)return{cls:'suit-poor',lvl:'SLABO',col:'#fb923c'};
  return{cls:'suit-bad',lvl:'NEPRIMERNO',col:'#f87171'};
}
function _wmoShort(w){
  if(w<=1)return'jasno';if(w<=3)return'delno oblačno';if(w<=48)return'megla';
  if(w<=57)return'rosenje';if(w<=67)return'dež';if(w<=77)return'sneg';
  if(w<=82)return'plohe';if(w<=86)return'snežne plohe';return'nevihte';
}
// Generic renderer for a suitability card (prefix → element ids)
function _renderSuitCard(prefix,icon,pct,desc,factors){
  const g=id=>document.getElementById(id);
  const card=g(prefix+'-card');if(!card)return;
  const s=_suitClass(pct);
  card.className='card sc-risk-card '+s.cls;
  if(g(prefix+'-icon'))g(prefix+'-icon').textContent=icon;
  if(g(prefix+'-level'))g(prefix+'-level').textContent=s.lvl;
  if(g(prefix+'-desc'))g(prefix+'-desc').textContent=desc;
  if(g(prefix+'-pct'))g(prefix+'-pct').textContent=pct+' %';
  const fill=g(prefix+'-fill');if(fill){fill.style.width=pct+'%';fill.style.background=s.col;}
  if(g(prefix+'-factors'))g(prefix+'-factors').innerHTML=factors.map(f=>`<div class="sc-risk-factor"><small>${f.l}</small><b>${f.v}</b><span>${f.d}</span></div>`).join('');
}
// Sea / beach suitability for today (Portorož)
function _buildMorjeSuit({fc,marine}){
  const c=marine.current||{},cf=fc.current||{},d=fc.daily||{};
  const sst=c.sea_surface_temperature,wave=c.wave_height,wind=cf.wind_speed_10m;
  const tmax=d.temperature_2m_max?.[0],wmo=d.weather_code?.[0]??0;
  let s=50;
  if(sst!=null){if(sst>=24)s+=22;else if(sst>=22)s+=15;else if(sst>=20)s+=6;else if(sst>=18)s-=6;else s-=22;}
  if(tmax!=null){if(tmax>=28)s+=16;else if(tmax>=24)s+=10;else if(tmax>=20)s+=2;else s-=12;}
  if(wave!=null){if(wave<0.3)s+=8;else if(wave<0.6)s+=2;else if(wave<1.0)s-=8;else if(wave<1.5)s-=18;else s-=30;}
  if(wind!=null){if(wind<12)s+=6;else if(wind<20)s-=2;else if(wind<30)s-=14;else s-=28;}
  if(wmo>=95)s-=40;else if(wmo>=80)s-=22;else if(wmo>=51)s-=14;else if(wmo>=45)s-=6;else if(wmo<=2)s+=6;
  const pct=Math.max(0,Math.min(100,Math.round(s)));
  const desc=pct>=80?'Odlične razmere za kopanje in plažo – toplo morje, mirna gladina.'
    :pct>=60?'Dobre razmere za morje, manjše omejitve.'
    :pct>=40?'Zmerne razmere – morje hladnejše ali rahlo valovito.'
    :pct>=20?'Slabe razmere za kopanje – mrzlo morje, veter ali valovi.'
    :'Neprimerno za morje – slabo vreme ali razburkano morje.';
  const factors=[
    {l:'Temp. morja',v:sst!=null?sst.toFixed(1)+' °C':'—',d:sst==null?'—':sst>=22?'prijetno toplo':sst>=20?'sveže':'mrzlo'},
    {l:'Temp. zraka',v:tmax!=null?Math.round(tmax)+' °C':'—',d:tmax==null?'—':tmax>=28?'vroče':tmax>=24?'toplo':tmax>=20?'milo':'hladno'},
    {l:'Valovanje',v:wave!=null?wave.toFixed(1)+' m':'—',d:wave==null?'—':_seaStateLabel(wave)},
    {l:'Veter',v:wind!=null?Math.round(wind)+' km/h':'—',d:wind==null?'—':wind<12?'šibek':wind<25?'zmeren':'močan'},
    {l:'Vreme',v:_wmoShort(wmo),d:''}
  ];
  _renderSuitCard('sea-suit','🏖',pct,desc,factors);
}
// Mountain hiking suitability for today (Triglav / Julian Alps)
function _buildGoreSuit({triglav}){
  const d=triglav.daily||{},fs=triglav._freezeStats||[];
  const tmax=d.temperature_2m_max?.[0],gust=d.wind_gusts_10m_max?.[0];
  const precip=d.precipitation_sum?.[0],snow=d.snowfall_sum?.[0],wmo=d.weather_code?.[0]??0;
  const freeze=fs[0]?.max??null;
  const tTriglav=tmax;
  let s=62;
  if(gust!=null){if(gust<25)s+=10;else if(gust<40)s-=6;else if(gust<60)s-=24;else if(gust<80)s-=40;else s-=55;}
  if(precip!=null){if(precip<1)s+=8;else if(precip<5)s-=8;else if(precip<15)s-=22;else s-=38;}
  if(wmo>=95)s-=45;else if(wmo>=80)s-=24;else if(wmo>=71)s-=18;else if(wmo>=51)s-=12;else if(wmo<=2)s+=8;
  if(snow!=null&&snow>0){if(snow<2)s-=4;else if(snow<10)s-=16;else s-=30;}
  if(tTriglav!=null){if(tTriglav<-15)s-=18;else if(tTriglav<-8)s-=8;else if(tTriglav<0)s-=2;}
  const pct=Math.max(0,Math.min(100,Math.round(s)));
  const desc=pct>=80?'Odlične razmere za turo – mirno vreme, šibek veter.'
    :pct>=60?'Dobre razmere v gorah – preveri lokalne pogoje.'
    :pct>=40?'Zmerne razmere – veter, mraz ali padavine zahtevajo previdnost.'
    :pct>=20?'Slabe razmere – močan veter ali padavine; le za izkušene.'
    :'Neprimerno za turo – nevarne razmere v visokogorju.';
  const factors=[
    {l:'T vrh (2864 m)',v:tTriglav!=null?tTriglav.toFixed(0)+' °C':'—',d:tTriglav==null?'—':tTriglav<-8?'hud mraz':tTriglav<0?'pod lediščem':'znosno'},
    {l:'Sunki vetra',v:gust!=null?Math.round(gust)+' km/h':'—',d:gust==null?'—':gust<25?'šibki':gust<40?'zmerni':gust<60?'močni':'nevarni'},
    {l:'Padavine',v:precip!=null?precip.toFixed(0)+' mm':'—',d:precip==null?'—':precip<1?'suho':precip<5?'malo':'mokro'},
    {l:'Sneg danes',v:snow!=null&&snow>0?snow.toFixed(0)+' cm':'0 cm',d:snow>0?(snow>=10?'pozor, plazovi':'sveži sneg'):'brez'},
    {l:'Meja ledišča',v:freeze!=null?Math.round(freeze)+' m':'—',d:freeze==null?'—':freeze<1500?'nizko':freeze<2500?'srednje':'visoko'}
  ];
  _renderSuitCard('mtn-suit','🥾',pct,desc,factors);
}
// Paragliding suitability for today (peak of daytime flyability)
function _buildPadalciSuit(d){
  const h=d.hourly||{};
  const today=_localDateStr(new Date());
  const idxs=[];(h.time||[]).forEach((t,i)=>{if(t.startsWith(today)&&h.is_day?.[i])idxs.push(i);});
  let best=0,flyHours=0,maxBL=0,maxWind=0,maxCAPE=0;
  idxs.forEach(i=>{
    const wind=h.wind_speed_10m?.[i]??0,pp=h.precipitation_probability?.[i]??0,cape=h.cape?.[i]??0,bl=h.boundary_layer_height?.[i]??0;
    const sc=_flyScore(wind,pp,cape,bl,h.is_day?.[i]);
    if(sc>best)best=sc;if(sc>=70)flyHours++;
    if(bl>maxBL)maxBL=bl;if(wind>maxWind)maxWind=wind;if(cape>maxCAPE)maxCAPE=cape;
  });
  const pct=Math.max(0,Math.min(100,Math.round(best)));
  const desc=pct>=80?`Odlični pogoji za letenje – okno kakovostne termike predvidoma ${flyHours} h.`
    :pct>=60?`Dobri pogoji – okno letenja predvidoma ${flyHours} h.`
    :pct>=40?'Zmerni pogoji – termika šibka ali veter mejni.'
    :pct>=20?'Slabi pogoji – veter, dež ali premočna termika.'
    :'Neprimerno za letenje.';
  const factors=[
    {l:'Vrhunec dneva',v:pct,d:'ocena (score) 0–100'},
    {l:'Ure letenja',v:flyHours+' h',d:'ocena ≥ 70'},
    {l:'Maks. BL strop',v:Math.round(maxBL)+' m',d:maxBL>1500?'visok':maxBL<400?'nizek':'zmeren'},
    {l:'Maks. veter',v:Math.round(maxWind)+' km/h',d:maxWind>30?'premočan':maxWind>20?'mejni':'ugoden'},
    {l:'Maks. CAPE',v:Math.round(maxCAPE)+' J/kg',d:maxCAPE>1000?'⚠️ nevihtno':maxCAPE>500?'pozor':'mirno'}
  ];
  _renderSuitCard('fly-suit','🪂',pct,desc,factors);
}

// ═══ GORE ══════════════════════════════════════════════════
const MTN_TRIGLAV_LAT=46.3794,MTN_TRIGLAV_LON=13.8376,MTN_TRIGLAV_ELEV=2864; // Triglav
const MTN_KRVAVEC_LAT=46.2989,MTN_KRVAVEC_LON=14.5360,MTN_KRVAVEC_ELEV=1971; // Krvavec
let _goreInit=false,_goreCache=null,_goreCacheT=0;

// Compute daily {max,min} of freezing_level_height from hourly data
function _dailyFreezeStats(h){
  const map={};
  (h.time||[]).forEach((t,i)=>{
    const date=t.slice(0,10),v=h.freezing_level_height?.[i];
    if(v==null)return;
    if(!map[date]){map[date]={max:v,min:v};}
    else{map[date].max=Math.max(map[date].max,v);map[date].min=Math.min(map[date].min,v);}
  });
  return Object.entries(map).sort(([a],[b])=>a<b?-1:1).map(([date,s])=>({date,...s}));
}

async function initGore(){
  if(_goreInit)return; _goreInit=true;
  try{
    const now=Date.now();
    if(!_goreCache||now-_goreCacheT>3600000){
      const params='hourly=freezing_level_height,snowfall'
        +'&daily=weather_code,temperature_2m_max,temperature_2m_min,precipitation_sum,'
        +'snowfall_sum,wind_speed_10m_max,wind_gusts_10m_max'
        +'&current=temperature_2m,wind_speed_10m,wind_gusts_10m'
        +'&timezone=Europe%2FLjubljana&forecast_days=7';
      // Pass each summit's elevation so Open-Meteo downscales temperature to it
      const [triglav,krvavec]=await Promise.all([
        fetch(`https://api.open-meteo.com/v1/forecast?latitude=${MTN_TRIGLAV_LAT}&longitude=${MTN_TRIGLAV_LON}&elevation=${MTN_TRIGLAV_ELEV}&${params}`).then(r=>r.json()),
        fetch(`https://api.open-meteo.com/v1/forecast?latitude=${MTN_KRVAVEC_LAT}&longitude=${MTN_KRVAVEC_LON}&elevation=${MTN_KRVAVEC_ELEV}&${params}`).then(r=>r.json()),
      ]);
      // Pre-compute daily freeze stats from hourly
      triglav._freezeStats=_dailyFreezeStats(triglav.hourly||{});
      krvavec._freezeStats=_dailyFreezeStats(krvavec.hourly||{});
      _goreCache={triglav,krvavec}; _goreCacheT=now;
    }
    _buildGoreKPIs(_goreCache);
    _buildGoreFreeze(_goreCache);
    _buildGoreTriglav(_goreCache);
    _buildGoreKrvavec(_goreCache);
    _buildGoreSuit(_goreCache);
  }catch(e){console.error('initGore',e);}
}

function _buildGoreKPIs({triglav}){
  const el=document.getElementById('mtn-kpis'); if(!el)return;
  const d=triglav.daily||{};
  const fs=triglav._freezeStats||[];
  const freeze=fs[0]?.max??null;
  const tTriglav=d.temperature_2m_max?.[0]??null;
  const snowfall=d.snowfall_sum?.[0]??null;
  const gust=d.wind_gusts_10m_max?.[0]??null;
  const kpis=[
    {val:freeze!=null?Math.round(freeze)+' m':'—',lbl:'Meja ledišča',sub:'danes',col:freeze!=null&&freeze<1000?'var(--blue)':null},
    {val:tTriglav!=null?tTriglav.toFixed(0)+' °C':'—',lbl:'T Triglav 2864 m n. v.',sub:'modelska višina vrha',col:tTriglav!=null&&tTriglav<0?'var(--blue)':null},
    {val:snowfall!=null&&snowfall>0?snowfall.toFixed(0)+' cm':'0 cm',lbl:'Sneg danes',sub:'cm novega snega'},
    {val:gust!=null?Math.round(gust)+' km/h':'—',lbl:'Maks. sunki',sub:'območje Triglava'},
  ];
  el.innerHTML=kpis.map(k=>`<div class="mtn-kpi"><div class="mtn-kpi-val"${k.col?` style="color:${k.col}"`:''}>${k.val}</div><div class="mtn-kpi-lbl">${k.lbl}</div><div class="mtn-kpi-sub">${k.sub}</div></div>`).join('');
}

function _buildGoreFreeze({triglav}){
  const chartEl=document.getElementById('mtn-freeze-chart');
  const legEl=document.getElementById('mtn-freeze-legend');
  if(!chartEl)return;
  const fs=triglav._freezeStats||[];
  const n=Math.min(7,fs.length);
  if(!n){chartEl.innerHTML='<div style="color:var(--muted);font-size:.75rem">Ni podatkov</div>';return;}
  const maxH=fs.map(s=>s.max);
  const minH=fs.map(s=>s.min);
  const days=['Ned','Pon','Tor','Sre','Čet','Pet','Sob'];
  // SVG bar chart 0–4000m
  const W=880,H=100,pad={l:40,r:10,t:10,b:20};
  const cW=W-pad.l-pad.r,cH=H-pad.t-pad.b;
  const yScale=v=>(cH-(v/4000)*cH+pad.t);
  const bW=Math.floor(cW/n)-4;
  // Reference lines: Krvavec 1971m, Vogel 1922m, Triglav 2864m
  const refs=[{h:1922,lbl:'Vogel',col:'#34d399'},{h:1971,lbl:'Krvavec',col:'#60a5fa'},{h:2864,lbl:'Triglav',col:'#f87171'}];
  let svg=`<svg viewBox="0 0 ${W} ${H}" class="mtn-freeze-svg">`;
  // Ref lines
  refs.forEach(r=>{
    const y=yScale(r.h);
    svg+=`<line x1="${pad.l}" y1="${y}" x2="${W-pad.r}" y2="${y}" stroke="${r.col}" stroke-width="1" stroke-dasharray="4,3" opacity=".6"/>`;
    svg+=`<text x="${W-pad.r-2}" y="${y-2}" font-size="7" fill="${r.col}" text-anchor="end" opacity=".8">${r.lbl}</text>`;
  });
  // Y axis ticks
  [0,1000,2000,3000,4000].forEach(v=>{
    const y=yScale(v);
    svg+=`<text x="${pad.l-3}" y="${y+3}" font-size="7" fill="var(--muted)" text-anchor="end">${v}</text>`;
    svg+=`<line x1="${pad.l}" y1="${y}" x2="${pad.l+2}" y2="${y}" stroke="var(--muted)" stroke-width="1"/>`;
  });
  // Bars
  for(let i=0;i<n;i++){
    const x=pad.l+i*(cW/n)+2;
    const hi=maxH[i]??2000,lo=minH[i]??hi;
    const yTop=yScale(hi),yBot=yScale(lo);
    const barH=Math.max(3,yBot-yTop);
    const col=hi<1000?'#818cf8':hi<2000?'#60a5fa':hi<3000?'#4ade80':'#fbbf24';
    svg+=`<rect x="${x}" y="${yTop}" width="${bW}" height="${barH}" fill="${col}" rx="2" opacity=".8"/>`;
    const dt=new Date(fs[i].date);
    svg+=`<text x="${x+bW/2}" y="${H-3}" font-size="7.5" fill="var(--muted)" text-anchor="middle">${days[dt.getDay()]}</text>`;
  }
  svg+='</svg>';
  chartEl.innerHTML=svg;
  if(legEl) legEl.innerHTML=refs.map(r=>`<span><svg width="14" height="2"><line x1="0" y1="1" x2="14" y2="1" stroke="${r.col}" stroke-width="1.5" stroke-dasharray="4,2"/></svg>${r.lbl} ${r.h} m</span>`).join('')
    +'<span style="opacity:.6">Stolpci = min–maks višina meje ledišča</span>';
}

function _buildGoreTriglav({triglav}){
  const el=document.getElementById('mtn-triglav-body'); if(!el)return;
  const d=triglav.daily||{};
  const n=Math.min(7,(d.time||[]).length);
  const days=['Ned','Pon','Tor','Sre','Čet','Pet','Sob'];
  let html='<div class="mtn-fc-row">';
  for(let i=0;i<n;i++){
    const dt=new Date(d.time[i]);
    const wmo=d.weather_code?.[i]??0;
    const tmaxT=d.temperature_2m_max?.[i]??null;
    const tminT=d.temperature_2m_min?.[i]??null;
    const snow=d.snowfall_sum?.[i]!=null&&d.snowfall_sum[i]>0?d.snowfall_sum[i].toFixed(0)+' cm':'—';
    const gust=d.wind_gusts_10m_max?.[i]!=null?Math.round(d.wind_gusts_10m_max[i]):'—';
    html+=`<div class="mtn-fc-day">
      <div class="mtn-fc-name">${days[dt.getDay()]}</div>
      <div class="mtn-fc-icon">${_wmoImg(wmo,true,28)}</div>
      <div class="mtn-fc-t">${tmaxT!=null?tmaxT.toFixed(0)+'°':'—'}/${tminT!=null?tminT.toFixed(0)+'°':'—'}</div>
      <div class="mtn-fc-sub">❄️ ${snow}<br>💨 ${gust} km/h</div>
    </div>`;
  }
  html+='</div>';
  html+=`<div class="mtn-summit-info">
    <b>Opomba:</b> Temperature so modelsko prilagojene na višino vrha Triglava (2864 m) z metodo statističnega zniževanja (Open-Meteo). Za operativno planinarjenje vedno preveri
    <a href="https://meteo.arso.gov.si/met/sl/mountain/" target="_blank" style="color:var(--blue)">ARSO planinsko napoved</a>.
  </div>`;
  el.innerHTML=html;
}

function _buildGoreKrvavec({krvavec}){
  const el=document.getElementById('mtn-krvavec-body'); if(!el)return;
  const d=krvavec.daily||{};
  const n=Math.min(7,(d.time||[]).length);
  const days=['Ned','Pon','Tor','Sre','Čet','Pet','Sob'];
  let html='<div class="mtn-fc-row">';
  for(let i=0;i<n;i++){
    const dt=new Date(d.time[i]);
    const wmo=d.weather_code?.[i]??0;
    const tmaxK=d.temperature_2m_max?.[i]??null;
    const tminK=d.temperature_2m_min?.[i]??null;
    const snow=d.snowfall_sum?.[i]!=null&&d.snowfall_sum[i]>0?d.snowfall_sum[i].toFixed(0)+' cm':'—';
    const gust=d.wind_gusts_10m_max?.[i]!=null?Math.round(d.wind_gusts_10m_max[i]):'—';
    html+=`<div class="mtn-fc-day">
      <div class="mtn-fc-name">${days[dt.getDay()]}</div>
      <div class="mtn-fc-icon">${_wmoImg(wmo,true,28)}</div>
      <div class="mtn-fc-t">${tmaxK!=null?tmaxK.toFixed(0)+'°':'—'}/${tminK!=null?tminK.toFixed(0)+'°':'—'}</div>
      <div class="mtn-fc-sub">❄️ ${snow}<br>💨 ${gust} km/h</div>
    </div>`;
  }
  html+='</div>';
  el.innerHTML=html;
}
// ═══ end GORE ══════════════════════════════════════════════

// ═══ GOBARJI ═══════════════════════════════════════════════
const GOBE_SPOTS=[
  {name:'Rečica ob Savinji', lat:46.326, lon:14.921, elev:'≈400 m'},
  {name:'Dobrovlje – Čreta',  lat:46.300, lon:14.860, elev:'≈900 m'},
  {name:'Logarska dolina',    lat:46.392, lon:14.628, elev:'≈750 m'},
  {name:'Golte',              lat:46.348, lon:14.840, elev:'≈1300 m'},
  {name:'Smrekovško pogorje', lat:46.430, lon:14.860, elev:'≈1300 m'},
];
let _gobeInit=false,_gobeCache=null,_gobeCacheT=0,_gobeDayOffset=0,_gobePrimaryAgg=null;

async function initGobe(){
  if(_gobeInit&&_gobeCache){_renderGobe();return;}
  _gobeInit=true;
  const setErr=m=>{const e=document.getElementById('gobe-suit-desc');if(e)e.textContent=m;};
  try{
    const now=Date.now();
    if(!_gobeCache||now-_gobeCacheT>3600000){
      const lats=GOBE_SPOTS.map(s=>s.lat).join(',');
      const lons=GOBE_SPOTS.map(s=>s.lon).join(',');
      const url='https://api.open-meteo.com/v1/forecast?latitude='+lats+'&longitude='+lons
        +'&daily=precipitation_sum,temperature_2m_max,temperature_2m_min'
        +'&hourly=soil_moisture_3_to_9cm,soil_temperature_6cm,relative_humidity_2m'
        +'&past_days=14&forecast_days=14&timezone=Europe%2FLjubljana';
      const res=await fetch(url).then(r=>r.json());
      _gobeCache=Array.isArray(res)?res:[res];
      _gobeCacheT=now;
    }
    _renderGobe();
  }catch(e){console.error('initGobe',e);setErr('Napaka pri pridobivanju podatkov: '+e.message);}
}

// Aggregate hourly soil/RH to daily means, keyed by date string
function _gobeDailyAgg(loc){
  const h=loc.hourly||{},map={};
  (h.time||[]).forEach((t,i)=>{
    const d=t.slice(0,10);
    const o=map[d]||(map[d]={sm:0,smn:0,st:0,stn:0,rh:0,rhn:0});
    const sm=h.soil_moisture_3_to_9cm?.[i];if(sm!=null){o.sm+=sm;o.smn++;}
    const st=h.soil_temperature_6cm?.[i];if(st!=null){o.st+=st;o.stn++;}
    const rh=h.relative_humidity_2m?.[i];if(rh!=null){o.rh+=rh;o.rhn++;}
  });
  const res={};
  Object.keys(map).forEach(d=>{const o=map[d];res[d]={sm:o.smn?o.sm/o.smn:null,st:o.stn?o.st/o.stn:null,rh:o.rhn?o.rh/o.rhn:null};});
  return res;
}
function _gobeTodayIdx(loc){
  const n=new Date();
  const s=n.getFullYear()+'-'+String(n.getMonth()+1).padStart(2,'0')+'-'+String(n.getDate()).padStart(2,'0');
  let i=(loc.daily?.time||[]).indexOf(s);
  return i<0?14:i;
}
// Gather mushroom-relevant inputs for a given daily index
function _gobeInputs(loc,agg,i){
  const d=loc.daily||{};
  const rainAt=k=>(k>=0&&k<(d.precipitation_sum||[]).length)?(d.precipitation_sum[k]??0):0;
  let ar=0;for(let k=i-12;k<=i-4;k++)ar+=rainAt(k); // antecedent rain (fruiting trigger, ~5–12 d lag)
  const date=d.time?.[i],a=date?agg[date]:null;
  const tmax=d.temperature_2m_max?.[i],tmin=d.temperature_2m_min?.[i];
  const tmean=(tmax!=null&&tmin!=null)?(tmax+tmin)/2:(tmax??tmin??null);
  return{ar,sm:a?a.sm:null,st:a?a.st:null,rh:a?a.rh:null,tmean};
}
// Mushroom fruiting score 0–100
function _gobeScore({ar,sm,st,rh,tmean}){
  let s=0;
  if(ar>=60)s+=34;else if(ar>=35)s+=27;else if(ar>=20)s+=18;else if(ar>=10)s+=9;else if(ar>=4)s+=3;
  if(sm!=null){if(sm>=0.32)s+=24;else if(sm>=0.26)s+=18;else if(sm>=0.20)s+=11;else if(sm>=0.15)s+=4;}
  if(st!=null){if(st>=10&&st<=18)s+=18;else if((st>=7&&st<10)||(st>18&&st<=21))s+=10;else if(st>=4&&st<=24)s+=4;}
  if(rh!=null){if(rh>=85)s+=12;else if(rh>=75)s+=8;else if(rh>=65)s+=4;}
  if(tmean!=null){if(tmean<2)s-=22;else if(tmean<5)s-=8;else if(tmean>26)s-=10;}
  return Math.max(0,Math.min(100,Math.round(s)));
}
function _gobeColor(p){if(p>=70)return'#4ade80';if(p>=50)return'#a3e635';if(p>=30)return'#fbbf24';if(p>=15)return'#fb923c';return'#64748b';}
function _gobeLevel(p){
  if(p>=75)return{lvl:'ODLIČNA',cls:'suit-excellent'};
  if(p>=55)return{lvl:'DOBRA',cls:'suit-good'};
  if(p>=35)return{lvl:'ZMERNA',cls:'suit-fair'};
  if(p>=18)return{lvl:'SLABA',cls:'suit-poor'};
  return{lvl:'BREZ',cls:'suit-bad'};
}

function _renderGobe(){
  if(!_gobeCache||!_gobeCache.length)return;
  const aggs=_gobeCache.map(_gobeDailyAgg);
  _gobePrimaryAgg=aggs[0];
  _buildGobeMain(_gobeCache[0],aggs[0]);
  _buildGobeStrip(_gobeCache[0],aggs[0]);
  _buildGobeSpots(_gobeCache,aggs);
  _buildGobeSpecies(_gobeCache[0],aggs[0]);
}
function scSetGobeDay(v){
  _gobeDayOffset=Math.max(0,Math.min(13,parseInt(v,10)||0));
  if(_gobeCache&&_gobeCache.length&&_gobePrimaryAgg){
    _buildGobeMain(_gobeCache[0],_gobePrimaryAgg);
    _buildGobeStrip(_gobeCache[0],_gobePrimaryAgg);
  }
}

function _buildGobeMain(loc,agg){
  const g=id=>document.getElementById(id);
  const card=g('gobe-suit-card');if(!card)return;
  const d=loc.daily||{},ti=_gobeTodayIdx(loc);
  const i=Math.min(ti+_gobeDayOffset,(d.time||[]).length-1);
  const inp=_gobeInputs(loc,agg,i);
  const pct=_gobeScore(inp);
  const lv=_gobeLevel(pct);
  card.className='card sc-risk-card '+lv.cls;
  // days since last good rain (≥5 mm), relative to the selected day
  let dsr=null;for(let k=i;k>=0;k--){if((d.precipitation_sum?.[k]??0)>=5){dsr=i-k;break;}}
  // rain over the 14 days up to the selected day
  let rain14=0;for(let k=i-13;k<=i;k++){if(k>=0)rain14+=(d.precipitation_sum?.[k]??0);}
  // Slider label + sync
  const tEl=document.getElementById('gobe-day-time'),dt=d.time?.[i]?new Date(d.time[i]):null;
  if(tEl){const dl=['ned','pon','tor','sre','čet','pet','sob'];tEl.textContent=_gobeDayOffset===0?'danes':(dt?`${dl[dt.getDay()]} ${dt.getDate()}.${dt.getMonth()+1}.`:'')+` · +${_gobeDayOffset} d`;}
  const rng=document.getElementById('gobe-day-range');if(rng&&+rng.value!==_gobeDayOffset)rng.value=_gobeDayOffset;
  const desc=pct>=75?'Odlične razmere – tla vlažna in topla, gobe so verjetno v polni rasti.'
    :pct>=55?'Dobre razmere za gobe. Po izdatnem dežju je smiselno na lov.'
    :pct>=35?'Zmerne razmere – posamezne gobe možne, predvsem v vlažnih legah.'
    :pct>=18?'Slabe razmere – pretežno suho ali prehladno za obrodnost.'
    :'Brez obrodnosti – premalo vlage ali prenizke temperature.';
  if(g('gobe-suit-icon'))g('gobe-suit-icon').textContent=pct>=55?'🍄':pct>=35?'🍄':'🌱';
  if(g('gobe-suit-level'))g('gobe-suit-level').textContent=lv.lvl;
  if(g('gobe-suit-desc'))g('gobe-suit-desc').textContent=desc;
  if(g('gobe-suit-pct'))g('gobe-suit-pct').textContent=pct+' %';
  const fill=g('gobe-suit-fill');if(fill){fill.style.width=pct+'%';fill.style.background=_gobeColor(pct);}
  const factors=[
    {l:'Vlaga tal (3–9 cm)',v:inp.sm!=null?Math.round(inp.sm*100)+' %':'—',d:inp.sm==null?'—':inp.sm>=0.3?'vlažno':inp.sm>=0.22?'zmerno':inp.sm>=0.15?'sušnato':'suho'},
    {l:'Temp. tal (6 cm)',v:inp.st!=null?inp.st.toFixed(0)+' °C':'—',d:inp.st==null?'—':inp.st>=10&&inp.st<=18?'idealno':inp.st<7?'hladno':inp.st>21?'toplo':'znosno'},
    {l:'Dež (14 dni)',v:Math.round(rain14)+' mm',d:rain14>=40?'obilno':rain14>=15?'zmerno':'malo'},
    {l:'Sprožilni dež (5–12 d)',v:Math.round(inp.ar)+' mm',d:inp.ar>=25?'močan zagon':inp.ar>=10?'zmeren':'šibek'},
    {l:'Od zadnjega dežja',v:dsr==null?'>14 dni':dsr+' dni',d:dsr==null?'dolgo suho':dsr<=2?'sveže namočeno':dsr<=8?'optimalno okno':'se suši'}
  ];
  if(g('gobe-suit-factors'))g('gobe-suit-factors').innerHTML=factors.map(f=>`<div class="sc-risk-factor"><small>${f.l}</small><b>${f.v}</b><span>${f.d}</span></div>`).join('');
}

function _buildGobeStrip(loc,agg){
  const strip=document.getElementById('gobe-strip');if(!strip)return;
  const d=loc.daily||{},ti=_gobeTodayIdx(loc);
  const days=['ned','pon','tor','sre','čet','pet','sob'];
  let html='',best=-1,bestIdx=ti;
  for(let k=0;k<14;k++){
    const i=ti+k;if(i>=(d.time||[]).length)break;
    const pct=_gobeScore(_gobeInputs(loc,agg,i));
    if(pct>best){best=pct;bestIdx=i;}
    const col=_gobeColor(pct),ht=Math.max(4,Math.round(pct/100*60));
    const dt=new Date(d.time[i]);
    html+=`<div class="sc-risk-cell${k===_gobeDayOffset?' active':''}" onclick="scSetGobeDay(${k})" title="${d.time[i]}: ${pct} %">`+
      `<div class="sc-risk-cell-pct">${pct}</div>`+
      `<div class="sc-risk-cell-bar" style="height:${ht}px;background:${col}"></div>`+
      `<div class="sc-risk-cell-hr">${k===0?'danes':days[dt.getDay()]}</div></div>`;
  }
  strip.innerHTML=html;
}

function _buildGobeSpots(all,aggs){
  const el=document.getElementById('gobe-spots');if(!el)return;
  const rows=GOBE_SPOTS.map((sp,n)=>{
    const loc=all[n];if(!loc||!loc.daily)return{...sp,pct:null};
    const ti=_gobeTodayIdx(loc);
    const pct=_gobeScore(_gobeInputs(loc,aggs[n],ti));
    return{...sp,pct};
  }).sort((a,b)=>(b.pct??-1)-(a.pct??-1));
  el.innerHTML=rows.map(r=>{
    const pct=r.pct,col=pct!=null?_gobeColor(pct):'#64748b';
    return `<div class="gobe-spot">
      <span class="gobe-spot-dot" style="background:${col}"></span>
      <span class="gobe-spot-name">${r.name} <span class="gobe-spot-elev">${r.elev}</span></span>
      <span class="gobe-spot-bar"><i style="width:${pct??0}%;background:${col}"></i></span>
      <span class="gobe-spot-pct">${pct!=null?pct+' %':'—'}</span>
    </div>`;
  }).join('');
}

// Likely species for the current month (Savinjska / Slovenia)
function _gobeSpeciesFor(month){
  const S={
    boletus:{ic:'🍄',nm:'Jurček (goban)',nt:'Listnati in iglasti gozdovi; 2–3 tedne po dežju, tla 12–18 °C. Pogost v Savinjski dolini in Kamniško-Savinjskih Alpah.'},
    chant:{ic:'🟡',nm:'Lisička',nt:'Mahovita, vlažna tla pod smreko in bukvijo; prenese več dežja kot jurček.'},
    morel:{ic:'🟤',nm:'Smrček (mavrah)',nt:'Pomladanska goba; gaji, jesenovi logi, ob potokih; tla 8–15 °C. Sezona: marec–maj.'},
    stmgeorge:{ic:'⚪',nm:'Majska goba (pripravljavnica)',nt:'Travniki in robovi gozda v aprilu in maju; raste v skupinah.'},
    chestnut:{ic:'🌰',nm:'Turek / kostanjevka',nt:'Pod kostanjem in hrastom; topli jesenski dnevi, tla 10–16 °C.'},
    parasol:{ic:'☂️',nm:'Orjaški dežnik',nt:'Travniki in poseke; pozno poletje in jesen. Zamenljiv s strupenim dežnikom – preveri!'},
    winter:{ic:'❄️',nm:'Zimska panjevka',nt:'Na štorih listavcev; raste ob nizkih temperaturah in blagi zmrzali.'},
    oyster:{ic:'🦪',nm:'Bukov ostrigar',nt:'Na bukovih in topolovih deblih; pozna jesen in zima.'},
    warn:{ic:'☠️',nm:'Pozor: nevarne dvojnice!',nt:'Mušnice in druge nevarne vrste rastejo sočasno z jedilnimi – natančno preveri vsako gobo!'},
  };
  // 0=jan ... 11=dec
  const byMonth=[
    [S.winter,S.oyster],                       // jan
    [S.winter,S.oyster],                       // feb
    [S.morel],                                 // mar
    [S.morel,S.stmgeorge],                     // apr
    [S.stmgeorge,S.morel,S.boletus],           // may
    [S.boletus,S.chant,S.warn],                // jun
    [S.boletus,S.chant,S.warn],                // jul
    [S.boletus,S.chant,S.parasol,S.warn],      // aug
    [S.boletus,S.chant,S.chestnut,S.parasol,S.warn], // sep
    [S.boletus,S.chant,S.chestnut,S.parasol,S.warn], // oct
    [S.chant,S.winter,S.oyster],               // nov
    [S.winter,S.oyster],                       // dec
  ];
  return byMonth[month]||[];
}
function _buildGobeSpecies(loc,agg){
  const el=document.getElementById('gobe-species');if(!el)return;
  const month=new Date().getMonth();
  const ti=_gobeTodayIdx(loc);
  const pct=_gobeScore(_gobeInputs(loc,agg,ti));
  const list=_gobeSpeciesFor(month);
  const mn=['januarja','februarja','marca','aprila','maja','junija','julija','avgusta','septembra','oktobra','novembra','decembra'][month];
  const note=pct>=55?'Razmere so ugodne – spodaj naštete vrste so trenutno najbolj verjetne.'
    :pct>=35?'Razmere so zmerne – verjetnost je manjša, a v vlažnih legah se splača pogledati.'
    :'Trenutno je presuho ali prehladno – kljub sezoni je obrodnost teh vrst malo verjetna.';
  el.innerHTML=`<div style="font-size:.72rem;color:var(--muted);margin-bottom:.5rem">Tipično v ${mn} v Savinjski dolini. ${note}</div>`+
    list.map(s=>`<div class="gobe-sp"><span class="gobe-sp-ic">${s.ic}</span><div><div class="gobe-sp-nm">${s.nm}</div><div class="gobe-sp-nt">${s.nt}</div></div></div>`).join('');
}

// ═══ NAPOVED PO MERI (tipske napovedi) ═════════════════════
const ACTIVITIES=[
  {key:'rekreacija',icon:'🏃',label:'Rekreacija',pane:'act-rekreacija'},
  {key:'cebelarji', icon:'🐝',label:'Čebelarji', pane:'act-cebelarji'},
  {key:'nebo',      icon:'🔭',label:'Nebo',      pane:'act-nebo'},
  {key:'pv',        icon:'☀️',label:'Sončna elektrarna', pane:'act-pv'},
  {key:'ribic',     icon:'🎣',label:'Ribiči',    pane:'act-ribic'},
  {key:'morje',     icon:'🌊',label:'Morje',     pane:'tab-morje',  init:()=>initMorje()},
  {key:'gore',      icon:'⛰',label:'Gore',       pane:'tab-gore',   init:()=>initGore()},
  {key:'padalci',   icon:'🪂',label:'Padalci',   pane:'tab-padalci',init:()=>initPadalci()},
  {key:'gobe',      icon:'🍄',label:'Gobarji',   pane:'tab-gobe',   init:()=>initGobe()},
];
let _poMeriInit=false,_poMeriCur=null;
function initPoMeri(){
  if(!_poMeriInit){
    _poMeriInit=true;
    const chips=document.getElementById('act-chips');
    if(chips)chips.innerHTML=ACTIVITIES.map(a=>`<button class="act-chip" id="act-chip-${a.key}" onclick="switchActivity('${a.key}')">${a.icon} ${a.label}</button>`).join('');
  }
  switchActivity(_poMeriCur||'rekreacija');
}
function switchActivity(key){
  _poMeriCur=key;
  ACTIVITIES.forEach(a=>{
    document.getElementById(a.pane)?.classList.toggle('active',a.key===key);
    document.getElementById('act-chip-'+a.key)?.classList.toggle('active',a.key===key);
  });
  const a=ACTIVITIES.find(x=>x.key===key);if(!a)return;
  if(a.init)a.init(); else _initActivity(key);
}

// ── Shared data for the 5 native activities ──
let _actData=null,_actDataT=0,_actBuilt={},_actOff={};
async function _actEnsureData(){
  const now=Date.now();
  if(_actData&&now-_actDataT<3600000)return _actData;
  const url='https://api.open-meteo.com/v1/forecast?latitude='+LAT+'&longitude='+LON
    +'&hourly=temperature_2m,apparent_temperature,relative_humidity_2m,dew_point_2m,precipitation,'
    +'precipitation_probability,cloud_cover,wind_speed_10m,wind_gusts_10m,uv_index,shortwave_radiation,'
    +'is_day,weather_code,surface_pressure'
    +'&timezone=Europe%2FLjubljana&past_days=1&forecast_days=7';
  _actData=await fetch(url).then(r=>r.json());
  _actDataT=now;
  return _actData;
}
const ACT_CFG={
  rekreacija:{icon:'🏃',title:'🏃 Rekreacija (tek / kolo)',gauge:'primernost',gran:'hour',span:24,sliderLbl:'🕐 Napoved naprej:',strip:'🕐 Najboljši čas — naslednjih 24 ur',
    tips:'Tek/kolo je najprijetnejši pri občutku temperature 8–18 °C, šibkem vetru in nizki verjetnosti dežja. V vročini izberi jutro ali večer in pij dovolj tekočine; pri visokem UV uporabi zaščito.'},
  cebelarji:{icon:'🐝',title:'🐝 Čebelja paša',gauge:'paša',gran:'hour',span:24,sliderLbl:'🕐 Napoved naprej:',strip:'🕐 Pašne razmere — naslednjih 24 ur',
    tips:'Čebele pašejo pri >12–15 °C, soncu in šibkem vetru. Pri toplem, vlažnem in mirnem vremenu po deževju je nevarnost rojenja večja — preglej panje. Pregledov ne opravljaj v dežju in mrazu.'},
  nebo:{icon:'🔭',title:'🔭 Opazovanje neba',gauge:'pogoji',gran:'hour',span:24,sliderLbl:'🕐 Napoved naprej:',strip:'🕐 Vidnost neba — naslednjih 24 ur',
    tips:'Za opazovanje so ključni jasno nebo, nizka vlaga (manj megle/rose) in tema. Polna luna prebije šibke objekte (galaksije, meglice) — za te izberi mlaj. Za planete in Luno je svetloba manj moteča.'},
  pv:{icon:'☀️',title:'☀️ Sončna elektrarna',gauge:'proizvodnja',gran:'hour',span:24,sliderLbl:'🕐 Napoved naprej:',strip:'🕐 Proizvodnja — naslednjih 24 ur',
    tips:'Ocena temelji na napovedanem sončnem sevanju (oblačnost je že upoštevana). »Ocena moči« velja za primer sistema 5 kWp z izkoristkom ~85 %. Največja proizvodnja je opoldne ob jasnem nebu.'},
  ribic:{icon:'🎣',title:'🎣 Ribolov',gauge:'ugodnost',gran:'day',span:7,sliderLbl:'🗓 Napoved naprej:',strip:'📅 Ribiški obeti — 7 dni',
    tips:'Ribe so pogosto bolj aktivne ob stabilnem ali rahlo rastočem zračnem tlaku, rahli oblačnosti in mirnem vetru. Hitri padec tlaka pred fronto lahko sproži kratko aktivnost, nato sledi zatišje. Upoštevaj lokalne predpise in dovolilnice.'},
};
function _actPanelHTML(key){
  const c=ACT_CFG[key],max=c.span-1;
  const ticks=c.gran==='hour'
    ?'<span>zdaj</span><span>+6 h</span><span>+12 h</span><span>+18 h</span><span>+23 h</span>'
    :'<span>danes</span><span>+2 d</span><span>+4 d</span><span>+6 d</span>';
  return `<div class="card sc-risk-card suit-fair" id="${key}-card">
    <div class="sc-risk-head">
      <span class="sc-risk-icon" id="${key}-icon">${c.icon}</span>
      <div class="sc-risk-text">
        <div class="clabel" style="margin:0">${c.title} — Rečica ob Savinji</div>
        <div class="sc-risk-level" id="${key}-level">—</div>
        <div class="sc-risk-desc" id="${key}-desc">Nalagam…</div>
      </div>
      <div class="sc-risk-gauge">
        <div class="sc-risk-pct" id="${key}-pct">—</div>
        <div class="sc-risk-bar"><div class="sc-risk-fill" id="${key}-fill" style="width:0%"></div></div>
        <div class="sc-risk-gauge-lbl">${c.gauge}</div>
      </div>
    </div>
    <div class="sc-risk-factors" id="${key}-factors"></div>
    <div class="sc-risk-scrub">
      <div class="sc-risk-scrub-head"><span class="clabel" style="margin:0">${c.sliderLbl}</span><span class="sc-risk-scrub-time" id="${key}-time">zdaj</span></div>
      <input type="range" class="sc-scrub-range" id="${key}-range" min="0" max="${max}" value="0" step="1" oninput="actSlide('${key}',this.value)">
      <div class="sc-scrub-ticks">${ticks}</div>
    </div>
  </div>
  <div class="card" style="margin-top:1rem"><div class="clabel">${c.strip}</div><div class="sc-risk-strip" id="${key}-strip" style="margin-top:.4rem"></div></div>
  <div class="card" style="margin-top:1rem"><div class="clabel">📋 Nasveti</div><div style="font-size:.74rem;color:var(--muted);line-height:1.7;margin-top:.4rem">${c.tips}</div></div>`;
}
async function _initActivity(key){
  const pane=document.getElementById('act-'+key);if(!pane)return;
  if(!_actBuilt[key]){pane.innerHTML=_actPanelHTML(key);_actBuilt[key]=true;}
  try{await _actEnsureData();_renderActivity(key);}
  catch(e){console.error('activity',key,e);const d=document.getElementById(key+'-desc');if(d)d.textContent='Napaka pri pridobivanju podatkov.';}
}
function actSlide(key,v){
  const c=ACT_CFG[key];_actOff[key]=Math.max(0,Math.min(c.span-1,parseInt(v,10)||0));
  _renderActivity(key);
}
function _renderActivity(key){
  if(!_actData||!_actData.hourly)return;
  if(ACT_CFG[key].gran==='hour')_renderActHour(key);else _renderActDay(key);
}
function _actDesc(key,pct){
  const noun={rekreacija:'za tek/kolesarjenje',cebelarji:'za čebeljo pašo',nebo:'za opazovanje neba',pv:'za proizvodnjo',ribic:'za ribolov'}[key]||'';
  if(pct>=80)return'Odlične razmere '+noun+'.';
  if(pct>=60)return'Dobre razmere '+noun+'.';
  if(pct>=40)return'Zmerne razmere '+noun+'.';
  if(pct>=20)return'Slabe razmere '+noun+'.';
  return'Neprimerno '+noun+'.';
}
function _actNowIdx(t){let i=t.findIndex(x=>x>=new Date())-1;return i<0?0:i;}
function _localDateStr(n){return n.getFullYear()+'-'+String(n.getMonth()+1).padStart(2,'0')+'-'+String(n.getDate()).padStart(2,'0');}
function _moonIllum(d){const syn=29.530588853,ref=Date.UTC(2000,0,6,18,14);let p=(((d.getTime()-ref)/86400000)%syn)/syn;if(p<0)p+=1;return(1-Math.cos(2*Math.PI*p))/2;}
function _moonName(d){const syn=29.530588853,ref=Date.UTC(2000,0,6,18,14);let p=(((d.getTime()-ref)/86400000)%syn)/syn;if(p<0)p+=1;return['mlaj','mlada','prvi krajec','rastoča','ščip','pojemajoča','zadnji krajec','stara'][Math.round(p*8)%8];}

// Hourly activity evaluation → {pct, factors}
function _actEval(key,h,i){
  const T=scIdx(h.temperature_2m,i),at=scIdx(h.apparent_temperature,i)??T,rh=scIdx(h.relative_humidity_2m,i),td=scIdx(h.dew_point_2m,i),
        pp=scIdx(h.precipitation_probability,i)??0,cloud=scIdx(h.cloud_cover,i)??50,wind=scIdx(h.wind_speed_10m,i)??0,
        gust=scIdx(h.wind_gusts_10m,i)??wind,uv=scIdx(h.uv_index,i)??0,rad=scIdx(h.shortwave_radiation,i)??0,
        day=(scIdx(h.is_day,i)??1)>0,dt=new Date((h.time||[])[i]);
  if(key==='rekreacija'){
    let s=100,a=at??15;
    if(a<-5)s-=55;else if(a<0)s-=35;else if(a<5)s-=15;else if(a<=18)s-=0;else if(a<=24)s-=8;else if(a<=28)s-=22;else if(a<=32)s-=40;else s-=60;
    if(pp>=70)s-=45;else if(pp>=45)s-=28;else if(pp>=25)s-=14;else if(pp>=10)s-=5;
    if(gust>=45)s-=35;else if(gust>=30)s-=18;else if(gust>=20)s-=8;
    if(uv>=8)s-=10;else if(uv>=6)s-=4;
    if((rh??60)>=90&&a>22)s-=8;
    const pct=Math.max(0,Math.min(100,Math.round(s)));
    return{pct,factors:[
      {l:'Občutek T',v:(at!=null?Math.round(at):'—')+' °C',d:a>=8&&a<=20?'prijetno':a<5?'mrzlo':a>26?'vroče':'znosno'},
      {l:'Dež',v:pp+' %',d:pp>=45?'verjeten':pp>=15?'možen':'suho'},
      {l:'Sunki vetra',v:Math.round(gust)+' km/h',d:gust>=30?'močni':gust>=20?'zmerni':'šibki'},
      {l:'UV indeks',v:Math.round(uv),d:uv>=8?'visok':uv>=3?'zmeren':'nizek'},
      {l:'Vlaga',v:(rh!=null?Math.round(rh):'—')+' %',d:(rh??0)>=85?'soparno':'ok'}]};
  }
  if(key==='cebelarji'){
    let s=0;const tt=T??10;
    if(day){
      if(tt>=18)s+=45;else if(tt>=15)s+=36;else if(tt>=12)s+=24;else if(tt>=10)s+=10;
      if(wind<12)s+=18;else if(wind<20)s+=10;else if(wind<30)s+=3;
      if(pp<10)s+=18;else if(pp<30)s+=8;
      if(cloud<30)s+=19;else if(cloud<60)s+=10;else s+=3;
    }
    const pct=day?Math.max(0,Math.min(100,Math.round(s))):0;
    return{pct,factors:[
      {l:'Temperatura',v:(T!=null?Math.round(T):'—')+' °C',d:tt>=15?'aktivna paša':tt>=12?'zmerna':tt>=10?'šibka':'premrzlo'},
      {l:'Veter',v:Math.round(wind)+' km/h',d:wind<12?'mirno':wind<20?'zmerno':'vetrovno'},
      {l:'Dež',v:pp+' %',d:pp>=30?'moti pašo':'ok'},
      {l:'Oblačnost',v:Math.round(cloud)+' %',d:cloud<30?'sončno':cloud<60?'delno':'oblačno'},
      {l:'Čas dneva',v:day?'dan':'noč',d:day?'paša možna':'brez paše'}]};
  }
  if(key==='nebo'){
    let s=0;const il=_moonIllum(dt),spread=(T!=null&&td!=null)?T-td:5;
    if(!day){
      if(cloud<10)s+=55;else if(cloud<25)s+=42;else if(cloud<50)s+=25;else if(cloud<75)s+=10;
      if((rh??80)<70)s+=20;else if((rh??80)<85)s+=10;
      if(pp<10)s+=15;else if(pp<30)s+=5;
      if(spread>5)s+=10;else if(spread>2)s+=5;
      if(il>0.85)s-=10;else if(il>0.6)s-=5;
    }
    const pct=day?0:Math.max(0,Math.min(100,Math.round(s)));
    return{pct,factors:[
      {l:'Oblačnost',v:Math.round(cloud)+' %',d:cloud<25?'jasno':cloud<50?'delno':'oblačno'},
      {l:'Vlaga',v:(rh!=null?Math.round(rh):'—')+' %',d:(rh??0)<70?'suho':(rh??0)<85?'zmerno':'megla možna'},
      {l:'Dež',v:pp+' %',d:pp>=20?'možen':'suho'},
      {l:'Luna',v:Math.round(il*100)+' %',d:_moonName(dt)},
      {l:'Čas dneva',v:day?'dan':'noč',d:day?'presvetlo':'temno'}]};
  }
  if(key==='pv'){
    const pct=Math.max(0,Math.min(100,Math.round(rad/850*100)));
    const power=rad/1000*5*0.85;
    return{pct,factors:[
      {l:'Sevanje',v:Math.round(rad)+' W/m²',d:rad>=600?'močno':rad>=300?'zmerno':rad>0?'šibko':'noč'},
      {l:'Oblačnost',v:Math.round(cloud)+' %',d:cloud<30?'jasno':cloud<60?'delno':'oblačno'},
      {l:'Ocena moči',v:power.toFixed(1)+' kW',d:'sistem 5 kWp'},
      {l:'Delež max',v:pct+' %',d:'glede na ~850 W/m²'}]};
  }
  return{pct:0,factors:[]};
}
function _renderActHour(key){
  const h=_actData.hourly,t=(h.time||[]).map(x=>new Date(x));if(!t.length)return;
  const nowIdx=_actNowIdx(t),off=_actOff[key]||0,ci=Math.min(nowIdx+off,t.length-1);
  const ev=_actEval(key,h,ci);
  _renderSuitCard(key,ACT_CFG[key].icon,ev.pct,_actDesc(key,ev.pct),ev.factors);
  const tEl=document.getElementById(key+'-time'),dt=t[ci];
  if(tEl&&dt){const hh=String(dt.getHours()).padStart(2,'0');tEl.textContent=off===0?`zdaj · ${hh}:00`:`${['ned','pon','tor','sre','čet','pet','sob'][dt.getDay()]} ${hh}:00 · +${off} h`;}
  const rng=document.getElementById(key+'-range');if(rng&&+rng.value!==off)rng.value=off;
  const strip=document.getElementById(key+'-strip');
  if(strip){let html='';for(let k=0;k<24;k++){const i=Math.min(nowIdx+k,t.length-1);const p=_actEval(key,h,i).pct;const col=_gobeColor(p),ht=Math.max(4,Math.round(p/100*60)),dd=t[i];const lbl=k===0?'zdaj':String(dd.getHours()).padStart(2,'0')+'h';
    html+=`<div class="sc-risk-cell${k===off?' active':''}" onclick="actSlide('${key}',${k})" title="+${k} h: ${p} %"><div class="sc-risk-cell-pct">${p>0?p:''}</div><div class="sc-risk-cell-bar" style="height:${ht}px;background:${col}"></div><div class="sc-risk-cell-hr">${lbl}</div></div>`;}
    strip.innerHTML=html;
    const ac=strip.children[off];if(ac)strip.scrollLeft=ac.offsetLeft-strip.clientWidth/2+ac.offsetWidth/2;}
}
// Ribiči — daily aggregation
function _actRibicDays(){
  if(_actData._ribicDays)return _actData._ribicDays;
  const h=_actData.hourly||{},map={};
  (h.time||[]).forEach((tt,i)=>{
    const d=tt.slice(0,10),o=map[d]||(map[d]={cloud:0,cn:0,wind:0,pp:0,ppn:0,precip:0,temp:0,tn:0,pres:0,pn:0});
    const c=scIdx(h.cloud_cover,i);if(c!=null){o.cloud+=c;o.cn++;}
    const w=scIdx(h.wind_speed_10m,i);if(w!=null)o.wind=Math.max(o.wind,w);
    const pp=scIdx(h.precipitation_probability,i);if(pp!=null){o.pp+=pp;o.ppn++;}
    o.precip+=scIdx(h.precipitation,i)??0;
    const tm=scIdx(h.temperature_2m,i);if(tm!=null){o.temp+=tm;o.tn++;}
    const pr=scIdx(h.surface_pressure,i);if(pr!=null){o.pres+=pr;o.pn++;}
  });
  const arr=Object.keys(map).sort().map(d=>{const o=map[d];return{date:d,cloud:o.cn?o.cloud/o.cn:50,wind:o.wind,pp:o.ppn?o.pp/o.ppn:0,precip:o.precip,temp:o.tn?o.temp/o.tn:10,pres:o.pn?o.pres/o.pn:1013};});
  _actData._ribicDays=arr;return arr;
}
function _ribicScore(days,i){
  const d=days[i],prev=days[i-1],trend=prev?d.pres-prev.pres:0;
  let s=50;
  if(Math.abs(trend)<=0.7)s+=14;else if(trend>0)s+=8;else if(trend>=-2)s+=2;else s-=14;
  if(d.cloud>=40&&d.cloud<=85)s+=12;else if(d.cloud<20)s+=4;
  if(d.wind<12)s+=10;else if(d.wind<22)s+=4;else if(d.wind>35)s-=12;
  if(d.precip<1)s+=4;else if(d.precip<8)s-=2;else s-=16;
  const il=_moonIllum(new Date(d.date));if(il<=0.08||il>=0.92)s+=12;else if(il<=0.25||il>=0.75)s+=4;
  return Math.max(0,Math.min(100,Math.round(s)));
}
function _ribicFactors(days,i){
  const d=days[i],prev=days[i-1],trend=prev?d.pres-prev.pres:0;
  return[
    {l:'Zračni tlak',v:Math.round(d.pres)+' hPa',d:Math.abs(trend)<=0.7?'stabilen':trend>0?'raste':'pada'},
    {l:'Oblačnost',v:Math.round(d.cloud)+' %',d:d.cloud>=40&&d.cloud<=85?'ugodno':d.cloud<20?'jasno':'spremenljivo'},
    {l:'Veter',v:Math.round(d.wind)+' km/h',d:d.wind<12?'mirno':d.wind<22?'zmerno':'vetrovno'},
    {l:'Padavine',v:Math.round(d.precip)+' mm',d:d.precip<1?'suho':d.precip<8?'rahle':'mokro'},
    {l:'Luna',v:_moonName(new Date(d.date)),d:'faza'}];
}
function _renderActDay(key){
  const days=_actRibicDays();if(!days.length)return;
  const todayStr=_localDateStr(new Date());let ti=days.findIndex(d=>d.date===todayStr);if(ti<0)ti=1;
  const off=_actOff[key]||0,di=Math.min(ti+off,days.length-1);
  const pct=_ribicScore(days,di);
  _renderSuitCard(key,ACT_CFG[key].icon,pct,_actDesc(key,pct),_ribicFactors(days,di));
  const tEl=document.getElementById(key+'-time'),dt=new Date(days[di].date);
  if(tEl)tEl.textContent=off===0?'danes':`${['ned','pon','tor','sre','čet','pet','sob'][dt.getDay()]} ${dt.getDate()}.${dt.getMonth()+1}. · +${off} d`;
  const rng=document.getElementById(key+'-range');if(rng&&+rng.value!==off)rng.value=off;
  const strip=document.getElementById(key+'-strip');
  if(strip){let html='';for(let k=0;k<7;k++){const i=Math.min(ti+k,days.length-1);const p=_ribicScore(days,i);const col=_gobeColor(p),ht=Math.max(4,Math.round(p/100*60)),dd=new Date(days[i].date);
    html+=`<div class="sc-risk-cell${k===off?' active':''}" onclick="actSlide('${key}',${k})" title="${days[i].date}: ${p} %"><div class="sc-risk-cell-pct">${p}</div><div class="sc-risk-cell-bar" style="height:${ht}px;background:${col}"></div><div class="sc-risk-cell-hr">${k===0?'danes':['ned','pon','tor','sre','čet','pet','sob'][dd.getDay()]}</div></div>`;}
    strip.innerHTML=html;}
}

