let _nerdInit=false;
function initNerd(){
  if(_nerdInit)return; _nerdInit=true;
  _buildNerdKPIs();
  _buildNerdSoundingLinks();
  _buildNerdIndexCards();
  _buildNerdLinks();
}

// Monthly temperature normals for Rečica ob Savinji (366m, 1991–2020 proxy)
const _TNORM=[-0.5,1.5,5.5,10.0,14.5,18.0,20.0,19.5,15.0,10.0,5.0,1.0];
// Monthly precipitation normals (mm/month)
const _PNORM=[70,60,80,90,110,130,115,110,115,125,105,85];

function _buildNerdKPIs(){
  const el=document.getElementById('nerd-kpis');
  if(!el)return;

  // Live obs values from DOM (already rendered by main data fetch)
  const T  = parseFloat(document.querySelector('#temp-val')?.textContent) || null;
  const Td = parseFloat(document.getElementById('dewpt-val')?.textContent) || null;
  const RH = parseFloat(document.querySelector('.hm-humidity .hm-val')?.textContent) || null;
  const P  = parseFloat(document.getElementById('pressure-val')?.textContent) || null;

  // Pressure tendency 3h (existing fn, returns number hPa)
  const dp3=pressureTrend3h();

  // Wet bulb via Stull (2011) — acc ±0.65°C for 5%≤RH≤99%
  let Tw=null;
  if(T!=null&&RH!=null&&RH>0){
    Tw=T*Math.atan(0.151977*Math.sqrt(RH+8.313659))
      +Math.atan(T+RH)
      -Math.atan(RH-1.676331)
      +0.00391838*Math.pow(RH,1.5)*Math.atan(0.023101*RH)
      -4.686035;
    Tw=Math.round(Tw*10)/10;
  }

  // Dew point depression
  const DPD=(T!=null&&Td!=null)?Math.round((T-Td)*10)/10:null;

  // Precipitable water estimate (empirical fit, ±20%)
  const PW=Td!=null?Math.round(6.2*Math.exp(0.067*Td)*10)/10:null;

  // Temperature anomaly vs monthly normal
  const mo=new Date().getMonth();
  const Tanom=(T!=null)?Math.round((T-_TNORM[mo])*10)/10:null;

  // 30-day rain from history
  const store=_insStore();
  const today=new Date();
  let rain30=0;
  for(let d=0;d<30;d++){
    const dt=new Date(today); dt.setDate(dt.getDate()-d);
    const k=_localDateStr(dt);
    rain30+=(store[k]?.rain??0);
  }
  const rainAnom=Math.round(rain30-_PNORM[mo]);

  const col=(v)=>v>0?'var(--red)':v<0?'var(--blue)':'var(--muted)';
  const sign=(v)=>v>0?'+':'';
  const f=(v,d=1)=>v!=null?v.toFixed(d):'—';

  const kpis=[
    {
      val: dp3!=null?(dp3>0?'+':'')+dp3.toFixed(1)+' hPa': '—',
      lbl:'Δ tlak/3h',
      sub: dp3>2?'rast':dp3<-2?'padanje':'stabilen',
      col: dp3>2?'var(--green)':dp3<-2?'var(--red)':null
    },
    {
      val: Tw!=null?Tw+' °C':'—',
      lbl:'Mokri term.',
      sub:'Tw · Stull 2011'
    },
    {
      val: DPD!=null?DPD+' K':'—',
      lbl:'Dep. rosišča',
      sub: DPD!=null?(DPD>20?'suho':DPD>10?'normalno':DPD>5?'vlažno':'blizu nasič.'):'—'
    },
    {
      val: PW!=null?PW+' mm':'—',
      lbl:'Padav. voda',
      sub:'PW estim.'
    },
    {
      val: Tanom!=null?sign(Tanom)+Tanom+' K':'—',
      lbl:'T odklon',
      sub:'vs mes. norma',
      col: Tanom!=null?col(Tanom):null
    },
    {
      val: rain30>0?(sign(rainAnom)+rainAnom+' mm'):'—',
      lbl:'Padav. odklon',
      sub:'30d vs norma',
      col: rainAnom!=0?col(rainAnom):null
    },
  ];

  el.innerHTML=kpis.map(k=>`<div class="nerd-kpi">
    <div class="nerd-kpi-val"${k.col?` style="color:${k.col}"`:''}>` +
    (k.val!=='—'?k.val:'<span style="color:var(--muted)">—</span>') +
    `</div>
    <div class="nerd-kpi-lbl">${k.lbl}</div>
    <div class="nerd-kpi-sub">${k.sub}</div>
  </div>`).join('');
}

function _buildNerdSoundingLinks(){
  // Build dynamic UWYO URLs with today's date (latest 12z sounding)
  const now=new Date();
  const y=now.getUTCFullYear();
  const mo=String(now.getUTCMonth()+1).padStart(2,'0');
  const d=String(now.getUTCDate()).padStart(2,'0');
  const time=now.getUTCHours()>=12?'1212':'0000';
  const base='https://weather.uwyo.edu/upperair/';
  const params=`sounding.html?region=europe&TYPE=GIF%3ASKEWT&YEAR=${y}&MONTH=${mo}&FROM=${d}${time.slice(0,2)}&TO=${d}${time.slice(0,2)}&STNM=14015`;
  const textP=`bufrraob.shtml?region=europe&TYPE=TEXT%3ALIST&YEAR=${y}&MONTH=${mo}&FROM=${d}${time.slice(0,2)}&TO=${d}${time.slice(0,2)}&STNM=14015`;
  const sk=document.getElementById('nerd-snd-skewt');
  const tx=document.getElementById('nerd-snd-text');
  if(sk) sk.href=base+params;
  if(tx) tx.href=base+textP;
}

