// ═══ SREDNJA NAPOVED ══════════════════════════════════════
let _srednjaLoaded=false;
async function initSrednja(){
  if(_srednjaLoaded)return; _srednjaLoaded=true;
  const kpis=document.getElementById('med-kpis');
  const cards=document.getElementById('med-cards');
  const upd=document.getElementById('med-upd');
  try{
    const url='https://api.open-meteo.com/v1/forecast?latitude='+LAT+'&longitude='+LON
      +'&daily=weather_code,temperature_2m_max,temperature_2m_min,precipitation_sum,precipitation_probability_max,wind_speed_10m_max'
      +'&timezone=Europe%2FLjubljana&forecast_days=16';
    const j=await fetch(url).then(r=>r.json());
    const d=j.daily; if(!d||!d.time)throw new Error('no data');
    const tx=d.temperature_2m_max, tn=d.temperature_2m_min, pr=d.precipitation_sum;
    const SL_DS=['ned','pon','tor','sre','čet','pet','sob'];
    const SL_MS=['jan','feb','mar','apr','maj','jun','jul','avg','sep','okt','nov','dec'];
    const avg=(tx.reduce((a,b)=>a+(b||0),0)/tx.length);
    const totP=pr.reduce((a,b)=>a+(b||0),0);
    const wI=tx.indexOf(Math.max(...tx)), cI=tn.indexOf(Math.min(...tn));
    kpis.innerHTML=[
      {v:avg.toFixed(1)+'°C',l:'Povprečna T (16 dni)'},
      {v:totP.toFixed(0)+' mm',l:'Skupne padavine'},
      {v:Math.round(Math.max(...tx))+'°C',l:'Najtoplejši · '+SL_DS[new Date(d.time[wI]+'T12:00').getDay()]},
      {v:Math.round(Math.min(...tn))+'°C',l:'Najhladnejši · '+SL_DS[new Date(d.time[cI]+'T12:00').getDay()]},
    ].map(k=>`<div class="med-kpi"><div class="med-kpi-val">${k.v}</div><div class="med-kpi-lbl">${k.l}</div></div>`).join('');
    _buildMedSvg(d);
    cards.innerHTML=d.time.map((t,i)=>{
      const dt=new Date(t+'T12:00'); const mo=dt.getMonth();
      const tx2=tx[i],tn2=tn[i],rain=(pr[i]||0),wc=d.weather_code[i]||0;
      const prob=d.precipitation_probability_max?.[i];
      const anom=((tx2+tn2)/2)-_TNORM[mo];
      const ac=anom>1.5?'warm':anom<-1.5?'cold':'normal';
      const at=(anom>=0?'+':'')+anom.toFixed(1)+'°';
      const dLbl=i===0?'Danes':i===1?'Jutri':SL_DS[dt.getDay()];
      const rainStr=rain>0?`<div class="med-card-rain">💧 ${rain.toFixed(rain<10?1:0)} mm${prob!=null?' · '+Math.round(prob)+'%':''}</div>`:'';
      return`<div class="med-card${i===0?' today':''}">
<div class="med-card-day">${dLbl}</div>
<div class="med-card-date">${dt.getDate()}. ${SL_MS[mo]}</div>
<div class="med-card-icon">${_wmoImg(wc,true,36)}</div>
<div class="med-card-temps">${Math.round(tx2)}° <span class="med-card-tmin">/ ${Math.round(tn2)}°</span></div>
${rainStr}
<div class="med-card-anom ${ac}">${at} norm.</div>
</div>`;
    }).join('');
    if(upd)upd.textContent='Open-Meteo · '+new Date().toLocaleTimeString('sl',{hour:'2-digit',minute:'2-digit'});
  }catch(e){
    if(kpis)kpis.innerHTML='<div style="color:var(--muted);font-size:.8rem">Napoved trenutno ni na voljo.</div>';
    console.error('initSrednja',e);
  }
}
function _buildMedSvg(d){
  const svg=document.getElementById('med-svg'); if(!svg)return;
  const n=d.time.length,W=900,H=230,PL=36,PR=8,PT=14,PB=54;
  const CW=W-PL-PR,CH=H-PT-PB,PRECH=52,TEMPH=CH-PRECH-10;
  const tx=d.temperature_2m_max,tn=d.temperature_2m_min,pr=d.precipitation_sum;
  const allT=[...tx,...tn].filter(v=>v!=null);
  const minT=Math.min(...allT)-3,maxT=Math.max(...allT)+3,maxP=Math.max(...pr,6);
  const bw=CW/n;
  const ty=t=>PT+TEMPH-(t-minT)/(maxT-minT)*TEMPH;
  const SL_DS=['ned','pon','tor','sre','čet','pet','sob'];
  // grid lines
  let grid='',glbl='';
  const step=Math.ceil((maxT-minT)/5/5)*5||5;
  for(let t=Math.ceil(minT/step)*step;t<=maxT;t+=step){
    const y=ty(t); if(y<PT-2||y>PT+TEMPH+2)continue;
    grid+=`<line x1="${PL}" y1="${y}" x2="${W-PR}" y2="${y}" stroke="var(--border)" stroke-width=".5" stroke-dasharray="3,4"/>`;
    glbl+=`<text x="${PL-3}" y="${y+3.5}" text-anchor="end" font-size="9" fill="var(--muted)">${t}°</text>`;
  }
  // temperature band polygon
  const topPts=tx.map((t,i)=>`${PL+i*bw+bw/2},${ty(t??0)}`).join(' ');
  const botPts=[...tn].reverse().map((t,i)=>`${PL+(n-1-i)*bw+bw/2},${ty(t??0)}`).join(' ');
  // midline
  const mid=tx.map((t,i)=>`${i?'L':'M'}${PL+i*bw+bw/2},${ty(((t??0)+(tn[i]??0))/2)}`).join('');
  // precip bars
  let pbars='',plbls='';
  pr.forEach((p,i)=>{
    if(!p)return;
    const x=PL+i*bw+2,bwi=bw-4,topY=PT+CH-p/maxP*PRECH,botY=PT+CH;
    pbars+=`<rect x="${x}" y="${topY}" width="${bwi}" height="${botY-topY}" fill="${i===0?'rgba(96,165,250,.8)':'rgba(96,165,250,.45)'}" rx="2"/>`;
    if(p>=1)plbls+=`<text x="${x+bwi/2}" y="${topY-2}" text-anchor="middle" font-size="7" fill="#60a5fa">${p.toFixed(p<10?1:0)}</text>`;
  });
  // day labels
  let dlbls='';
  d.time.forEach((t,i)=>{
    const dt=new Date(t+'T12:00'),x=PL+i*bw+bw/2,cur=i===0;
    const day=cur?'Danes':SL_DS[dt.getDay()];
    dlbls+=`<text x="${x}" y="${H-PB+13}" text-anchor="middle" font-size="${cur?9.5:8.5}" font-weight="${cur?700:400}" fill="${cur?'var(--blue)':'var(--muted)'}">${day}</text>`;
    dlbls+=`<text x="${x}" y="${H-PB+24}" text-anchor="middle" font-size="7.5" fill="var(--muted)">${dt.getDate()}.</text>`;
  });
  // dots on line
  let dots='';
  tx.forEach((t,i)=>{
    const x=PL+i*bw+bw/2,norm=(((t+tn[i])/2)-minT)/(maxT-minT);
    const r=Math.round(Math.min(255,norm*255+35)),b=Math.round(Math.max(35,255-norm*220));
    const col=`rgb(${r},100,${b})`;
    if(t!=null)dots+=`<circle cx="${x}" cy="${ty(t)}" r="2.8" fill="${col}" stroke="var(--card-bg)" stroke-width="1.2"/>`;
    if(tn[i]!=null)dots+=`<circle cx="${x}" cy="${ty(tn[i])}" r="2.2" fill="${col}" stroke="var(--card-bg)" stroke-width="1.2"/>`;
  });
  const sepY=PT+TEMPH+5;
  svg.innerHTML=`<defs>
  <linearGradient id="mband" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="rgba(251,146,60,.38)"/><stop offset="100%" stop-color="rgba(96,165,250,.22)"/></linearGradient>
</defs>
<rect x="${PL}" y="${PT}" width="${bw}" height="${CH}" fill="rgba(96,165,250,.05)" rx="3"/>
${grid}${glbl}
<polygon points="${topPts} ${botPts}" fill="url(#mband)" opacity=".75"/>
<path d="${mid}" fill="none" stroke="#fb923c" stroke-width="1.8" stroke-linejoin="round" stroke-linecap="round"/>
${pbars}${plbls}
<line x1="${PL}" y1="${sepY}" x2="${W-PR}" y2="${sepY}" stroke="var(--border)" stroke-width=".8"/>
${dots}${dlbls}
<text x="${PL}" y="${H-6}" font-size="8" fill="var(--muted)">💧 padavine (mm)</text>
<text x="${W-PR-70}" y="${H-6}" font-size="8" fill="var(--muted)">🌡 temperatura (°C)</text>`;
}

// ═══ DOLGOROČNA NAPOVED ═══════════════════════════════════
let _dolgorocnaLoaded=false;
function initDolgorocna(){
  if(_dolgorocnaLoaded)return; _dolgorocnaLoaded=true;
  const curM=new Date().getMonth();
  const SL_MON_FULL=['Januar','Februar','Marec','April','Maj','Junij','Julij','Avgust','September','Oktober','November','December'];
  const SL_SEASONS=['Zima','Zima','Pomlad','Pomlad','Pomlad','Poletje','Poletje','Poletje','Jesen','Jesen','Jesen','Zima'];
  const SEA_EMJ=['❄️','❄️','🌱','🌸','🌿','☀️','🌞','🌞','🍂','🍁','🌫️','❄️'];
  const elev=-(366-241)/1000*6.5; // elevation correction Rečica vs Celje
  const N=ARSO_NORMALS;

  // hero card
  const hero=document.getElementById('ltf-hero'); if(hero){
    const t=_TNORM[curM],p=_PNORM[curM];
    const tmx=(N.tmax[curM]+elev).toFixed(1),tmn=(N.tmin[curM]+elev).toFixed(1);
    const warm=t>10,cold=t<2,wet=p>110;
    const outlook=warm&&wet?'Toplo in padavinsko mesečno povprečje.':warm&&!wet?'Toplo in razmeroma suho mesečno povprečje.':cold&&wet?'Hladno in padavinsko mesečno povprečje.':cold&&!wet?'Hladno in razmeroma suho mesečno povprečje.':'Zmerno mesečno povprečje za temperaturo in padavine.';
    const tCol=t>15?'#fb923c':t>5?'#34d399':'#60a5fa';
    const tmxCol=+tmx>20?'#f87171':+tmx>12?'#fb923c':'#60a5fa';
    const tmnCol=+tmn<0?'#818cf8':'#34d399';
    hero.innerHTML=`<div class="ltf-hero-title">${SEA_EMJ[curM]} ${SL_MON_FULL[curM]} — klimatska pričakovanja za Rečico</div>
<div class="ltf-hero-body">${outlook} Povprečna temperatura ${t}°C, pričakovane padavine ${p} mm. Vrednosti temeljijo na klimatskih normalah 1991–2020 (postaja Celje) z višinsko korekcijo za Rečico (366 m).</div>
<div class="ltf-hero-chips">
<div class="ltf-chip"><div class="ltf-chip-val" style="color:${tCol}">${t}°C</div><div class="ltf-chip-lbl">Povprečna T</div></div>
<div class="ltf-chip"><div class="ltf-chip-val" style="color:${tmxCol}">${tmx}°C</div><div class="ltf-chip-lbl">Pov. Tmax</div></div>
<div class="ltf-chip"><div class="ltf-chip-val" style="color:${tmnCol}">${tmn}°C</div><div class="ltf-chip-lbl">Pov. Tmin</div></div>
<div class="ltf-chip"><div class="ltf-chip-val" style="color:#60a5fa">${p} mm</div><div class="ltf-chip-lbl">Pov. padavine</div></div>
</div>`;
  }

  // 12-month grid
  const grid=document.getElementById('ltf-grid'); if(grid){
    const maxP=Math.max(..._PNORM);
    const allTx=N.tmax.map(t=>t+elev),allTn=N.tmin.map(t=>t+elev);
    const fullMin=Math.min(...allTn)-2,fullMax=Math.max(...allTx)+2;
    grid.innerHTML=_TNORM.map((t,i)=>{
      const tmx=allTx[i],tmn=allTn[i],p=_PNORM[i];
      const isCur=i===curM;
      // temperature bar position within annual range
      const leftPct=Math.max(0,(tmn-fullMin)/(fullMax-fullMin)*100);
      const widthPct=Math.max(4,(tmx-tmn)/(fullMax-fullMin)*100);
      // color: cold=blue, warm=orange/red
      const norm=(t-(-5))/(22-(-5));
      const r=Math.round(Math.min(255,norm*255+35)),b=Math.round(Math.max(30,255-norm*220));
      const col=`rgb(${r},90,${b})`;
      const pPct=Math.round(p/maxP*100);
      return`<div class="ltf-month${isCur?' cur':''}">
<div class="ltf-mon-name">${SL_MON_FULL[i]}</div>
<div class="ltf-mon-season">${SEA_EMJ[i]} ${SL_SEASONS[i]}</div>
<div class="ltf-bar-labels"><span>${Math.round(tmn)}°</span><span>${t}°</span><span>${Math.round(tmx)}°</span></div>
<div class="ltf-bar-track">
  <div class="ltf-bar-fill" style="left:${leftPct}%;width:${widthPct}%;background:${col}"></div>
</div>
<div class="ltf-bar-labels"><span>💧 ${p} mm</span></div>
<div class="ltf-bar-track">
  <div class="ltf-bar-fill" style="left:0;width:${pPct}%;background:linear-gradient(to right,rgba(96,165,250,.65),rgba(147,197,253,.9))"></div>
</div>
</div>`;
    }).join('');
  }

  // annual climatogram
  _buildLtfChart();
}

function _buildLtfChart(){
  const el=document.getElementById('ltf-annual'); if(!el)return;
  const W=700,H=180,PL=36,PR=10,PT=12,PB=32;
  const CW=W-PL-PR,CH=H-PT-PB,PRECH=50,TEMPH=CH-PRECH-10;
  const elev=-(366-241)/1000*6.5,N=ARSO_NORMALS;
  const tmx=N.tmax.map(t=>t+elev),tmn=N.tmin.map(t=>t+elev);
  const pr=_PNORM,maxP=Math.max(...pr);
  const minT=Math.min(...tmn)-2,maxT=Math.max(...tmx)+2;
  const bw=CW/12,ty=t=>PT+TEMPH-(t-minT)/(maxT-minT)*TEMPH;
  const curM=new Date().getMonth();
  const SML=['J','F','M','A','M','J','J','A','S','O','N','D'];
  // grid
  let grid='',glbl='';
  for(let t=-5;t<=30;t+=5){
    const y=ty(t);if(y<PT-2||y>PT+TEMPH+2)continue;
    grid+=`<line x1="${PL}" y1="${y}" x2="${W-PR}" y2="${y}" stroke="var(--border)" stroke-width=".5" stroke-dasharray="2,4"/>`;
    glbl+=`<text x="${PL-3}" y="${y+3.5}" text-anchor="end" font-size="8" fill="var(--muted)">${t}°</text>`;
  }
  // band polygon
  const topPts=tmx.map((t,i)=>`${PL+i*bw+bw/2},${ty(t)}`).join(' ');
  const botPts=[...tmn].reverse().map((t,i)=>`${PL+(11-i)*bw+bw/2},${ty(t)}`).join(' ');
  const midLine=_TNORM.map((t,i)=>`${i?'L':'M'}${PL+i*bw+bw/2},${ty(t)}`).join('');
  // precip
  let pbars='';
  pr.forEach((p,i)=>{
    const x=PL+i*bw+2,bwi=bw-4,topY=PT+CH-p/maxP*PRECH,botY=PT+CH,cur=i===curM;
    pbars+=`<rect x="${x}" y="${topY}" width="${bwi}" height="${botY-topY}" fill="${cur?'rgba(96,165,250,.85)':'rgba(96,165,250,.45)'}" rx="2"/>`;
  });
  // month labels
  let mlbls='';
  SML.forEach((s,i)=>{
    const x=PL+i*bw+bw/2,cur=i===curM;
    mlbls+=`<text x="${x}" y="${H-PB+14}" text-anchor="middle" font-size="${cur?9.5:8.5}" font-weight="${cur?700:400}" fill="${cur?'var(--blue)':'var(--muted)'}">${s}</text>`;
  });
  const sepY=PT+TEMPH+5;
  el.innerHTML=`<div class="ltf-annual-title">📊 Letni klimatogram — Rečica ob Savinji (normale 1991–2020)</div>
<div style="overflow-x:auto;-webkit-overflow-scrolling:touch">
<svg viewBox="0 0 ${W} ${H}" style="display:block;width:100%;height:auto;min-width:${W}px">
<defs><linearGradient id="ltfband" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="rgba(251,146,60,.38)"/><stop offset="100%" stop-color="rgba(96,165,250,.25)"/></linearGradient></defs>
<rect x="${PL+curM*bw}" y="${PT}" width="${bw}" height="${CH}" fill="rgba(96,165,250,.07)" rx="2"/>
${grid}${glbl}
<polygon points="${topPts} ${botPts}" fill="url(#ltfband)" opacity=".8"/>
<path d="${midLine}" fill="none" stroke="#fb923c" stroke-width="2" stroke-linejoin="round" stroke-linecap="round"/>
${pbars}
<line x1="${PL}" y1="${sepY}" x2="${W-PR}" y2="${sepY}" stroke="var(--border)" stroke-width=".8"/>
${mlbls}
<text x="${PL}" y="${H-3}" font-size="7.5" fill="var(--muted)">💧 padavine</text>
<text x="${W-PR-60}" y="${H-3}" font-size="7.5" fill="var(--muted)">🌡 temperatura</text>
</svg></div>`;
}
// ═══ end DOLGOROČNA ════════════════════════════════════════

// ═══ end METEO NERD ════════════════════════════════════════

// ═══ WEATHER CARD GENERATOR ════════════════════════════════

function generateWeatherCard() {
  const W = 1200, H = 630, PAD = 60;
  const cvs = document.createElement('canvas');
  cvs.width = W; cvs.height = H;
  const ctx = cvs.getContext('2d');

  // Background
  const bg = ctx.createLinearGradient(0, 0, W, H);
  bg.addColorStop(0, '#030812');
  bg.addColorStop(0.55, '#080f1e');
  bg.addColorStop(1, '#0c1a30');
  ctx.fillStyle = bg; ctx.fillRect(0, 0, W, H);

  // Cyan glow top-left
  const g1 = ctx.createRadialGradient(230, 290, 0, 230, 290, 520);
  g1.addColorStop(0, 'rgba(56,189,248,0.13)'); g1.addColorStop(1, 'rgba(0,0,0,0)');
  ctx.fillStyle = g1; ctx.fillRect(0, 0, W, H);

  // Indigo glow bottom-right
  const g2 = ctx.createRadialGradient(W - 160, H - 80, 0, W - 160, H - 80, 380);
  g2.addColorStop(0, 'rgba(99,102,241,0.10)'); g2.addColorStop(1, 'rgba(0,0,0,0)');
  ctx.fillStyle = g2; ctx.fillRect(0, 0, W, H);

  // ── Live data ──
  const temp      = document.getElementById('temp-val')?.textContent?.trim() || '—';
  const condIcon  = document.getElementById('cond-icon')?.textContent?.trim() || '';
  const condLabel = document.getElementById('cond-label')?.textContent?.trim() || '—';
  const feels     = document.getElementById('feels-val')?.textContent?.trim() || '—';
  const dewpt     = document.getElementById('dewpt-hero')?.textContent?.trim() || '—';
  const updated   = document.getElementById('updated')?.textContent?.trim() || '';

  const numOf = id => {
    const el = document.getElementById(id);
    if (!el) return '—';
    const t = el.firstChild?.nodeValue?.trim();
    return t || el.textContent.trim();
  };
  const humidity = numOf('hs-humidity');
  const pressure = numOf('hs-pressure');
  const wind     = numOf('hs-wind');
  const rain     = numOf('hs-rain-today');
  const uv       = document.getElementById('hs-uv')?.textContent?.trim() || '—';

  // Temperature colour (always dark-palette)
  const t = parseFloat(temp);
  const tColor = isNaN(t) ? '#e8edf8'
    : t < 0  ? '#bae6fd' : t < 8  ? '#67e8f9' : t < 15 ? '#6ee7b7'
    : t < 22 ? '#f1f5f9' : t < 28 ? '#fcd34d' : t < 35 ? '#fb923c' : '#f87171';

  // ── Header ──
  const LOGO = 52;
  _cardLogo(ctx, PAD, 34, LOGO);
  ctx.textBaseline = 'middle'; ctx.textAlign = 'left';
  ctx.font = "800 34px 'Space Grotesk', sans-serif";
  ctx.fillStyle = '#e8edf8';
  ctx.fillText('Meteo', PAD + LOGO + 12, 34 + LOGO / 2);
  const mw = ctx.measureText('Meteo').width;
  ctx.fillStyle = '#38bdf8';
  ctx.fillText('rec', PAD + LOGO + 12 + mw, 34 + LOGO / 2);
  ctx.textAlign = 'right';
  ctx.font = "400 18px 'Inter', sans-serif";
  ctx.fillStyle = '#6a8eae';
  ctx.fillText('📍 Rečica ob Savinji · 366 m n.m.', W - PAD, 34 + LOGO / 2);

  // Divider
  ctx.strokeStyle = 'rgba(56,189,248,0.18)'; ctx.lineWidth = 1;
  ctx.beginPath(); ctx.moveTo(PAD, 102); ctx.lineTo(W - PAD, 102); ctx.stroke();

  // ── Temperature ──
  // Vertically center the content block (temp + label + feels) between
  // the divider (y=102) and the metrics strip (y=482)
  const TEMP_BASE = 315;
  ctx.textAlign = 'left'; ctx.textBaseline = 'alphabetic';
  ctx.font = "800 168px 'Space Grotesk', sans-serif";
  ctx.fillStyle = tColor;
  ctx.fillText(temp, PAD, TEMP_BASE);
  const tempW = ctx.measureText(temp).width;
  // °C superscript — cap-top aligned with numerals
  ctx.font = "700 44px 'Space Grotesk', sans-serif";
  ctx.fillStyle = 'rgba(173,192,216,0.6)';
  ctx.fillText('°C', PAD + tempW + 10, TEMP_BASE - 168 * 0.72 + 44 * 0.72);

  // Condition label
  ctx.font = "700 30px 'Space Grotesk', sans-serif";
  ctx.fillStyle = '#c8daf0';
  ctx.fillText(condLabel, PAD, TEMP_BASE + 47);

  // Feels / dew
  ctx.font = "400 18px 'Inter', sans-serif";
  ctx.fillStyle = '#6a8eae';
  ctx.fillText('Občutena: ' + feels + ' °C  ·  Rosišče: ' + dewpt + ' °C', PAD, TEMP_BASE + 81);

  // ── Large condition emoji (right) ──
  ctx.font = "128px 'Segoe UI Emoji','Apple Color Emoji','Noto Color Emoji',serif";
  ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
  ctx.globalAlpha = 0.9;
  ctx.fillText(condIcon, 960, 255);
  ctx.globalAlpha = 1;

  // ── Metrics strip ──
  const MX = PAD - 14, MY = H - 148, MW = W - (MX * 2), MH = 98;
  ctx.fillStyle = 'rgba(56,189,248,0.055)';
  _cardRRect(ctx, MX, MY, MW, MH, 16); ctx.fill();
  ctx.strokeStyle = 'rgba(56,189,248,0.14)'; ctx.lineWidth = 1;
  _cardRRect(ctx, MX, MY, MW, MH, 16); ctx.stroke();

  const metrics = [
    { label: 'Vlažnost',  value: humidity, unit: '%'    },
    { label: 'Tlak',      value: pressure, unit: 'hPa'  },
    { label: 'Veter',     value: wind,     unit: 'km/h' },
    { label: 'Padavine',  value: rain,     unit: 'mm'   },
    { label: 'UV indeks', value: uv,       unit: ''     },
  ];
  const colW = MW / metrics.length;
  metrics.forEach((m, i) => {
    const cx = MX + colW * i + colW / 2;
    ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
    ctx.font = "400 14px 'Inter', sans-serif";
    ctx.fillStyle = '#6a8eae';
    ctx.fillText(m.label, cx, MY + 26);
    ctx.font = "700 26px 'Space Grotesk', sans-serif";
    ctx.fillStyle = '#dde8f8';
    ctx.fillText(m.value + (m.unit ? ' ' + m.unit : ''), cx, MY + 66);
    if (i < metrics.length - 1) {
      ctx.strokeStyle = 'rgba(56,189,248,0.13)'; ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.moveTo(MX + colW * (i + 1), MY + 10);
      ctx.lineTo(MX + colW * (i + 1), MY + MH - 10);
      ctx.stroke();
    }
  });

  // ── Footer ──
  ctx.textBaseline = 'middle';
  ctx.font = "400 15px 'Inter', sans-serif";
  ctx.fillStyle = 'rgba(106,142,174,0.55)';
  ctx.textAlign = 'left';
  ctx.fillText(updated, PAD, H - 24);
  ctx.textAlign = 'right';
  ctx.fillStyle = 'rgba(56,189,248,0.65)';
  ctx.font = "600 16px 'Inter', sans-serif";
  ctx.fillText('meteorec.si', W - PAD, H - 24);

  // ── Show preview modal ──
  try {
    const dataUrl = cvs.toDataURL('image/png');
    _cardModalDataUrl = dataUrl;
    document.getElementById('card-modal-img').src = dataUrl;
    document.getElementById('card-modal').classList.add('open');
    document.body.style.overflow = 'hidden';
  } catch(e) {
    console.error('Weather card error:', e);
  }
}

let _cardModalDataUrl = '';

function closeCardModal(e) {
  if (e && e.target !== document.getElementById('card-modal')) return;
  document.getElementById('card-modal').classList.remove('open');
  document.body.style.overflow = '';
}

function downloadWeatherCard() {
  if (!_cardModalDataUrl) return;
  const a = document.createElement('a');
  a.download = 'meteorec-karta.png';
  a.href = _cardModalDataUrl;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
}

function _cardLogo(ctx, x, y, size) {
  const s = size / 64;
  ctx.save();
  ctx.translate(x, y);
  ctx.scale(s, s);

  // Sun
  const sunG = ctx.createLinearGradient(0, 0, 64, 64);
  sunG.addColorStop(0, '#fde68a'); sunG.addColorStop(1, '#f59e0b');
  ctx.fillStyle = sunG;
  ctx.beginPath(); ctx.arc(32, 24, 10, 0, Math.PI * 2); ctx.fill();

  // Rays
  ctx.strokeStyle = '#fbbf24'; ctx.lineWidth = 2.4; ctx.lineCap = 'round';
  [[32,4,32,9],[46,10,42.5,13.5],[18,10,21.5,13.5]].forEach(([x1,y1,x2,y2]) => {
    ctx.beginPath(); ctx.moveTo(x1,y1); ctx.lineTo(x2,y2); ctx.stroke();
  });

  // Mountains
  const mtnG = ctx.createLinearGradient(0, 0, 0, 64);
  mtnG.addColorStop(0, '#38bdf8'); mtnG.addColorStop(1, '#6366f1');
  ctx.fillStyle = mtnG;
  ctx.beginPath();
  ctx.moveTo(4,50); ctx.lineTo(22,30); ctx.lineTo(33,42);
  ctx.lineTo(44,24); ctx.lineTo(60,50); ctx.closePath(); ctx.fill();

  // Snow caps
  ctx.fillStyle = 'rgba(224,242,254,0.85)';
  ctx.beginPath(); ctx.moveTo(44,24); ctx.lineTo(50,38); ctx.lineTo(38,38); ctx.closePath(); ctx.fill();
  ctx.beginPath(); ctx.moveTo(22,30); ctx.lineTo(28,39); ctx.lineTo(16,39); ctx.closePath(); ctx.fill();

  // Wave
  ctx.strokeStyle = '#38bdf8'; ctx.lineWidth = 2.4;
  ctx.beginPath();
  ctx.moveTo(4,54);
  ctx.quadraticCurveTo(12,50,18,54);
  ctx.quadraticCurveTo(26,50,32,54);
  ctx.quadraticCurveTo(40,50,46,54);
  ctx.quadraticCurveTo(54,50,60,54);
  ctx.stroke();

  ctx.restore();
}

function _cardRRect(ctx, x, y, w, h, r) {
  ctx.beginPath();
  ctx.moveTo(x+r, y); ctx.lineTo(x+w-r, y);
  ctx.quadraticCurveTo(x+w, y, x+w, y+r);
  ctx.lineTo(x+w, y+h-r);
  ctx.quadraticCurveTo(x+w, y+h, x+w-r, y+h);
  ctx.lineTo(x+r, y+h);
  ctx.quadraticCurveTo(x, y+h, x, y+h-r);
  ctx.lineTo(x, y+r);
  ctx.quadraticCurveTo(x, y, x+r, y);
  ctx.closePath();
}

